-- Dumping data for table `books`
--

LOCK TABLES `books` WRITE;
/*!40000 ALTER TABLE `books` DISABLE KEYS */;
INSERT INTO `books` VALUES (1,'OTL-4','GT-ISBN9781946135100','Accounting in the Finance World',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This book is intended for an undergraduate or MBA level Financial Accounting course. It covers the standard topics in a standard sequence, utilizing the Socratic method of asking and answering questions.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 4.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/financial-accounting\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781946135100.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Accounting.\nSubject OTL 2 — nguyên bản ô CSV —: Business.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781946135100.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:30','2026-05-06 09:00:00',NULL),(2,'OTL-5','GT-ISBN9780984417551','A First Course in Linear Algebra',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'A First Course in Linear Algebra is an introductory textbook aimed at college-level sophomores and juniors. Typically students will have taken calculus, but it is not a prerequisite. The book begins with systems of linear equations, then covers matrix algebra, before taking up finite-dimensional vector spaces in full generality. The final chapter covers matrix representations of linear transformations, through diagonalization, change of basis and Jordan canonical form. Determinants and eigenvalues are covered along the way. A unique feature of this book is that chapters, sections and theorems are labeled rather than numbered. For example, the chapter on vectors is labeled \"Chapter V\" and the theorem that elementary matrices are nonsingular is labeled \"Theorem EMN.\" Another feature of this book is that it is designed to integrate SAGE, an open source alternative to mathematics software such as Matlab and Maple. The author includes a 45-minute video tutorial on SAGE and teaching linear algebra. This textbook has been used in classes at: Centre for Excellence in Basic Sciences, Westmont College, University of Ottawa, Plymouth State University, University of Puget Sound, University of Notre Dame, Carleton University, Amherst College, Felician College, Southern Connecticut State University, Michigan Technological University, Mount Saint Mary College, University of Western Australia, Moorpark College, Pacific University, Colorado State University, Smith College, Wilbur Wright College, Central Washington U (Lynwood Center), St. Cloud State University, Miramar College, Loyola Marymount University.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 5.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/a-first-course-in-linear-algebra\nPublisher ô CSV: Robert Beezer.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9780984417551.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Free Documentation License (GNU).\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Algebra.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Robert A. Beezer - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9780984417551.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:30','2026-05-06 09:00:00',NULL),(3,'OTL-7','GT-ISBN9780989472128','Book of Proof - Third Edition',NULL,'Tiếng Anh',NULL,2018,NULL,NULL,NULL,NULL,1,0,'This is a book about how to prove theorems. Until this point in your education, you may have regarded mathematics primarily as a computational discipline. You have learned to solve equations, compute derivatives and integrals, multiply matrices and find determinants; and you have seen how these things can answer practical questions about the real world. In this setting, your primary goal in using mathematics has been to compute answers. But there is another approach to mathematics that is more theoretical than computational. In this approach, the primary goal is to understand mathematical structures, to prove mathematical statements, and even to invent or discover new mathematical theorems and theories. The mathematical techniques and procedures that you have learned and used up until now have their origins in this theoretical side of mathematics. For example, in computing the area under a curve, you use the fundamental theorem of calculus. It is because this theorem is true that your answer is correct. However, in your calculus class you were probably far more concerned with how that theorem could be applied than in understanding why it is true. But how do we know it is true? How can we convince ourselves or others of its validity? Questions of this nature belong to the theoretical realm of mathematics. This book is an introduction to that realm. This book will initiate you into an esoteric world. You will learn and apply the methods of thought that mathematicians use to verify theorems,explore mathematical truth and create new mathematical theories. This will prepare you for advanced mathematics courses, for you will be better able to understand proofs, write your own proofs and think critically and inquisitively about mathematics. This text has been used in classes at: Virginia Commonwealth University, Lebanon Valley College, University of California - San Diego, Colorado State University, Westminster College, South Dakota State University, PTEK College - Brunei, Christian Brothers High School, University of Texas Pan American, Schola Europaea, James Madison University, Heriot-Watt University, Prince of Songkla University, Queen Mary University of London, University of Nevada - Reno, University of Georgia - Athens, Saint Peter\'s University, California State University,Bogaziçi University, Pennsylvania State University, University of Notre Dame\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 7.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/book-of-proof\nPublisher ô CSV: Richard Hammack.\nCopyright Year ô CSV: 2018.\nISBN-13 ô CSV: 9780989472128.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Pure.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Richard Hammack - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9780989472128.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:30','2026-05-06 09:00:00',NULL),(4,'OTL-8','GT-ISBN9781946135056','Communication for Business Success',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Business Communication for Success (BCS) provides a comprehensive, integrated approach to the study and application of written and oral business communication to serve both student and professor. This series features chapters with the following elements: Learning Objectives Introductory Exercises Clear expectations, relevant background, and important theories Practical, real-world examples Key Takeaways or quick internal summaries Key terms that are easily identified In-chapter assignments Postchapter assessments linked to objectives and skills acquisition Each chapter is self-contained, allowing for mix-and-match flexibility and custom or course-specific design. Each chapter focuses on clear objectives and skill demonstrations that can be easily linked to your syllabus and state or federal requirements. Supported by internal and external assessments, each chapter features time-saving and learning-enhancement support for instructors and students. BCS is designed to help students identify important information, reinforce for retention, and demonstrate mastery with a clear outcome product. The text has three content categories: Foundations Process and products Contexts The first three chapters form the core foundation for the study of oral and written business communication. The next sequence of chapters focus on the process of writing, then oral performance with an emphasis on results. The final sequence focuses on contexts where business communication occurs, from interpersonal to intercultural, from groups to leadership. In each of the process and product chapter sequences, the chapters follow a natural flow, from prewriting to revision, from preparation for a presentation to performance. Each sequence comes together in a concluding chapter that focuses on action—where we apply the skills and techniques of written or oral communication in business, from writing a letter to presenting a sales speech. These performances not only serve to reinforce real-world applications but also may serve as course assessments. This text has been used in classes at: Ohio University, Miami University – Oxford, Kent State University – Salem Campus, Cuyahoga Community College – West, University of Toledo, Cuyahoga Community College – District, Northern Arizona University, Gateway Community College, University of Arizona, Arizona Western College, Boise State University,Western Governors University, Doane College, Mcpherson College, University of Nebraska Med Center, Suny Fredonia, State University of New York Institute of Technology at Utica/Rome, Trinidad State Junior College, University of Delaware, Brenau University, Brewton-Parker College, Loras College, Kapiolani Community College, Muscatine Community College, Greenville College, University of Illinois – Chicago, Millikin University, Rockland Community College, Cornell University, National-Louis University – Lisle, St. Gregory\'s University, University of Southern Indiana, Missouri State University – W Plains, Bucks County Community College – Newton, Clarion University of Pennsylvania, Pulaski Technical College, Temple University, Dixie State College of Utah, Averett University, Virginia Polytech Institute, Fond Du Lac Tribal Community College, Lipscomb University, Edgewood College, University of Wisconsin – Stout, Wisconsin Lutheran College, Virginia State University, North Georgia Technical College – Blairsville, Paradise Valley Community College, Fordham University – Lincoln Center, New England College of Business/Finance, Eastern New Mexico University, University of Alabama, Albertus Magnus College, Pepperdine University, Fullerton College, Santa Ana College, Miracosta College – Oceanside, San Jose State University, De Anza College, University of The Southwest, Florida Institute of Technology, Forida State University, Dean College, California State University, University of Massachusetts, Suffolk University, Stevenson University, Worcester State College, University of Maryland, Clover Park Technical College, Minnesota State University – Moorhead, College of St. Scholastica, Ferris State University, Concordia University, Southern New Hampshire University, Lower Columbia College, University of North Carolina – Greensboro, Rockingham Community College, Stanly Community College, Wayland Baptist University, Bunker Hill Community College, Salve Regina University, University of The Incarnate Word, St. Mary\'s University, University of Rhode Island, Texarkana College, Renton Technical College, Tarleton State University, Wayland Baptist University – Plainview, University of Houston, Stephen F. Austin State University, Bates Technical College, Chabot College, Bakersfield College, Azusa Pacific University, University of Houston – Downtown, California Southern University, Miracosta College, American Public University, American Public University System, Huntington Junior College, Flat World Knowledge University, Jackson Senior High School, Holmes High School, Dlielc, Clintondale High School, American University in Kosovo in Conjunction with Rochester Institute of Technology, Southeast Lauderdale High School, Benedict Business Hotel Management School, University of the People, Kwame Nkrumah University of Science and Technology, New Brunswick College of Craft and Design, New England School of English, Comsats Institute of Information Technology, Wayland Baptist University – Anchorage, Volcano Vista High School, Wayland Baptist University – San Antonio, Morrill High School, North Island College – B Campus, Seneca College, APOU, University of North Carolina – Greensboro, Southern New Hampshire University, University of Maryland University College, Harrisburg High School\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 8.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/business-communication-for-success\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781946135056.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Journalism, Media Studies & Communications - Organizational Communication.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781946135056.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:30','2026-05-06 09:00:00',NULL),(5,'OTL-9','GT-ISBN9781946135063','College Success',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Our primary goal in writing College Success is to help you succeed in college. According to Department of Education data, 30 percent of college freshmen leave school in their first year and as many as 50 percent never graduate. College Success is designed to help change that. College Success has a student-friendly format arranged to help you develop the essential skills and provide the information you need to succeed in college. This is not a textbook full of theory and extensive detail that merely discusses student success; rather, this is a how-to manual for succeeding in college. The book provides realistic, practical guidance ranging from study skills to personal health, from test taking to managing time and money. Furthermore, College Success is accessible—information is presented concisely and as simply as possible. College Success has the following features to help you achieve your goals: Each chapter asks you to evaluate yourself because success starts with recognizing your strengths and weaknesses, your hopes and desires, and your own personal, individual realities. You\'ll develop your own goals based on these self-assessments, determining what success in college really means for you as an individual. Throughout the book, you will find numerous interactive activities created to help you improve your skills. To assist you with this, the material is presented in easily digestible “chunks” of information so you can begin applying it immediately in your own life—and get the most out of your college education.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 9.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/college-success\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781946135063.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Student Success.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781946135063.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:30','2026-05-06 09:00:00',NULL),(6,'OTL-10','GT-ISBN9780961408824','Calculus - Third Edition',NULL,'Tiếng Anh',NULL,1991,NULL,NULL,NULL,NULL,1,0,'Published in 1991 by Wellesley-Cambridge Press, the book is a useful resource for educators and self-learners alike. It is well organized, covers single variable and multivariable calculus in depth, and is rich with applications. Prof. Strang has also developed a related series of videos, Highlights of Calculus, on the basic ideas of calculus.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 10.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/calculus\nPublisher ô CSV: Wellesley-Cambridge Press.\nCopyright Year ô CSV: 1991.\nISBN-13 ô CSV: 9780961408824.\nISBN-10 ô CSV: 0961408820.\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Gilbert Strang - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9780961408824.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:30','2026-05-06 09:00:00',NULL),(7,'OTL-11','GT-ISBN9780978745073','Collaborative Statistics',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Collaborative Statistics was written by Barbara Illowsky and Susan Dean, faculty members at De Anza Collegein Cupertino, California. The textbook was developed over several years and has been used in regularand honors-level classroom settings and in distance learning classes. Courses using this textbook have beenarticulated by the University of California for transfer of credit. The textbook contains full materials forcourse offerings, including expository text, examples, labs, homework, and projects. A Teacher\'s Guide iscurrently available in print form and on the Connexions site at and supplemental course materials including additional problem sets and video lectures are available. The on-line text for each of these collections collections willmeet the Section 508 standards for accessibility. An on-line course based on the textbook was also developed by Illowsky and Dean. It has won an awardas the best on-line California community college course. The on-line course will be available at a later dateas a collection in Connexions, and each lesson in the on-line course will be linked to the on-line textbookchapter. The on-line course will include, in addition to expository text and examples, videos of courselectures in captioned and non-captioned format. The original preface to the book as written by professors Illowsky and Dean, now follows: This book is intended for introductory statistics courses being taken by students at two– and four–yearcolleges who are majoring in fields other than math or engineering. Intermediate algebra is the only prerequisite.The book focuses on applications of statistical knowledge rather than the theory behind it. Thetext is named Collaborative Statistics because students learn best by doing. In fact, they learn best byworking in small groups. The old saying “two heads are better than one” truly applies here. Our emphasis in this text is on four main concepts: thinking statistically incorporating technology working collaboratively writing thoughtfully These concepts are integral to our course. Students learn the best by actively participating, not by justwatching and listening. Teaching should be highly interactive. Students need to be thoroughly engagedin the learning process in order to make sense of statistical concepts. Collaborative Statistics providestechniques for students to write across the curriculum, to collaborate with their peers, to think statistically,and to incorporate technology. This book takes students step by step. The text is interactive. Therefore, students can immediately applywhat they read. Once students have completed the process of problem solving, they can tackle interestingand challenging problems relevant to today\'s world. The problems require the students to apply theirnewly found skills. In addition, technology (TI-83 graphing calculators are highlighted) is incorporatedthroughout the text and the problems, as well as in the special group activities and projects. The book alsocontains labs that use real data and practices that lead students step by step through the problem solvingprocess. At De Anza, along with hundreds of other colleges across the country, the college audience involves alarge number of ESL students as well as students from many disciplines. The ESL students, as well asthe non-ESL students, have been especially appreciative of this text. They find it extremely readable andunderstandable. Collaborative Statistics has been used in classes that range from 20 to 120 students, and inregular, honor, and distance learning classes.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 11.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/collaborative-statistics\nPublisher ô CSV: OpenStax CNX.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9780978745073.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Applied.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Barbara Illowsky - Author / Susan Dean - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9780978745073.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:30','2026-05-06 09:00:00',NULL),(8,'OTL-12','GT-OTL000012','College Algebra',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'College Algebra is an introductory text for a college algebra survey course. The material is presented at a level intended to prepare students for Calculus while also giving them relevant mathematical skills that can be used in other classes. The authors describe their approach as \"Functions First,\" believing introducing functions first will help students understand new concepts more completely. Each section includes homework exercises, and the answers to most computational questions are included in the text (discussion questions are open-ended). Graphing calculators are used sparingly and only as a tool to enhance the Mathematics, not to replace it. The authors also offer a Precalculus version of this text, which has two extra chapters covering Trigonometry.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 12.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/college-algebra\nPublisher ô CSV: Stitz Zeager Open Source Mathematics.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Algebra.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Carl Stitz - Author / Jeff Zeager - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:30','2026-05-06 09:01:00',NULL),(9,'OTL-13','GT-ISBN9781453300923','Elementary Algebra',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'It is essential to lay a solid foundation in mathematics if a student is to be competitive in today\'s global market. The importance of algebra, in particular, cannot be overstated, as it is the basis of all mathematical modeling used in applications found in all disciplines. Traditionally, the study of algebra is separated into a two parts, elementary algebra and intermediate algebra. This textbook, Elementary Algebra, is the first part, written in a clear and concise manner, making no assumption of prior algebra experience. It carefully guides students from the basics to the more advanced techniques required to be successful in the next course. This text is, by far, the best elementary algebra textbook offered under a Creative Commons license. It is written in such a way as to maintain maximum flexibility and usability. A modular format was carefully integrated into the design. For example, certain topics, like functions, can be covered or omitted without compromising the overall flow of the text. An introduction of square roots in Chapter 1 is another example that allows for instructors wishing to include the quadratic formula early to do so. Topics such as these are carefully included to enhance the flexibility throughout. This textbook will effectively enable traditional or nontraditional approaches to elementary algebra. This, in addition to robust and diverse exercise sets, provides the base for an excellent individualized textbook instructors can use free of needless edition changes and excessive costs! A few other differences are highlighted below: Equivalent mathematical notation using standard text found on a keyboard A variety of applications and word problems included in most exercise sets Clearly enumerated steps found in context within carefully chosen examples Alternative methods and notation, modularly integrated, where appropriate Video examples available, in context, within the online version of the textbook Robust and diverse exercise sets with discussion board questions Key words and key takeaways summarizing each section This text employs an early-and-often approach to real-world applications, laying the foundation for students to translate problems described in words into mathematical equations. It also clearly lays out the steps required to build the skills needed to solve these equations and interpret the results. With robust and diverse exercise sets, students have the opportunity to solve plenty of practice problems. In addition to embedded video examples and other online learning resources, the importance of practice with pencil and paper is stressed. This text respects the traditional approaches to algebra pedagogy while enhancing it with the technology available today. In addition, textual notation is introduced as a means to communicate solutions electronically throughout the text. While it is important to obtain the skills to solve problems correctly, it is just as important to communicate those solutions with others effectively in the modern era of instant communications.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 13.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/elementary-algebra\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: 9781453300923.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Algebra.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: John Redden - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781453300923.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(10,'OTL-14','GT-ISBN9780639707808','eMarketing: The Essential Guide to Marketing in a Digital World - 7th Edition',NULL,'Tiếng Anh',NULL,2022,NULL,NULL,NULL,NULL,1,0,'Since our 10th Anniversary Edition of eMarketing: The Essential Guide to Marketing in a Digital World, we have witnessed a global wave of change that has had an undeniable impact on how we live, connect, and communicate worldwide. There is no doubt that the COVID-19 pandemic has, and will continue to have, a lasting effect on human reality. With this in mind, we are incredibly proud to present the 7th Edition of our textbook.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 14.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/emarketing-the-essential-guide-to-marketing-in-a-digital-world\nPublisher ô CSV: Red & Yellow.\nCopyright Year ô CSV: 2022.\nISBN-13 ô CSV: 9780639707808.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Marketing.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Dionne Solomons - Author / Tania Kliphuis - Author / Michelle Wadley - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9780639707808.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(11,'OTL-15','GT-ISBN9781946135094','Exploring Business',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'The author\'s goals in writing Exploring Business Version 2.0 was simple: introduce students to business in an exciting way. Exploring Business is adapted from a work produced by a publisher who has requested that they and the original author not receive attribution. This adapted edition is produced by the University of Minnesota Libraries Publishing through the eLearning Support Initiative. Though the publisher has requested that they and the original author not receive attribution, this adapted edition reproduces all original text and sections of the book, except for publisher and author name attribution. This textbook has been used in classes at: College of Alameda, Columbia Basin College, Flagler College, Johnson County Community College, Pasadena City College, Penn State University, Renton Technical College, San Diego Mesa College, Sierra College, Yuba College.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 15.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/exploring-business\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781946135094.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Management.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781946135094.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(12,'OTL-16','GT-ISBN9781946135124','Information Systems - A Manager\'s Guide to Harnessing Technology',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Information Systems: A Manager\'s Guide to Harnessing Technology is intended for use in undergraduate and/or graduate courses in Management Information Systems and Information Technology. The teaching approach in Information Systems: A Manager\'s Guide to Harnessing Technology can change this. The text offers a proven approach that has garnered student praise, increased IS enrollment, and engaged students to think deeper and more practically about the space where business and technology meet. Every topic is related to specific business examples, so students gain an immediate appreciation of its importance. Rather than lead with technical topics, the book starts with strategic thinking, focusing on big-picture issues that have confounded experts but will engage students. And while chapters introduce concepts, cases on approachable, exciting firms across industries further challenge students to apply what they\'ve learned, asking questions like: Why was Netflix able to repel Blockbuster and WalMart? How did Harrah\'s Casino\'s become twice as profitable as comparably-sized Caesar\'s, enabling the former to acquire the latter? How does Spain\'s fashion giant Zara, a firm that shuns the sort of offshore manufacturing used by every other popular clothing chain, offer cheap fashions that fly off the shelves, all while achieving growth rates and profit margins that put Gap to shame? Why do technology markets often evolve into winner-take-all or winner take-most scenarios? And how can managers compete when these dynamics are present? Why is Google more profitable than Disney? How much is Facebook really worth? The teaching approach in this text encourages students to think deeper and more practically about the space where business and technology meet. Every topic is related to specific business examples, so students gain an immediate appreciation of its importance. Rather than starting with technical topics, the book starts with strategic thinking, focusing on big-picture issues that interest students.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 16.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/information-systems-a-manager-s-guide-to-harnessing-technology\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781946135124.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781946135124.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(13,'OTL-18','GT-ISBN9781936126460','International Finance: Theory and Policy',NULL,'Tiếng Anh',NULL,2010,NULL,NULL,NULL,NULL,1,0,'International Finance Theory and Policy is built on Steve Suranovic\'s belief that to understand the international economy, students need to learn how economic models are applied to real world problems. It is true what they say, that ”economists do it with models.“ That\'s because economic models provide insights about the world that are simply not obtainable solely by discussion of the issues. International Finance Theory and Policy develops a unified model of the international macroeconomy. The text provides detailed descriptions of major macroeconomic variables, covers the interest rate parity and purchasing power parity theories of exchange rate determination, takes an exhaustive look at the pros and cons of trade imbalances and presents the well-known AA-DD model to explore the effects of fiscal and monetary policy under both fixed and flexible exchange rates. The models are developed, not by employing advanced mathematics, but rather by walking students through a detailed description of how a model\'s assumptions influence its conclusions. But more importantly, each model and theory is connected to real world policy issues. The Finance Text has the following unique features: o Begins with an historical overview of the international macroeconomy to provide context for the theory. o Concludes with a detailed discussion of the pros and cons of fixed and floating exchange rate systems. o Provides an extensive look at the issue of trade imbalances. Readers learn techniques to evaluate whether a country\'s trade deficit (or surplus) is dangerous, beneficial, or benign. o Explains how purchasing power parity is used to make cross country income comparisons. o Offers clear detailed explanations of the AA-DD model. o Applies the AA-DD model to understand the effects of monetary and fiscal policy on GDP, the exchange rate, and the trade balance. International Finance Theory and Policy by Steve Suranovic is intended for a one-semester course in International Finance. After March 2010, you can check out the entire book online or request a desk copy.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 18.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/international-finance-theory-and-policy\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2010.\nISBN-13 ô CSV: 9781936126460.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Finance.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Steve Suranovic - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781936126460.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(14,'OTL-19','GT-ISBN9781936126446','International Trade: Theory and Policy',NULL,'Tiếng Anh',NULL,2010,NULL,NULL,NULL,NULL,1,0,'International Trade: Theory and Policy is built on Steve Suranovic\'s belief that to understand the international economy, students need to learn how economic models are applied to real world problems. It is true what they say, that ”economists do it with models.“ That\'s because economic models provide insights about the world that are simply not obtainable solely by discussion of the issues. International Trade: Theory and Policy presents a variety of international trade models including the Ricardian model, the Heckscher-Ohlin model, and the monopolistic competition model. It includes trade policy analysis in both perfectly competitive and imperfectly competitive markets. The text also addresses current issues such as free trade area formation and administered protection policies. The models are developed, not by employing advanced mathematics, but rather by walking students through a detailed description of how a model\'s assumptions influence its conclusions. But more importantly, each model and theory is connected to real world policy issues. The main purpose of the text is to provide a thorough grounding in the arguments concerning the age-old debate about free trade versus protectionism. This text has the following unique features: The text begins with an historical overview of trade policy issues to provide context for the theory. The text concludes with a detailed economic argument supporting free trade.The welfare analysis in the Ricardian, Heckscher-Ohlin and specific factors models emphasize the redistributive effects of free trade by calculating changes in real incomes.The trade policy chapter provides a comprehensive look at many more trade policies than are found in a printed textbook. A chapter about domestic policies contains an evaluation of domestic taxes and subsidies that are often ignored in traditional trade textbooks but are increasingly important as large countries complain more about each other\'s domestic agriculture policies and labor and environmental policies. The text uses the theory of the second-best to explain why protection can improve national welfare. This well-known theoretical result is rarely presented as methodically and consistently as it is in this text. International Trade: Theory and Policy by Steve Suranovic is intended for a one-semester course in International Trade. After April 2010, you can check out the entire book online or request a desk copy.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 19.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/international-trade-theory-and-policy\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2010.\nISBN-13 ô CSV: 9781936126446.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Economics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Steve Suranovic - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781936126446.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(15,'OTL-20','GT-OTL000020','Introduction to Physical Oceanography',NULL,'Tiếng Anh',NULL,2008,NULL,NULL,NULL,NULL,1,0,'This textbook covers physical-oceanographic processes, theories, data, and measurements, targeted at upper-division undergraduates and graduate students in oceanography, meteorology, and ocean engineering. In addition to the classical topics, the author includes discussions of heat fluxes, the role of the ocean in climate, the deep circulation, equatorial processes including El Nino, data bases used by oceanographers, the role of satellites and data from space, ship-based measurements, and the importance of vorticity in understanding oceanic flows. Students should have studied differential equations and introductory college physics, although math is de-emphasized.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 20.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-physical-oceanography\nPublisher ô CSV: OTL ID 20 không có ô Publisher trong bản CSV tải về..\nCopyright Year ô CSV: 2008.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Earth Sciences.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Robert H. Stewart - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:01:00',NULL),(16,'OTL-21','GT-OTL000021','Introduction to Probability - 2nd edition',NULL,'Tiếng Anh',NULL,2006,NULL,NULL,NULL,NULL,1,0,'Probability theory began in seventeenth century France when the two great French mathematicians, Blaise Pascal and Pierre de Fermat, corresponded over two problems from games of chance. Problems like those Pascal and Fermat solved continuedto influence such early researchers as Huygens, Bernoulli, and DeMoivre in establishing a mathematical theory of probability. Today, probability theory is a wellestablished branch of mathematics that finds applications in every area of scholarlyactivity from music to physics, and in daily experience from weather prediction topredicting the risks of new medical treatments. This text is designed for an introductory probability course taken by sophomores,juniors, and seniors in mathematics, the physical and social sciences, engineering,and computer science. It presents a thorough treatment of probability ideas andtechniques necessary for a form understanding of the subject. The text can be usedin a variety of course lengths, levels, and areas of emphasis. For use in a standard one-term course, in which both discrete and continuousprobability is covered, students should have taken as a prerequisite two terms ofcalculus, including an introduction to multiple integrals. In order to cover Chapter 11, which contains material on Markov chains, some knowledge of matrix theoryis necessary. The text can also be used in a discrete probability course. The material has beenorganized in such a way that the discrete and continuous probability discussions arepresented in a separate, but parallel, manner. This organization dispels an overlyrigorous or formal view of probability and o?ers some strong pedagogical valuein that the discrete discussions can sometimes serve to motivate the more abstractcontinuous probability discussions. For use in a discrete probability course, studentsshould have taken one term of calculus as a prerequisite. Very little computing background is assumed or necessary in order to obtain fullbenefits from the use of the computing material and examples in the text. All ofthe programs that are used in the text have been written in each of the languagesTrueBASIC, Maple, and Mathematica.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 21.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-probability\nPublisher ô CSV: American Mathematical Society.\nCopyright Year ô CSV: 2006.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Free Documentation License (GNU).\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Applied.\nSubject OTL 2 — nguyên bản ô CSV —: Engineering & Technology.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Charles M. Grinstead - Author / J. Laurie Snell - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:01:00',NULL),(17,'OTL-22','GT-ISBN9781453311073','Introductory Chemistry',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'David W. Ball of Cleveland State University brings his new survey of general chemistry text, Introductory Chemistry, to the market with a fresh theme that will be sure to hold student interest: \"Chemistry is Everywhere.\" Introductory Chemistry is intended for a one-semester introductory or preparatory chemistry course. Throughout the chapters, David presents two features that reinforce the theme of the textbook, that chemistry is everywhere. The first is the boxed feature titled, appropriately, ”Chemistry is Everywhere“. This feature takes a topic of the chapter and demonstrates how this topic shows up in everyday life. In the introductory chapter, ”Chemistry is Everywhere“ focuses on the personal hygiene products that students may use every morning: toothpaste, soap, shampoo among others. These products are chemicals, aren\'t they? This book explores some of the chemical reactions like the ones that give students clean and healthy teeth, and shiny hair. This feature makes it clear to students that chemistry is, indeed, everywhere, and it will promote student retention in what is sometimes considered an intimidating course. The second boxed feature focuses on chemistry that students likely indulge in every day: eating and drinking. In the ”Food and Drink App“, David discusses how the chemistry of the chapter applies to things that students eat and drink every day. Carbonated beverages depend on the behavior of gases, foods contain acids and bases, and everyone actually eats certain rocks. (Yikes!) Cooking, eating, drinking, metabolism — all chemical processes students are involved with all the time. These features allow students to see the things we interact with every day in a new light — as chemistry. Just like many of the one-semester chemistry books you may be used to, each section in David Ball\'s starts with one or more Learning Objectives, which list the main points of the section. Each section ends with Key Takeaways, which are reviews of the main points of the section. Each chapter is full of examples to illustrate the key points of the materials, and each example is followed with a similar ”Test Yourself“ exercise to see if the student understands the concept. Each section ends with its own set of paired exercises to practice the material from that section, and each chapter ends with a section of ”Additional Exercises“ that are more challenging or require multiple steps or skills to answer. David took the time to treat mathematical problems in Introductory Chemistry one of two ways, either as a conversion-factor problem or as a formula problem. David believes having two basic mathematical approaches (converting and formulas) allows the text to focus on the logic of the approach and not tricks or shortcuts; which speaks to the final point about Introductory Chemistry. You\'ll notice that David took no shortcuts with the material in this text, his inviting writing style, concise approach, consistent presentation, and interesting pedagogy have given it some of the best peer reviews we\'ve seen at Flat World. So, order a desk copy or dive in now to see for yourself.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 22.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introductory-chemistry\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: 9781453311073.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Chemistry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: David W. Ball - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781453311073.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(18,'OTL-23','GT-ISBN9780982043028','Launch! Advertising and Promotion in Real Time',NULL,'Tiếng Anh',NULL,2009,NULL,NULL,NULL,NULL,1,0,'Launch! Advertising and Promotion is written for advertising and promotion courses taught to students in the business school and journalism & mass communication students. This textbook is the first of its kind to teach advertising concepts by reverse engineering a real advertising campaign from beginning to end. In April 2007, SS+K, an innovative New York City communications agency, launched the first ever branding campaign for msnbc.com with the tag \"A Fuller Spectrum of News.\" Launch! follows that campaign from initial agency pitch through roll-out of print and media assets to post-campaign analysis. Throughout, it exposes readers to the theory and concepts of advertising and promotion, and the personalities and decisions that drove this campaign. The book takes a rare look ”behind the curtain“ — even letting you see some of the paths not chosen by the agency and client. Students get a realistic sense of how theory plays out in practice, and get a flavor for the exciting field of advertising and promotion. And, they consistently learn the perspectives of both the advertising agency (where many journalism and communications students will work) and the client (where many marketing majors will work). This is a unique book, with a unique perspective, by a unique author team, and you won\'t find this kind of insight in any other text on the market. We think you\'re going to love it! This textbook has been used in classes at: Ball State University, Emerson College, Florida Institute of Technology, Grand Valley State University, Johnson County Community College, Manchester Business School, McLennan Community College, Michigan State University, North Hennepin Community College, Pierce College, Rochester Institute of Technology, Saint Louis University, Salem State College, South Dakota State University, Texas State University, Texas Tech University, University of New Hampshire, University of North Carolina, University of Notre Dame, University of South Florida, Virginia Tech, Western Kentucky University.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 23.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/launch-advertising-and-promotion-in-real-time\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2009.\nISBN-13 ô CSV: 9780982043028.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Marketing.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Michael Solomon - Author / Lisa Duke Cornell - Author / Amit Nizan - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9780982043028.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(19,'OTL-24','GT-ISBN9781944325039','Linear Algebra',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This text covers the standard material for a US undergraduate first course: linear systems and Gauss\'s Method, vector spaces, linear maps and matrices, determinants, and eigenvectors and eigenvalues, as well as additional topics such as introductions to various applications. It has extensive exercise sets with worked answers to all exercises, including proofs, beamer slides for classroom use, and a lab manual for computer work. The approach is developmental. Although everything is proved, it introduces the material with a great deal of motivation, many computational examples, and exercises that range from routine verifications to a few challenges. Ancillary materials are available at the publisher link.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 24.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/linear-algebra\nPublisher ô CSV: Jim Hefferon.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781944325039.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Algebra.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Jim Hefferon - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781944325039.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(20,'OTL-28','GT-ISBN9781453313282','Microeconomics: Theory Through Applications',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'Russell Cooper and Andrew John have written an economics text aimed directly at students from its very inception. You\'re thinking, ”Yeah, sure. I\'ve heard that before.“ This textbook, Microeconomics: Theory Through Applications, centers around student needs and expectations through two premises: … Students are motivated to study economics if they see that it relates to their own lives. … Students learn best from an inductive approach, in which they are first confronted with a problem, and then led through the process of solving that problem. Many books claim to present economics in a way that is digestible for students; Russell and Andrew have truly created one from scratch. This textbook will assist you in increasing students\' economic literacy both by developing their aptitude for economic thinking and by presenting key insights about economics that every educated individual should know. How? Russell and Andrew have done three things in this text to accomplish that goal: 1. Applications Ahead of Theory: They present all the theory that is standard in Principles books. But by beginning with applications, students get to learn why this theory is needed. The authors take the kind of material that other authors put in ”applications boxes“ and place it at the heart of their book. Each chapter is built around a particular business or policy application, such as minimum wages, the stock exchange, and auctions. Why take this approach? Traditional courses focus too much on abstract theory relative to the interests and capabilities of the average undergraduate. Students are rarely engaged and the formal theory is never integrated into the way students think about economic issues. And traditional books are organized around theoretical constructs that mean nothing to students. The authors\' applications-first approach ensures that students will not see chapters with titles like ”Cost Functions“ or ”Short-Run Fluctuations“. They introduce tools and ideas as and when they are needed. Each chapter is designed with two goals. First, the application upon which the chapter is built provides a ”hook“ that gets students\' attention. Second, the application is a suitable vehicle a vehicle for teaching the principles of economics. 2. Learning through Repetition: Important tools appear over and over again, allowing students to learn from repetition and to see how one framework can be useful in many different contexts. Each piece of economic theory in this text is first introduced and explained in the context of a specific application. Most are re-used in other chapters, so students see them in action on multiple occasions. As students progress through the book, they accumulate a set of techniques and ideas. These are collected separately in a ”toolkit“ that provides students with an easy reference and also gives them a condensed summary of economic principles for examination preparation. 3. A Student\'s Table of Contents vs. An Instructor\'s Table of Contents: There is no further proof that Russell and Andrew have created a book aimed specifically at educating students about economics than their two tables of contents. The Student\'s Table of Contents speaks to students, piquing their interest to involve them in the economics, and a Instructor\'s Table of Contents with the economics to better help you organize your teaching—and frankly, you don\'t need to get excited by economics, you already are.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 28.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/microeconomics-theory-through-applications\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: 9781453313282.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Economics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Russell Cooper - Author / Andrew John - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453313282.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(21,'OTL-29','GT-ISBN9780982043080','Money and Banking',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'The financial crisis of 2007-8 has already revolutionized institutions, markets, and regulation. Wright\'s Money and Banking V 2.0 captures those revolutionary changes and packages them in a way that engages undergraduates enrolled in Money and Banking and Financial Institutions and Markets courses. Minimal mathematics, accessible language, and a student-oriented tone ease readers into complex subjects like money, interest rates, banking, asymmetric information, financial crises and regulation, monetary policy, monetary theory, and other standard topics. Numerous short cases, called \"Stop and Think\" boxes, promote internalization over memorization. Exercise drills ensure basic skills competency where appropriate. Short, snappy sections that begin with a framing question enhance readability and encourage assignment completion. The 2.0 version of this text boasts substantive revisions (additions, deletions, rearrangements) of almost every chapter based on the suggestions of many Money and Banking instructors. Some specific highlights are: Chapter 11 now contains enhanced descriptions of recent regulatory changes, including Dodd-Frank, Chapter 12 is an entirely new chapter on derivatives covering forwards, futures, options, and swaps that also including comprehensive treatment of the causes and consequences of financial crises, and Chapter 14 has updated discussions of the Federal Reserve\'s monetary policy tools, including paying interest on reserves, and the structure and leadership of the European Central Bank. Recent financial turmoil has increased student interest in the financial system but simultaneously threatens to create false impressions and negative attitudes. This up-to-date text by a dynamic, young author encourages students to critique the financial system without rejecting its many positive attributes. Peruse the book online now to see for yourself if this book fits the needs of your course and students. This textbook has been used in classes at:Augustana College, Central Michigan University, Florida State University, Lyndon State College, Princeton University, Rutgers University, University of Southern Maine, Western Oregon University., Westminster College.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 29.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/money-and-banking\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9780982043080.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Business - Accounting.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Robert E. Wright - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9780982043080.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(22,'OTL-30','GT-ISBN9781946135155','Organizational Behavior',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'Organizational Behavior bridges the gap between theory and practice with a distinct \"experiential\" approach. On average, a worker in the USA will change jobs 10 times in 20 years. In order to succeed in this type of career situation, individuals need to be armed with the tools necessary to be life-long learners. To that end, this book is not be about giving students all the answers to every situation they may encounter when they start their first job or as they continue up the career ladder. Instead, this book gives students the vocabulary, framework, and critical thinking skills necessary to diagnose situations, ask tough questions, evaluate the answers received, and to act in an effective and ethical manner regardless of situational characteristics. Often, students taking OB either do not understand how important knowledge of OB can be to their professional careers, or they DO understand and they want to put that knowledge into practice. Organizational Behavior takes a more experiential angle to the material to meet both of those needs. The experiential approach can be incorporated in the classroom primarily through the \"OB Toolbox.\" This feature brings life to the concepts and allows students to not only see how the OB theories unfold, but to practice them, as well.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 30.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/organizational-behavior\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: 9781946135155.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Human Resources.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781946135155.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(23,'OTL-31','GT-ISBN9780982361863','Personal Finance',NULL,'Tiếng Anh',NULL,2009,NULL,NULL,NULL,NULL,1,0,'Personal Finance by Rachel Siegel and Carol Yacht is a comprehensive Personal Finance text which includes a wide range of pedagogical aids to keep students engaged and instructors on track. This book is arranged by learning objectives. The headings, summaries, reviews, and problems all link together via the learning objectives. This helps instructors to teach what they want, and to assign the problems that correspond to the learning objectives covered in class. Personal Finance includes personal finance planning problems with links to solutions, and personal application exercises, with links to their associated worksheet(s) or spreadsheet(s). In addition, the text boasts a large number of links to videos, podcasts, experts\' tips or blogs, and magazine articles to illustrate the practical applications for concepts covered in the text. Rachel would love to hear from you. If you have questions about teaching with her book, comments about teaching Personal Finance, or just feedback, feel free to email her at rachelsiegelcfa@hughes.net. This textbook has been used in classes at: Miami University.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 31.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/personal-finance\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2009.\nISBN-13 ô CSV: 9780982361863.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Finance.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Rachel Siegel - Author / Carol Yacht - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9780982361863.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(24,'OTL-32','GT-ISBN9781946135162','Principles of Economics',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This book is intended for a two-semester course in Economics taught out of the social sciences or business school. Principles of Economics aims to teach considerable range and depth of Economic concepts through an approachable style and methodology. The authors take a three-pronged approach to every chapter: The concept is covered with a “Heads Up” to ward off confusion, a real-world application for that concept, and a “You Try It” section to make sure students are staying on top of the concept.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 32.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/principles-of-economics\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781946135162.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Economics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781946135162.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(25,'OTL-33','GT-ISBN9781946135179','Principles of Macroeconomics',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Recognizing that a course in economics may seem daunting to some students, we have tried to make the writing clear and engaging. Clarity comes in part from the intuitive presentation style, but we have also integrated a number of pedagogical features that we believe make learning economic concepts and principles easier and more fun. These features are very student-focused. The chapters themselves are written using a “modular” format. In particular, chapters generally consist of three main content sections that break down a particular topic into manageable parts. Each content section contains not only an exposition of the material at hand but also learning objectives, summaries, examples, and problems. Each chapter is introduced with a story to motivate the material and each chapter ends with a wrap-up and additional problems. Our goal is to encourage active learning by including many examples and many problems of different types. A tour of the features available for each chapter may give a better sense of what we mean: Start Up—Chapter introductions set the stage for each chapter with an example that we hope will motivate readers to study the material that follows. These essays, on topics such as the value of a college degree in the labor market or how policy makers reacted to a particular economic recession, lend themselves to the type of analysis explained in the chapter. We often refer to these examples later in the text to demonstrate the link between theory and reality. Learning Objectives—These succinct statements are guides to the content of each section. Instructors can use them as a snapshot of the important points of the section. After completing the section, students can return to the learning objectives to check if they have mastered the material.Heads Up!—These notes throughout the text warn of common errors and explain how to avoid making them. After our combined teaching experience of more than fifty years, we have seen the same mistakes made by many students. This feature provides additional clarification and shows students how to navigate possibly treacherous waters. Key Takeaways—These statements review the main points covered in each content section. Key Terms—Defined within the text, students can review them in context, a process that enhances learning. Try It! questions—These problems, which appear at the end of each content section and which are answered completely in the text, give students the opportunity to be active learners. They are designed to give students a clear signal as to whether they understand the material before they go on to the next topic. Cases in Point—These essays included at the end of each content section illustrate the influence of economic forces on real issues and real people. Unlike other texts that use boxed features to present interesting new material or newspaper articles, we have written each case ourselves to integrate them more clearly with the rest of the text. Summary—In a few paragraphs, the information presented in the chapter is pulled together in a way that allows for a quick review of the material.End-of-chapter concept and numerical problems—These are bountiful and are intended to check understanding, to promote discussion of the issues raised in the chapter, and to engage students in critical thinking about the material. Included are not only general review questions to test basic understanding but also examples drawn from the news and from results of economics research. Some have students working with real-world data.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 33.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/principles-of-macroeconomics\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781946135179.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Economics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781946135179.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(26,'OTL-34','GT-ISBN9781946135186','Principles of Management',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Principles of Management teaches management principles to tomorrow\'s business leaders by weaving three threads through every chapter: strategy, entrepreneurship and active leadership. Strategic — All business school teachings have some orientation toward performance and strategy and are concerned with making choices that lead to high performance. Principles of Management will frame performance using the notion of the triple bottom-line — the idea that economic performance allows individuals and organizations to perform positively in social and environmental ways as well. The triple bottom line is financial, social, and environmental performance. It is important for all students to understand the interdependence of these three facets of organizational performance. The Entrepreneurial Manager — While the \"General Management\" course at Harvard Business School was historically one of its most popular and impactful courses (pioneered in the 1960s by Joe Bower), recent Harvard MBAs did not see themselves as \"general managers.\" This course was relabeled \"The Entrepreneurial Manager\" in 2006, and has regained its title as one of the most popular courses. This reflects and underlying and growing trend that students, including the undergraduates this book targets, can see themselves as entrepreneurs and active change agents, but not just as managers. By starting fresh with an entrepreneurial/change management orientation, this text provides an exciting perspective on the art of management that students can relate to. At the same time, this perspective is as relevant to existing for-profit organizations (in the form intrapreneurship) as it is to not-for-profits and new entrepreneurial ventures. Active Leadership — Starting with the opening chapter, Principles of Management shows students how leaders and leadership are essential to personal and organizational effectiveness and effective organizational change. Students are increasingly active as leaders at an early age, and are sometimes painfully aware of the leadership failings they see in public and private organizations. It is the leader and leadership that combine the principles of management (the artist\'s palette, tools, and techniques) to create the art of management. This book\'s modular format easily maps to a POLC (Planning, Organizing, Leading, and Controlling) course organization, which was created by Henri Fayol (General and industrial management (1949). London: Pitman Publishing company), and suits the needs of both undergraduate and graduate course in Principles of Management. This textbook has been used in classes at: College of Alameda, Columbia Basin College, Flagler College, Johnson County Community College, Pasadena City College, Penn State University, Renton Technical College, San Diego Mesa College, Sierra College, Yuba College.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 34.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/principles-of-management\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781946135186.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Management.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781946135186.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(27,'OTL-35','GT-OTL000035','Programming Languages: Application and Interpretation - Version Second Edition',NULL,'Tiếng Anh',NULL,2007,NULL,NULL,NULL,NULL,1,0,'Unlike some other textbooks, this one does not follow a top-down narrative. Rather it has the flow of a conversation, with backtracking. We will often build up programs incrementally, just as a pair of programmers would. We will include mistakes, not because I don\'t know the answer, but because this is the best way for you to learn. Including mistakes makes it impossible for you to read passively: you must instead engage with the material, because you can never be sure of the veracity of what you\'re reading. At the end, you\'ll always get to the right answer. However, this non-linear path is more frustrating in the short term (you will often be tempted to say, “Just tell me the answer, already!”), and it makes the book a poor reference guide (you can\'t open up to a random page and be sure what it says is correct). However, that feeling of frustration is the sensation of learning. I don\'t know of a way around it. At various points you will encounter this: ExerciseThis is an exercise. Do try it. This is a traditional textbook exercise. It\'s something you need to do on your own. If you\'re using this book as part of a course, this may very well have been assigned as homework. In contrast, you will also find exercise-like questions that look like this: Do Now!There\'s an activity here! Do you see it? When you get to one of these, stop. Read, think, and formulate an answer before you proceed. You must do this because this is actually an exercise, but the answer is already in the book—most often in the text immediately following (i.e., in the part you\'re reading right now)—or is something you can determine for yourself by running a program. If you just read on, you\'ll see the answer without having thought about it (or not see it at all, if the instructions are to run a program), so you will get to neither (a) test your knowledge, nor (b) improve your intuitions. In other words, these are additional, explicit attempts to encourage active learning. Ultimately, however, I can only encourage it; it\'s up to you to practice it. The main programming language used in this book is Racket. Like with all operating systems, however, Racket actually supports a host of programming languages, so you must tell Racket which language you\'re programming in. This textbook has been used in classes at: Brown University, Cal Poly, Columbus State University, Northeastern University, NYU, Reed College, UC-San Diego, UC-Santa Cruz, University of Rhode Island, University of Utah, Westmont College, Williams College, Worcester Polytechnic Institute.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 35.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/programming-languages-application-and-interpretation\nPublisher ô CSV: Brown University.\nCopyright Year ô CSV: 2007.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: 0073523399.\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Shriram Krishnamurthi - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:01:00',NULL),(28,'OTL-36','GT-ISBN9781946135216','Project Management from Simple to Complex',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'In a world that is becoming more virtual, more global, and more complex, the project manager\'s ability to function in this environment becomes critical to the success of the project. Project Management from Simple to Complex explores project management within this complex, virtual, and global environment. This is not a standard textbook that was adapted to the new publishing paradigm; it was designed from the beginning to utilize its capabilities. The book is written in collaboration by an expert in Project Management and an expert in writing instructional textbooks and using technology for communicating online to create a unique learning environment that prepares students to manage projects in a global, multicultural, and online environment. Project Management from Simple to Complex features a new model for managing projects, as well as, exploration into the personal dynamics of project management and the role those dynamics play in project outcomes.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 36.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/project-management-from-simple-to-complex\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781946135216.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Management.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781946135216.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(29,'OTL-37','GT-ISBN9780982361801','Risk Management for Enterprises and Individuals',NULL,'Tiếng Anh',NULL,2009,NULL,NULL,NULL,NULL,1,0,'This book is intended for the Risk Management and Insurance course where Risk Management is emphasized. When we think of large risks, we often think in terms of natural hazards such as hurricanes, earthquakes or tornados. Perhaps man-made disasters come to mind such as the terrorist attacks in the U.S. on September 11, 2001. Typically we have overlooked financial crises, such as the credit crisis of 2008. However, these types of man-made disasters have the potential to devastate the global marketplace. Losses in multiple trillions of dollars and in much human suffering and insecurity are already being totaled, and the global financial markets are collapsing as never before seen. We can attribute the 2008 collapse to financially risky behavior of a magnitude never before experienced. The 2008 U.S. credit markets were a financial house of cards. A basic lack of risk management (and regulators\' inattention or inability to control these overt failures) lay at the heart of the global credit crisis. This crisis started with lack of improperly underwritten mortgages and excessive debt. Companies depend on loans and lines of credit to conduct their routine business. If such credit lines dry up, production slows down and brings the global economy to the brink of deep recession—or even depression. The snowballing effect of this failure to manage the risk associated with providing mortgage loans to unqualified home buyers have been profound, indeed. When the mortgages failed because of greater risk- taking on the Street, the entire house of cards collapsed. Probably no other risk-related event has had, and will continue to have, as profound an impact world wide as this risk management failure. How was risk in this situation so badly managed? What could firms and individuals have done to protect themselves? How can government measure such risks (beforehand) to regulate and control them? These and other questions come to mind when we contemplate the consequences of this risk management fiasco. Standard risk management practice would have identified sub-prime mortgages and their bundling into mortgage-backed-securities as high risk. People would have avoided these investments or would have put enough money into reserve to be able to withstand defaults. This did not happen. Accordingly, this book may represent one of the most critical topics of study that the student of the 21st century could ever undertake. Risk management will be a major focal point of business and societal decision—making in the 21st century. A separate focused field of study, it draws on core knowledge bases from law, engineering, finance, economics, medicine, psychology, accounting, mathematics, statistics and other fields to create a holistic decision-making framework that is sustainable and value- enhancing. This is the subject of this book.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 37.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/risk-management-for-enterprises-and-individuals\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2009.\nISBN-13 ô CSV: 9780982361801.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Management.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Etti Baranoff - Author / Patrick Lee Brockett - Author / Yehuda Kahane - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9780982361801.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(30,'OTL-38','GT-OTL000038','Introduction to Sociology: Understanding and Changing the Social World',NULL,'Tiếng Anh',NULL,2024,NULL,NULL,NULL,NULL,1,0,'It is no accident that many sociology instructors and students are first drawn to sociology because they want to learn a body of knowledge that can help them make a difference in the world at large. This text is designed for this audience and aims to present not only a sociological understanding of society but also a sociological perspective on how to improve society. In this regard, the text responds to the enthusiasm that “public sociology” has generated after serving as the theme of the 2004 annual meeting of the American Sociological Association, and it demonstrates sociology’s relevance for today’s students who want to make a difference in the world beyond them.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 38.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/sociology-understanding-and-changing-the-social-world\nPublisher ô CSV: LibreTexts.\nCopyright Year ô CSV: 2024.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Sociology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:01:00',NULL),(31,'OTL-39','GT-ISBN9781453314128','Sustainability, Innovation, and Entrepreneurship',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'This book is suited for the Entrepreneurship or Innovation course with an emphasis on Sustainability or for a course devoted entirely to Sustainability. What are the trends and forces underlying the changing character of the business-environment relationship? How they are creating significant entrepreneurial opportunities for individuals and companies? Around the world, the movement toward ”sustainable development“ has caused many firms to adopt policies and practices that reflect what is sometimes called a ”sustainable business“ or ”triple bottom line“ approach. ”Triple bottom line“ refers to the demonstration of strong performance across economic, social, and environmental indicators. Those measures serve as indicators of fiduciary responsibility to a growing set of concerned investors and therefore can help ensure access to capital. They also enable innovators to lower costs, create strategic differentiation, reduce risk, and position themselves for competitive advantage over rivals less attuned to trends. The deep roots of sustainability thinking are now evident in widespread and increasingly visible activities worldwide, and Sustainability, Innovation, and Entrepreneurship explores this evolution; its necessity, its implications and its progression.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 39.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/sustainability-innovation-and-entrepreneurship\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: 9781453314128.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Management.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Andrea Larson - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453314128.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(32,'OTL-40','GT-ISBN9781453311097','The Basics of General, Organic, and Biological Chemistry',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'The Basics of General, Organic, and Biological Chemistry by David W. Ball, John W. Hill, and Rhonda J. Scott is for the one-semester General, Organic and Biological Chemistry course. The authors designed this textbook from the ground up to meet the needs of a one-semester course. It is 20 chapters in length and approximately 350-400 pages; just the right breadth and depth for instructors to teach and students to grasp. In addition, The Basics of General, Organic, and Biological Chemistry is written not by one chemist, but THREE chemistry professors with specific, complimentary research and teaching areas. David W. Ball\'s specialty is physical chemistry, John W. Hill\'s is organic chemistry, and finally, Rhonda J. Scott\'s background is in enzyme and peptide chemistry. These three authors have the expertise to identify and present only the most important material for students to learn in the GOB Chemistry course. These experienced authors have ensured their text has ample in-text examples, and ”Test Yourself“ questions following the examples so students can immediately check their comprehension. The end-of-chapter exercises will be paired, with one answered in the back of the text so homework can easily be assigned and self-checked. The Basics of General, Organic, and Biological Chemistry by David W. Ball, John W. Hill, and Rhonda J. Scott is the right text for you and your students if you are looking for a GOB textbook with just the right amount of coverage without overdoing the concepts and overwhelming your students.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 40.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-basics-of-general-organic-and-biological-chemistry\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: 9781453311097.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Chemistry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: David W Ball - Author / John W Hill - Author / Rhonda J Scott - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781453311097.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(33,'OTL-42','GT-ISBN9781936126002','The Power of Selling',NULL,'Tiếng Anh',NULL,2010,NULL,NULL,NULL,NULL,1,0,'The Power of Selling is the perfect textbook to teach students about the proven process of selling. More important, it teaches students how to apply the tenets of selling to how to sell themselves and get the job they want, with the same process professional sales people learn (or brush up) on their own selling skills. What makes someone successful in sales? Are great sales people born or made? Is there one magic selling process, or does the process change based on the business‚ or the customer? How can the selling process really come alive for students in the classroom? How do students learn how to sell for life, not just for a course? The Power of Selling by Kim Richmond answers these questions and makes the principles of selling come alive. Kim looks at the topic of selling through a different lens, and provides inspiration and ideas. The Power of Selling provides an exciting and interactive experience for both professors and students through the use of 4 unique elements: 1. Content The content is based on the core selling tenets so instructors will find the familiar principles of selling. In addition, the impact of Sales 2.0 is addressed at every stage including how to use interactive tools such as Twitter, LinkedIn, Facebook, blogs, and wikis effectively. 2. Selling U: The last section of each chapter is called Selling U. It applies the concepts covered in the chapter to a student\'s job search. Selling U topics include how to think about yourself as a brand, how to create a powerful cover letter and resume, how to create your personal elevator pitch, how to use networking and informational interviews to get the word out about your brand, how to prepare and dress for an interview, and how to negotiate and accept the right job offer. What makes The Power of Selling different is that Selling U is integrated into every chapter, which makes this text the ultimate guide to selling yourself. 3. Video Resources:Videos are used throughout the book. Additional videos that are not included in the text are available for instructor use. Here are videos that are available: … Video Ride-alongs — One of the best ways to learn about sales is by going on ride-alongs. So every chapter starts with an exclusive feature called a Video Ride-along. These short videos feature seven different sales professionals — one that starts each chapter. Each one talks about how he or she applies one of the key concepts covered in the chapter in their job. These videos are designed to be ”virtual ride-alongs“ so the students can actually feel as though they are getting insights first hand from selling professionals. … Over 50 videos are included featuring the sales professionals who are highlighted in the Video Ride-alongs. About half of the videos are used in the textbook. The balance are available for instructor use. Several are included in Video Learning Segments (see below). These videos are excellent resources for use in the classroom, exercises, and assignments. … Video Learning Segments In addition to the traditional supplements of Instructor Manual, PowerPoints, and Test Bank, there are also Video Learning Segments. These are PowerPoint slides embedded with videos designed to supplement the course PowerPoints and focus on one concept, like an ethical dilemma, pre-call preparation, or effective presentations, how to use email effectively. Each segment includes slides, videos, discussion questions, or exercises. 4. The Power of Selling LinkedIn Group. This group was created on LinkedIn.com expressly as a resource for the faculty and students who use this textbook. The group includes sales professionals from across the country and from different industries. This is a great tool for faculty and students alike to network, participate in discussions, ask questions, and connect with ”real world“ selling professionals. Kim Richmond\'s The Power of Selling is a fresh, interactive, and applied textbook intended for all introductory and sales, selling and salesmanship courses. If you\'re ready to prepare your ”students of selling“ for all that lies ahead in their professional career—you\'re ready for this book. Check it out.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 42.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-power-of-selling\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2010.\nISBN-13 ô CSV: 9781936126002.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Business - Management.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Kimberly Richmond - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781936126002.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(34,'OTL-43','GT-ISBN9781491939369','Think Python: How to Think Like a Computer Scientist - 2e',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Think Python is a concise introduction to software design using the Python programming language. Intended for people with no programming experience, this book starts with the most basic concepts and gradually adds new material. Some of the ideas students find most challenging, like recursion and object-oriented programming, are divided into a sequence of smaller steps and introduced over the course of several chapters. This textbook has been used in classes at Bard College, Olin College of Engineering, University of California, Santa Barbara, University of Maine, University of Northern Colorado.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 43.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/think-python-how-to-think-like-a-computer-scientist\nPublisher ô CSV: Green Tea Press.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781491939369.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science - Programming Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Allen B. Downey - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781491939369.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(35,'OTL-45','GT-ISBN9781602351844','Writing Spaces: Readings on Writing Vol. I',NULL,'Tiếng Anh',NULL,2010,NULL,NULL,NULL,NULL,1,0,'Volumes in Writing Spaces: Readings on Writing offer multiple perspectives on a wide-range of topics about writing, much like the modelmade famous by Wendy Bishop\'s “The Subject Is . . .” series. In eachchapter, authors present their unique views, insights, and strategies forwriting by addressing the undergraduate reader directly. Drawing ontheir own experiences, these teachers-as-writers invite students to joinin the larger conversation about developing nearly every aspect of thecraft of writing. Consequently, each essay functions as a standalonetext that can easily complement other selected readings in writing orwriting-intensive courses across the disciplines at any level. Topics in Volume 1 of the series include academic writing, how to interpret writing assignments, motives for writing, rhetorical analysis, revision, invention, writing centers, argumentation, narrative, reflective writing, Wikipedia, patchwriting, collaboration, and genres.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 45.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/writing-spaces-readings-on-writing-vol-i\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2010.\nISBN-13 ô CSV: 9781602351844.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Charlie Lowe - Author / Pavel Zemliansky - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781602351844.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(36,'OTL-46','GT-ISBN9781453311578','Business Information Systems: Design an App for That',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'We set out to design an introductory course governed by four themes: Give students a good idea of what a career in MIS looks like by doing MIS. Enhance the professionalism of deliverables by teaching design and usability concepts. Promote creativity by assigning projects that demand it. Teach students about cloud computing by having them do cloud computing. Students in an introductory Management Information Systems (MIS) course often ask what a career in MIS looks like. Lacking a clear vision, they make their own assumptions. Often they assume the career involves programming with little human interaction. That MIS is a technical field could not be further from the truth. MIS job descriptions typically require candidates to be able to collaborate, communicate, analyze needs and gather requirements. They also list the need for excellent written and communication skills. In other words, MIS workers are constantly interacting with other people both inside and outside the organization. They are coming up with creative solutions to business problems. This course is designed to help students get a feel for what a career in MIS would be like. Our students report that they learn more about information systems from their internships than from their IS courses. Consequently, we designed a course that looks very much like an internship—an introduction to the field followed by a substantial project. Chapter 1 begins by introducing the information systems landscape. Here we discuss all the usual suspects: the information systems triangle, the systems development life cycle, transaction systems (ERP, SCM, CRM), collaboration systems, and business intelligence systems. Other aspects of the landscape such as usability, outsourcing, database concepts and so forth are introduced throughout chapter in Chapter 2 where they fit in naturally with the flow of the project. Chapter 2 is the substantial project which runs over a number of chapters. Over the course of the semester, students plan, build, and develop a proposal for an iPhone application. They develop a very realistic mockup. They also build a website to help market and support the app. Students are engaged because the project is fun and feels real. However, they are simultaneously learning business concepts and MIS skills. Prior to the existence of this course, we were only able to give such an interesting project at the senior level. Now, even as freshmen, students have a real experience of MIS in operation. A by product of creating an engaging course is increased enrollment in the MIS major. Even students who have never heard of MIS become excited about the major and either switch majors or add it as a double major or minor. Many other books have students study tools and then do a case. By contrast, most of this book is a case. Much like the real world, we introduce tools when needed, and only to the extent needed, to get at each part of the case.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 46.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/business-information-systems-design-an-app-for-that\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: 9781453311578.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science - Information Systems.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Raymond Frost - Author / Jacqueline Pike - Author / Lauren Kenyo - Author / Sarah Pels - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453311578.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(37,'OTL-47','GT-ISBN9780982043097','Introduction to Economic Analysis',NULL,'Tiếng Anh',NULL,2009,NULL,NULL,NULL,NULL,1,0,'This book presents standard intermediate microeconomics material and some material that, in the authors\' view, ought to be standard but is not. Introductory economics material is integrated. Standard mathematical tools, including calculus, are used throughout. The book easily serves as an intermediate microeconomics text, and can be used for a relatively sophisticated undergraduate who has not taken a basic university course in economics. The focus of this book is on the conceptual tools and not on fluff. As such, it reflects the approach actually adopted by the majority of economists for understanding economic activity. There are lots of models and equations, and no pictures of economists ;-) Economic analysis is used in many situations. When British Petroleum sets the price for Alaskan crude oil, it uses an estimated demand model, both for gasoline consumers and also for the refineries to which BP sells. Economic analysis was used by experts in the antitrust suit brought by the U.S. Department of Justice both to understand Microsoft\'s incentive to foreclose (eliminate from the market) rival Netscape and consumer behavior in the face of alleged foreclosure. Stock market analysts use economic models to forecast the profits of companies to predict the price of their stocks. When the government forecasts the budget deficit or considers a change in environmental regulations, it uses economic models. This book presents the building blocks of the models in common use by an army of economists thousands of times per day. This book, plus econometrics, provides most of the economic analysis tools to take upper division economics courses of any type.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 47.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-economic-analysis\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2009.\nISBN-13 ô CSV: 9780982043097.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Economics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Preston McAfee - Author / Tracy R Lewis - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9780982043097.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(38,'OTL-48','GT-ISBN9781946135131','Introduction to Psychology',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'When you teach Introduction to Psychology, do you find it difficult — much harder than teaching classes in statistics or research methods? Do you easily give a lecture on the sympathetic nervous system, a lecture on Piaget, and a lecture on social cognition, but struggle with linking these topics together for the student? Do you feel like you are presenting a laundry list of research findings rather than an integrated set of principles and knowledge? Have you wondered how to ensure your course is relevant to your students? Introduction to Psychology utilizes the dual theme of behavior and empiricism to make psychology relevant to intro students. The author wrote this book to help students organize their thinking about psychology at a conceptual level. Five or ten years from now, he does not expect his students to remember the details of most of what he teaches them. However, he does hope that they will remember that psychology matters because it helps us understand behavior and that our knowledge of psychology is based on empirical study. This book is designed to facilitate these learning outcomes, and he has used three techniques to help focus students on behavior: Chapter Openers: Each chapter opens showcasing an interesting real world example of people who dealing with behavioral questions and who can use psychology to help them answer them. The opener is designed to draw the student into the chapter and create an interesting in learning about the topic. Psychology in Everyday Life: Each chapter contains one or two features designed to link the principles from the chapter to real-world applications in business, environment, health, law, learning, and other relevant domains. For instance, the application in Chapter 7 on Development, ”What makes good parents“ applies the concepts of parenting styles in a mini-handbook about parenting, and the application in Chapter 3 is about the difficulties that left-handed people face performing everyday tasks in a right-handed world. Research Foci: Introduction to Psychology emphasizes empiricism throughout, but without making it a distraction from the main story line. Each chapter presents two close-ups on research — well articulated and specific examples of research within the content area, each including a summary of the hypotheses, methods, results, and interpretations. This feature provides a continuous thread that reminds students of the importance of empirical research. The research foci also emphasize the fact that findings are not always predictable ahead of time (dispelling the myth of hindsight bias), and also help students understand how research really works. The author\'s focus on behavior and empiricism has produced, Introduction to Psychology, a text that is better organized, has fewer chapters, and is somewhat shorter than many of the leading books. Now, you don\'t have to believe us. Check the book out online or order your desk copy today.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 48.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-psychology\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781946135131.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Psychology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781946135131.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(39,'OTL-50','GT-ISBN9781946135193','Principles of Marketing',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Principles of Marketing teaches the experience and process of actually doing marketing – not just the vocabulary. It carries five dominant themes throughout in order to expose students to marketing in today\'s environment: Service dominant logic — This textbook employs the term \"offering\" instead of the more traditional First \"P\" — product. That is because consumers don\'t sacrifice value when alternating between a product and a service. They are evaluating the entire experience, whether they interact with a product, a service, or a combination. So the fundamental focus is providing value throughout the value chain, whether that value chain encompasses a product, service, or both. Sustainability — Increasingly, companies are interested in the impact they are having on their local community as well as the overall environment. This is often referred to as the \"triple bottom line\" of financial, social, and environment performance. Ethics and social responsibility — Following on the sustainability notion is the broader importance of ethics and social responsibility in creating successful organizations. The authors make consistent references to ethical situations throughout chapter coverage, and end of chapter material in most chapters will encompass ethical situations. Global coverage — the authors deliberately entitled Chapter 1 \"What is Marketing?\" Whether it is today\'s price of gasoline, the current U.S. presidential race, or Midwestern U.S. farming, almost every industry and company needs strong global awareness. And today\'s marketing professionals must understand the world in which they and their companies operate. Metrics — Firms today have the potential to gather more information than ever before about their current and potential customers. That information gathering can be costly, but it can also be very revealing. With the potential to capture so much more detail about micro transactions, firms should now be more able to answer \"well, what this marketing strategy really worth it?\" And \"what is the marketing ROI?\" And finally, \"what is this customer or set of customers worth to us over their lifetime?\"\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 50.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/principles-of-marketing\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781946135193.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Marketing.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781946135193.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(40,'OTL-51','GT-ISBN9781936126583','The Legal and Ethical Environment of Business',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'Terence Lau & Lisa Johnson\'s The Legal and Ethical Environment of Business is a book for today\'s student, who expects learning to be comprised not only of substance, but also of interactive exercises and multimedia. This book streamlines the presentation of material to ensure that every page is relevant, engaging, and interesting to undergraduate business students, without losing the depth of coverage that they need to be successful in their academic journeys and in their professional careers. This is not Legal Environment of Business (LEB) ”light.“ Rather, this is LEB without risk of students\' eyes glazing over in boredom or from lack of comprehension. This is LEB presented in an exciting way, where every page is interesting to students and relevant to real life. The authors recognize that the sheer volume of information to be covered in a LEB course makes it one of the more challenging courses for the business undergraduate. Not only do typical LEB texts read like the first year curriculum at law school, but also the LEB course is grounded in the humanities, which can make the subject even more demanding for students who are also taking statistics, economics, finance, and accounting. Each chapter contains not only substantive law, but also illustrative videos, interactive exercises for hands-on learning, and discussion questions for critical thought. Additionally, each chapter presents ”A Question of Ethics“ section, which contains real world ethical dilemmas relevant to the topic under study. These videos, exercises, discussion questions, and ethics sections all provide opportunities for students to apply concepts that they are learning in the context of relevant LEB topics that shape or restrain actual decision-makers\' actions. It\'s real world practice in the safety of the classroom environment. Lau & Johnson\'s The Legal and Ethical Environment of Business is a textbook that students will enjoy reading. This will encourage them to come to class prepared, and free you to teach the kind of course you want to teach. Request a desk copy and see for yourself.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 51.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-legal-and-ethical-environment-of-business\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: 9781936126583.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Law - Civil Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Terence Lau - Author / Lisa Johnson - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781936126583.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:00:00',NULL),(41,'OTL-52','GT-OTL000052','Whitman Calculus',NULL,'Tiếng Anh',NULL,2010,NULL,NULL,NULL,NULL,1,0,'An introductory level single variable calculus book, covering standard topics in differential and integral calculus, and infinite series. Late transcendentals and multivariable versions are also available. This textbook has been used in classes at: Boise State University, Claremont McKenna College, University of Minnesota, University of Puget Sound, Western Connecticut State University, Whitman College.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 52.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/whitman-calculus\nPublisher ô CSV: David Guichard.\nCopyright Year ô CSV: 2010.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: David Guichard - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:31','2026-05-06 09:01:00',NULL),(42,'OTL-53','GT-ISBN9781946135285','Writing for Success',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Writing for Success is a text that provides instruction in steps, builds writing, reading, and critical thinking, and combines comprehensive grammar review with an introduction to paragraph writing and composition. Beginning with the sentence and its essential elements, this book addresses each concept with clear, concise and effective examples that are immediately reinforced with exercises and opportunities to demonstrate, and reinforce, learning. Each chapter allows your students to demonstrate mastery of the principles of quality writing. With its incremental approach, it can address a range of writing levels and abilities, helping each student in your course prepare for their next writing or university course. Constant reinforcement is provided through examples and exercises, and the text involves students in the learning process through reading, problem-solving, practicing, listening, and experiencing the writing process. Each chapter also has integrated examples that unify the discussion and form a common, easy-to-understand basis for discussion and exploration. This will put your students at ease, and allow for greater absorption of the material. Tips for effective writing are included in every chapter, as well. Thought-provoking scenarios provide challenges and opportunities for collaboration and interaction. These exercises are especially helpful if you incorporate group work in your course. Clear exercises teach sentence and paragraph writing skills that lead to common English composition and research essays. Features: Exercises are integrated in each segment. Each concept is immediately reinforced as soon as it is introduced to keep students on track. Exercises are designed to facilitate interaction and collaboration. This allows for peer-peer engagement, development of interpersonal skills, and promotion of critical thinking skills. Exercises that involve self-editing and collaborative writing are featured. This feature develops and promotes student interest in the areas and content. There are clear internal summaries and effective displays of information. This contributes to ease of access to information and increases the ability of your students to locate desired content. Rule explanations are simplified with clear, relevant, and theme-based examples. This feature provides context that will facilitate learning and increase knowledge retention. There is an obvious structure to the chapter and segment level. This allows for easy adaptation to your existing and changing course needs or assessment outcomes.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 53.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/writing-for-success\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781946135285.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781946135285.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(43,'OTL-54','GT-OTL000054','An Introduction to Formal Logic',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'forall x is an introduction to sentential logic and first-order predicate logic with identity, logical systems that significantly influenced twentieth-century analytic philosophy. After working through the material in this book, a student should be able to understand most quantified expressions that arise in their philosophical reading. This books treats symbolization, formal semantics, and proof theory for each language. The discussion of formal semantics is more direct than in many introductory texts. Although forall x does not contain proofs of soundness and completeness, it lays the groundwork for understanding why these are things that need to be proven. Throughout the book, I have tried to highlight the choices involved in developing sentential and predicate logic. Students should realize that these two are not the only possible formal languages. In translating to a formal language, we simplify and profit in clarity. The simplification comes at a cost, and different formal languages are suited to translating different parts of natural language. The book is designed to provide a semester\'s worth of material for an introductory college course. It would be possible to use the book only for sentential logic, by skipping chapters 4-5 and parts of chapter 6.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 54.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/an-introduction-to-formal-logic\nPublisher ô CSV: Fecundity.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Philosophy.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: P.D. Magnus - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:01:00',NULL),(44,'OTL-57','GT-OTL000057','College Trigonometry',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'Covers chapters 10-11 of Precalculus.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 57.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/college-trigonometry\nPublisher ô CSV: Stitz Zeager Open Source Mathematics.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Geometry and Trigonometry.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Carl Stitz - Author / Jeff Zeager - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:01:00',NULL),(45,'OTL-58','GT-OTL000058','Precalculus',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'A casual glance through the Table of Contents of most of the major publishers\' College Algebra books reveals nearly isomorphic content in both order and depth. Our Table of Contents shows a different approach, one that might be labeled “Functions First.” To truly use The Rule of Four, that is, in order to discuss each new concept algebraically, graphically, numerically and verbally, it seems completely obvious to us that one would need to introduce functions first. (Take a moment and compare our ordering to the classic “equations first, then the Cartesian Plane and THEN functions” approach seen in most of the major players.) We then introduce a class of functions and discuss the equations, inequalities (with a heavy emphasis on sign diagrams) and applications which involve functions in that class. The material is presented at a level that definitely prepares a student for Calculus while giving them relevant Mathematics which can be used in other classes as well. Graphing calculators are used sparingly and only as a tool to enhance the Mathematics, not to replace it. The answers to nearly all of the computational homework exercises are given in thetext and we have gone to great lengths to write some very thought provoking discussion questions whose answers are not given. One will notice that our exercise sets are much shorter than the traditional sets of nearly 100 “drill and kill” questions which build skill devoid of understanding. Our experience has been that students can do about 15-20 homework exercises a night so we very carefully chose smaller sets of questions which cover all of the necessary skills and get the students thinking more deeply about the Mathematics involved.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 58.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/precalculus\nPublisher ô CSV: Stitz Zeager Open Source Mathematics.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Carl Stitz - Author / Jeff Zeager - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:01:00',NULL),(46,'OTL-59','GT-OTL000059','Light and Matter',NULL,'Tiếng Anh',NULL,2010,NULL,NULL,NULL,NULL,1,0,'This is an introductory text intended for a one-year introductory course of the type typically taken by biology majors, or for AP Physics B. Algebra and trig are used, and there are optional calculus-based sections.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 59.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/light-and-matter\nPublisher ô CSV: Benjamin Crowell.\nCopyright Year ô CSV: 2010.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Physics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Benjamin Crowell - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:01:00',NULL),(47,'OTL-60','GT-OTL000060','OpenIntro Statistics - Fourth Edition',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'OpenIntro Statistics covers a first course in statistics, providing a rigorous introduction to appliedstatistics that is clear, concise, and accessible. This book was written with the undergraduate levelin mind, but it’s also popular in high schools and graduate courses.We hope readers will take away three ideas from this book in addition to forming a foundationof statistical thinking and methods. • Statistics is an applied field with a wide range of practical applications.• You don’t have to be a math guru to learn from real, interesting data.• Data are messy, and statistical tools are imperfect. But, when you understand the strengthsand weaknesses of these tools, you can use them to learn about the world.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 60.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/openintro-statistics\nPublisher ô CSV: OpenIntro.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Applied.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: David M. Diez - Author / Christopher D. Barr - Author / Mine Cetinkaya-Rundel - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:01:00',NULL),(48,'OTL-61','GT-ISBN9781951693602','College Physics - 2e',NULL,'Tiếng Anh',NULL,2022,NULL,NULL,NULL,NULL,1,0,'College Physics 2e introduces topics conceptually and progresses through clear explanations in the context of career-oriented, practical applications, and meets the scope and sequence of an algebra-based physics course. The narrative of physics and scientific discovery has been even further expanded to focus on including more diverse contributors to the field. Building on the success of the first edition the authors have increased focus on interdisciplinary connections, including enhancements to biological and medical applications. The problem solving approach has been revised to further unify conceptual, analytical, and calculation skills within the learning process, the authors have integrated a wide array of strategies and supports throughout the text for students. View the first edition of College Physics at OpenStax.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 61.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/college-physics\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2022.\nISBN-13 ô CSV: 9781951693602.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Physics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Paul Peter Urone - Author / Roger Hinrichs - Author / Kim Dirks - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781951693602.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(49,'OTL-62','GT-ISBN9781711493978','Introduction to Sociology - 3e',NULL,'Tiếng Anh',NULL,2021,NULL,NULL,NULL,NULL,1,0,'Introduction to Sociology 3e aligns to the topics and objectives of many introductory sociology courses. It is arranged in a manner that provides foundational sociological theories and contexts, then progresses through various aspects of human and societal interactions. The new edition is focused on driving meaningful and memorable learning experiences related to critical thinking about society and culture. The text includes comprehensive coverage of core concepts, discussions and data relevant to a diverse audience, and features that draw learners into the discipline in powerful and personal ways. Overall, Introduction to Sociology 3e aims to center the course and discipline as crucial elements for understanding relationships, society, and civic engagement; the authors seek to lay the foundation for students to apply what they learn throughout their lives and careers. The authors, reviewers, and the entire team worked to build understanding of the causes and impacts of discrimination and prejudice. Introduction to Sociology 3e contains dozens of examples of discrimination and its outcomes regarding social science, society, institutions, and individuals. The text seeks to strike a balance between confronting the damaging aspects of our culture and history and celebrating those who have driven change and overcome challenges. The core discussion of these topics are present in Chapter 11 on Race and Ethnicity, and Chapter 12 on Gender, Sex, and Sexuality, but their causes and effects are extensively discussed in the context of other topics, including education, law enforcement, government, healthcare, the economy, and so on. Together and when connected by an instructor, these elements have potential for deep and lasting effects.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 62.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-sociology-3e\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2021.\nISBN-13 ô CSV: 9781711493978.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Religion.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences - Sociology.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Tonja R. Conerly - Author / Kathleen Holmes - Author / Asha Lal Tamang - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781711493978.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(50,'OTL-64','GT-ISBN9781946135049','American Government and Politics in the Information Age',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This text is a comprehensive introduction to the vital subject of American government and politics. Governments decide who gets what, when, how (See Harold D. Lasswell, Politics: Who Gets What, When, How, [New York: McGraw-Hill, 1936]); they make policies and pass laws that are binding on all a society\'s members; they decide about taxation and spending, benefits and costs, even life and death. Governments possess power—the ability to gain compliance and to get people under their jurisdiction to obey them—and they may exercise their power by using the police and military to enforce their decisions. However, power need not involve the exercise of force or compulsion; people often obey because they think it is in their interest to do so, they have no reason to disobey, or they fear punishment. Above all, people obey their government because it has authority; its power is seen by people as rightfully held, as legitimate. People can grant their government legitimacy because they have been socialized to do so; because there are processes, such as elections, that enable them to choose and change their rulers; and because they believe that their governing institutions operate justly. Politics is the process by which leaders are selected and policy decisions are made and executed. It involves people and groups, both inside and outside of government, engaged in deliberation and debate, disagreement and conflict, cooperation and consensus, and power struggles. In covering American government and politics, our text introduces the intricacies of the Constitution, the complexities of federalism, the meanings of civil liberties, and the conflicts over civil rights;explains how people are socialized to politics, acquire and express opinions, and participate in political life; describes interest groups, political parties, and elections—the intermediaries that link people to government and politics; details the branches of government and how they operate; and shows how policies are made and affect people\'s lives.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 64.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/american-government-and-politics-in-the-information-age\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781946135049.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Political Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781946135049.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(51,'OTL-65','GT-ISBN9781453320181','Business English for Success',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'Business English for Success is a creative solution to a common challenge across Business Communication courses: Business English or Business Presentations? Some classes place an equal emphasis on oral and written communication. If that\'s the case for you check out our text Business Communication for Success. If, however, your class places the emphasis squarely on written communication and writing proficiency, then Business English for Success is for you. Business English for Success provides instruction in steps, builds writing, reading, and critical thinking, and combines comprehensive grammar review with an introduction to paragraph writing and composition. This step-by-step approach provides a clear path to student-centered learning. A wide range of writing levels and abilities are addressed, helping each student prepare for the next writing or university course. The text opens with a discussion on the sentence and then breaks it down into its elemental components, before reconstructing them into effective sentences, paragraphs, and larger assignments. Then, starting in Chapter 9: Effective Business Writing, the discussion applies lessons learned from the previous foundational chapters into common business issues and applications. From paraphrasing and plagiarism to style to the research process, the expectations increase as several common business documents are presented, including text messages and e-mail, memorandums and letters, the business proposal, business report, resume, and the sales message. This textbook has been used in classes at:Arizona Western College, Hostos Community College, Virginia State University, Truckee Meadows Community College, San Jose State University, Concordia University - Irvine, University New Brunswick - Fredericton, Cerritos College, University of Houston - Downtown, Flat World Knowledge University, A-C Central High School, University of The People, Truckee Meadows Community College, Danville Community High School\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 65.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/business-english-for-success\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: 9781453320181.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Scott McLean - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453320181.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(52,'OTL-66','GT-ISBN9781946135087','Introduction to Criminal Law',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Criminal Law uses a two-step process to augment learning, called the applied approach. First, after building a strong foundation from scratch, Criminal Law introduces you to crimes and defenses that have been broken down into separate components. It is so much easier to memorize and comprehend the subject matter when it is simplified this way. However, becoming proficient in the law takes more than just memorization. You must be trained to take the laws you have studied and apply them to various fact patterns. Most students are expected to do this automatically, but application must be seen, experienced, and practiced before it comes naturally. Thus the second step of the applied approach is reviewing examples of the application of law to facts after dissecting and analyzing each legal concept. Some of the examples come from cases, and some are purely fictional. All the examples are memorable, even quirky, so they will stick in your mind and be available when you need them the most (like during an exam). After a few chapters, you will notice that you no longer obsess over an explanation that doesn\'t completely make sense the first time you read it—you will just skip to the example. The examples clarify the principles for you, lightening the workload significantly.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 66.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/criminal-law\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781946135087.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781946135087.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(53,'OTL-67','GT-ISBN9781453321966','Essentials of Geographic Information Systems',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'Essentials of Geographic Information Systems integrates key concepts behind the technology with practical concerns and real-world applications. Recognizing that many potential GIS users are nonspecialists or may only need a few maps, this book is designed to be accessible, pragmatic, and concise. Essentials of Geographic Information Systems also illustrates how GIS is used to ask questions, inform choices, and guide policy. From the melting of the polar ice caps to privacy issues associated with mapping, this book provides a gentle, yet substantive, introduction to the use and application of digital maps, mapping, and GIS. In today\'s world, learning involves knowing how and where to search for information. In some respects, knowing where to look for answers and information is arguably just as important as the knowledge itself. Because Essentials of Geographic Information Systems is concise, focused, and directed, readers are encouraged to search for supplementary information and to follow up on specific topics of interest on their own when necessary. Essentials of Geographic Information Systems provides the foundations for learning GIS, but readers are encouraged to construct their own individual frameworks of GIS knowledge. The benefits of this approach are two-fold. First, it promotes active learning through research. Second, it facilitates flexible and selective learning—that is, what is learned is a function of individual needs and interest. Since GIS and related geospatial and navigation technology change so rapidly, a flexible and dynamic text is necessary in order to stay current and relevant. Though essential concepts in GIS tend to remain constant, the situations, applications, and examples of GIS are fluid and dynamic. Though this book is intended for use in introductory GIS courses, Essentials of Geographic Information Systems will also appeal to the large number of certificate, professional, extension, and online programs in GIS that are available today. In addition to providing readers with the tools necessary to carry out spatial analyses, Essentials of Geographic Information Systems outlines valuable cartographic guidelines for maximizing the visual impact of your maps. The book also describes effective GIS project management solutions that commonly arise in the modern workplace.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 67.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/essentials-of-geographic-information-systems\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: 9781453321966.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science - Information Systems.\nSubject OTL 2 — nguyên bản ô CSV —: Natural Sciences - Earth Sciences.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Jonathan Campbell - Author / MIchael Shin - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781453321966.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(54,'OTL-68','GT-ISBN9781453311455','Exploring Perspectives: A Concise Guide to Analysis',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'The reason why Randall Fallows wrote Exploring Perspectives: A Concise Guide to Analysis is simple: to help give students a better understanding of how to discover, develop, and revise an analytical essay. Here is how his 5 chapter book goes about doing just that: The first two chapters focus on the nature of an analysis and what\'s involved in writing an analytical essay. Randall shows that analysis consists of a balance of assertions (statements which present their viewpoints or launch an exploration of their concerns), examples (specific passages/scenes/events which inspire these views), explanations (statements that reveal how the examples support the assertions), and significance (statements which reveal the importance of their study to personal and/or cultural issues). After showing why each feature should be present throughout an essay, he reveals how to \"set the stage\" for producing one of their own. He first helps students to evaluate their own views on a subject and to examine how these views emerge from their own experiences, values and judgments. He, then, shows them how to research what others have said about the subject and provides suggestions for evaluating and incorporating this research into their own perspectives. Finally, Randall discusses the nature of writing, not as a linear procedure, but as a recursive process where the discovery and clarification of a concept occur simultaneously. The remaining three chapters reveal more specific advice on how to develop an analytical essay. Exploring Perspectives: A Concise Guide to Analysis by Randall Fallows is a great text to prepare any student to write analytical essays for the argument and persuasion courses.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 68.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/exploring-perspectives-a-concise-guide-to-analysis\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: 9781453311455.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Education.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Randall Fallows - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781453311455.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(55,'OTL-69','GT-ISBN9781453322307','General Chemistry: Principles, Patterns, and Applications',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'The overall goal of the authors with General Chemistry: Principles, Patterns, and Applications was to produce a text that introduces the students to the relevance and excitement of chemistry. Although much of first-year chemistry is taught as a service course, Bruce and Patricia feel there is no reason that the intrinsic excitement and potential of chemistry cannot be the focal point of the text and the course. So, they emphasize the positive aspects of chemistry and its relationship to students\' lives, which requires bringing in applications early and often. In addition, the authors feel that many first year chemistry students have an enthusiasm for biologically and medically relevant topics, so they use an integrated approach in their text that includes explicit discussions of biological and environmental applications of chemistry. Topics relevant to materials science are also introduced to meet the more specific needs of engineering students. To facilitate integration of such material, simple organic structures, nomenclature, and reactions are introduced very early in the text, and both organic and inorganic examples are used wherever possible. This approach emphasizes the distinctions between ionic and covalent bonding, thus enhancing the students\' chance of success in the organic chemistry course that traditionally follows general chemistry. Finally, the authors made a conscious effort to treat material that has traditionally been relegated to boxes, and thus perhaps perceived as peripheral by the students, by incorporating it into the text to serve as a learning tool. To begin the discussion of chemistry rapidly, the traditional first chapter introducing units, significant figures, conversion factors, dimensional analysis, and so on, has been reorganized. The material has been placed in the chapters where the relevant concepts are first introduced, thus providing three advantages: Eliminates the tedium of the traditional approach, which introduces mathematical operations at the outset, and thus avoids the perception that chemistry is a mathematics course; Avoids the early introduction of operations such as logarithms and exponents, which are typically not encountered again for several chapters and may easily be forgotten when they are needed; and Provides a review for those students who have already had relatively sophisticated high school chemistry and math courses, although the sections are designed primarily for students unfamiliar with the topic. Consider this text for your course if you are interested in In summary, a text that represents a step in the evolution of general chemistry texts toward one that reflects the increasing overlap between chemistry and other disciplines. Most importantly, if you want a text that discusses exciting and relevant aspects of biological, environmental, and materials science that are usually relegated to the last few chapters, in a format that allows the you to tailor the emphasis to the needs of the class. Request your desk copy today.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 69.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/general-chemistry-principles-patterns-and-applications\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: 9781453322307.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Chemistry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Bruce Averill - Author / Patricia Eldredge - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781453322307.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(56,'OTL-70','GT-OTL000070','Beginning Excel 2019',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'This textbook was written for a community college introductory course in spreadsheets utilizing Microsoft Excel. While the figures shown utilize Excel 2019, the textbook was written to be applicable to other versions of Excel as well. The book introduces new users to the basics of spreadsheets and is appropriate for students in any major who have not used Excel before. This textbook includes instructions for Excel for Mac also.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 70.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/beginning-excel\nPublisher ô CSV: Open Oregon Educational Resources.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Accounting.\nSubject OTL 2 — nguyên bản ô CSV —: Business.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Noreen Brown - Author / Barbara Lave - Author / Julie Romey - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:01:00',NULL),(57,'OTL-71','GT-ISBN9781946135117','Beginning Management of Human Resources',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Human Resource Management teaches HRM strategies and theories that any manager—not just those in HR—needs to know about recruiting, selecting, training, and compensating people. Most students will be managing people at some point in their careers and not necessarily in a human resource management capacity. As businesses cut back, they may outsource HR duties to outside vendors. Or, in smaller businesses, the HR department is sometimes small or non-existent, and managers from other departments have to perform their own HRM. Therefore, teaching HRM from the perspective of a general manager, in addition to an HR manager, provides more relevance to students\' careers and will give them a competitive advantage in the workplace. This text also provides practical applications of theory relevant to today\'s workplace. You won\'t find discussions about “posting vacancies on a job board” or “sending memos.” In the real world, HRM leverages technology in every aspect of the job—from online training modules to technology for better managing flex-time workers and telecommuters. Consider how most companies have gone “paperless” with pay stubs by using software. While such technology has made HRM easier, it has also created a new set of challenges. For example, how does a manager actually implement a new pay system? Therefore, it\'s important for students to understand what kinds of platforms exist in today\'s workplace to enhance their effectiveness as future managers. The conversational style of Human Resource Management engages students, while the academic rigor of its content provides them with the tools that any manager needs—whether they work in HR or a different department. PLUS it offers an array of supplements that gives them practice creating real HR documents and role-playing real HR scenarios. Add value to your students\' education, enhance the relevance of your curriculum, and make your students more employable by adopting this book for your HRM class. Read it now online today!\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 71.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/human-resource-management\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781946135117.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Business - Human Resources.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781946135117.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(58,'OTL-72','GT-ISBN9781453312995','International Business',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'International Business is one of the most challenging and exciting courses to teach in the Business School. To teach a current, dynamic and complete course you need a textbook by authors as passionate and informed about International Business as you are. Carpenter and Dunung\'s International Business: The Opportunities and Challenges of a Flat World provides exploration into building, leading, and thriving in global organizations in an increasingly flat world. The authors define ”Flat world“ as one where service industries that dwarf manufacturing industries in terms of scale and scope, an Internet that pervades life and work, and networks define modern businesses, whether service or manufacturing. Carpenter and Dunung\'s text is designed to speak to technologically-savvy students who see national borders as bridges and not barriers. The authors use the lexicon of international business, and additionally, develop students\' knowledge of international contexts with the aim that they may launch, run, and work in any organization that is global in scope (or is wrestling with global competition or other global threats). The textbook is organized in 5 Sections: Section 1 introduces the global business course and concludes with a chapter on seizing global opportunities. Section 2 develops student knowledge about key facets of the global business environment, while Section 3 develops knowledge about how a student or organization can exploit opportunities in that global environment. Section 4 is devoted to entrepreneurship in a flat world — this section will explore why the entrepreneurial context is changing, provide lenses for identifying and capitalizing on entrepreneurial opportunities, and Section 5 shows how key organizational activities can be managed for global effectiveness. Every chapter has five enumerated learning objectives, each of these five sections concludes with a short summary (”Key Takeaways“) and five review questions. In addition, each chapter concludes with a mini case on a unique global business that encompasses the topics shown in the chapter. The authors even provide a set of end-of-chapter questions that are mapped to AACSB learning standards, so that you will be able to measure how well students are grasping course content that aligns with the AACSB guidelines. Request a desk copy of Carpenter and Dunung\'s International Business: The Opportunities and Challenges of a Flat World to experience its current and progressive look at International Business for yourself.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 72.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/international-business\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: 9781453312995.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Management.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Mason A Carpenter - Author / Sanjyot P Dunung - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453312995.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(59,'OTL-73','GT-ISBN9781949373950','Strategic Management',NULL,'Tiếng Anh',NULL,2020,NULL,NULL,NULL,NULL,1,0,'STRATEGIC MANAGEMENT offers an introduction to the key topics and themes of strategic management. The authors draw on examples of familiar companies and personalities to illustrate the different strategies used by today’s firms—and how they go about implementing those strategies. Students will learn how to conduct a case analysis, measure organizational performance, and conduct external and internal analyses. In short, they will understand how organizations operate at the strategic level to be successful. An older version of Mastering Strategic Management (2015) by University of Minnesota Libraries Publishing can be found here: https://open.lib.umn.edu/strategicmanagement/\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 73.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/mastering-strategic-management\nPublisher ô CSV: Virginia Tech Publishing.\nCopyright Year ô CSV: 2020.\nISBN-13 ô CSV: 9781949373950.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Management.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Kennedy B. Reed - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781949373950.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(60,'OTL-74','GT-ISBN9781946135209','Principles of Social Psychology',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Have you ever had trouble teaching the various topics of social psychology and fitting them together to form a coherent field? Unnamed Author felt like he was presenting a laundry list of ideas, research studies, and phenomena, rather than an integrated set of principles and knowledge. He wondered how his students could be expected to remember and understand the many phenomena that social psychologists study? How could they tell what was most important? It was then that he realized a fresh approach to a Social Psychology textbook was needed to structure and integrate student learning; thus, Principles of Social Psychology was born. This textbook is based on a critical thinking approach, and its aim is to get students thinking actively and conceptually – with a greater focus on the forest than the trees. Yes, there are right and wrong answers, but the answers are not the only thing. What is perhaps even more important is how students get to the answers – the thinking process itself. To help students better grasp the big picture of social psychology, and to provide you with a theme that you can use to organize your lectures, Unnamed Author\'s text has a consistent pedagogy across the chapters. The presentation is organized around two underlying principles that are essential to social psychology: Person and Situation (the classic treatment)The ABCs of social psychology (Affect, Behavior, and Cognition) The author believes these dimensions are fundamental, that they are extremely heuristic, and that they are what he hopes your students (and his) will learn and remember. You may find that this organization represents a more explicit representation of what you\'re already doing in your lectures. Although the pedagogy is consistent, it is not constraining. You can and will use these dimensions more in some lectures than in others, and you will find them more useful for some topics than others. But they will always work for you when you are ready for them. Perhaps most important, a focus on these dimensions helps us bridge the gap between the textbook, the real-life experiences of our students, and our class presentations. It is almost impossible to can\'t cover every phenomenon in your lectures – you can naturally let the textbook fill in the details. The goal of Principles of Social Psychology is to allow you to rest assured that the text has provided your students with the foundations– the fundamental language of social psychology – from which you can build as you see fit. And when you turn to ask students to apply their learning to real life, you can know that they will be doing this as social psychologists do – using a basic underlying framework. A note about the organization of this text: it moves systematically from lower to higher levels of analysis – a method that makes sense to students. On the other hand, Unnamed Author insists, the chapter order should not constrain you – choose a different order if you wish. Chapter 1 presents an introduction to social psychology and the research methods in social psychology, Chapter 2 presents the fundamental principles of social cognition, and Chapter 3 focuses on social affect. The remainder of the text is organized around three levels of analysis, moving systematically from the individual level (Chapters 4-6), to the level of social interaction (Chapters 7-10) to the group and cultural level (Chapters 11-13). Rather than relying on “modules” or “appendices” of applied materials, this text integrates applied concepts into the text itself. This approach is consistent with the underlying theme that if students learn to think like social psychologists they will easily and naturally apply that knowledge to any and all applications. The following applications are woven throughout the text: Business and Consumer behavior Environment Health Law It is the \"thinking like a social psychologist\" theme, structured approach and new pedagogy (like research foci and Social Psychology in the Public Interest), that will make teaching and learning Social Psychology from this textbook an even more exciting and rewarding endeavor.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 74.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/principles-of-social-psychology\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781946135209.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Psychology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781946135209.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(61,'OTL-75','GT-ISBN9781999198107','Research Methods in Psychology - 4th American Edition',NULL,'Tiếng Anh',NULL,2019,NULL,NULL,NULL,NULL,1,0,'This fourth edition (published in 2019) was co-authored by Rajiv S. Jhangiani (Kwantlen Polytechnic University), Carrie Cuttler (Washington State University), and Dana C. Leighton (Texas A&M University—Texarkana) and is licensed under a Creative Commons Attribution-NonCommercial-ShareAlike 4.0 International License. Revisions throughout the current edition include changing the chapter and section numbering system to better accommodate adaptions that remove or reorder chapters; continued reversion from the Canadian edition; general grammatical edits; replacement of “he/she” to “they” and “his/her” to “their”; removal or update of dead links; embedded videos that were not embedded; moved key takeaways and exercises from the end of each chapter section to the end of each chapter; a new cover design.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 75.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/research-methods-in-psychology-3rd-american-edition\nPublisher ô CSV: Kwantlen Polytechnic University.\nCopyright Year ô CSV: 2019.\nISBN-13 ô CSV: 9781999198107.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Psychology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Carrie Cuttler - Author / Rajiv S. Jhangiani - Author / Dana C. Leighton - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781999198107.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(62,'OTL-76','GT-ISBN9781453317259','Six Steps To Job Search Success',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'This book is a practical discussion of six actionable steps that students can take to land a job regardless of the market. Whether the estimate is 25% unemployment or single-digit unemployment, that number doesn\'t apply to any one student. For any individual, the unemployment rate is 0% or 100%. One either has a job or doesn\'t. When any one person is looking for a job and there is 10% unemployment, that person just wants to be one of the nine people that has a job. Students might think even that one job is beyond their grasp. They think they don\'t have the right degree. Their school is in a different location than where they\'d like to work. Not enough jobs are listed or employers are visiting the campus. This type of thinking cedes control of a student\'s search to outside forces. It is not up to professors, schools, career services support, or recruiters to get students a job. This book is about the proactive things that students can do to get themselves a job. In the first chapter, Six Steps to Job Search Success covers the different types of job searches: full-time job after graduation, internship, return to workforce, career change, relocation. The rest of the book is about how, regardless of the type of job search or overall market, one can be proactive and successfully land a job. This textbook outlines a structured approach, actionable steps, and stresses the importance of a student\'s willingness to see this through. Six Steps to Job Search Success provides that structure with six steps anyone can take to: Identify the types of jobs they\'d like (Step 1: Identify Your Target) Position themselves for these jobs (Step 2: Create A Powerful Marketing Campaign) Figure out what employers are looking for (Step 3: Research) Develop relationships with prospective employers (Step 4: Network and Interview) Stay connected throughout the decision-making process and fix any problems that might arise (Step 5: Stay Motivated; Organized and Troubleshoot Your Search) Complete their search (Step 6: Negotiate and Close the Offer). Connie and Caroline are both former recruiters with over 40 years of combined hiring experience between them. Connie led recruiting areas for three Fortune 500 companies, and Caroline led recruiting in-house for a Fortune 500 but also as an external recruiter for established firms and start-ups. They\'ve hired thousands of people from interns to senior executives. They developed the process detailed in Six Steps to Job Search Success based on how hiring works. The authors explain that in reality, the ability to look for a job and land a job is a separate and distinct skill than any of the skills required for the job itself. The goal of their book is share their job search techniques with your students so that your students can take control of their job search, add an exceptional new job to their career and enjoy the life rewards a satisfying career can bring. If you are interested in a practical approach that can deliver results, this book is for you and your course. Order a desk copy today and see for yourself.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 76.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/six-steps-to-job-search-success\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: 9781453317259.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Student Success.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Caroline Ceniza-Levine - Author / Connie Thanasoulis-Cerrachio - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781453317259.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(63,'OTL-77','GT-ISBN9781946135254','Stand up, Speak out - The Practice and Ethics of Public Speaking',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Stand up, Speak out: The Practice and Ethics of Public Speaking features two key themes. First it focuses on helping students become more seasoned and polished public speakers, and second is its emphasis on ethics in communication. It is this practical approach and integrated ethical coverage that setsStand up, Speak out: The Practice and Ethics of Public Speakingapart from the other texts in this market.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 77.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/stand-up-speak-out-the-practice-and-ethics-of-public-speaking\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781946135254.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781946135254.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(64,'OTL-78','GT-ISBN9781946135278','World Regional Geography - People, Places and Globalization',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'World Regional Geography: People, Places and Globalization is designed for students to experience and study as much of the world as possible within a limited amount of time. It gives students the fundamental concepts and the latest data regarding world places in a concise, easy-to-read format. This World Regional Geography textbook focuses on the primary issues that have created our cultural and societal structures, and presents them within a framework for global understanding. A pattern of development is outlined from the imprint that European colonialism had on culture to the impact that giant retail corporations like Wal-Mart have on consumerism. Within this framework, the textbook takes a regional approach to globalization and world geography, as each chapter focuses on one subject or region. The first unit covers the basic concepts of location, the environment, and global economic dynamics. Then, these basic concepts, theories, and principles are presented for each region on a chapter-by-chapter basis. The basic concepts are covered using real world examples to provide purpose and relevance for the students. And each lesson begins with learning objectives and ends with key takeaways to stimulate critical thinking about each topic or region. Basic spatial concepts are also tracked throughout the text to connect ideas and apply concepts to every region of the world. Special sections on relevant topics are also distributed throughout the book. With each chapter focused on one region, the textbook provides professors with some course management and flexibility. The text is also brief enough to provide additional flexibility if professors want to include specialized information from outside sources. World Regional Geography: People, Places and Globalization provides students with a working knowledge of world geography in an easy-to-read format. Basic geographic concepts of world places are presented in concise chapters, and each chapter provides a foundational framework for understanding the development patterns of world regions. See for yourself and take a look at the book today!\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 78.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/world-regional-geography-people-places-and-globalization\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781946135278.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Earth Sciences.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences - Geography.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781946135278.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(65,'OTL-79','GT-ISBN9781475146127','Social Science Research: Principles, Methods and Practices - (Revised edition)',NULL,'Tiếng Anh',NULL,2019,NULL,NULL,NULL,NULL,1,0,'This book is designed to introduce doctoral and postgraduate students to the process of conducting scientific research in the social sciences, business, education, public health, and related disciplines. It is a one-stop, comprehensive, and compact source for foundational concepts in behavioural research, and can serve as a standalone text or as a supplement to research readings in any doctoral seminar or research methods class. This book is currently being used as a research text at universities in 216 countries, across six continents and has been translated into seven different languages. To receive updates on this book, including the translated versions, please follow the author on Facebook or Twitter @Anol_B.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 79.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/social-science-research-principles-methods-and-practices\nPublisher ô CSV: University of Southern Queensland.\nCopyright Year ô CSV: 2019.\nISBN-13 ô CSV: 9781475146127.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Political Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Anol Bhattacherjee - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781475146127.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(66,'OTL-80','GT-OTL000080','How to Think Like a Computer Scientist: Learning with Python',NULL,'Tiếng Anh',NULL,2008,NULL,NULL,NULL,NULL,1,0,'How to Think Like a Computer Scientist: Learning with Python is an introduction to programming using Python.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 80.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/how-to-think-like-a-computer-scientist-learning-with-python\nPublisher ô CSV: Green Tea Press.\nCopyright Year ô CSV: 2008.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science - Programming Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Allen Downey - Author / Jeff Elkner - Author / Chris Meyers - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:01:00',NULL),(67,'OTL-82','GT-OTL000082','Physical Modeling in MATLAB - Version 4.0',NULL,'Tiếng Anh',NULL,2021,NULL,NULL,NULL,NULL,1,0,'Modeling and simulation are powerful tools for explaining the world, making predictions, designing things that work, and making them work better. Learning to use these tools can be difficult; this book is my attempt to make the experience as enjoyable and productive as possible. By reading this book — and working on the exercises — you will learn some programming, some modeling, and some simulation: With basic programming skills, you can create models for a wide range of physical systems. My goal is to help you develop these skills in a way you can apply immediately to real-world problems. This book presents the entire modeling process, including model selection, analysis, simulation, and validation. I explain this process in Chapter 1, and there are examples throughout the book. Simulation is an approach to modeling that uses computer programs to implement models and generate predictions. This book shows how simulations are used to run experiments, answer questions, and guide decision-making.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 82.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/physical-modeling-in-matlab\nPublisher ô CSV: Green Tea Press.\nCopyright Year ô CSV: 2021.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Allen Downey - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:01:00',NULL),(68,'OTL-83','GT-OTL000083','The Little Book of Semaphores',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'The Little Book of Semaphores is a free (in both senses of the word) textbook that introduces the principles of synchronization for concurrent programming. In most computer science curricula, synchronization is a module in an Operating Systems class. OS textbooks present a standard set of problems with a standard set of solutions, but most students don\'t get a good understanding of the material or the ability to solve similar problems. The approach of this book is to identify patterns that are useful for a variety of synchronization problems and then show how they can be assembled into solutions. After each problem, the book offers a hint before showing a solution, giving students a better chance of discovering solutions on their own. The book covers the classical problems, including \"Readers-writers,\" \"Producer-consumer\", and \"Dining Philosophers.\" In addition, it collects a number of not-so-classical problems, some written by the author and some by other teachers and textbook writers. Readers are invited to create and submit new problems.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 83.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-little-book-of-semaphores\nPublisher ô CSV: Green Tea Press.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Allen B. Downey - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:01:00',NULL),(69,'OTL-85','GT-ISBN9781616100940','Basics of Fluid Mechanics - ver. 0.6.9.a',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'The topic of fluid mechanics is common to several disciplines: mechanical engineering, aerospace engineering, chemical engineering, and civil engineering. In fact, it is also related to disciplines like industrial engineering, and electrical engineering. While the emphasis is somewhat different in this book, the common material is presented and hopefully can be used by all. One can only admire the wonderful advances done by the previous geniuses who work in this field. In this book it is hoped to insert, what and when a certain model is suitable than other models. One of the difference in this book is the insertion of the introduction to multiphase flow. Clearly, multiphase is an advance topic. However, some minimal familiarity can be helpful for many engineers who have to deal with non pure single phase fluid. This book is the third book in the series of POTTO project books. POTTO project books are open content textbooks so everyone are welcome to joint in. The topic of fluid mechanics was chosen just to fill the introduction chapter to compressible flow. During the writing it became apparent that it should be a book in its own right. In writing the chapter on fluid statics, there was a realization that it is the best chapter written on this topic. It is hoped that the other chapters will be as good this one. This book is written in the spirit of my adviser and mentor E.R.G. Eckert. Eckert, aside from his research activity, wrote the book that brought a revolution in the education of the heat transfer. Up to Egret\'s book, the study of heat transfer was without any dimensional analysis. He wrote his book because he realized that the dimensional analysis utilized by him and his adviser (for the post doc), Ernst Schmidt, and their colleagues, must be taught in engineering classes. His book met strong criticism in which some called to \"burn\" his book. Today, however, there is no known place in world that does not teach according to Eckert\'s doctrine. It is assumed that the same kind of individual(s) who criticized Eckert\'s work will criticize this work. Indeed, the previous book, on compressible flow, met its opposition. For example, anonymous Wikipedia user name EMBaero claimed that the material in the book is plagiarizing, he just doesn\'t know from where and what. Maybe that was the reason that he felt that is okay to plagiarize the book on Wikipedia. These criticisms will not change the future or the success of the ideas in this work. As a wise person says \"don\'t tell me that it is wrong, show me what is wrong\"; this is the only reply. With all the above, it must be emphasized that this book is not expected to revolutionize the field but change some of the way things are taught. The book is organized into several chapters which, as a traditional textbook, deals with a basic introduction to the fluid properties and concepts (under construction). The second chapter deals with Thermodynamics. The third book chapter is a review of mechanics. The next topic is statics. When the Static Chapter was written, this author did not realize that so many new ideas will be inserted into this topic. As traditional texts in this field, ideal flow will be presented with the issue of added mass and added forces (under construction). The classic issue of turbulence (and stability) will be presented. An introduction to multi-phase flow, not a traditional topic, will be presented next (again under construction). The next two chapters will deal with open channel flow and gas dynamics. At this stage, dimensional analysis will be present (again under construction).\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 85.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/basics-of-fluid-mechanics\nPublisher ô CSV: Potto Project.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781616100940.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Free Documentation License (GNU).\nSubject OTL 1 — nguyên bản ô CSV —: Engineering & Technology - Chemical Engineering.\nSubject OTL 2 — nguyên bản ô CSV —: Engineering & Technology - Civil Engineering.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 600 — Công nghệ (Khoa học ứng dụng).\nContributors — nguyên bản ô CSV —: Genick Bar-Meir - Author',NULL,NULL,'600','utc-elibrary/book-covers/isbn/9781616100940.jpg',4,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(70,'OTL-86','GT-OTL000086','Fundamentals of Compressible Flow Mechanics',NULL,'Tiếng Anh',NULL,2004,NULL,NULL,NULL,NULL,1,0,'This book deals with an introduction to the flow of compressible substances (gases). The main difference between compressible flow and almost incompressible flow is not the fact that compressibility has to be considered. Rather, the difference is in two phenomena that do not exist in incompressible flow. The first phenomenon is the very sharp discontinuity (jump) in the flow in properties. The second phenomenon is the choking of the flow. Choking is when downstream variations don\'t effect the flow. Though choking occurs in certain pipe flows in astronomy, there also are situations of choking in general (external) flow.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 86.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/fundamentals-of-compressible-flow-mechanics\nPublisher ô CSV: Potto Project.\nCopyright Year ô CSV: 2004.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Free Documentation License (GNU).\nSubject OTL 1 — nguyên bản ô CSV —: Engineering & Technology - Mechanical Engineering.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 600 — Công nghệ (Khoa học ứng dụng).\nContributors — nguyên bản ô CSV —: Genick Bar-Meir - Author',NULL,NULL,'600','utc-elibrary/book-covers/defaults/default-book-cover.jpg',4,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:01:00',NULL),(71,'OTL-91','GT-OTL000091','Vector Calculus',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'This is a text on elementary multivariable calculus, designed for students who have completed courses in single-variable calculus. The traditional topics are covered: basic vector algebra; lines, planes and surfaces; vector-valued functions; functions of 2 or 3 variables; partial derivatives; optimization; multiple integrals; line and surface integrals. The book also includes discussion of numerical methods: Newton\'s method for optimization, and the Monte Carlo method for evaluating multiple integrals. There is a section dealing with applications to probability. Appendices include a proof of the right-hand rule for the cross product, and a short tutorial on using Gnuplot for graphing functions of 2 variables There are 420 exercises in the book. Answers to selected exercises are included.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 91.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/vector-calculus\nPublisher ô CSV: Michael Corral.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Free Documentation License (GNU).\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Michael Corral - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:01:00',NULL),(72,'OTL-92','GT-ISBN9781467976664','Calculus for the Life Sciences: A Modeling Approach Volume 1',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'Our writing is based on three premises. First, life sciences students are motivated by and respond well to actual data related to real life sciences problems. Second, the ultimate goal of calculus in the life sciences primarily involves modeling living systems with difference and differential equations. Understanding the concepts of derivative and integral are crucial, but the ability to compute a large array of derivatives and integrals is of secondary importance. Third, the depth of calculus for life sciences students should be comparable to that of the traditional physics and engineering calculus course; else life sciences students will be short changed and their faculty will advise them to take the \'best\' (engineering) course. In our text, mathematical modeling and difference and differential equations lead, closely follow, and extend the elements of calculus. Chapter one introduces mathematical modeling in which students write descriptions of some observed processes and from these descriptions derive first order linear difference equations whose solutions can be compared with the observed data. In chapters in which the derivatives of algebraic, exponential, or trigonometric functions are defined, biologically motivated differential equations and their solutions are included. The chapter on partial derivatives includes a section on the diffusion partial differential equation. There are two chapters on non-linear difference equations and on systems of two difference equations and two chapters on differential equations and on systems of differential equation.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 92.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/calculus-for-the-life-sciences-a-modeling-approach-volume-1\nPublisher ô CSV: A.T. Still University.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: 9781467976664.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: James L. Cornette - Author / Ralph A. Ackerman - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781467976664.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:00:00',NULL),(73,'OTL-95','GT-OTL000095','Basic Analysis: Introduction to Real Analysis',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This free online textbook (e-book in webspeak) is a one semester course in basic analysis. This book started its life as my lecture notes for Math 444 at the University of Illinois at Urbana-Champaign (UIUC) in the fall semester of 2009, and was later enhanced to teach Math 521 at University of Wisconsin-Madison (UW-Madison). A prerequisite for the course is a basic proof course. It should be possible to use the book for both a basic course for students who do not necessarily wish to go to graduate school, but also as a first semester of a more advanced course that also covers topics such as metric spaces.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 95.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/basic-analysis-introduction-to-real-analysis\nPublisher ô CSV: Jirí Lebl.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Analysis.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Applied.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Jirí Lebl - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:01:00',NULL),(74,'OTL-96','GT-OTL000096','Sustainability: A Comprehensive Foundation',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'With “Sustainability: A Comprehensive Foundation”, first and second-year college students are introduced to this expanding new field, comprehensively exploring the essential concepts from every branch of knowledge – including engineering and the applied arts, natural and social sciences, and the humanities. As sustainability is a multi-disciplinary area of study, the text is the product of multiple authors drawn from the diverse faculty of the University of Illinois: each chapter is written by a recognized expert in the field. This text is designed to introduce the reader to the essential concepts of sustainability. This subject is of vital importance seeking as it does to uncover the principles of the long-term welfare of all the peoples of the planet but is only peripherally served by existing college textbooks. The content is intended to be useful for both a broad-based introductory class on sustainability and as a useful supplement to specialist courses which wish to review the sustainability dimensions of their areas of study. By covering a wide range of topics with a uniformity of style, and by including glossaries, review questions, case studies, and links to further resources, the text has sufficient range to perform as the core resource for a semester course. Students who cover the material in the book will be conversant in the language and concepts of sustainability, and will be equipped for further study in sustainable planning, policy, economics, climate, ecology, infrastructure, and more. Furthermore, the modular design allows individual chapters and sections to be easily appropriated without the purchase of a whole new text. This allows educators to easily bring sustainability concepts, references, and case studies into their area of study. This appropriation works particularly well as the text is free downloadable to anyone who wishes to use it. Furthermore, readers are encouraged to work with the text. Provided there is attribution to the source, users can adapt, add to, revise and republish the text to meet their own needs. Because sustainability is a cross-disciplinary field of study, producing this text has required the bringing together over twenty experts from a variety of fields. This enables us to cover all of the foundational components of sustainability: understanding our motivations requires the humanities, measuring the challenges of sustainability requires knowledge of the sciences (both natural and social), and building solutions requires technical insight into systems (such as provided by engineering, planning, and management). Readers accustomed to textbooks that present material in a unitary voice might be surprised to find in this one statements that do not always agree. Here, for example, cautious claims about climate change stand beside sweeping pronouncements predicting future social upheaval engendered by a warming world. And a chapter that includes market-based solutions to environmental problems coexists with others that call for increased government control. Such diversity of thought characterizes many of the fields of inquiry represented in the book; by including it, we invite users to engage in the sort of critical thinking a serious study of sustainability requires. It is our sincerest hope that this work is shared freely and widely, as we all struggle to understand and solve the enormous environmental challenges of our time.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 96.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/sustainability-a-comprehensive-foundation\nPublisher ô CSV: OpenStax CNX.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Engineering & Technology.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences - Political Science.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Tom Theis - Editor / Jonathan Tomkin - Editor',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:01:00',NULL),(75,'OTL-97','GT-OTL000097','Precalculus: An Investigation of Functions',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'Precalculus: An Investigation of Functions is a free, open textbook covering a two-quarter pre-calculus sequence including trigonometry. The first portion of the book is an investigation of functions, exploring the graphical behavior of, interpretation of, and solutions to problems involving linear, polynomial, rational, exponential, and logarithmic functions. An emphasis is placed on modeling and interpretation, as well as the important characteristics needed in calculus. The second portion of the book introduces trigonometry. Trig is introduced through an integrated circle/triangle approach. Identities are introduced in the first chapter, and revisited throughout. Likewise, solving is introduced in the second chapter and revisited more extensively in the third chapter. As with the first part of the book, an emphasis is placed on motivating the concepts and on modeling and interpretation. In addition to the paper homework sets, algorithmetically generated online homework is available as part of a complete course shell package, which also includes a sample syllabus, teacher notes with lecture examples, sample quizzes and exams, printable classwork sheets and handouts, and chapter review problems. If you teach in Washington State, you can find the course shell in the WAMAP.org template course list. For those located elsewhere, you can access the course shell at MyOpenMath.com. A self-study version of the online course exercises is also available on MyOpenMath.com for students wanting to learn the material on their own, or who need a refresher.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 97.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/precalculus-an-investigation-of-functions\nPublisher ô CSV: David Lippman and Melonie Rasmussen.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: David Lippman - Author / Melonie Rasmussen - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:01:00',NULL),(76,'OTL-98','GT-OTL000098','Math in Society - Edition 2.5',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'Math in Society is a free, open textbook. This book is a survey of contemporary mathematical topics, most non-algebraic, appropriate for a college-level topics course for liberal arts majors. The text is designed so that most chapters are independent, allowing the instructor to choose a selection of topics to be covered. Emphasis is placed on the applicability of the mathematics. Core material for each topic is covered in the main text, with additional depth available through exploration exercises appropriate for in-class, group, or individual investigation. This book is appropriate for Math 107 (Washington State Community Colleges common course number).\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 98.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/math-in-society\nPublisher ô CSV: David Lippman.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: David Lippman - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:01:00',NULL),(77,'OTL-99','GT-OTL000099','Introduction to Basic Legal Citation',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'This is not a comprehensive citation reference work. Its limited aim is to serve as a tutorial onhow to cite the most widely referenced types of U.S. legal material, taking account of localnorms and the changes in citation practice forced by the shift from print to electronic sources.It begins with an introductory unit. That is followed immediately by one on \"how to cite\" thecategories of authority that comprise a majority of the citations in briefs and legalmemoranda. Using the full table of contents one can proceed through this material insequence. The third unit, organized around illustrative examples, is intended to be used eitherfor review and reinforcement of the prior \"how to\" sections or as an alternative approach tothem. One can start with it since the illustrative examples for each document type are linkedback to the relevant \"how to\" principles. The sections on abbreviations and omissions, on typeface (italics and underlining), and onhow citations fit into the larger project of legal writing that follow all support the precedingunits. They are accessible independently and also, where appriopriate, via links from theearlier sections. Finally, there are a series of cross reference tables tying this introduction tothe two major legal citation reference works and to state-specific citation rules and practices. The work is also designed to be used by those confronting a specific citation issue. For suchpurposes the table of contents provides one path to the relevant material. Another, to whichthe bar at the top of each major section provides ready access, is a topical index. This index isalphabetically arrayed and more detailed than the table of contents. Finally, the searchfunction in your e-book reader software should allow an even narrower inquiry, such as oneseeking the abbreviation for a specific word (e.g.,institute) or illustrative citations for aparticular state, Ohio, say. If the device on which you are reading this e-book allows it, the pdf format will enable you toprint or to copy and paste portions, large or small, into other documents. However, since thev work is filled with linked cross references and both the table of contents and index rely onthem, most will find a print copy far less useful than the electronic original.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 99.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-basic-legal-citation\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Peter W. Martin - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:32','2026-05-06 09:01:00',NULL),(78,'OTL-100','GT-OTL000100','Contract Doctrine, Theory & Practice Volume 2',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'This is Volume 2 in a three volume series written for Contracts Law. Its orginal title was \"Collaborative Teaching Materials for Contracts.\" The first semester of law school is mostly about learning to speak a new legal language (but emphatically not “legalese”), to formulate and evaluate legal arguments, to become comfortable with the distinctive style of legal analysis. We could teach these skills using almost any legal topic. But we begin the first-year curriculum with subjects that pervade the entire field of law. Contract principles have a long history and they form a significant part of the way that lawyers think about many legal problems. As you will discover when you study insurance law, employment law, family law, and dozens of other practice areas, your knowledge of contract doctrine and theory will be invaluable.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 100.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/contract-doctrine-theory-practice-volume-2\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Law - Contract Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: J.H. Verkerke - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(79,'OTL-101','GT-OTL000101','Contract Doctrine, Theory & Practice Volume 1',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'This is the first in a series of Contracts casebooks. It was originally titled \"Collaborative Teaching Materials for Contracts.\" The first semester of law school is mostly about learning to speak a new legal language (but emphatically not “legalese”), to formulate and evaluate legal arguments, to become comfortable with the distinctive style of legal analysis. We could teach these skills using almost any legal topic. But we begin the first-year curriculum with subjects that pervade the entire field of law. Contract principles have a long history and they form a significant part of the way that lawyers think about many legal problems. As you will discover when you study insurance law, employment law, family law, and dozens of other practice areas, your knowledge of contract doctrine and theory will be invaluable.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 101.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/contract-doctrine-theory-practice-volume-1\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Law - Contract Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: J.H. Verkerke - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(80,'OTL-102','GT-OTL000102','Federal Rules of Appellate Procedure',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'The Federal Rules of Appellate Procedure appear in the Appendix to Title 28 of the United State Code. This publication was made with data provided by the United States government on the Office of Law Revision Counsel Bulk US Code. This title is current through July 31, 2014. All updates to this material will appear at the above URL.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 102.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/federal-rules-of-appellate-procedure\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Procedural Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: eLangdell Press Editorial Staff - Editor',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(81,'OTL-103','GT-OTL000103','United States Copyright Law',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'This Intellectual Property Supplement from eLangdell Press contains the text of federal laws and regulations in the area of copyright, trademarks and patents. The editors have endeavored to gather all relevant laws, rules and regulations. This collection is intended to be used primarily as a statutory supplement for law students and legal scholars in academic settings, although practitioners in this area of law will also find it useful. This volume, Volume 1: Copyright Statutory Law contains the text of Title 17 of the United States Code as it appears on the most current edition available on the U.S. Government website FDSYS. Updates to the U.S. Code not yet found in the FDSYS published editions can be found in the United States House of Representatives Office of Law Revision Counsel\'s Classification Tables. Some formatting modification has been performed to better accommodate electronic readers.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 103.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/united-states-copyright-law\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Property Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: eLangdell Press Editorial Staff - Editor',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(82,'OTL-104','GT-OTL000104','United States Patent Law',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'This Intellectual Property Supplement from eLangdell Press contains the text of federal laws and regulations in the area of copyright, trademarks and patents. The editors have endeavored to gather all relevant laws, rules and regulations. This collection is intended to be used primarily as a statutory supplement for law students and legal scholars in academic settings, although practitioners in this area of law will also find it useful. This volume, Volume 2: Patent Statutory Law contains the text of Title 35 of the United States Code as it appears on the most current edition available on the U.S. Government website FDSYS. Updates to the U.S. Code not yet found in the FDSYS published editions can be found in the United States House of Representatives Office of Law Revision Counsel\'s Classification Tables. Some formatting modification has been performed to better accommodate electronic readers.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 104.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/united-states-patent-law\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Property Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: eLangdell Press Editorial Staff - Editor',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(83,'OTL-105','GT-OTL000105','United States Trademark Law',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'This Intellectual Property Supplement from eLangdell Press contains the text of federal laws and regulations in the area of copyright, trademarks and patents. The editors have endeavored to gather all relevant laws, rules and regulations. This collection is intended to be used primarily as a statutory supplement for law students and legal scholars in academic settings, although practitioners in this area of law will also find it useful. This volume, Volume III: Trademark Statutory Law contains Chapter 22 of Title 15 of the United States Code as it appears on the most current edition available on the U.S. Government website FDSYS. Updates to the U.S. Code not yet found in the FDSYS published editions can be found in the United States House of Representatives Office of Law Revision Counsel\'s Classification Tables. Some formatting modification has been performed to better accommodate electronic readers.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 105.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/united-states-trademark-law\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Property Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: eLangdell Press Editorial Staff - Editor',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(84,'OTL-106','GT-OTL000106','Land Use',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'This text explores the laws governing the use of land. Sometimes narrowly focused, often intensely local, land use regulation may give the impression of a highly specialized field with small stakes. The text is divided into three parts: First, we will survey the ordinary, local administrative scheme of land use regulation. The cases in this section are intended to establish what that system is and what it\'s standards are. In the second part of the course, we will turn our attention to cases illustrating litigation attacks on the ordinary administrative scheme. The purpose here is not, as it was in the first part, to understand better the standards the administrators should apply, but to understand the constraints imposed on the contents of local laws, the procedures of enactment and permitting, and the composition of local lawmaking bodies. In the third part, we focus on the distributive concerns raised by land use regulation. The regulatory takings doctrine has gone from, literally, nothing, to wrestling to disentangle distributive concerns from substantive ones, to trying to craft either rules or standards to identify regulations that go “too far” and should be considered “takings” within the meaning of the Fifth Amendment. We will consider what the doctrine\'s purposes are, how it should be governed, and how it should be invoked as a procedural matter.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 106.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/land-use\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Property Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Christian Turner - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(85,'OTL-107','GT-OTL000107','Evidence: Best Evidence Rule',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'The Best Evidence Rule, contained in Article X of the Federal Rules of Evidence (Rules 1001-1008) and state counterparts, is a Rule that requires a party seeking to prove the contents of a writing, recording, or photograph to produce the original (or a duplicate) or account for its nonproduction. Through a series of cases and hypotheticals drawn from actual cases, this chapter gives readers a roadmap for how to address any Best Evidence Rule issue in practice. Faculty materials also available: In addition to the free, open learning materials for students listed above, this eLangdell chapter includes a teacher\'s manual. Faculty and staff at CALI member schools can access these materials by logging in to eLangdell with a cali.org username and password. Contact CALI.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 107.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/evidence-best-evidence-rule\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Procedural Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Colin Miller - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(86,'OTL-108','GT-OTL000108','Evidence: Jury Impeachment',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'The anti-jury impeachment rule, contained in Federal Rule of Evidence 606(b) and state counterparts, is a rule preventing the admission of jury testimony or statements in connection with an inquiry into the validity of the verdict, subject to certain exceptions. Through a series of cases and hypotheticals drawn from actual cases, this chapter gives readers a roadmap for how to address any jury impeachment issue in practice. Faculty materials also available: In addition to the free, open learning materials for students listed above, this eLangdell chapter includes a teacher\'s manual. Faculty and staff at CALI member schools can access these materials by logging in to eLangdell with a cali.org username and password. Contact CALI if you have questions.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 108.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/evidence-jury-impeachment\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Procedural Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Colin Miller - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(87,'OTL-109','GT-OTL000109','Evidence: Rape Shield Rule',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'The Rape Shield Rule, contained in Federal Rule of Evidence 412 and state counterparts is a Rule preventing the admission of evidence concerning the sexual predisposition and behavior of an alleged victim of sexual misconduct, subject to certain exceptions. Through a series of cases and hypotheticals drawn from actual cases, this chapter gives readers a roadmap for how to address any Rape Shield Rule issue in practice. Faculty materials also available: In addition to the free, open learning materials for students listed above, this eLangdell chapter includes a teacher\'s manual. Faculty and staff at CALI member schools can access these materials by logging in to eLangdell with a cali.org username and password. Contact CALI if you have questions.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 109.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/evidence-rape-shield-rule\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Procedural Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Colin Miller - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(88,'OTL-113','GT-OTL000113','Computer-Aided Exercises in Civil Procedure - 7th Edition',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'The sixth edition, first published as an ebook, and this seventh edition carry forward the philosophy and structure of the earlier editions. This book is not a comprehensive treatise on the subject of civil procedure, yet it provides a mixture of expository text, cases, and self-testing questions in nearly all of the major areas of the subject. In order to maximize accessibility, flexibility, and compatibility of the book, the authors have chosen CALI\'s eLangdell Press to publish and distribute the sixth edition (as chapters) and this revised seventh (as a complete book) electronically with a Creative Commons license. Publishing a law textbook electronically with far fewer restrictions than most commercial books and using a somewhat new, boutique outfit such as eLangdell Press is an unconventional choice, to say the least. But the authors share the eLangdell vision of more flexible teaching materials for professors and more cost-effective books for students. Professors may now edit and remix this work to match their teaching without worry of copyright infringement. Students may now adopt this book, read it using any number of software or devices, and even print it - all for free. The book\'s authors, like its publishers, believe that this new book model represents an important and long overdue step forward in the way law school books are published. All the exercises have been substantially revised for this edition. The individual exercises also are reorganized and expanded so that they follow a more standardized pattern: expository text on the topic area, work-book questions, and introduction to the related online CALI lessons. This book, and the accompanying interactive exercises known as CALI Lessons available online through the Center for Computer-Assisted Legal Instruction (CALI) at www.cali.org, are intended to provide a challenging educational experience. For each exercise, students should read the text in this book and answer the questions before accessing the rest of the exercise online. Professors choosing to assign only some of the exercises - or students looking for additional work only in certain areas of the subject - may especially want to consider these exercises and lessons: Exercise Two: Jurisdiction (Jurisdiction & Venue and Jurisdiction Over the Person); Exercise Three: Pleading a Complaint; Exercise Five: Motions to Dismiss and Waiver under Federal Rule 12; Exercise Six: Joinder and Supplemental Jurisdiction (An Exercise in Civil Procedure, Review of Joinder Concepts, Joinder of Claims and Parties, and An Interpleader Primer); Exercise Eight: Summary Judgment; and Exercise Eleven: Preclusion. Additionally, Exercise One: Holding and Dicta in the Context of a Diversity Case is an excellent introduction to legal method. The first two editions of this book, by Roger Park, included Exercise One: Holding and Dicta in the Context of a Diversity Case, Exercise Two: Jurisdiction, Exercise Three: Pleading a Complaint, Exercise Four: Demurrers and Judgments on the Pleadings, Exercise Five: Motions to Dismiss and Waiver Under Rule 12, Exercise Nine: Judgment as a Matter of Law, and Exercise Ten: Evidence for Civil Procedure Students. For the last five editions of this book, Douglas McFarland has edited the above exercises and added Exercise Six: Joinder and Supplemental Jurisdiction, Exercise Seven: Discovery, Exercise Eight: Summary Judgment, and Exercise Eleven: Preclusion. Accordingly, the book has become more comprehensive, expanding from seven to eleven exercises. Of course, each new edition incorporates changes and updates in procedural law. All of the information necessary to prepare for an interactive exercise is contained in this book. Reference to additional materials may be useful, but is not necessary. Each exercise can be assigned separately. No exercise is a prerequisite for another. In fact, students will find the expository material and work-book questions in each exercise independently valuable even without completing the CALI lesson for that chapter. The CALI lessons are valuable either to provide additional understanding and self-testing of subjects discussed in class or as primary substitutes for areas not covered in depth in class. In general, the interactive, online exercises follow a non-linear branching format. They seek to present challenges and questions instead of rote learning or leading students through an error-free educational experience. Although the exercises eventually evaluate student answers, they sometimes eschew immediate feedback in favor of the development of a line of questions. The ideal is the creation of a classroom-like Socratic dialogue. For a description of general goals and educational theory of the exercises, see Roger C. Park & Russell Burris, Computer-Aided Legal Instruction in Law: Theories, Techniques, and Trepidations, 1978 Am. B. Found. Res. J. 1. This book and accompanying exercises cannot reproduce the spontaneity and flexibility of the live classroom, but they can be a useful supplement. They require an active learning process in which students respond to questions dozens of times during each hour of instruction, and receive prompt evaluation of their answers. Another benefit of computer-aided instruction—and the phrase “computer-aided” is used loosely here and in the title of this book; the exercises are compatible with many non-computer devices such as tablets and smartphones—is its “individualized” nature. Law professors and students should not take this literally, however. Surveys administered at several law schools indicate that an overwhelming majority of students believe that the exercises are more valuable when done in pairs or threes instead of alone. Students who do the exercises with a partner are more likely to consider their responses carefully and to enjoy the experience. They also have lively discussions about what their response should be and why the computer responded as it did. As with previous editions, we continue to welcome and solicit comments from professors and students about the book and the accompanying exercises.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 113.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/computer-aided-exercises-in-civil-procedure\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Civil Law.\nSubject OTL 2 — nguyên bản ô CSV —: Law - Procedural Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Roger C. Park - Author / Douglas D. McFarland - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(89,'OTL-114','GT-OTL000114','Civil Procedure: Pleading',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'This chapter covers the Civil Procedure topic of Pleading: The Plaintiff‘s Complaint. The chapter takes approximately four class periods to cover in detail. The student is exposed to cases, presented with questions that are designed to both guide class discussion and to help the student focus his reading of the materials, pleadings from cases, and the applicable Federal Rules of Civil Procedure. Faculty materials available: This eLangdell chapter includes a teacher\'s manual. Faculty and staff at CALI member schools can access these faculty-only materials by logging in to eLangdell with their normal cali.org username and password. Contact CALI if you have questions. This chapter covers the Civil Procedure topic of Pleading: The Plaintiff\'s Complaint. The chapter takes approximately four class periods to cover in detail. The student is exposed to cases, presented with questions that are designed to both guide class discussion and to help the student focus his reading of the materials, pleadings from cases, and the applicable Federal Rules of Civil Procedure. There are two accompanying files available only to faculty who are registered at cali.org (registration is free for faculty at CALI member schools): a Teaching Manual and a Supplemental Material document. The Supplemental Material should be distributed to students at the appropriate point in the unit. Please see the Teaching Manual for details.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 114.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/civil-procedure-pleading\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Civil Law.\nSubject OTL 2 — nguyên bản ô CSV —: Law - Procedural Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Hillel Y. Levin - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(90,'OTL-115','GT-OTL000115','Federal Rules of Bankruptcy Procedure',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'The Federal Rules of Bankruptcy Procedure appear in the Appendix to Title 11 of the United State Code. This publication was made with data provided by the United States government on the Office of Law Revision Counsel Bulk US Code. This title is current through July 31, 2014.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 115.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/federal-rules-of-bankruptcy-procedure\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Procedural Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Scott A. Cromar - Editor / Robert M. Lawless - Editor',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(91,'OTL-116','GT-OTL000116','Federal Rules of Evidence',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Rules of evidence are, as the name indicates, the rules by which a court determines what evidence is admissible at trial. In the U.S., federal courts follow the Federal Rules of Evidence. This series of Federal Rules books, consisting of the Federal Rules of Evidence, Criminal Procedure and Civil Procedure, are powered by the Legal Information Institute at Cornell Law School, and created in partnership with The Center for Computer-Assisted Legal Instruction (CALI). You may download the books for free, but remember that publishing these books is not free for our organizations. Our Federal Rules ebooks include: The complete rules as of December 1, 2014 (for the 2015 edition). All notes of the Advisory Committee following each rule. Internal links to rules referenced within the rules. External links to the LII website\'s version of the US Code.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 116.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/federal-rules-of-evidence\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Procedural Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Legal Information Institute - Editor',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(92,'OTL-117','GT-OTL000117','Federal Rules of Criminal Procedure',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'This series of Federal Rules books, consisting of the Federal Rules of Evidence, Criminal Procedure and Civil Procedure, are powered by the Legal Information Institute at Cornell Law School, and created in partnership with The Center for Computer-Assisted Legal Instruction (CALI).These rules govern the conduct of all criminal proceedings brought in Federal courts. Our Federal Rules ebooks include: The complete rules as of December 1, 2012 (for the 2013 edition). All notes of the Advisory Committee following each rule. Internal links to rules referenced within the rules. External links to the LII website\'s version of the US Code.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 117.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/federal-rules-of-criminal-procedure\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Criminal Law.\nSubject OTL 2 — nguyên bản ô CSV —: Law - Procedural Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Legal Information Institute - Editor',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(93,'OTL-118','GT-OTL000118','Federal Rules of Civil Procedure',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Civil procedure consists of the rules by which courts conduct civil trials. In the U.S., civil procedure usually takes the form of a series of rules and judicial practices. The federal courts follow the Federal Rules of Civil Procedure. This series of Federal Rules books, consisting of the Federal Rules of Evidence, Criminal Procedure and Civil Procedure, are powered by the Legal Information Institute at Cornell Law School, and created in partnership with The Center for Computer-Assisted Legal Instruction (CALI). You may download the books for free, but remember that publishing these books is not free for our organizations. These rules govern the conduct of all criminal proceedings brought in Federal courts. Our Federal Rules ebooks include: The complete rules as of December 1, 2014 (for the 2015 edition). All notes of the Advisory Committee following each rule. Internal links to rules referenced within the rules. External links to the LII website\'s version of the US Code.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 118.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/federal-rules-of-civil-procedure\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Civil Law.\nSubject OTL 2 — nguyên bản ô CSV —: Law - Procedural Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Legal Information Institute - Editor',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(94,'OTL-119','GT-OTL000119','The Ethics of Tax Lawyering - Third Edition',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'This chapter’s objective is to raise interesting tax ethics issues in practical contexts. There are 42 notes and questions to prompt and guide discussions, and primary source materials to inform the discussions (e.g., cases, IRC provisions, and Circular 230 excerpts).\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 119.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-ethics-of-tax-lawyering\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Michael Hatfield - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(95,'OTL-120','GT-OTL000120','Calculus for the Life Sciences: A Modeling Approach Volume 2',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'Our writing is based on three premises. First, life sciences students are motivated by and respond well to actual data related to real life sciences problems. Second, the ultimate goal of calculus in the life sciences primarily involves modeling living systems with difference and differential equations. Understanding the concepts of derivative and integral are crucial, but the ability to compute a large array of derivatives and integrals is of secondary importance. Third, the depth of calculus for life sciences students should be comparable to that of the traditional physics and engineering calculus course; else life sciences students will be short changed and their faculty will advise them to take the \'best\' (engineering) course. In our text, mathematical modeling and difference and differential equations lead, closely follow, and extend the elements of calculus. Chapter one introduces mathematical modeling in which students write descriptions of some observed processes and from these descriptions derive first order linear difference equations whose solutions can be compared with the observed data. In chapters in which the derivatives of algebraic, exponential, or trigonometric functions are defined, biologically motivated differential equations and their solutions are included. The chapter on partial derivatives includes a section on the diffusion partial differential equation. There are two chapters on non-linear difference equations and on systems of two difference equations and two chapters on differential equations and on systems of differential equation.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 120.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/calculus-for-the-life-sciences-a-modeling-approach-volume-2\nPublisher ô CSV: A.T. Still University.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: James L. Cornette - Author / Ralph A. Ackerman - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(96,'OTL-121','GT-OTL000121','Advanced Business Law and the Legal Environment',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Mayer, Warner, Siedel and Lieberman\'s Advanced Business Law and the Legal Environment is an up-to-date textbook with coverage of legal and regulatory issues that are more technical than the topics in the authors\' Foundations of Business Law and the Legal Environment. Appropriate for students who have already taken an introductory Legal Environment or Business Law course, the text is organized to permit instructors to tailor the materials to their particular approach. The authors take special care to engage students by relating law to everyday events with which they are already familiar with their clear, concise and readable style. Advanced Business Law and the Legal Environment provides students with context and essential legal concepts relating to the Uniform Commercial Code and various aspects of property law. The text provides the vocabulary and legal savvy necessary for business people to talk in an educated way to their customers, employees, suppliers, and other stakeholders — and to their own lawyers.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 121.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/advanced-business-law-and-the-legal-environment\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Law - Civil Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Don Mayer - Author / Daniel Warner - Author / George J. Siedel - Author / Jethro K. Lieberman - Author / Alyssa Rose Martina - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(97,'OTL-122','GT-ISBN9781453332917','Building Strategy and Performance',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'This book uses a balanced blend of frameworks and illustrations to teach you how to tackle the challenge of driving performance into the future. Kim Warren takes special care with this new textbook, Building Strategy and Performance, to ensure that it delivers instruction on how to deliver strategy powerfully over a sustained period of time. This book helps you to show your students where the levers are that they can control and how to choose what to do, when, and how much to achieve their specific goals. This book effectively outlines the dynamics of strategy, how one drives performance - past, today and into the future. It shows what causes performance to improve or deteriorate and what your students can do to change this trajectory for the better. But don\'t take our word for it, review the book now to see if it can help you to deliver the kind of tactical strategy course you desire for your students.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 122.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/building-strategy-and-performance\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453332917.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Management.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Kim Warren - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453332917.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(98,'OTL-123','GT-OTL000123','Electronic Commerce: The Strategic Perspective',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'This book is written both for practitioners and business students. Managers wishing to understand how electronic commerce is revolutionizing business will find that our comprehensive coverage of essential business issues (e.g., pricing and distribution) answers many of their questions. Advanced business students (junior, seniors, and graduate students) will find that the blend of academic structure and practical examples provides an engaging formula for learning. The book\'s title reflects some key themes that we develop. First, we are primarily concerned with electronic commerce, which we define as using technology (e.g., the Internet) to communicate or transact with stakeholders (e.g., customers). Second, we discuss how organizations must change in order to take advantage of electronic commerce opportunities. In this sense, our book offers the strategic perspective (i.e., the best way to operate a successful business in the 21st century). Third, with the growing importance of the Internet and related technologies, organizations must take electronic commerce into account when they are creating strategic plans. Thus, electronic commerce is a strategic perspective that all firms must adopt, both in the present and in the future. In other words, an organization that does not explicitly consider electronic commerce as a strategic imperative is probably making a crucial error. Here, we focus primarily on the opportunities and tactics that can lead to success in the electronic marketplace.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 123.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/electronic-commerce-the-strategic-perspective\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Business - Management.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Richard T. Watson - Author / Pierre Berthon - Author / Leyland F. Pitt - Author / George M. Zinkhan - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:01:00',NULL),(99,'OTL-124','GT-ISBN9781453343630','Corporate Governance',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Corporate Governance by de Kluyver is a primer on corporate governance. It is designed to help students understand corporate governance by looking at the subject from both a macro- and micro-perspective. Historical data and examples including the recent scandals that have torn the fabric of capitalism pave a pathway to the principal challenges facing today\'s corporate boards, and how to successfully manage them. Topics Include: Clear coverage on why proper corporate governance has become a moral imperative and how to corporations achieve it. Discussions on recent governance reforms in the United States. Outlines of the roles that each individual in the corporate governance process must take on and how to effectively execute on those roles. Exploration on the future of corporate governance in the epilogue Take some time to review Corporate Governance by de Kluyver to see if it is a good fit for your strategy courses.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 124.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/corporate-governance\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453343630.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Business - Human Resources.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Cornelis A. de Kluyver - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453343630.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(100,'OTL-125','GT-ISBN9781453343609','Developing New Products and Services',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Developing New Products and Services by Sanders is an outstanding contribution to market research. The book focuses on the upfront activities and ideas for new product and service development. A central theme of Developing New Products and Services is that there is, or should be, a constant struggle going on in every organization, business, and system between delivering feature-rich versions of products and services using extravagant engineering and delivering low-cost versions of products and services using frugal engineering. Students will come away with this notion and how to manifest it as a contributing employee at any company. A number of powerful concepts and tools are presented so your students can better understand how to facilitate new product development. For example, three templates are featured that facilitate new product and service development. The FAD (features, attributes, and design) template is used to identify the features and attributes that can be used for product and service differentiation. The Ten–Ten planning process contains two templates: an Organizational and Industry Analysis template and the Business Plan Overview template. These two templates coupled with the FAD template can be used to develop a full-blown business plan. In addition, Developing New Products and Services includes the following topics: entrepreneurship, technology and product life cycles, product and service versioning, product line optimization, creativity, lock-in real options, business valuation, and project management. Evaluate Developing New Products and Services by Sanders for your marketing courses today.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 125.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/developing-new-products-and-services\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453343609.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Management.\nSubject OTL 2 — nguyên bản ô CSV —: Engineering & Technology.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: G. Lawrence Sanders - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453343609.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(101,'OTL-126','GT-ISBN9781453328361','Economics – Theory Through Applications',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Russell Cooper and Andrew John have written an economics text aimed directly at students from its very inception. You\'re thinking, ”Yeah, sure. I\'ve heard that before.“ This textbook, Economics: Theory Through Applications, centers around student needs and expectations through two premises: … Students are motivated to study economics if they see that it relates to their own lives. … Students learn best from an inductive approach, in which they are first confronted with a problem, and then led through the process of solving that problem. Many books claim to present economics in a way that is digestible for students; Russell and Andrew have truly created one from scratch. This textbook will assist you in increasing students\' economic literacy both by developing their aptitude for economic thinking and by presenting key insights about economics that every educated individual should know. How? Russell and Andrew have done three things in this text to accomplish that goal: Applications Ahead of Theory: They present all the theory that is standard in Principles books. But by beginning with applications, students get to learn why this theory is needed. Learning through Repetition: Important tools appear over and over again, allowing students to learn from repetition and to see how one framework can be useful in many different contexts. A Student\'s Table of Contents vs. An Instructor\'s Table of Contents: There is no further proof that Russell and Andrew have created a book aimed specifically at educating students about economics than their two tables of contents.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 126.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/economics-theory-through-applications\nPublisher ô CSV: OTL ID 126 không có ô Publisher trong bản CSV tải về..\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453328361.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Economics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Russell Cooper - Author / Andrew John - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453328361.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(102,'OTL-127','GT-ISBN9781453328422','Macroeconomics: Theory through Applications',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Russell Cooper and Andrew John have written an economics text aimed directly at students from its very inception. You\'re thinking, ”Yeah, sure. I\'ve heard that before.“ This textbook, Macroeconomics: Theory Through Applications, centers around student needs and expectations through two premises: … Students are motivated to study economics if they see that it relates to their own lives. … Students learn best from an inductive approach, in which they are first confronted with a problem, and then led through the process of solving that problem. Many books claim to present economics in a way that is digestible for students; Russell and Andrew have truly created one from scratch. This textbook will assist you in increasing students\' economic literacy both by developing their aptitude for economic thinking and by presenting key insights about economics that every educated individual should know. How? Russell and Andrew have done three things in this text to accomplish that goal: 1. Applications Ahead of Theory: They present all the theory that is standard in Principles books. But by beginning with applications, students get to learn why this theory is needed. The authors take the kind of material that other authors put in ”applications boxes“ and place it at the heart of their book. Each chapter is built around a particular business or policy application, such as social security, globalization, and the wealth and poverty of nations. Why take this approach? Traditional courses focus too much on abstract theory relative to the interests and capabilities of the average undergraduate. Students are rarely engaged and the formal theory is never integrated into the way students think about economic issues. And traditional books are organized around theoretical constructs that mean nothing to students. The authors\' applications-first approach ensures that students will not see chapters with titles like ”Cost Functions“ or ”Short-Run Fluctuations“. They introduce tools and ideas as and when they are needed. Each chapter is designed with two goals. First, the application upon which the chapter is built provides a ”hook“ that gets students\' attention. Second, the application is a suitable vehicle a vehicle for teaching the principles of economics. 2. Learning through Repetition: Important tools appear over and over again, allowing students to learn from repetition and to see how one framework can be useful in many different contexts. Each piece of economic theory in this text is first introduced and explained in the context of a specific application. Most are re-used in other chapters, so students see them in action on multiple occasions. As students progress through the book, they accumulate a set of techniques and ideas. These are collected separately in a ”toolkit“ that provides students with an easy reference and also gives them a condensed summary of economic principles for examination preparation. 3. A Student\'s Table of Contents vs. An Instructor\'s Table of Contents: There is no further proof that Russell and Andrew have created a book aimed specifically at educating students about economics than their two tables of contents. The Student\'s Table of Contents speaks to students, piquing their interest to involve them in the economics, and a Instructor\'s Table of Contents with the economics to better help you organize your teaching—and frankly, you don\'t need to get excited by economics, you already are.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 127.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/macroeconomics-theory-through-applications\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453328422.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Economics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Russell Cooper - Author / Andrew John - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453328422.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(103,'OTL-128','GT-ISBN9781453332887','Focusing on Organizational Change',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Never before have strategic leaders been confronted with so much overwhelming change. The traditional approach is to teach the leader or leaders how to direct or control the organizations\' reaction on a monthly, weekly, or even daily basis. This approach is stressful and overwhelming for executive leaders, makes middle managers feel torn between honoring their senior leaders and listening to the demands of front line employees, and is alienating for front line employees. Focusing on Organizational Change offers an alternative to the traditional approach by focusing on building the change capacity of the entire organization in anticipation of future pressures to change. Based on systematic research of more than 5,000 respondents working within more than 200 organization or organizational units conducted during the previous decade, this book offers a clear and proven method for diagnosing your organizational change capacity. While building organizational change capacity is not fast or easy, it is essential for effective leadership and organizational survival in the 21st century.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 128.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/focusing-on-organizational-change\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453332887.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Business - Human Resources.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: William Q. Judge - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453332887.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(104,'OTL-129','GT-ISBN9781453343722','Foundations of Business Law and Legal Environment',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Mayer, Warner, Siedel and Lieberman\'s Foundations of Business Law and the Legal Environment is an up-to-date textbook with comprehensive coverage of legal and regulatory issues for your introductory Legal Environment or Business Law course. The text is organized to permit instructors to tailor the materials to their particular approach. The authors take special care to engage students by relating law to everyday events with which they are already familiar with their clear, concise and readable style. Business Law and the Legal Environment provides students with context and essential concepts across a broad range of legal issues with which managers and business executives must grapple. The text provides the vocabulary and legal savvy necessary for business people to talk in an educated way to their customers, employees, suppliers, government officials — and to their own lawyers.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 129.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/foundations-of-business-law-and-legal-environment\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453343722.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Law - Administrative Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Don Mayer - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453343722.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(105,'OTL-130','GT-ISBN9781453332870','Fundamentals of Global Strategy',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'The globalization of the competitive landscape has forced companies to fundamentally rethink their strategies. Whereas once only a few industries such as oil could be labeled truly global, today many—from pharmaceuticals to aircraft to computers—have become global in scale and scope. As a consequence, creating a global competitive advantage has become a key strategic issue for many companies, and students need to possess an understanding of the impact of global strategies on a business. Crafting a global strategy requires making decisions about which strategy elements can and should be globalized and to what extent, and de Kluyver\'s Fundamentals of Global Strategy can help you illuminate these facts to your students. Fundamentals of Global Strategy poses the following questions for your students to analyze: What markets and/or regions should a company compete in and why? To what degree can and should products and services be standardized? Is it advantageous to adopt a more or less uniform market positioning worldwide? What value-added activities should it keep in-house, outsource, or relocate for competitive advantage? How can competitive responses be most effectively coordinated on a global basis?\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 130.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/fundamentals-of-global-strategy\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453332870.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Management.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Cornelis A. de Kluyver - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453332870.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(106,'OTL-131','GT-ISBN9781453343272','Government Regulation and the Legal Environment of Business',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Mayer, Warner, Siedel and Lieberman\'s Government Regulation and the Legal Environment of Business is an up-to-date textbook that covers legal issues that students must understand in today\'s highly regulated business environment. The text is organized to permit instructors to tailor the materials to their particular approach. The authors take special care to engage students by relating law to everyday events with their clear, concise and readable style. After introductory chapters covering the legal environment of business, Government Regulation and the Legal Environment of Business provides students with context and essential legal concepts relating to contracts, consumer credit transactions, bankruptcy, intellectual property, securities regulation, regulation of real estate, antitrust, unfair trade practices, employment law and labor relations. The text provides the vocabulary and legal savvy they will need to talk in an educated way to customers, suppliers, employees, creditors, shareholders, government regulators and other stakeholders — and to their own lawyers.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 131.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/government-regulation-and-the-legal-environment-of-business\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453343272.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Administrative Law.\nSubject OTL 2 — nguyên bản ô CSV —: Business.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Don Mayer - Author / Daniel Warner - Author / George Siedel - Author / Jethro K. Lieberman - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453343272.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(107,'OTL-132','GT-ISBN9781453349755','Human Relations',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Human Relations by Laura Portolese-Dias addresses all of the critical topics to obtain career success as they relate to professional relationships. Knowing how to get along with others, resolve workplace conflict, manage relationships, communicate well, and make good decisions are all critical skills all students need to succeed in career and in life. Human Relations is not an organizational behavior; rather, it provides a good baseline of issues students will deal with in their careers on a day-to-day basis. It is also not a professional communications, business English, or professionalism textbook, as its focus is much broader — on general career success and how to effectively maneuver in the workplace. From communication challenges to focusing on one\'s own emotional intelligence, the examples throughout Human Relations will help students understand the importance of the human side in their career. This book\'s easy-to-understand language and tone is written to convey practical information in an engaging way. Every chapter opens with a realistic example which introduces a concept to be explained in detail later. Each chapter contains relevant examples, YouTube videos, figures, learning objectives, key takeaways, exercises, and a chapter-ending case that offer different ways to promote learning. Many of the end-of-section exercises offer self-assessment quizzes, so students may engage in self-understanding and development.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 132.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/human-relations\nPublisher ô CSV: LibreTexts.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453349755.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Human Resources.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Laura Portolese Dias - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453349755.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(108,'OTL-134','GT-ISBN9781453347485','Intermediate Algebra',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'It is essential to lay a solid foundation in mathematics if a student is to be competitive in today\'s global market. The importance of algebra, in particular, cannot be overstated, as it is the basis of all mathematical modeling used in applications found in all disciplines. Traditionally, the study of algebra is separated into a two parts, Elementary and Intermediate Algebra. This textbook by John Redden, Intermediate Algebra, is the second part. Written in a clear and concise manner, it carefully builds on the basics learned in Elementary Algebra and introduces the more advanced topics required for further study in applications found in most disciplines. Used as a standalone textbook, Intermediate Algebra offers plenty of review as well as something new to engage the student in each chapter. Written as a blend of the traditional and graphical approaches to the subject, this textbook introduces functions early and stresses the geometry behind the algebra. While CAS independent, a standard scientific calculator will be required and further research using technology is encouraged. Intermediate Algebra is written from the ground up in an open and modular format, allowing the instructor to modify it and leverage their individual expertise as a means to maximize the student experience and success. A more modernized element, embedded video examples, are present, but the importance of practice with pencil and paper is consistently stressed. Therefore, this text respects the traditional approaches to algebra pedagogy while enhancing it with the technology available today. The importance of Algebra cannot be overstated; it is the basis for all mathematical modeling used in all disciplines. After completing a course sequence based on Elementary and Intermediate Algebra, students will be on firm footing for success in higher-level studies at the college level.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 134.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/intermediate-algebra\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453347485.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Algebra.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: John Redden - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781453347485.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(109,'OTL-135','GT-ISBN9781453344873','Introductory Statistics',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'In many introductory level courses today, teachers are challenged with the task of fitting in all of the core concepts of the course in a limited period of time. The Introductory Statistics teacher is no stranger to this challenge. To add to the difficulty, many textbooks contain an overabundance of material, which not only results in the need for further streamlining, but also in intimidated students. Shafer and Zhang wrote Introductory Statistics by using their vast teaching experience to present a complete look at introductory statistics topics while keeping in mind a realistic expectation with respect to course duration and students\' maturity level. Over time the core content of this course has developed into a well-defined body of material that is substantial for a one-semester course. Shafer and Zhang believe that the students in this course are best served by a focus on that core material and not by an exposure to a plethora of peripheral topics. Therefore in writing Introduction to Statistics they have sought to present only the core concepts and use a wide-ranging set of exercises for each concept to drive comprehension. As a result Introduction to Statistics is a smaller and less intimidating textbook that trades some extended and unnecessary topics for a better-focused presentation of the central material. You will not only appreciate the depth and breadth of exercises in Introduction to Statistics, but you will also like the close attention to detail that Shafer and Zhang have paid to the student and instructor solutions manuals. This is one of few books on the market where the textbook authors have written the solutions manuals to maintain the integrity of the material. In addition, in order to facilitate the use of technology with the book the authors included “large data set exercises,” where appropriate, that refer to large data sets that are available on the web, and for which use of statistical software is necessary.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 135.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introductory-statistics\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453344873.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Applied.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Douglas S. Shafer - Author / Zhiyi Zhang - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781453344873.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(110,'OTL-136','GT-ISBN9781453332894','Leading with Cultural Intelligence',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Organizations in the 21st century are in need of culturally intelligent managers and leaders. The pressure to build authentic global networks and to cultivate an appreciation and respect for cultural differences and similarities has driven cultural intelligence to the forefront of diversity and inclusion work. Preparing today\'s students to be effective leaders in their professional lives requires that they hone their cultural intelligence as it is vital to working inter- and intra-culturally in today\'s global economy. This unique ability to identify, recognize, and acknowledge the differences and similarities that exist between and among cultural groups and systems will set their leadership skills apart from the masses. And when applied, cultural intelligence can bridge the gap in cultural misunderstanding by creating awareness, knowledge, and patience of cultural norms and behaviors. The purpose of Leading With Cultural Intelligence by Mia Moua is to outline the important ideas of cultural intelligence and the steps that must be considered and then practiced to become a culturally intelligent leader. The most important aspect covered within this book is that cultural intelligence is both a strategy and a tool towards cultural competency and proficiency. This book outlines the importance of understanding culture and its impact on organizations, the strategic value of cultural intelligence, and the significance of integrating and practicing cultural intelligence in everyday business life. When all these aspects are properly integrated and applied in the leadership and management process, organizations are more innovative and adaptable to respond to cultural changes.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 136.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/leading-with-cultural-intelligence\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453332894.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Business - Human Resources.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Mai Moua - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453332894.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(111,'OTL-137','GT-ISBN9781453345290','Managerial Accounting',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Kurt Heisinger and Joe Ben Hoyle believe that students want to learn accounting in the most efficient way possible, balancing coursework with personal schedules. They tend to focus on their studies in short intense segments between jobs, classes, and family commitments. Meanwhile, the accounting industry has endured dramatic shifts since the collapse of Enron and WorldCom, causing a renewed focus on ethical behavior in accounting. This dynamic author team designed Managerial Accounting to work within the confines of today\'s students\' lives while delivering a modern look at managerial accounting. Managerial Accounting was written around three major themes: Ready, Reinforcement and Relevance. This book is aimed squarely at the new learning styles evident with today\'s students and addresses accounting industry changes as well. Ready. Your students want to be as efficient as possible in their learning. This book adopts a concise, jargon-free, and easy-to-understand approach that is ready with concise sections and concepts when the student is ready to study in a format the student wants. Key concepts are provided in short segments with bullet points and step-by-step instructions to simplify concepts. This thoughtful, step-wise approach will help your students avoid distractions and focuses attention on the big picture. Reinforcement. Managerial Accounting boasts “Review Problems” at the end of each major section or learning objective which offer practical opportunities for students to apply what they have learned. These “Review Problems” allow students to immediately reinforce what they have learned and are provided within the body of the chapter along with the solutions. Relevance. Why is managerial accounting important? Since all students perform better when they can answer the “why” question, meaningful references to companies throughout the chapters help students tie the concepts presented in each chapter to real organizations. In addition, realistic managerial scenarios present an issue that must be addressed by the management accountant. These will pique your students\' interest and were designed to show how issues can be resolved using the concepts presented in the chapter. Finally, “Business in Action” features in Managerial Accounting link managerial decision-making to real business decisions to help your students complete the learning cycle from concept, to accounting decision, to real-world application. Managerial Accounting by Heisinger and Hoyle also contains a handful of other pedagogical aids to compliment your lectures and help your students come to class prepared. From a focus on decision-making, to end of chapter materials that can only be characterized as very deep and very wide, to ethics coverage, group projects and spreadsheet applications—these features allow you to teach the course you want to teach and assign the materials you like to assign.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 137.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/managerial-accounting\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453345290.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Accounting.\nSubject OTL 2 — nguyên bản ô CSV —: Business.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Kurt Heisinger - Author / Joe Hoyle - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453345290.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(112,'OTL-138','GT-ISBN9781447545545','The Adventure of Physics - Vol. I: Fall, Flow, and Heat',NULL,'Tiếng Anh',NULL,1990,NULL,NULL,NULL,NULL,1,0,'This book is written for anybody who is curious about nature and motion. Curiosity about how people, animals, things, images and space move leads to many adventures. This volume presents the best of them in the domain of everyday life. Carefully observing everyday motion allows us to deduce six essential statements: everyday motion is continuous, conserved, relative, reversible, mirror-invariant – and lazy. Yes, nature is indeed lazy: in every motion, it minimizes change. This text explores how these six results are deduced and how they fit with all those observations that seem to contradict them. In the structure of modern physics, shown in Figure 1, the results on everyday motion form the major part of the starting point at the bottom. The present volume is the first of a six-volume overview of physics. It resulted from a threefold aim I have pursued since 1990: to present motion in a way that is simple, up to date and captivating. In order to be simple, the text focuses on concepts, while keeping mathematics to the necessary minimum. Understanding the concepts of physics is given precedence over using formulae in calculations. The whole text is within the reach of an undergraduate. In order to be up to date, the text is enriched by the many gems – both theoretical and empirical – that are scattered throughout the scientific literature. In order to be captivating, the text tries to startle the reader as much as possible. Read- ing a book on general physics should be like going to a magic show. We watch, we are astonished, we do not believe our eyes, we think, and finally we understand the trick. When we look at nature, we often have the same experience. Indeed, every page presents at least one surprise or provocation for the reader to think about. Numerous interesting challenges are proposed. The motto of the text, die Menschen stärken, die Sachen klären, a famous statement by Hartmut von Hentig on pedagogy, translates as: ‘To fortify people, to clarify things.\' Clarifying things – and adhering only to the truth – requires courage, as changing the habits of thought produces fear, often hidden by anger. But by overcoming our fears we grow in strength. And we experience intense and beautiful emotions. All great adventures in life allow this, and exploring motion is one of them. Enjoy it!\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 138.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-adventure-of-physics-vol-i-fall-flow-and-heat\nPublisher ô CSV: Motion Mountain.\nCopyright Year ô CSV: 1990.\nISBN-13 ô CSV: 9781447545545.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Physics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Christoph Schiller - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781447545545.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(113,'OTL-139','GT-ISBN9781453328897','Principles of Sociological Inquiry – Qualitative and Quantitative Methods',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'The author of Principles of Sociological Inquiry: Qualitative and Quantitative Methods, Amy Blackstone, started envisioning this textbook while sitting in her own undergraduate sociology research methods class. She enjoyed the material but wondered about its relevance to her everyday life and future plans (the idea that one day she would be teaching such a class hadn\'t yet occurred to her). Now that she teaches the research methods course, she realizes that students today wonder the very same thing. While the importance of understanding research methods is usually clear to those students who intend to pursue an advanced degree, Amy wanted to write a text that would assist research methods teachers in demonstrating to all types of students the relevance of this course. In addition, Amy Blackstone\'s experience as an active researcher who uses both qualitative and quantitative methods made her acutely aware of the need for a balanced approach in teaching methods of sociological inquiry. Together, Amy Blackstone\'s experiences as a student, researcher, and teacher shape the three overriding objectives of Principles of Sociological Inquiry: Qualitative and Quantitative Methods: Relevance, Balance, and Accessibility. Principles of Sociological Inquiry: Qualitative and Quantitative Methods emphasizes the relevance of research methods for the everyday lives of its readers, undergraduate students.Each chapter describes how research methodology is useful for students in the multiple roles they fill: As consumers of popular and public information As citizens As current and future employees. Connections to these roles are made throughout and directly within the main text of the book Principles of Sociological Inquiry: Qualitative and Quantitative Methods also provides balanced coverage of qualitative and quantitative approaches by integrating a variety of examples from recent and classic sociological research. The text challenges students to debate and discuss the strengths and weaknesses of both approaches. Finally, one of the most important goals Amy had for Principles of Sociological Inquiry: Qualitative and Quantitative Methods was to introduce students to the core principles of social research in a way that is straightforward and engaging. As such, the text reflects public sociology\'s emphasis on making sociology accessible and readable. No one can validate that claim more than a teacher or student. So, take a look for yourself today and review Principles of Sociological Inquiry: Qualitative and Quantitative Methods by Amy Blackstone to see if its approach toward relevance, balance, and accessibility are right for your course and students.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 139.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/principles-of-sociological-inquiry-qualitative-and-quantitative-methods\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453328897.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Sociology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Amy Blackstone - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453328897.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(114,'OTL-140','GT-ISBN9781453345566','Small Business Management in the 21st Century',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Small Business Management in the 21st Century offers a unique perspective and set of capabilities for instructors. The authors designed this book with a “less can be more” approach, and by treating small business management as a practical human activity rather than as an abstract theoretical concept. The text has a format and structure that will be familiar to you if you use other books on small business management. Yet it brings a fresh perspective by incorporating three distinctive and unique themes and an important new feature (Disaster Watch) which is embedded throughout the entire text. These themes assure that students see the material in an integrated context rather than a stream of separate and distinct topics. First, the authors incorporate the use of technology and e-business as a way to gain competitive advantage over larger rivals. Technology is omnipresent in today\'s business world. Small business must use it to its advantage. We provide practical discussions and examples of how a small business can use these technologies without having extensive expertise or expenditures. Second, they explicitly acknowledge the constant need to examine how decisions affect cash flow by incorporating cash flow impact content in several chapters. As the life blood of all organizations, cash flow implications must be a factor in all business decision-making. Third, they recognize the need to clearly identify sources of customer value and bring that understanding to every decision. Decisions that do not add to customer value should be seriously reconsidered. Small Business Management in 21st Century boasts a new feature called Disaster Watch scenarios. Few texts cover, in any detail, some of the major hazards that small business managers face. Disaster Watch scenarios, included in most chapters, cover topics that include financing, bankers, creditors, employees, customers who don\'t pay, economic downturns, and marketing mistakes.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 140.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/small-business-management-in-the-21st-century\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453345566.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Business - Human Resources.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: David Cadden - Author / Sandra L. Lueder - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453345566.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(115,'OTL-141','GT-ISBN9781946135230','Social Problems - Continuity and Change',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Social Problems: Continuity and Change is a realistic but motivating look at the many issues that are facing our society today. As this book\'s subtitle, Continuity and Change, implies, social problems are persistent, but they have also improved in the past and can be improved in the present and future, provided that our nation has the wisdom and will to address them. It is easy for students to read a social problems textbook and come away feeling frustrated by the enormity of the many social problems facing us today. Social Problems: Continuity and Change certainly does not minimize the persistence of social problems, but neither does it overlook the possibilities for change offered by social research and by the activities of everyday citizens working to make a difference. Readers the book will find many examples of how social problems have been improved and of strategies that hold great potential for solving them today and in the future. You will find several pedagogical features help to convey the “continuity and change” theme of this text and the service sociology vision in which it is grounded: Each chapter begins with a “Social Problems in the News” story related to the social problem discussed in that chapter. These stories provide an interesting starting point for the chapter\'s discussion and show its relevance for real-life issues. Three types of boxes in each chapter provide examples of how social problems have been changed and can be changed. In no particular order, A first box, “Applying Social Research,” discusses how the findings from sociological and other social science research have either contributed to public policy related to the chapter\'s social problem or have the potential of doing so. A second box, “Lessons from Other Nations,” discusses how another nation or nations have successfully addressed the social problem of that chapter. A third box, “People Making a Difference,” discusses efforts by individuals, non-profit organizations or social change groups, or social movements relating to the chapter\'s social problem. Students will see many examples in this box of how ordinary people can indeed make a difference. A fourth box in each chapter, “Children and Our Future,” examines how the social problem discussed in that chapter particularly affects children, and it outlines the problem\'s repercussions for their lives as adolescents and adults. This box reinforces for students the impact of social problems on children and the importance of addressing these problems for their well-being as well as for the nation\'s well-being.Each chapter ends with a “Using What You Know” feature that presents students with a scenario involving the social problem from the chapter and that puts them in a decision-making role. This feature helps connect the chapter\'s theoretical discussion with potential real-life situations. Each chapter also ends with a “What You Can Do” feature that suggests several activities, strategies, or other efforts that students might undertake to learn more about and/or to address the social problem examined in the chapter. Like other aspects of the book, this feature helps counter “doom and gloom” feelings that little can be done about social problems. Other pedagogical features in each chapter include Learning Objectives at the beginning of a major section that highlight key topics to be learned; Key Takeaways at the end of a major section that highlight important points that were discussed in the section; For Your Review questions, also at the end of a major section, that have students think critically about that section\'s discussion; and a Summary that reviews the major points made in the chapter. The founders of American sociology a century or more ago in cities like Atlanta and Chicago wanted to reduce social inequality, to improve the lives of people of color, and more generally to find solutions to the most vexing social problems of their times. A former president of the Society for the Study of Social Problems, A. Javier Treviño, has used the term service sociology to characterize their vision of their new discipline. Social Problems: Continuity and Change is grounded in this vision by offering a sociological understanding of today\'s social problems and of possible solutions to these problems.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 141.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/social-problems-continuity-and-change\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781946135230.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Political Science.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781946135230.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(116,'OTL-142','GT-ISBN9781453346778','The Sustainable Business Case Book',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'The issue of sustainability and specifically sustainable business is of increasing interest and importance to students of business and also students in the sciences, government, public policy, planning and other fields. There can be significant benefits from students learning about sustainable business from the rich experiences of business practice. The Sustainable Business Case Book by Gittell, Magnusson and Merenda is one of the first of its kind. It combines the the theory of sustainability with key concepts, analytical information and contextual information with a collection of cases which provide insights, perspective and practical guidance on how sustainable businesses operate from different business functional area perspectives. The Sustainable Business Case Book can be used as a stand-alone text or as a supplemental textbook for undergraduate courses that have an interest in sustainable business. While the book\'s primary focus is on the relationship between business and sustainability, the book can also be used in courses offered in fields other than business, including environmental and earth systems sciences, environmental studies, urban planning, economics and public policy. The first part of The Sustainable Business Case Book, Chapter 1 through Chapter 3, introduces students to the meaning of sustainability, and the practice of sustainable business. The introductory chapters also describe key concepts, analytical frameworks, and contextual information relevant for the understanding of business sustainability. Chapter 1, defines sustainability and describes how and why businesses choose to engage in sustainable practices and how sustainable business practices relate to corporate profitability and social responsibility. Chapters 2 and 3 provide important background and contextual information affecting sustainable business practice. Chapter 2, The Science of Sustainability, reviews scientific evidence about climate change and the human and business influences on climate change. Chapter 3, Sustainability, Public Policy and Business, describes the significant role of government and public policy in sustainability, including setting the rules, regulations and laws that define the market and market opportunities for sustainable business practice. After presenting a framework for understanding business engagement in sustainability and helping your students develop a core background of information on sustainable business seven case studies across the business disciplines illustrating business sustainability practices are presented. At the beginning of each case study chapter Learning Objectives are listed with major sustainable business points and principles that the case will illustrate and illuminate. Each case chapter includes listing of Key Takeaways, Key Terms and Exercises for students. In each case chapter, there are four main areas of focus: Context and motivating interest in sustainability for company; Description of the sustainable business practice and how it was implemented; Results in terms of changes in sales/revenues, costs, profits and competitive positioning from the sustainable business practice; Challenges and opportunities, and future considerations as a result of the company implementing the sustainable business practice.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 142.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-sustainable-business-case-book\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453346778.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Management.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Ross Gittell - Author / Matt Magnusson - Author / Michael Merenda - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453346778.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:33','2026-05-06 09:00:00',NULL),(117,'OTL-143','GT-ISBN9781946135261','Mass Communication, Media, and Culture - An Introduction to Mass Communication',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'According to the author, the world did not need another introductory text in mass communication. But the world did need another kind of introductory text in mass communication, and that is how Understanding Media and Culture: An Introduction to Mass Communication was birthed. The only question was: What would be the purpose of another introductory mass communication text? Understanding Media and Culture: An Introduction to Mass Communication was written to squarely emphasize media technology. The author believes that an introduction to mass communication text should be a compelling, historical narrative sketching the *ongoing evolution* of media technology and how that technology shapes and is shaped by culture — and that is what he set out to deliver with his new textbook. Today\'s students are immersed in media technology. They live in a world of cell phones, smart phones, video games, iPods, laptops, Facebook, Twitter, FourSquare, and more. They fully expect that new technology will be developed tomorrow. Yet students often lack an historical perspective on media technology. They lack knowledge of the social, political and economic forces that shape media technology. This is not knowledge for knowledge\'s sake. It is knowledge that can help them understand, comprehend, appreciate, anticipate, shape and control media technology. With this focus, Understanding Media and Culture becomes an appropriate title. Indeed, the title has particular significance. Marshall McLuhan\'s Understanding Media is a key text in media studies. Written in the 1960s, Understanding Media was the subject of intense debates that continue to this day. Its central message was that the technology of media — not their content — was their most important feature. In a typically pithy phrase, McLuhan said, \"The medium is the message.\" The title, Understanding Media and Culture: An Introduction to Mass Communication, situates the introductory text in a large, engrossing theoretical conversation. The goal is to adopt a textbook that will support and complement your teaching of this course. Understanding Media and Culture: An Introduction to Mass Communication will support an engaging and interesting course experience for students that will not only show them the powerful social, political and economic forces will affect the future of media technology, but will challenge students to do their part in shaping that future.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 143.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/understanding-media-and-culture-an-introduction-to-mass-communication\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781946135261.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Journalism, Media Studies & Communications - New Media Journalism.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 700 — Nghệ thuật & Giải trí.',NULL,NULL,'700','utc-elibrary/book-covers/isbn/9781946135261.jpg',5,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:00:00',NULL),(118,'OTL-144','GT-OTL000144','Programming Fundamentals - A Modular Structured Approach using C++',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'Programming Fundamentals - A Modular Structured Approach using C++ is written by Kenneth Leroy Busbee, a faculty member at Houston Community College in Houston, Texas. The materials used in this textbook/collection were developed by the author and others as independent modules for publication within the Connexions environment. Programming fundamentals are often divided into three college courses: Modular/Structured, Object Oriented and Data Structures. This textbook/collection covers the first of those three courses. The learning modules of this textbook/collection were written as standalone modules. Students using a collection of modules as a textbook will usually view it contents by reading the modules sequentially as presented by the author of the collection. The learning modules of this textbook/collection were, for the most part, written without consideration of a speci??c programming language. In many cases the C++ language is discussed as part of the explanation of the concept. Often the examples used for C++ are exactly the same for the Java programming language. However, some modules were written speci??cally for the C++ programming language. This could not beavoided as the C++ language is used in conjunction with this textbook/collection by the author in teaching college courses.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 144.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/programming-fundamentals-a-modular-structured-approach-using-c\nPublisher ô CSV: OpenStax CNX.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science - Programming Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Kenneth Leroy Busbee - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(119,'OTL-150','GT-OTL000150','Algorithms and Data Structures With Applications to Graphics and Geometry',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'An introductory coverage of algorithms and data structures with application to graphics and geometry.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 150.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/algorithms-and-data-structures-with-applications-to-graphics-and-geometry\nPublisher ô CSV: Global Text Project.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Jurg Nievergelt - Author / Klaus Hinrichs - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(120,'OTL-153','GT-OTL000153','Educational Psychology - Second Edition',NULL,'Tiếng Anh',NULL,2009,NULL,NULL,NULL,NULL,1,0,'Chapters in the text can be assigned either from beginning to end, as with a conventional printed book, or they can be selected in some other sequence to meet the needs of particular students or classes. In general the first half of the book focuses on broader questions and principles taken from psychology per se, and the second half focuses on somewhat more practical issues of teaching. But the division between “theory” and “practice” is only approximate; all parts of the book draw on research, theory, and practical wisdom wherever appropriate. Chapter 2 is about learning theory, and Chapter 3 is about development; but as we point out, these topics overlap with each other as well as with the concerns of daily teaching. Chapter 4 is about several forms of student diversity (what might be called individual differences in another context), and Chapter 5 is about one form of diversity that has become prominent in schools recently—students with disabilities. Chapter 6 is about motivation, a topic that is heavily studied by psychological researchers, but that also poses perennial challenges to classroom teachers. Following these somewhat more basic psychological chapters, we turn to several lasting challenges of classroom life—challenges that seem to be an intrinsic part of the job. Chapter 7 offers ideas about classroom management; Chapter 8, ideas about communicating with students; Chapter 9, about ways to assist students\' complex forms of thinking; and Chapter 10, about planning instruction systematically. The book closes with two chapters about assessment of learning: Chapter 11 focuses on teachers\' own efforts to assess students, and Chapter 12 focuses on standardized measures of assessment. We have organized material and features in ways that we hope will allow for a variety of students, instructors, and institutions to use the book. For instructors and courses that seek a strong focus on research and the research process, for example, we have included an extra “chapter” on research methods—Appendix C, “The Reflective Practitioner”—that discusses the nature of research and the research process. We have also included a set of research-related case studies in Appendix B, “Deciding for yourself about the research”, that describe a number of particular educational research programs or topics in detail and that invite students to reflect on the quality and implications of the research. Whether or not a strong focus on research is a priority in your particular course, there are additional features of the book that are intended to help students in learning about educational psychology. In particular, each chapter ends with a “Chapter summary”, a list of “Key terms”, and links to Internet sites (called “Further resources”) relevant to the themes of the chapter. One of the sites that is cited frequently and that may be particularly helpful to instructors is the teachingedpsych wiki (http://teachingedpsych.wikispaces.com/), an archive of hundreds of teaching and learning materials that supports the teaching of introductory educational psychology. Teachingedpsych is a project of the Special Interest Group on the Teaching of Educational Psychology (TEP SIG), affiliated with the American Educational Research Association. All in all, we hope that you find Educational Psychology a useful and accessible part of your education. If you are preparing to be a teacher, good luck with your studies and your future! If you are an instructor, good luck with helping your students learn about this subject!\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 153.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/educational-psychology\nPublisher ô CSV: University of Manitoba.\nCopyright Year ô CSV: 2009.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Education.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences - Psychology.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Kelvin Seifert - Author / Rosemary Sutton - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(121,'OTL-154','GT-OTL000154','Fundamentals of Mathematics',NULL,'Tiếng Anh',NULL,2008,NULL,NULL,NULL,NULL,1,0,'Fundamentals of Mathematics is a work text that covers the traditional study in a modern prealgebra course, as well as the topics of estimation, elementary analytic geometry, and introductory algebra. It is intended for students who: have had previous courses in prealgebra wish to meet the prerequisites of higher level courses such as elementary algebra need to review fundamental mathematical concenpts and techniques This text will help the student devlop the insight and intuition necessary to master arithmetic techniques and manipulative skills. It was written with the following main objectives: to provide the student with an understandable and usable source of information to provide the student with the maximum oppurtinity to see that arithmetic concepts and techniques are logically based to instill in the student the understanding and intuitive skills necessary to know how and when to use particular arithmetic concepts in subsequent material cources and nonclassroom situations to give the students the ability to correctly interpret arithmetically obtained results We have tried to meet these objects by presenting material dynamically much the way an instructure might present the material visually in a classroom. (See the development of the concept of addition and subtraction of fractions in section 5.3 for examples) Intuition and understanding are some of the keys to creative thinking, we belive that the material presented in this text will help students realize that mathematics is a creative subject.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 154.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/fundamentals-of-mathematics\nPublisher ô CSV: OpenStax CNX.\nCopyright Year ô CSV: 2008.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Pure.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Denny Burzynski - Author / Wade Ellis - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(122,'OTL-155','GT-OTL000155','The Adventure of Physics - Vol. II: Relativity',NULL,'Tiếng Anh',NULL,1990,NULL,NULL,NULL,NULL,1,0,'This book is written for anybody who is curious about nature and motion. Curiosity about how people, animals, things, images and empty space move leads to many adven- tures. This volume presents the best of them in the domains of relativity and cosmology. In the study of motion – physics – special and general relativity form two important building blocks. Special relativity is the exploration of the energy speed limit c. General relativity is the exploration of the force limit c4/4G. The text shows that in both domains, all equations follow from these two limit values. This simple, intuitive and unusual way of learning relativity should reward the curiosity of every reader – whether student or professional. The present volume is the second of a six-volume overview of physics that arose from a threefold aim that I have pursued since 1990: to present motion in a way that is simple, up to date and captivating. In order to be simple, the text focuses on concepts, while keeping mathematics to the necessary minimum. Understanding the concepts of physics is given precedence over using formulae in calculations. The whole text is within the reach of an undergraduate. In order to be up to date, the text is enriched by the many gems – both theoretical and empirical – that are scattered throughout the scientific literature. In order to be captivating, the text tries to startle the reader as much as possible. Read- ing a book on general physics should be like going to a magic show. We watch, we are astonished, we do not believe our eyes, we think, and finally we understand the trick. When we look at nature, we often have the same experience. Indeed, every page presents at least one surprise or provocation for the reader to think about. Numerous interesting challenges are proposed. The motto of the text, die Menschen stärken, die Sachen klären, a famous statement by Hartmut von Hentig on pedagogy, translates as: ‘To fortify people, to clarify things.\' Clar- ifying things – and adhering only to the truth – requires courage, as changing the habits of thought produces fear, often hidden by anger. But by overcoming our fears we grow in strength. And we experience intense and beautiful emotions. All great adventures in life allow this, and exploring motion is one of them. Enjoy it!\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 155.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-adventure-of-physics-vol-ii-relativity\nPublisher ô CSV: Motion Mountain.\nCopyright Year ô CSV: 1990.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Physics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Christoph Schiller - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(123,'OTL-156','GT-OTL000156','The Adventure of Physics - Vol. III: Light, Charges, and Brains',NULL,'Tiếng Anh',NULL,1990,NULL,NULL,NULL,NULL,1,0,'This book is written for anybody who is curious about nature and motion. Curiosity about how people, animals, things, images and space move leads to many adventures. This volume presents the adventures one encounters when exploring everything electric. The story ranges from the weighing of electric current to the use of magnetic fields to heal bone fractures and up to the understanding of the human brain. In the structure of physics, shown in Figure 1, motion due to electricity is the most fascinating aspect of the starting point at the bottom. Indeed, almost everything around us is due to electric processes. The present introduction to electricity, magnetism, light and the brain is the third of a six-volume overview of physics that arose from a threefold aim that I have pursued since 1990: to present motion in a way that is simple, up to date and captivating. In order to be simple, the text focuses on concepts, while keeping mathematics to the necessary minimum. Understanding the concepts of physics is given precedence over using formulae in calculations. The whole text is within the reach of an undergraduate. In order to be up to date, the text is enriched by the many gems – both theoretical and empirical – that are scattered throughout the scientific literature. In order to be captivating, the text tries to startle the reader as much as possible. Read- ing a book on general physics should be like going to a magic show. We watch, we are astonished, we do not believe our eyes, we think, and finally we understand the trick. When we look at nature, we often have the same experience. Indeed, every page presents at least one surprise or provocation for the reader to think about. Numerous interesting challenges are proposed. The motto of the text, die Menschen stärken, die Sachen klären, a famous statement by Hartmut von Hentig on pedagogy, translates as: ‘To fortify people, to clarify things.\' Clar- ifying things – and adhering only to the truth – requires courage, as changing the habits of thought produces fear, often hidden by anger. But by overcoming our fears we grow in strength. And we experience intense and beautiful emotions. All great adventures in life allow this, and exploring motion is one of them. Enjoy it!\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 156.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-adventure-of-physics-vol-iii-light-charges-and-brains\nPublisher ô CSV: Motion Mountain.\nCopyright Year ô CSV: 1990.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Physics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Christoph Schiller - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(124,'OTL-157','GT-ISBN9781447560371','The Adventure of Physics - Vol. IV: The Quantum of Change',NULL,'Tiếng Anh',NULL,1990,NULL,NULL,NULL,NULL,1,0,'This book is written for anybody who is curious about nature and motion. Have you ever asked: Why do people, animals, things, images and space move? The answer leads to many adventures; this volume presents those due to the discovery that there is a smallest change value in nature. This smallest change value, the quantum of action, leads to what is called quantum physics. In the structure of modern physics, quantum physics covers three points; this volume covers the introduction to the point in the lower right: the foundations of quantum theory. The present introduction to quantum physics arose from a threefold aim I have pursued since 1990: to present the basics of motion in a way that is simple, up to date and captivating. In order to be simple, the text focuses on concepts, while keeping mathematics to the necessary minimum. Understanding the concepts of physics is given precedence over using formulae in calculations. The whole text is within the reach of an undergraduate. In order to be up to date, the text is enriched by the many gems – both theoretical and empirical – that are scattered throughout the scientific literature. In order to be captivating, the text tries to startle the reader as much as possible. Read- ing a book on general physics should be like going to a magic show. We watch, we are astonished, we do not believe our eyes, we think, and finally we understand the trick. When we look at nature, we often have the same experience. Indeed, every page presents at least one surprise or provocation for the reader to think about. Numerous interesting challenges are proposed. The motto of the text, die Menschen stärken, die Sachen klären, a famous statement by Hartmut von Hentig on pedagogy, translates as: ‘To fortify people, to clarify things.\' Clarifying things – and adhering only to the truth – requires courage, as changing the habits of thought produces fear, often hidden by anger. But by overcoming our fears we grow in strength. And we experience intense and beautiful emotions. All great adventures in life allow this, and exploring motion is one of them. Enjoy it!\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 157.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-adventure-of-physics-vol-iv-the-quantum-of-change\nPublisher ô CSV: Motion Mountain.\nCopyright Year ô CSV: 1990.\nISBN-13 ô CSV: 9781447560371.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Physics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Christoph Schiller - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781447560371.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:00:00',NULL),(125,'OTL-158','GT-OTL000158','The Adventure of Physics - Vol. V: Motion Inside Matter - Pleasure, Technology, and Stars',NULL,'Tiếng Anh',NULL,1990,NULL,NULL,NULL,NULL,1,0,'This book is written for anybody who is curious about nature and motion. Curiosity about how bodies, images and empty space move leads to many adventures. This volume presents the best adventures about the motion inside people, inside animals, and inside any other type of matter – from the largest stars to the smallest nuclei. Motion inside bodies – dead or alive – is described by quantum theory. Quantum theory describes all motion with the quantum of action h, the smallest change observed in nature. Building on this basic idea, the text first shows how to describe life, death and pleasure. Then, the text explains the observations of chemistry, materials science, astrophysics and particle physics. In the structure of physics, these topics correspond to the three ‘quantum\' points in Figure 1. The story of motion inside living and non-living matter, from the coldest gases to the hottest stars, is told here in a way that is simple, up to date and captivating. In order to be simple, the text focuses on concepts, while keeping mathematics to the necessary minimum. Understanding the concepts of physics is given precedence over using formulae in calculations. The whole text is within the reach of an undergraduate. In order to be up to date, the text is enriched by the many gems – both theoretical and empirical – that are scattered throughout the scientific literature. In order to be captivating, the text tries to startle the reader as much as possible. Read- ing a book on physics should be like going to a magic show. We watch, we are astonished, we do not believe our eyes, we think, and finally we understand the trick. When we look at nature, we often have the same experience. Indeed, every page presents at least one sur- prise that makes the reader think. Also numerous interesting challenges are proposed. The motto of the text, die Menschen stärken, die Sachen klären, a famous statement by Hartmut von Hentig on pedagogy, translates as: ‘To fortify people, to clarify things.\' Clar- ifying things – and adhering only to the truth – requires courage, as changing the habits of thought produces fear, often hidden by anger. But by overcoming our fears we grow in strength. And we experience intense and beautiful emotions. All great adventures in life allow this, and exploring motion is one of them. Enjoy it!\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 158.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-adventure-of-physics-vol-v-motion-inside-matter-pleasure-technology-and-stars\nPublisher ô CSV: Motion Mountain.\nCopyright Year ô CSV: 1990.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Physics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Christoph Schiller - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(126,'OTL-159','GT-OTL000159','The Adventure of Physics - Vol. VI: The Strand Model - A Speculation on Unification',NULL,'Tiếng Anh',NULL,2008,NULL,NULL,NULL,NULL,1,0,'This book is written for anybody who is intensely curious about nature and motion. Have you ever asked: Why do people, animals, things, images and empty space move? The answer leads to many adventures, and this book presents one of the best of them: the search for a precise, unified and final description of all motion. The wish to describe all motion is a large endeavour. Fortunately, this large endeavour can be structured in the simple diagram shown in Figure 1. The final and unified descrip- tion of motion, the topic of this book, corresponds to the highest point in the diagram. Searching for this final and unified description is an old quest. In the following, I briefly summarize its history and then present an intriguing, though speculative solution to the riddle. The search for the final, unified description of motion is a story of many surprises. For example, twentieth-century research has shown that there is a smallest distance in nature. Research has also shown that matter cannot be distinguished from empty space at those small distances. A last surprise dates from this century: particles and space are best described as made of strands, instead of little spheres or points. The present text explains how to reach these unexpected conclusions. In particular, quantum field theory, the standard model of particle physics, general relativity and cosmology are shown to follow from strands. The three gauge interactions, the three particle generations and the three dimensions of space turn out to be due to strands. In fact, all the open questions of twentieth-century physics about the foundations of motion, all the millennium issues, can be solved with the help of strands. The strand model, as presented in this text, is an unexpected result from a threefold aim that I have pursued since 1990, in the five previous volumes of this series: to present the basics of motion in a way that is up to date, captivating and simple. In retrospect, the aim for maximum simplicity has been central in deducing this speculation. While the previous volumes introduced, in an entertaining way, the established parts of physics, this volume presents, in the same entertaining and playful way, a speculation about uni- fication. Nothing in this volume is established knowledge – yet. The text is the original presentation of the topic. The search for a final theory is one of the great adventures of life: it leads to the limits of thought. The search overthrows our thinking habits about nature. A change in think- ing habits can produce fear, often hidden by anger. But by overcoming our fears we gain strength and serenity. Changing thinking habits thus requires courage, but it also pro- duces intense and beautiful emotions. Enjoy them!\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 159.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-adventure-of-physics-vol-vi-the-strand-model-a-speculation-on-unification\nPublisher ô CSV: Motion Mountain.\nCopyright Year ô CSV: 2008.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Physics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Christoph Schiller - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(127,'OTL-160','GT-ISBN9781105559297','Applied Discrete Structures',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'In writing this book, care was taken to use language and examples that gradually wean students from a simpleminded mechanical approach andmove them toward mathematical maturity. We also recognize that many students who hesitate to ask for help from an instructor need a readable text, and we have tried to anticipate the questions that go unasked. The wide range of examples in the text are meant to augment the \"favorite examples\" that most instructors have for teaching the topcs in discrete mathematics. To provide diagnostic help and encouragement, we have included solutions and/or hints to the odd-numbered exercises. These solutions include detailed answers whenever warranted and complete proofs, not just terse outlines of proofs. Our use of standard terminology and notation makes Applied Discrete Structures a valuable reference book for future courses. Although many advanced books have a short review of elementary topics, they cannot be complete. The text is divided into lecture-length sections, facilitating the organization of an instructor\'s presentation.Topics are presented in such a way that students\' understanding can be monitored through thought-provoking exercises. The exercises require an understanding of the topics and how they are interrelated, not just a familiarity with the key words. An Instructor\'s Guide is available to any instructor who uses the text. It includes: Chapter-by-chapter comments on subtopics that emphasize the pitfalls to avoid; Suggested coverage times; Detailed solutions to most even-numbered exercises; Sample quizzes, exams, and final exams. This textbook has been used in classes atCasper College (WY), Grinnell College (IA), Luzurne Community College (PA), University of the Puget Sound (WA).\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 160.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/applied-discrete-structures\nPublisher ô CSV: Alan Doerr & Kenneth Levasseur.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: 9781105559297.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Applied.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Alan Doerr - Author / Kenneth Levasseur - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781105559297.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:00:00',NULL),(128,'OTL-161','GT-OTL000161','Operating Systems and Middleware: Supporting Controlled Interaction',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'In this book, you will learn about all three kinds of interaction. In all three cases, interesting software techniques are needed in order to bring the computations into contact, yet keep them suffciently at arm\'s length that they don\'t compromise each other\'s reliability. The exciting challenge, then, is supporting controlled interaction. This includes support for computations that share a single computer and interact with one another, as your email and word processing programs do. It also includes support for data storage and network communication. This book describes how all these kinds of support are provided both by operating systems and by additional software layered on top of operating systems, which is known as middleware. Chapter 1 provides an overview of the text as a whole, explaining what an operating system is, what middleware is, and what sorts of support these systems provide for controlled interaction. The next nine chapters work through the varieties of controlled interac- tion that are exemplified by the scenario at the beginning of the preface: in- teraction between concurrent computations on the same system (as between your email program and your word processor), interaction across time (as between your word processor before your trip and your word processor after your trip), and interaction across space (as between your email program and your service provider\'s email server). The first of these three topics is controlled interaction between computa- tions operating at one time on a particular computer. Before such interaction can make sense, you need to understand how it is that a single computer can be running more than one program, such as an email program in one window and a word processing program in another. Therefore, Chapter 2 explains the fundamental mechanism for dividing a computer\'s attention between concurrent computations, known as threads. Chapter 3 continues with the related topic of scheduling. That is, if the computer is dividing its time between computations, it needs to decide which ones to work on at any moment. With concurrent computations explained, Chapter 4 introduces con- trolled interactions between them by explaining synchronization, which is control over the threads\' relative timing. For example, this chapter explains how, when your email program sends a document to your word processor, the word processor can be constrained to read the document only after the email program writes it. One particularly important form of synchroniza- tion, atomic transactions, is the topic of Chapter 5. Atomic transactions are groups of operations that take place as an indivisible unit; they are most commonly supported by middleware, though they are also playing an increasing role in operating systems. Other than synchronization, the main way that operating systems con- trol the interaction between computations is by controlling their access to memory. Chapter 6 explains how this is achieved using the technique known as virtual memory. That chapter also explains the many other objectives this same technique can serve. Virtual memory serves as the foundation for Chapter 7\'s topic, which is processes. A process is the fundamental unit of computation for protected access, just as a thread is the fundamental unit of computation for concurrency. A process is a group of threads that share a protection environment; in particular, they share the same access to virtual memory. The next three chapters move outside the limitations of a single com- puter operating in a single session. First, consider the document stored before a trip and available again after it. Chapter 8 explains persistent storage mechanisms, focusing particularly on the file storage that operat- ing systems provide. Second, consider the interaction between your email program and your service provider\'s email server. Chapter 9 provides an overview of networking, including the services that operating systems make available to programs such as the email client and server. Chapter 10 ex- tends this discussion into the more sophisticated forms of support provided by communication middleware, such as messaging systems, RMI, and web services. Finally, Chapter 11 focuses on security. Because security is a pervasive issue, the preceding ten chapters all provide some information on it as well. Specifically, the final section of each chapter points out ways in which se- curity relates to that chapter\'s particular topic. However, even with that coverage distributed throughout the book, a chapter specifically on security is needed, primarily to elevate it out of technical particulars and talk about general principles and the human and organizational context surrounding the computer technology. The best way to use these chapters is in consecutive order. However, Chapter 5 can be omitted with only minor harm to Chapters 8 and 10, and Chapter 9 can be omitted if students are already suffciently familiar with networking.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 161.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/operating-systems-and-middleware-supporting-controlled-interaction\nPublisher ô CSV: Max Hailperin.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Max Hailperin - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(129,'OTL-165','GT-ISBN9781602351967','Writing Spaces: Readings on Writing Vol. II',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'Volumes in Writing Spaces: Readings on Writing offer multiple perspectives on a wide-range of topics about writing. In each chapter, authors present their unique views, insights, and strategies for writing by addressing the undergraduate reader directly. Drawing on their own experiences, these teachers-as-writers invite students to join in the larger conversation about the craft of writing. Consequently, each essay functions as a standalone text that can easily complement other selected readings in writing or writing-intensive courses across the disciplines at any level. Volume 2 continues the tradition of the previous volume with topics, such as the rhetorical situation, collaboration, documentation styles, weblogs, invention, writing assignment interpretation, reading critically, information literacy, ethnography, interviewing, argument, document design, and source integration.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 165.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/writing-spaces-readings-on-writing-vol-ii\nPublisher ô CSV: Parlor Press.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: 9781602351967.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Charlie Lowe - Author / Pavel Zemliansky - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781602351967.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:00:00',NULL),(130,'OTL-166','GT-OTL000166','Foundations of Computation',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'Foundations of Computation is a free textbook for a one-semester course in theoretical computer science. It has been used for several years in a course at Hobart and William Smith Colleges. The course has no prerequisites other than introductory computer programming. The first half of the course covers material on logic, sets, and functions that would often be taught in a course in discrete mathematics. The second part covers material on automata, formal languages, and grammar that would ordinarily be encountered in an upper level course in theoretical computer science.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 166.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/foundations-of-computation\nPublisher ô CSV: Carol Crichlow and David Eck.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Carol Critchlow - Author / David Eck - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(131,'OTL-167','GT-ISBN9781947172517','Biology - 2e',NULL,'Tiếng Anh',NULL,2018,NULL,NULL,NULL,NULL,1,0,'Biology 2e is designed to cover the scope and sequence requirements of a typical two-semester biology course for science majors. The text provides comprehensive coverage of foundational research and core biology concepts through an evolutionary lens. Biology includes rich features that engage students in scientific inquiry, highlight careers in the biological sciences, and offer everyday applications. The book also includes various types of practice and homework questions that help students understand—and apply—key concepts. The 2nd edition has been revised to incorporate clearer, more current, and more dynamic explanations, while maintaining the same organization as the first edition. Art and illustrations have been substantially improved, and the textbook features additional assessments and related resources.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 167.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/biology-2e\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2018.\nISBN-13 ô CSV: 9781947172517.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Biology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Mary Ann Clark - Author / Jung Choi - Author / Matthew Douglas - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781947172517.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:00:00',NULL),(132,'OTL-168','GT-ISBN9781947172036','Concepts of Biology',NULL,'Tiếng Anh',NULL,2023,NULL,NULL,NULL,NULL,1,0,'Concepts of Biology is designed for the typical introductory biology course for nonmajors, covering standard scope and sequence requirements. The text includes interesting applications and conveys the major themes of biology, with content that is meaningful and easy to understand. The book is designed to demonstrate biology concepts and to promote scientific literacy.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 168.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/concepts-of-biology\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2023.\nISBN-13 ô CSV: 9781947172036.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Biology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Samantha Fowler - Author / Rebecca Roush - Author / James Wise - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781947172036.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:00:00',NULL),(133,'OTL-169','GT-ISBN9781938168130','Anatomy and Physiology - 2e',NULL,'Tiếng Anh',NULL,2021,NULL,NULL,NULL,NULL,1,0,'Anatomy and Physiology 2e is developed to meet the scope and sequence for a two-semester human anatomy and physiology course for life science and allied health majors. The book is organized by body systems. The revision focuses on inclusive and equitable instruction and includes new student support. Illustrations have been extensively revised to be clearer and more inclusive. The web-based version of Anatomy and Physiology 2e also features links to surgical videos, histology, and interactive diagrams. Please learn more about the changes by previewing the preface.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 169.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/anatomy-and-physiology\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2021.\nISBN-13 ô CSV: 9781938168130.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Biology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 600 — Công nghệ (Khoa học ứng dụng).\nContributors — nguyên bản ô CSV —: J. Gordon Betts - Author / Kelly A. Young - Author / James A Wise - Author',NULL,NULL,'600','utc-elibrary/book-covers/isbn/9781938168130.jpg',4,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:00:00',NULL),(134,'OTL-170','GT-ISBN9781927356173','Mind, Body, World: Foundations of Cognitive Science',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'Cognitive science arose in the 1950s when it became apparent that a number of disciplines, including psychology, computer science, linguistics, and philosophy, were fragmenting. Perhaps owing to the field\'s immediate origins in cybernetics, as well as to the foundational assumption that cognition is information processing, cognitive science initially seemed more unified than psychology. However, as a result of differing interpretations of the foundational assumption and dramatically divergent views of the meaning of the term information processing, three separate schools emerged: classical cognitive science, connectionist cognitive science, and embodied cognitive science. Examples, cases, and research findings taken from the wide range of phenomena studied by cognitive scientists effectively explain and explore the relationship among the three perspectives. Intended to introduce both graduate and senior undergraduate students to the foundations of cognitive science, Mind, Body, World addresses a number of questions currently being asked by those practicing in the field: What are the core assumptions of the three different schools? What are the relationships between these different sets of core assumptions? Is there only one cognitive science, or are there many different cognitive sciences? Giving the schools equal treatment and displaying a broad and deep understanding of the field, Dawson highlights the fundamental tensions and lines of fragmentation that exist among the schools and provides a refreshing and unifying framework for students of cognitive science.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 170.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/mind-body-world-foundations-of-cognitive-science\nPublisher ô CSV: Athabasca University Press.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: 9781927356173.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences - Psychology.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Michael R. W. Dawson - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781927356173.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:00:00',NULL),(135,'OTL-171','GT-ISBN9781927356388','Open Data Structures: An Introduction',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'Offered as an introduction to the field of data structures and algorithms, Open Data Structures covers the implementation and analysis of data structures for sequences (lists), queues, priority queues, unordered dictionaries, ordered dictionaries, and graphs. Focusing on a mathematically rigorous approach that is fast, practical, and efficient, Morin clearly and briskly presents instruction along with source code. Analyzed and implemented in Java, the data structures presented in the book include stacks, queues, deques, and lists implemented as arrays and linked-lists; space-efficient implementations of lists; skip lists; hash tables and hash codes; binary search trees including treaps, scapegoat trees, and red-black trees; integer searching structures including binary tries, x-fast tries, and y-fast tries; heaps, including implicit binary heaps and randomized meldable heaps; graphs, including adjacency matrix and adjacency list representations; and B-trees. A modern treatment of an essential computer science topic, Open Data Structures is a measured balance between classical topics and state-of-the art structures that will serve the needs of all undergraduate students or self-directed learners.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 171.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/open-data-structures-an-introduction\nPublisher ô CSV: Athabasca University Press.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: 9781927356388.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Pat Morin - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781927356388.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:00:00',NULL),(136,'OTL-172','GT-OTL000172','Contract Doctrine, Theory & Practice Volume 3',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'This is Volume 3 in a three volume series written for Contracts Law. Its former title is \"Collaborative Teaching Materials for Contracts.\" The first semester of law school is mostly about learning to speak a new legal language (but emphatically not “legalese”), to formulate and evaluate legal arguments, to become comfortable with the distinctive style of legal analysis. We could teach these skills using almost any legal topic. But we begin the first-year curriculum with subjects that pervade the entire field of law. Contract principles have a long history and they form a significant part of the way that lawyers think about many legal problems. As you will discover when you study insurance law, employment law, family law, and dozens of other practice areas, your knowledge of contract doctrine and theory will be invaluable.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 172.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/contract-doctrine-theory-practice-volume-3\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Contract Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: J.H. Verkerke - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(137,'OTL-173','GT-OTL000173','Elementary Differential Equations with Boundary Value Problems',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'Elementary Differential Equations with Boundary Value Problems is written for students in science, engineering, and mathematics who have completed calculus through partial differentiation. An elementary text should be written so the student can read it with comprehension without too much pain. I have tried to put myself in the student\'s place, and have chosen to err on the side of too much detail rather than not enough. An elementary text can\'t be better than its exercises. This text includes 1695 numbered exercises, many with several parts. They range in difficulty from routine to very challenging. An elementary text should be written in an informal but mathematically accurate way, illustrated by appropriate graphics. I have tried to formulate mathematical concepts succinctly in language that students can understand. I have minimized the number of explicitly stated theorems and definitions, preferring to deal with concepts in a more conversational way, copiously illustrated by 250 completely worked out examples. Where appropriate, concepts and results are depicted in 144 figures. Although I believe that the computer is an immensely valuable tool for learning, doing, and writing mathematics, the selection and treatment of topics in this text reflects my pedagogical orientation along traditional lines. However, I have incorporated what I believe to be the best use of modern technology, so you can select the level of technology that you want to include in your course. The text includes 336 exercises – identified by the symbols C and C/G – that call for graphics or computation and graphics. There are also 73 laboratory exercises – identified by L – that require extensive use of technology. In addition, several sections include informal advice on the use of technology. If you prefer not to emphasize technology, simply ignore these exercises and the advice.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 173.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/elementary-differential-equations-with-boundary-value-problems\nPublisher ô CSV: A.T. Still University.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Engineering & Technology.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Calculus.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: William F. Trench - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(138,'OTL-174','GT-OTL000174','Introduction to Real Analysis',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'This is a text for a two-term course in introductory real analysis for junior or senior mathematics majors and science students with a serious interest in mathematics. Prospective educators or mathematically gifted high school students can also benefit from the mathematical maturity that can be gained from an introductory real analysis course. The book is designed to fill the gaps left in the development of calculus as it is usually presented in an elementary course, and to provide the background required for insight into more advanced courses in pure and applied mathematics. The standard elementary calculus sequence is the only specific prerequisite for Chapters 1–5, which deal with real-valued functions. (However, other analysis oriented courses, such as elementary differential equation, also provide useful preparatory experience.) Chapters 6 and 7 require a working knowledge of determinants, matrices and linear transformations, typically available from a first course in linear algebra. Chapter 8 is accessible after completion of Chapters 1–5.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 174.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-real-analysis\nPublisher ô CSV: A.T. Still University.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: 0130457868.\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Analysis.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Applied.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: William F. Trench - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(139,'OTL-176','GT-OTL000176','Precalculus',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Prior to 1990, the performance of a student in precalculus at the University of Washington was not a predictor of success in calculus. For this reason, the mathematics department set out to create a new course with a specific set of goals in mind: A review of the essential mathematics needed to succeed in calculus. An emphasis on problem solving, the idea being to gain both experience and confidence in working with a particular set of mathematical tools. This text was created to achieve these goals and the 2004-05 academic year marks the eleventh year in which it has been used. Several thousand students have successfully passed through the course. This book is full of worked out examples. We use the the notation “Soluion.” to indicate where the reasoning for a problem begins; the symbol ?? is used to indicate the end of the solution to a problem. There is a Table of Contents that is useful in helping you find a topic treated earlier in the course. It is also a good rough outline when it comes time to study for the final examination. The book also includes an index at the end. Finally, there is an appendix at the end of the text with ”answers” to most of the problems in the text. It should be emphasized these are ”answers” as opposed to ”solutions”. Any homework problems you may be asked to turn in will require you include all your work; in other words, a detailed solution. Simply writing down the answer from the back of the text would never be sufficient; the answers are intended to be a guide to help insure you are on the right track.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 176.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/precalculus-2016\nPublisher ô CSV: A.T. Still University.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Free Documentation License (GNU).\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: David H. Collingwood - Author / K. David Prince - Author / Matthew M. Conroy - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(140,'OTL-177','GT-OTL000177','A Gentle Introduction to the Art of Mathematics',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'This book is designed for the transition course between calculus and differential equations and the upper division mathematics courses with an emphasis on proof and abstraction. The book has been used by the author and several other faculty at Southern Connecticut State University. There are nine chapters and more than enough material for a semester course. Student reviews are favorable. It is written in an informal, conversational style with a large number of interesting examples and exercises, so that a student learns to write proofs while working on engaging problems.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 177.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/a-gentle-introduction-to-the-art-of-mathematics-177\nPublisher ô CSV: Southern Connecticut State University.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Free Documentation License (GNU).\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Pure.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Joseph E. Fields - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(141,'OTL-178','GT-ISBN9781974206841','Active Calculus 2.0',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'Active Calculus is different from most existing calculus texts in at least the following ways: the text is freely readable online in HTML format and is also available for in PDF; in the electronic format, graphics are in full color and there are live links to java applets; version 2.0 now contains WeBWorK exercises in each chapter, which are fully interactive in the HTML format and included in print in the PDF; the text is open source, and interested users can gain access to the original source files on GitHub; the style of the text requires students to be active learners — there are very few worked examples in the text, with there instead being 3-4 activities per section that engage students in connecting ideas, solving problems, and developing understanding of key calculus concepts; each section begins with motivating questions, a brief introduction, and a preview activity, all of which are designed to be read and completed prior to class; following the WeBWorK exercises in each section, there are several challenging problems that require students to connect key ideas and write to communicate their understanding.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 178.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/active-calculus-2-0\nPublisher ô CSV: Grand Valley State University.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: 9781974206841.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Matt Boelkins - Author / David Austin - Author / Steve Schlicker - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781974206841.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:00:00',NULL),(142,'OTL-182','GT-OTL000182','Combinatorics Through Guided Discovery',NULL,'Tiếng Anh',NULL,2004,NULL,NULL,NULL,NULL,1,0,'This book is an introduction to combinatorial mathematics, also known as combinatorics. The book focuses especially but not exclusively on the part of combinatorics that mathematicians refer to as “counting.” The book consists almost entirely of problems. Some of the problems are designed to lead you to think about a concept, others are designed to help you figure out a concept and state a theorem about it, while still others ask you to prove the theorem. Other problems give you a chance to use a theorem you have proved. From time to time there is a discussion that pulls together some of the things you have learned or introduces a new idea for you to work with. Many of the problems are designed to build up your intuition for how combinatorial mathematics works. There are problems that some people will solve quickly, and there are problems that will take days of thought for everyone. Probably the best way to use this book is to work on a problem until you feel you are not making progress and then go on to the next one. Think about the problem you couldn\'t get as you do other things. The next chance you get, discuss the problem you are stymied on with other members of the class. Often you will all feel you\'ve hit dead ends, but when you begin comparing notes and listening carefully to each other, you will see more than one approach to the problem and be able to make some progress. In fact, after comparing notes you may realize that there is more than one way to interpret the problem. In this case your first step should be to think together about what the problem is actually asking you to do. You may have learned in school that for every problem you are given, there is a method that has already been taught to you, and you are supposed to figure out which method applies and apply it. That is not the case here. Based on some simplified examples, you will discover the method for yourself. Later on, you may recognize a pattern that suggests you should try to use this method again.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 182.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/combinatorics-through-guided-discovery\nPublisher ô CSV: Kenneth P. Bogart.\nCopyright Year ô CSV: 2004.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Free Documentation License (GNU).\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Applied.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Kenneth P. Bogart - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(143,'OTL-187','GT-OTL000187','A Computational Introduction to Number Theory and Algebra',NULL,'Tiếng Anh',NULL,2009,NULL,NULL,NULL,NULL,1,0,'All of the mathematics required beyond basic calculus is developed “from scratch.” Moreover, the book generally alternates between “theory” and “applications”: one or two chapters on a particular set of purely mathematical concepts are followed by one or two chapters on algorithms and applications; the mathematics provides the theoretical underpinnings for the applications, while the applications both motivate and illustrate the mathematics. Of course, this dichotomy between theory and applications is not perfectly maintained: the chapters that focus mainly on applications include the development of some of the mathematics that is specific to a particular application, and very occasionally, some of the chapters that focus mainly on mathematics include a discussion of related algorithmic ideas as well. The mathematical material covered includes the basics of number theory (including unique factorization, congruences, the distribution of primes, and quadratic reciprocity) and of abstract algebra (including groups, rings, fields, and vector spaces). It also includes an introduction to discrete probability theory—this material is needed to properly treat the topics of probabilistic algorithms and cryptographic applications. The treatment of all these topics is more or less standard, except that the text only deals with commutative structures (i.e., abelian groups and commutative rings with unity) — this is all that is really needed for the purposes of this text, and the theory of these structures is much simpler and more transparent than that of more general, non-commutative structures. There are a few sections that are marked with a “(∗),” indicating that the material covered in that section is a bit technical, and is not needed else- where. There are many examples in the text, which form an integral part of the book, and should not be skipped. There are a number of exercises in the text that serve to reinforce, as well as to develop important applications and generalizations of, the material presented in the text. Some exercises are underlined. These develop important (but usually simple) facts, and should be viewed as an integral part of the book. It is highly recommended that the reader work these exercises, or at the very least, read and understand their statements. In solving exercises, the reader is free to use any previously stated results in the text, including those in previous exercises. However, except where otherwise noted, any result in a section marked with a “(∗),” or in §5.5, need not and should not be used outside the section in which it appears. There is a very brief “Preliminaries” chapter, which fixes a bit of notation and recalls a few standard facts. This should be skimmed over by the reader. There is an appendix that contains a few useful facts; where such a fact is used in the text, there is a reference such as “see §An,” which refers to the item labeled “An” in the appendix.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 187.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/a-computational-introduction-to-number-theory-and-algebra\nPublisher ô CSV: Cambridge University Press.\nCopyright Year ô CSV: 2009.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Algebra.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Applied.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Victor Shoup - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(144,'OTL-188','GT-OTL000188','Linear Algebra',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'We believe the entire book can be taught in twenty five 50-minute lectures to a sophomore audience that has been exposed to a one year calculus course. Vector calculus is useful, but not necessary preparation for this book, which attempts to be self-contained. Key concepts are presented multiple times, throughout the book, often first in a more intuitive setting, and then again in a definition, theorem, proof style later on. We do not aim for students to become agile mathematical proof writers, but we do expect them to be able to show and explain why key results hold. We also often use the review exercises to let students discover key results for themselves; before they are presented again in detail later in the book. The book has been written such that instructors can reorder the chapters (using the La- TeX source) in any (reasonable) order and still have a consistent text. We hammer the notions of abstract vectors and linear transformations hard and early, while at the same time giving students the basic matrix skills necessary to perform computations. Gaussian elimination is followed directly by an “exploration chapter” on the simplex algorithm to open students minds to problems beyond standard linear systems ones. Vectors in Rn and general vector spaces are presented back to back so that students are not stranded with the idea that vectors are just ordered lists of numbers. To this end, we also labor the notion of all functions from a set to the real numbers. In the same vein linear transformations and matrices are presented hand in hand. Once students see that a linear map is specified by its action on a limited set of inputs, they can already understand what a basis is. All the while students are studying linear systems and their solution sets, so after matrices determinants are introduced. This material can proceed rapidly since elementary matrices were already introduced with Gaussian elimination. Only then is a careful discussion of spans, linear independence and dimension given to ready students for a thorough treatment of eigenvectors and diagonalization. The dimension formula therefore appears quite late, since we prefer not to elevate rote computations of column and row spaces to a pedestal. The book ends with applications–least squares and singular values. These are a fun way to end any lecture course. It would also be quite easy to spend any extra time on systems of differential equations and simple Fourier transform problems.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 188.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/linear-algebra-2016\nPublisher ô CSV: University of California, Davis.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Algebra.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: David Cherney - Author / Tom Denton - Author / Andrew K. Waldon - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(145,'OTL-189','GT-OTL000189','Information Systems for Business and Beyond',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'This book is written as an introductory text, meant for those with little or no experience with computers or information systems. While sometimes the descriptions can get a little bit technical, every effort has been made to convey the information essential to understanding a topic while not getting bogged down in detailed terminology or esoteric discussions. Information Systems for Business and Beyond was written by Dr. David Bourgeois and originally published in 2014 as part of the Open Textbook Challenge at the Saylor Foundation. Since then, it has been accessed thousands of time and used in many courses worldwide. This 2019 update to the textbook brings it up to date and adds many new topics. True to its open textbook roots, many of the updates have come from the community of instructors and practitioners who are passionate about information systems. Please note that the XML and MS Word links go to an earlier version.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 189.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/information-systems-for-business-and-beyond\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science - Information Systems.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: David T. Bourgeois - Author / James L. Smith - Author / Shouhong Wang - Author / Joseph Mortati - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:01:00',NULL),(146,'OTL-190','GT-ISBN9780989722629','The Information Literacy User\'s Guide: An Open, Online Textbook',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'Good researchers have a host of tools at their disposal that make navigating today\'s complex information ecosystem much more manageable. Gaining the knowledge, abilities, and self-reflection necessary to be a good researcher helps not only in academic settings, but is invaluable in any career, and throughout one\'s life. The Information Literacy User\'s Guide will start you on this route to success. The Information Literacy User\'s Guide is based on two current models in information literacy: The 2011 version of The Seven Pillars Model, developed by the Society of College, National and University Libraries in the United Kingdom and the conception of information literacy as a metaliteracy, a model developed by one of this book\'s authors in conjunction with Thomas Mackey, Dean of the Center for Distance Learning at SUNY Empire State Col- lege.2 These core foundations ensure that the material will be relevant to today\'s students. The Information Literacy User\'s Guide introduces students to critical concepts of information literacy as defined for the information-infused and technology-rich environment in which they find themselves. This book helps students examine their roles as information creators and sharers and enables them to more effectively deploy related skills. This textbook includes relatable case studies and scenarios, many hands-on exercises, and interactive quizzes.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 190.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-information-literacy-user-s-guide-an-open-online-textbook\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9780989722629.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Education - Higher Education.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Deborah Bernnard - Author / Greg Bobish - Author / Daryl Bullis - Author / Jenna Hecker - Author / Irina Holden - Author / Allison Hosier - Author / Trudi Jacobson - Author / Tor Loney - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9780989722629.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:00:00',NULL),(147,'OTL-191','GT-ISBN9781938168239','Principles of Economics - 3e',NULL,'Tiếng Anh',NULL,2022,NULL,NULL,NULL,NULL,1,0,'Principles of Economics 3e covers the scope and sequence of most introductory economics courses. The third edition takes a balanced approach to the theory and application of economics concepts. The text uses conversational language and ample illustrations to explore economic theories, and provides a wide array of examples using both fictional and real-world scenarios. The third edition has been carefully and thoroughly updated to reflect current data and understanding, as well as to provide a deeper background in diverse contributors and their impacts on economic thought and analysis. For example, the third edition highlights the research and views of a broader group of economists. Brief references and deeply explored socio-political examples have been updated to showcase the critical – and sometimes unnoticed – ties between economic developments and topics relevant to students. A fuller list of changes made in Principles of Economics 3e are described in the preface and the transition guide to help instructors transition to the third edition.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 191.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/principles-of-economics-191\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2022.\nISBN-13 ô CSV: 9781938168239.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Economics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Steven A. Greenlaw - Author / David A. Shapiro - Author / Daniel MacDonald - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781938168239.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:34','2026-05-06 09:00:00',NULL),(148,'OTL-192','GT-ISBN9781947172388','Principles of Macroeconomics - 3e',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'Principles of Macroeconomics 3e covers the scope and sequence of most one semester introductory macroeconomics courses. The third edition takes a balanced approach to the theory and application of macroeconomics concepts. The text uses conversational language and ample illustrations to explore economic theories, and provides a wide array of examples using both fictional and real-world scenarios. The third edition has been carefully and thoroughly updated to reflect current data and understanding, as well as to provide a deeper background in diverse contributors and their impacts on economic thought and analysis. For example, the third edition highlights the research and views of a broader group of economists. Brief references and deeply explored socio-political examples have also been updated to showcase the critical – and sometimes unnoticed – ties between economic developments and topics relevant to students. A fuller list of changes made in Principles of Macroeconomics 3e are described in the preface and the transition guide to help instructors transition to the third edition.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 192.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/principles-of-macroeconomics-3e\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: 9781947172388.\nISBN-10 ô CSV: 1947172387.\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Economics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Steven A. Greenlaw - Author / David Shapiro - Author / Timothy Taylor - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781947172388.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:00:00',NULL),(149,'OTL-193','GT-ISBN9781938168246','Principles of Microeconomics',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'Principles of Economics 2e covers the scope and sequence of most introductory economics courses. The text includes many current examples, which are handled in a politically equitable way. The outcome is a balanced approach to the theory and application of economics concepts. The second edition has been thoroughly revised to increase clarity, update data and current event impacts, and incorporate the feedback from many reviewers and adopters. Changes made in Principles of Economics 2e are described in the preface and the transition guide to help instructors transition to the second edition. The first edition of Principles of Economics by OpenStax is available in web view in the ancillaries\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 193.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/principles-of-microeconomics\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781938168246.\nISBN-10 ô CSV: 1938168240.\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Economics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Timothy Taylor - Author / Steven A. Greenlaw - Author / Eric Dodge - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781938168246.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:00:00',NULL),(150,'OTL-194','GT-OTL000194','Liberté',NULL,'Tiếng Anh',NULL,2003,NULL,NULL,NULL,NULL,1,0,'This French book is aimed at a first-year college student. Its features include: Each chapter is built around communicative strategies. Clearly defined objectives in communi- cation, culture, and grammar are given at the start of each chapter, and summary exercises at the end allow students to measure their mastery of these objectives. The exercises in the in-class (A) sections are composed mainly of guided practice and extension activities, along with occasional comprehension checks and comprehensible input. Some further activities are indicated in the instructor\'s marginal notes. The teacher can provide teacher- directed “setting-the-stage” activities, comprehension checks, and further comprehensible input before beginning each section. Many models are provided to the students to give them a secure context in which to practice their vocabulary before they are asked to produce independent language. The grammar included is explained in a more narrative form and in more detail than is typical for first-year textbooks. The grammar (B) sections should be read by the students outside of class before the communicative activities requiring those grammar points are done in class. By providing more explicit grammatical detail than is usual in a first-year book, the author hopes to stimulate students to reflect on the grammar of their own language as well as of French, helping students to become aware that their study of French is not just about mastery of a new language and culture, but about a more critical view of their own. The amount of grammar is less than is typically contained in a first-year text. The grammar included has been chosen to meet the needs of the communicative goals of each chapter, and these have been selected based on what a student ranking intermediate-low to -mid on the ACTFL oral proficiency scale should be able to accomplish. The grammatical concepts included in this book focus on those that will be needed for the sentences and questions that a typical low-intermediate speaker can form, and those are emphasized repeatedly. The book implicitly and explicitly recycles material from previous chapters on a regular basis, so that students can see their learning as a continual progression rather than as a rush from one grammar point to the next. The book is ideally used in a classroom with internet and projection capabilities; the PDF version of the book contains hyperlinks to video and audio-based activities as well as navigational links to referenced exercises within the text itself.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 194.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/liberte\nPublisher ô CSV: Gretchen V. Angelo.\nCopyright Year ô CSV: 2003.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Gretchen Angelo - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:01:00',NULL),(151,'OTL-196','GT-ISBN9781961584327','Introductory Statistics - 2e',NULL,'Tiếng Anh',NULL,2023,NULL,NULL,NULL,NULL,1,0,'Introductory Statistics 2e provides an engaging, practical, and thorough overview of the core concepts and skills taught in most one-semester statistics courses. The text focuses on diverse applications from a variety of fields and societal contexts, including business, healthcare, sciences, sociology, political science, computing, and several others. The material supports students with conceptual narratives, detailed step-by-step examples, and a wealth of illustrations, as well as collaborative exercises, technology integration problems, and statistics labs. The text assumes some knowledge of intermediate algebra, and includes thousands of problems and exercises that offer instructors and students ample opportunity to explore and reinforce useful statistical skills.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 196.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introductory-statistics-2013\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2023.\nISBN-13 ô CSV: 9781961584327.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Applied.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Barbara Illowsky - Author / Susan Dean - Author / Daniel Birmajer - Author / Bryan Blount - Author / Sheri Boyd - Author / Matthew Einsohn - Author / James Helmreich - Author / Lynette Kenyon - Author / Sheldon Lee - Author / Jeff Taub - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781961584327.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:00:00',NULL),(152,'OTL-197','GT-ISBN9781938168345','Precalculus',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'Precalculus is intended for college-level precalculus students. Since precalculus courses vary from one institution to the next, we have attempted to meet the needs of as broad an audience as possible, including all of the content that might be covered in any particular course. The result is a comprehensive book that covers more ground than an instructor could likely cover in a typical one- or two-semester course; but instructors should find, almost without fail, that the topics they wish to include in their syllabus are covered in the text. Many chapters of Openstax College Precalculus are suitable for other freshman and sophomore math courses such as College Algebra and Trigonometry; however, instructors of those courses might need to supplement or adjust the material. Openstax will also be releasing College Algebra and Algebra and Trigonometry titles tailored to the particular scope, sequence, and pedagogy of those courses. OpenStax College has compiled many resources for faculty and students, from faculty-only content to interactive homework and study guides.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 197.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/precalculus-2014\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781938168345.\nISBN-10 ô CSV: 1947172069.\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Jay Abramson - Author / Valeree Falduto - Author / Rachael Grosss - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781938168345.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:00:00',NULL),(153,'OTL-198','GT-ISBN9781514225158','APEX Calculus',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'This text comprises a three–text series on Calculus. The first part covers material taught in many “Calc 1” courses: limits, derivatives, and the basics of integration, found in Chapters 1 through 6.1. The second text covers material often taught in “Calc 2:” integration and its applications, along with an introduction to sequences, series and Taylor Polynomials, found in Chapters 5 through 8. The third text covers topics common in “Calc 3” or “multivariable calc:” parametric equations, polar coordinates, vector–valued functions, and functions of more than one variable, found in Chapters 9 through 14. More information, including free downloads of .pdf versions of the text, is available at www.apexcalculus.com.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 198.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/apex-calculus\nPublisher ô CSV: APEX Calculus.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781514225158.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Gregory Hartman - Author / Brian Heinold - Author / Troy Siemers - Author / Dimplekumar Chalishajar - Author / Jennifer Bowen - Editor',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781514225158.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:00:00',NULL),(154,'OTL-199','GT-ISBN9781942341024','Native Peoples of North America',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'Native Peoples of North America is intended to be an introductory text about the Native peoples of North America (primarily the United States and Canada) presented from an anthropological perspective. As such, the text is organized around anthropological concepts such as language, kinship, marriage and family life, political and economic organization, food getting, spiritual and religious practices, and the arts. Prehistoric, historic and contemporary information is presented. Each chapter begins with an example from the oral tradition that reflects the theme of the chapter. The text includes suggested readings, videos, and classroom activities. This text was updated September 2019; the changes are detailed in an errata section in the text.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 199.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/native-peoples-of-north-america\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: 9781942341024.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Anthropology.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences - Cultural & Ethnic Studies.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Susan Stebbins - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781942341024.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:00:00',NULL),(155,'OTL-200','GT-ISBN9781312348691','How We Got from There to Here: A Story of Real Analysis',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'The typical introductory real analysis text starts with an analysis of the real number system and uses this to develop the definition of a limit, which is then used as a foundation for the definitions encountered thereafter. While this is certainly a reasonable approach from a logical point of view, it is not how the subject evolved, nor is it necessarily the best way to introduce students to the rigorous but highly non-intuitive definitions and proofs found in analysis. This book proposes that an effective way to motivate these definitions is to tell one of the stories (there are many) of the historical development of the subject, from its intuitive beginnings to modern rigor. The definitions and techniques are motivated by the actual difficulties encountered by the intuitive approach and are presented in their historical context. However, this is not a history of analysis book. It is an introductory analysis textbook, presented through the lens of history. As such, it does not simply insert historical snippets to supplement the material. The history is an integral part of the topic, and students are asked to solve problems that occur as they arise in their historical context. This book covers the major topics typically addressed in an introductory undergraduate course in real analysis in their historical order. Written with the student in mind, the book provides guidance for transforming an intuitive understanding into rigorous mathematical arguments. For example, in addition to more traditional problems, major theorems are often stated and a proof is outlined. The student is then asked to fill in the missing details as a homework problem.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 200.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/how-we-got-from-there-to-here-a-story-of-real-analysis\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781312348691.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Robert Rogers - Author / Eugene Boman - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781312348691.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:00:00',NULL),(156,'OTL-201','GT-ISBN9780989722674','Instruction in Functional Assessment',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'Instruction in Functional Assessment introduces learners to functional assessment (FA), which includes a variety of assessment approaches (indirect, observational, and experimental) for identifying the cause of an individual\'s challenging behavior for the purpose of designing effective treatments. FA is mandated by federal law and is a recognized empirically based approach to treatment of individuals with challenging behaviors (e.g., disruptive, self-injurious, and aggressive behaviors). Instruction in FA is essential for students who will one day enter professions as educators, psychologists, social workers, counselors, or mental health professionals. The purpose of this textbook is to provide instruction in FA skills for pre-professionals in the fields of education and psychology. This supplemental resource provides the context, background, and knowledge to facilitate students\' acquisition of the methods, decision-making, and skills involved in conducting FA. Each chapter begins with focus questions designed to promote reflective thinking and ends with discussion questions. To promote application of FA in diverse situations and teach important lessons, case studies of individuals with challenging behaviors, interactive activities, and opportunities for practice are embedded in the chapters. Moreover, the text includes the ingredients to facilitate students\' role play and rehearsal of appropriate FA skills while working in cooperative groups and using performance-based training.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 201.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/instruction-in-functional-assessment\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9780989722674.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Education.\nSubject OTL 2 — nguyên bản ô CSV —: Education - Elementary Education.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Marcie Desrochers - Author / Moira Fallon - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9780989722674.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:00:00',NULL),(157,'OTL-202','GT-ISBN9781942341000','Guidelines for Improving the Effectiveness of Boards of Directors of Nonprofit Organizations',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'The purpose of this book is to help boards of directors of nonprofit organizations improve their performance after completing the online board self-assessment tool found at www.boardcheckup.com. However, it can also be used as a stand-alone resource for any board seeking to enhance its effectiveness in that it also contains the diagnostic questions on which the online tool is based. The approach taken here is similar to that which lies behind health checkups for individuals. Doctors usually begin by asking us to review a lengthy list of many possible health issues and we check those about which we have concerns. The doctor and patient then focus their discussions on these issues. The typical process proceeds through the following three stages: Understanding the symptoms. The doctor and patient begin by trying to define the issues more clearly. Diagnosis. Effort is made to understand the causes of the problems through tests and further examination. Treatment. Once the problem has been properly diagnosed, a treatment program to remedy it is begun. While the Board Check-Up survey on which this book is based does not pretend to be as scientifically rigorous as a medical examination, it is based on the same logic. It begins by having those who belong to, or relate to, boards provide their perceptions of how well the board is working by guiding them through a list of potential \"health issues”, i.e. statements of possible problems, issues or challenges that boards might encounter in their work. These statements have been derived from comments made by those who serve on boards or interact with them as well as from the work of researchers and consultants who have studied boards over the past 30 years. Once issues (symptoms) have been identified, they become the focal point for discussions that explore how serious they are, what might be causing them (diagnosis) and what can be done to resolve them (treatment). As noted above, this book is intended to help boards assess performance and make decisions to improve the effectiveness of the governance process. Each chapter deals with one of the nine dimensions of governance effectiveness. It starts with the items dealing with that dimension on the Board Performance Self-Assessment Questionnaire. These items represent the symptoms that indicate possible issues, problems or challenges faced by the board. This is followed by a discussion of possible reasons that such symptoms might exist (diagnosis) The third part of each chapter looks at what might be done to alleviate the symptoms once a diagnosis is made (treatment). Included in this final part of the chapter are references to websites, books and articles that provide additional advice and assistance on how to deal with the issues raised.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 202.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/guidelines-for-improving-the-effectiveness-of-boards-of-directors-of-nonprofit-organizations\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781942341000.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Business - Human Resources.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Yvonne Harrison - Author / Vic Murray - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781942341000.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:00:00',NULL),(158,'OTL-203','GT-ISBN9781502447968','The Missing Link: An Introduction to Web Development and Programming',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'Web development is an evolving amalgamation of languages that work in concert to receive, modify, and deliver information between parties using the Internet as a mechanism of delivery. While it is easy to describe conceptually, implementation is accompanied by an overwhelming variety of languages, platforms, templates, frameworks, guidelines, and standards. Navigating a project from concept to completion often requires more than mastery of one or two complementing languages, meaning today\'s developers need both breadth, and depth, of knowledge to be effective. This text provides the developer with an understanding of the various elements of web development by focusing on the concepts and fundamentals through the examples within, providing a foundation that allows easier transition to other languages and a better understanding of how to approach their work. The reader will be introduced to topics in a manner that follows most project development methods, from initial conceptualization and design through front end development, back end development, and introducing additional concepts like accessibility and security, while focusing on responsive design techniques. Each section of the text includes opportunities to practice the material and assess increased knowledge after examining the topics.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 203.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-missing-link-an-introduction-to-web-development-and-programming\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781502447968.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Michael Mendez - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781502447968.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:00:00',NULL),(159,'OTL-204','GT-ISBN9781942341031','Literature, the Humanities, and Humanity',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'Literature, the Humanities, and Humanity attempts to make the study of literature more than simply another school subject that students have to take. At a time when all subjects seem to be valued only for their testability, this book tries to show the value of reading and studying literature, even earlier literature. It shows students, some of whom will themselves become teachers, that literature actually has something to say to them. Furthermore, it shows that literature is meant to be enjoyed, that, as the Roman poet Horace (and his Renaissance disciple Sir Philip Sidney) said, the functions of literature are to teach and to delight. The book will also be useful to teachers who want to convey their passion for literature to their students. After an introductory chapter that offers advice on how to read (and teach) literature, the book consists of a series of chapters that examine individual literary works ranging from The Iliad to Charles Dickens\' Bleak House. These chapters can not substitute for reading the actual works. Rather they are intended to help students read those works. They are attempts to demystify the act of reading and to show that these works, whether they are nearly three thousand or less than two hundred years old, still have important things to say to contemporary readers.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 204.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/literature-the-humanities-and-humanity\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781942341031.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Theodore L. Steinberg - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781942341031.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:00:00',NULL),(160,'OTL-205','GT-ISBN9781942341178','Natural Resources Biometrics',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'Natural Resources Biometrics begins with a review of descriptive statistics, estimation, and hypothesis testing. The following chapters cover one- and two-way analysis of variance (ANOVA), including multiple comparison methods and interaction assessment, with a strong emphasis on application and interpretation. Simple and multiple linear regressions in a natural resource setting are covered in the next chapters, focusing on correlation, model fitting, residual analysis, and confidence and prediction intervals. The final chapters cover growth and yield models, volume and biomass equations, site index curves, competition indices, importance values, and measures of species diversity, association, and community similarity.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 205.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/natural-resources-biometrics\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781942341178.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Diane Kiernan - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781942341178.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:00:00',NULL),(161,'OTL-206','GT-ISBN9781938168369','U.S. History',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'U.S. Historycovers the breadth of the chronological history of the United States and also provides the necessary depth to ensure the course is manageable for instructors and students alike. U.S. History is designed to meet the scope and sequence requirements of most courses. The authors introduce key forces and major developments that together form the American experience, with particular attention paid to considering issues of race, class, and gender. The text provides a balanced approach to U.S. history, considering the people, events, and ideas that have shaped the United States from both the top down (politics, economics, diplomacy) and bottom up (eyewitness accounts, lived experience). OpenStax College has compiled many resources for faculty and students, from faculty-only content to interactive homework and study guides.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 206.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/u-s-history\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781938168369.\nISBN-10 ô CSV: 1938168364.\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - History.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 900 — Lịch sử & Địa lý.\nContributors — nguyên bản ô CSV —: P. Scott Corbett - Author / Volker Janssen - Author / John M. Lund - Author',NULL,NULL,'900','utc-elibrary/book-covers/isbn/9781938168369.jpg',7,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:00:00',NULL),(162,'OTL-207','GT-ISBN9781951693237','Psychology - 2e',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'Psychology 2e is designed to meet scope and sequence requirements for the single-semester introduction to psychology course. The book offers a comprehensive treatment of core concepts, grounded in both classic studies and current and emerging research. The text also includes coverage of the DSM-5 in examinations of psychological disorders. Psychology incorporates discussions that reflect the diversity within the discipline, as well as the diversity of cultures and communities across the globe. The second edition contains detailed updates to address comments and suggestions from users. Significant improvements and additions were made in the areas of research currency, diversity and representation, and the relevance and recency of the examples. Many concepts were expanded or clarified, particularly through the judicious addition of detail and further explanation where necessary. Finally, the authors addressed the replication issues in the psychology discipline, both in the research chapter and where appropriate throughout the book.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 207.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/psychology\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781951693237.\nISBN-10 ô CSV: 1938168356.\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Psychology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Rose Spielman - Author / Kathryn Dumper - Author / William Jenkins - Author / Marilyn D. Lovett - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781951693237.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:00:00',NULL),(163,'OTL-208','GT-OTL000208','United States Securities Law',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'The United States Securities Code and Regulations appear in Title 15 of the United States Code and Title 17 of the Code of Federal Regulations. This publication was made with data provided by the United States government on the Office of Law Revision Counsel as well as the eCFR.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 208.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/united-states-securities-law\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Contract Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: eLangdell Press Editorial Staff - Editor',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:01:00',NULL),(164,'OTL-210','GT-OTL000210','Linear Algebra, Theory And Applications',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'This is a book on linear algebra and matrix theory. While it is self contained, it will work best for those who have already had some exposure to linear algebra. It is also assumed that the reader has had calculus. Some optional topics require more analysis than this, however. This book features an ugly, elementary, and complete treatment of determinants early in the book. Thus it might be considered as Linear algebra done wrong. I have done this because of the usefulness of determinants. However, all major topics are also presented in an alternative manner which is independent of determinants. The book has an introduction to various numerical methods used in linear algebra. This is done because of the interesting nature of these methods. The presentation here emphasizes the reasons why they work. It does not discuss many important numerical considerations necessary to use the methods effectively. These considerations are found in numerical analysis texts.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 210.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/linear-algebra-theory-and-applications\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Algebra.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Kenneth Kuttler - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:01:00',NULL),(165,'OTL-211','GT-ISBN9781505698190','Notes on Diffy Qs: Differential Equations for Engineers',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'A one semester first course on differential equations, aimed at engineering students. Prerequisite for the course is the basic calculus sequence. This free online book (e-book in webspeak) should be usable as a stand-alone textbook or as a companion to a course using another book such as Edwards and Penney, Differential Equations and Boundary Value Problems: Computing and Modeling or Boyce and DiPrima, Elementary Differential Equations and Boundary Value Problems (section correspondence to these two is given). I developed and used these notes to teach Math 286/285 at the University of Illinois at Urbana-Champaign Sample Dirichlet problem solution (one is a 4-day-a-week, the other a 3-day-a-week semester-long course). I have also taught Math 20D at University of California, San Diego with these notes (a 3-day-a-week quarter-long course). There is enough material to run a 2-quarter course, and even perhaps a two semester course depending on lecturer speed.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 211.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/notes-on-diffy-qs-differential-equations-for-engineers\nPublisher ô CSV: Jirí Lebl.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781505698190.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Engineering & Technology.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Jirí Lebl - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781505698190.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:00:00',NULL),(166,'OTL-213','GT-OTL000213','A First Course in Linear Algebra - 10th Edition-2023-B-D',NULL,'Tiếng Anh',NULL,2023,NULL,NULL,NULL,NULL,1,0,'This text, originally by K. Kuttler, has been redesigned by the Lyryx editorial team as a first course in linear algebra for science and engineering students who have an understanding of basic algebra. All major topics of linear algebra are available in detail, as well as proofs of important theorems. In addition, connections to topics covered in advanced courses are introduced. The text is designed in a modular fashion to maximize flexibility and facilitate adaptation to a given course outline and student profile. Each chapter begins with a list of student learning outcomes, and examples and diagrams are given throughout the text to reinforce ideas and provide guidance on how to approach various problems. Suggested exercises are included at the end of each section, with selected answers at the end of the text. Lyryx develops and supports open texts, with editorial services to adapt the text for each particular course. In addition, Lyryx provides content-specific formative online assessment, a wide variety of supplements, and in-house support available 7 days/week for both students and instructors.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 213.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/a-first-course-in-linear-algebra-2017\nPublisher ô CSV: Lyryx.\nCopyright Year ô CSV: 2023.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Algebra.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Ken Kuttler - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:01:00',NULL),(167,'OTL-215','GT-OTL000215','Introduction to Financial Accounting - 2024-A-D',NULL,'Tiếng Anh',NULL,2024,NULL,NULL,NULL,NULL,1,0,'Introduction to Financial Accounting, originally by D. Annand and H. Dauderis, is intended for a first course in introductory financial accounting. It has been extensively edited by Athabasca University and reflects current International Financial Reporting Standards (IFRS). A corporate approach is utilized, versus beginning with a sole proprietorship emphasis and then converting to a corporate approach. The textbook focuses on core introductory financial accounting topics that match pre-requisite requirements for students advancing to intermediate financial accounting. The textbook covers all essential topics, including: the accounting cycle; merchandising; assigning costs to inventory; cash and receivables; property, plant and equipment; debt financing; equity financing; statement of cash flows; financial statement analysis; and proprietorships and partnerships. The original Annand/Dauderis version of the textbook including .docx files and ancillary material remains available upon request to D. Annand (davida@athabascau.ca).\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 215.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-financial-accounting\nPublisher ô CSV: Lyryx.\nCopyright Year ô CSV: 2024.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Accounting.\nSubject OTL 2 — nguyên bản ô CSV —: Business.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: David Annand - Author / Henry Dauderis - Author / Tilly Jensen - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:01:00',NULL),(168,'OTL-217','GT-ISBN9781944325022','Abstract Algebra: Theory and Applications',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This text is intended for a one- or two-semester undergraduate course in abstract algebra. Traditionally, these courses have covered the theoretical aspects of groups, rings, and fields. However, with the development of computing in the last several decades, applications that involve abstract algebra and discrete mathematics have become increasingly important, and many science, engineering, and computer science students are now electing to minor in mathematics. Though theory still occupies a central role in the subject of abstract algebra and no student should go through such a course without a good notion of what a proof is, the importance of applications such as coding theory and cryptography has grown significantly. Until recently most abstract algebra texts included few if any applications. However, one of the major problems in teaching an abstract algebra course is that for many students it is their first encounter with an environment that requires them to do rigorous proofs. Such students often find it hard to see the use of learning to prove theorems and propositions; applied examples help the instructor provide motivation. This text contains more material than can possibly be covered in a single semester. Certainly there is adequate material for a two-semester course, and perhaps more; however, for a one-semester course it would be quite easy to omit selected chapters and still have a useful text. The order of presentation of topics is standard: groups, then rings, and finally fields. Emphasis can be placed either on theory or on applications. A typical one-semester course might cover groups and rings while briefly touching on field theory, using Chapters 1 through 6, 9, 10, 11, 13 (the first part), 16, 17, 18 (the first part), 20, and 21. Parts of these chapters could be deleted and applications substituted according to the interests of the students and the instructor. A two-semester course emphasizing theory might cover Chapters 1 through 6, 9, 10, 11, 13 through 18, 20, 21, 22 (the first part), and 23. On the other hand, if applications are to be emphasized, the course might cover Chapters 1 through 14, and 16 through 22. In an applied course, some of the more theoretical results could be assumed or omitted. A chapter dependency chart appears below. (A broken line indicates a partial dependency.)\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 217.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/abstract-algebra-theory-and-applications\nPublisher ô CSV: University of Puget Sound.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781944325022.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Free Documentation License (GNU).\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Algebra.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Thomas W. Judson - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781944325022.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:00:00',NULL),(169,'OTL-218','GT-OTL000218','Java, Java, Java: Object-Oriented Problem Solving',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'We have designed this third edition of Java, Java, Java to be suitable for a typical Introduction to Computer Science (CS1) course or for a slightly more advanced Java as a Second Language course. This edition retains the “objects first” approach to programming and problem solving that was characteristic of the first two editions. Throughout the text we emphasize careful coverage of Java language features, introductory programming concepts, and object-oriented design principles. The third edition retains many of the features of the first two editions, including: Early Introduction of Objects Emphasis on Object Oriented Design (OOD) Unified Modeling Language (UML) Diagrams Self-study Exercises with Answers Programming, Debugging, and Design Tips. From the Java Library Sections Object-Oriented Design Sections End-of-Chapter Exercises Companion Web Site, with Power Points and other Resources The In the Laboratory sections from the first two editions have been moved onto the book\'s Companion Web Site. Table 1 shows the Table of Contents for the third edition.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 218.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/java-java-java-object-oriented-problem-solving\nPublisher ô CSV: Ralph Morelli, Ralph Walde.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science - Programming Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Ralph Morelli - Author / Ralph Walde - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:01:00',NULL),(170,'OTL-219','GT-ISBN9781947172616','Chemistry - 2e',NULL,'Tiếng Anh',NULL,2019,NULL,NULL,NULL,NULL,1,0,'Chemistry 2e is designed to meet the scope and sequence requirements of the two-semester general chemistry course. The textbook provides an important opportunity for students to learn the core concepts of chemistry and understand how those concepts apply to their lives and the world around them. The book also includes a number of innovative features, including interactive exercises and real-world applications, designed to enhance student learning. The second edition has been revised to incorporate clearer, more current, and more dynamic explanations, while maintaining the same organization as the first edition. Substantial improvements have been made in the figures, illustrations, and example exercises that support the text narrative.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 219.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/chemistry\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2019.\nISBN-13 ô CSV: 9781947172616.\nISBN-10 ô CSV: 1947172611.\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Chemistry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Paul Flowers - Author / Klaus Theopold - Author / Richard Langley - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781947172616.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:00:00',NULL),(171,'OTL-220','GT-OTL000220','Calculus One',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'Calculus is about the very large, the very small, and how things change—the surprise is that something seemingly so abstract ends up explaining the real world. This course is a first and friendly introduction to calculus, suitable for someone who has never seen the subject before, or for someone who has seen some calculus but wants to review the concepts and practice applying those concepts to solve problems. One learns calculus by doing calculus, and so this course is based around doing practice problems.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 220.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/calculus-one\nPublisher ô CSV: Mooculus.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Roman Holowinsky - Author / Johann Thiel - Author / David Lindberg - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:01:00',NULL),(172,'OTL-221','GT-OTL000221','Teaching in a Digital Age: Guidelines for designing teaching and learning - 2nd Edition',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Teachers, instructors and faculty are facing unprecedented change, with often larger classes, more diverse students, demands from government and employers who want more accountability and the development of graduates who are workforce ready, and above all, we are all having to cope with ever changing technology. To handle change of this nature, teachers and instructors need a base of theory and knowledge that will provide a solid foundation for their teaching, no matter what changes or pressures they face. Although the book contains many practical examples, it is more than a cookbook on how to teach. It addresses the following questions: is the nature of knowledge changing, and how do different views on the nature of knowledge result in different approaches to teaching? what is the science and research that can best help me in my teaching? how do I decide whether my courses should be face-to-face, blended or fully online? what strategies work best when teaching in a technology-rich environment? what methods of teaching are most effective for blended and online classes? how do I make choices among all the available media, whether text, audio, video, computer, or social media, in order to benefit my students and my subject? how do I maintain high quality in my teaching in a rapidly changing learning environment while managing my workload? what are the real possibilities for teaching and learning using MOOCs, OERS, open textbooks? In summary, the book examines the underlying principles that guide effective teaching in an age when everyone, and in particular the students we are teaching, are using technology. A framework and a set of guidelines are suggested for making decisions about your teaching, while understanding that every subject is different, and every teacher and instructor has something unique and special to bring to their teaching. In the end, though, the book isn\'t really about teachers and instructors, although you are the target group. It\'s about you helping your students to develop the knowledge and skills they will need in a digital age: not so much digital skills, but the thinking and knowledge that will bring them success. For that to happen, though, your students need you to be on top of your game. This book is your coach.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 221.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/teaching-in-a-digital-age-guidelines-for-designing-teaching-and-learning-for-a-digital-age\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Education - Curriculum & Instruction.\nSubject OTL 2 — nguyên bản ô CSV —: Education - Distance Education.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: A.W. (Tony) Bates - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:01:00',NULL),(173,'OTL-223','GT-OTL000223','Beyond Lean: Simulation in Practice - Second Edition',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'Lean thinking, as well as associated processes and tools, have involved into a ubiquitous perspective for improving systems particularly in the manufacturing arena. With application experience has come an understanding of the boundaries of lean capabilities and the benefits of getting beyond these boundaries to further improve performance. Discrete event simulation is recognized as one beyond-the-boundaries of lean technique. Thus, the fundamental goal of this text is to show how discrete event simulation can be used in addition to lean thinking to achieve greater benefits in system improvement than with lean alone. Realizing this goal requires learning the problems that simulation solves as well as the methods required to solve them. The problems that simulation solves are captured in a collection of case studies. These studies serve as metaphors for industrial problems that are commonly addressed using lean and simulation.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 223.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/beyond-lean-simulation-in-practice-second-edition\nPublisher ô CSV: Grand Valley State University.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Management.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Charles R. Standridge - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:01:00',NULL),(174,'OTL-224','GT-OTL000224','Introduction to Human Osteology',NULL,'Tiếng Anh',NULL,2010,NULL,NULL,NULL,NULL,1,0,'This text was designed for use in the human osteology laboratory classroom. Bones are described to aid in identification of skeletonized remains in either an archaeological or forensic anthropology setting. Basic techniques for siding, aging, sexing, and stature estimation are described. Both images of bone and drawings are included which may be used for study purposes outside of the classroom. The text represents work that has been developed over more than 30 years by its various authors and is meant to present students with the basic analytical tools for the study of human osteology.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 224.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-human-osteology\nPublisher ô CSV: Grand Valley State University.\nCopyright Year ô CSV: 2010.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Biology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Roberta Hall - Author / Kenneth Beals - Author / Holm Neumann - Author / Georg Neumann - Author / Gwyn Madden - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:35','2026-05-06 09:01:00',NULL),(175,'OTL-225','GT-ISBN9781492103851','Mathematical Reasoning: Writing and Proof, Version 2.1',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'Mathematical Reasoning: Writing and Proofis designed to be a text for the ?rst course in the college mathematics curriculum that introduces students to the processes of constructing and writing proofs and focuses on the formal development of mathematics. The primary goals of the text are to help students: Develop logical thinking skills and to develop the ability to think more abstractly in a proof oriented setting. Develop the ability to construct and write mathematical proofs using standard methods of mathematical proof including direct proofs, proof by contradiction, mathematical induction, case analysis, and counterexamples. Develop the ability to read and understand written mathematical proofs. Develop talents for creative thinking and problem solving. Improve their quality of communication in mathematics. This includes improving writing techniques, reading comprehension, and oral communication in mathematics. Better understand the nature of mathematics and its language. This text also provides students with material that will be needed for their further study of mathematics.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 225.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/mathematical-reasoning-writing-and-proof-version-2-1\nPublisher ô CSV: Grand Valley State University.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781492103851.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Pure.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Ted Sundstrom - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781492103851.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(176,'OTL-226','GT-OTL000226','Writing Spaces Web Writing Style Guide',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'The Writing Spaces Web Writing Style Guide was created as a crowdsourcing project of Collaborvention 2011: A Computers and Writing Unconference. College writing teachers from around the web joined together to create this guide (see our Contributors list). The advice within it is based on contemporary theories and best practices. While the text was originally written for students in undergraduate writing classes, it can also be a suitable resource for other writers interested in learning more about writing for the web. This document is available as a web text for reading online, a printer-friendly PDF, and an EPUB ereader versions.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 226.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/writing-spaces-web-writing-style-guide\nPublisher ô CSV: Grand Valley State University.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Matt Barton - Editor / James Kalmbach - Editor / Charles Lowe - Editor',NULL,NULL,'800','utc-elibrary/book-covers/defaults/default-book-cover.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:01:00',NULL),(177,'OTL-227','GT-OTL000227','Discover Psychology 2.0: A Brief Introductory Text',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'This textbook presents core concepts common to introductory courses. The 15 units cover the traditional areas of intro-to-psychology; ranging from biological aspects of psychology to psychological disorders to social psychology. This book can be modified: feel free to add or remove modules to better suit your specific needs. Each module in this book is accompanied by instructor\'s manual, PowerPoint presentation, test items, adaptive student quiz, and reading anticipation guide. Please note that the publisher requires you to login to access and download the textbooks.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 227.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/discover-psychology-2-0-a-brief-introductory-text\nPublisher ô CSV: Noba.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Psychology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Robert Biswas-Diener - Editor / Ed Diener - Editor',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:01:00',NULL),(178,'OTL-228','GT-OTL000228','Introduction to Psychology: The Full Noba Collection',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This textbook represents the entire catalog of Noba topics. It contains 90 learning modules covering every area of psychology commonly taught in introductory courses. This book can be modified: feel free to rearrange or remove modules to better suit your specific needs.Please note that the publisher requires you to login to access and download the textbooks.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 228.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-psychology-the-full-noba-collection\nPublisher ô CSV: Noba.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Psychology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Robert Biswas-Diener - Editor / Ed Diener - Editor',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:01:00',NULL),(179,'OTL-229','GT-OTL000229','Psychology as a Biological Science',NULL,'Tiếng Anh',NULL,2020,NULL,NULL,NULL,NULL,1,0,'This textbook provides standard introduction to psychology course content with a specific emphasis on biological aspects of psychology. This includes more content related to neuroscience methods, the brain and the nervous system. This book can be modified: feel free to add or remove modules to better suit your specific needs. Please note that the publisher requires you to login to access and download the PDF.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 229.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/psychology-as-a-biological-science\nPublisher ô CSV: Noba.\nCopyright Year ô CSV: 2020.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Biology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Robert Biswas-Diener - Editor / Ed Diener - Editor',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:01:00',NULL),(180,'OTL-230','GT-OTL000230','Psychology as a Social Science',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'This textbook provides standard introduction to psychology course content with a specific emphasis on social aspects of psychology. This includes expanded content related to social cognition, aggression, attraction and similar topics. This book can be modified: feel free to add or remove modules to better suit your specific needs.Please note that the publisher requires you to login to access and download the textbooks.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 230.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/psychology-as-a-social-science\nPublisher ô CSV: Noba.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Robert Bissau-Diener - Editor / Ed Diener - Editor',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:01:00',NULL),(181,'OTL-231','GT-OTL000231','Digital Circuit Projects: An Overview of Digital Circuits Through Implementing Integrated Circuits',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'Digital circuits, often called Integrated Circuits or ICs, are the central building blocks of a Central Processing Unit (CPU). To understand how a computer works, it is essential to understand the digital circuits which make up the CPU. This text introduces the most important of these digital circuits; adders, decoders, multiplexers, D flip-flops, and simple state machines. What makes this textbook unique is that it puts the ability to understand these circuits into the hands of anyone, from hobbyists to students studying Computer Science. This text is designed to teach digital circuits using simple projects the reader can implement. But unlike most lab manuals used in classes in Digital Circuits or Computer Organization classes, this textbook is designed to remove the barrier of a laboratory infrastructure needed in a face-to-face environment at a college or university. This textbook is designed to be used by the reader to create the circuits in their own homes. The textbook is free. The cost of the kits needed to do the labs is reasonable. And the projects are well documented and can be implemented by even novices to electronic projects. This text allows professors to add laboratory projects in digital circuits to students in online classes in Computer Organization. This enhances these classes with interesting and fun exercises that reinforce the classroom topics. This text can also be used by a hobbyist who wants to learn more about digital circuits and how computers work. The material is presented at a level that someone with no experience in digital circuits and electronics can successfully complete the projects, and gain an understanding of the circuits which go into making up a computer.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 231.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/digital-circuit-projects-an-overview-of-digital-circuits-through-implementing-integrated-circuits\nPublisher ô CSV: Gettysburg College.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Charles W. Kann - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:01:00',NULL),(182,'OTL-232','GT-ISBN9781942341109','Foundations of Academic Success: Words of Wisdom',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Foundations of Academic Success: Words of Wisdom (FAS: WoW) introduces you to the various aspects of student and academic life on campus and prepares you to thrive as a successful college student (since there is a difference between a college student and a successful college student). Each section of FAS: WoW is framed by self-authored, true-to-life short stories from actual State University of New York (SUNY) students, employees, and alumni. The advice they share includes a variety of techniques to help you cope with the demands of college. The lessons learned are meant to enlarge your awareness of self with respect to your academic and personal goals and assist you to gain the necessary skills to succeed in college. Foundations of Academic Success is an engaging, informational, and succinct read that connects the reader to personal essays about succeeding in college. The text allows the reader to see different perspectives of the shared experience of navigating higher education. As an adjunct lecturer teaching a course entitled “Learning to Learn,” I see the advice and life lessons discussed as both helpful and informative to many types of students. I believe that this book has a universal appeal for any classroom that is discussing the college life cycle, and would advocate using this text with students who seek out campus services, such as Career Services, Study Abroad, and Academic Advising. I also see this text applicable in the education of student leaders, peer mentors, and peer advocates at the undergraduate and graduate levels. This text goes beyond traditional Student Affairs and Student Development theories to connect the reader with real, honest, and understandable life lessons.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 232.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/foundations-of-academic-success-words-of-wisdom\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781942341109.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Student Success.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Thomas C. Priester - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781942341109.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(183,'OTL-233','GT-ISBN9781942341093','Introduction to the Modeling and Analysis of Complex Systems',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Introduction to the Modeling and Analysis of Complex Systems introduces students to mathematical/computational modeling and analysis developed in the emerging interdisciplinary field of Complex Systems Science. Complex systems are systems made of a large number of microscopic components interacting with each other in nontrivial ways. Many real-world systems can be understood as complex systems, where critically important information resides in the relationships between the parts and not necessarily within the parts themselves. This textbook offers an accessible yet technically-oriented introduction to the modeling and analysis of complex systems. The topics covered include: fundamentals of modeling, basics of dynamical systems, discrete-time models, continuous-time models, bifurcations, chaos, cellular automata, continuous field models, static networks, dynamic networks, and agent-based models. Most of these topics are discussed in two chapters, one focusing on computational modeling and the other on mathematical analysis. This unique approach provides a comprehensive view of related concepts and techniques, and allows readers and instructors to flexibly choose relevant materials based on their objectives and needs. Python sample codes are provided for each modeling example.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 233.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-the-modeling-and-analysis-of-complex-systems\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781942341093.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Hiroki Sayama - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781942341093.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(184,'OTL-234','GT-ISBN9781312778986','Spatial Thinking in Planning Practice: An Introduction to GIS',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'The goals of this textbook are to help students acquire the technical skills of using software and managing a database, and develop research skills of collecting data, analyzing information and presenting results. We emphasize that the need to investigate the potential and practicality of GIS technologies in a typical planning setting and evaluate its possible applications. GIS may not be necessary (or useful) for every planning application, and we anticipate these readings to provide the necessary foundation for discerning its appropriate use. Therefore, this textbook attempts to facilitate spatial thinking focusing more on open-ended planning questions, which require judgment and exploration, while developing the analytical capacity for understanding a variety of local and regional planning challenges. While this textbook provides the background for understanding the concepts in GIS as applicable to urban and regional planning, it is best when accompanied by a hands-on tutorial, which will enable readers to develop an in-depth understanding of the specific planning applications of GIS. In the end of each chapter, we also provided several discussion questions, together with contextual applications through some web links.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 234.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/spatial-thinking-in-planning-practice-an-introduction-to-gis\nPublisher ô CSV: Portland State University Library.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781312778986.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Yiping Fang - Author / Vivek Shandas - Author / Eugenio Arriaga Cordero - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781312778986.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(185,'OTL-235','GT-ISBN9781312886872','Comprehensive Individualized Curriculum and Instructional Design: Curriculum and Instruction for Students with Developmental Disabilities/Autism Spectrum Disorders',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'This open textbook addresses the population of individuals with disabilities that experience complex lifelong needs across multiple areas in their lives. Drs. Sennott and Loman drafted this book (along with the help from some friends) with the hope of providing pertinent, practical, and current resources to future special educators who plan to serve individuals with complex disabilities.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 235.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/comprehensive-individualized-curriculum-and-instructional-design-curriculum-and-instruction-for-students-with-developmental-disabilities-autism-spectrum-disorders\nPublisher ô CSV: Portland State University Library.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781312886872.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Education - Curriculum & Instruction.\nSubject OTL 2 — nguyên bản ô CSV —: Education.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Samuel Sennott - Author / Sheldon Loman - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781312886872.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(186,'OTL-236','GT-ISBN9781312554504','Preadvanced Japanese',NULL,'Ngôn ngữ gốc đa dạng — xem chủ đề OTL và nhan đề',NULL,2014,NULL,NULL,NULL,NULL,1,0,'Preadvanced Japanese is designed for students who have intermediate competency in Japanese, roughly at Level 2 on the ILR (The Interagency Language Roundtable) proficiency scale, and are working on reaching Level 3.This textbook can be used for self-study, as part of online course, and in a traditional classroom setting. It is comprised of four chapters, intended to be covered in one term of a quarter system. Each chapter has Drills on expressions and grammar, Kanji Drills, and Listening Exercises. These activities are to be performed using the accompanying audio.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 236.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/preadvanced-japanese\nPublisher ô CSV: Portland State University Library.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781312554504.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Emiko Konomi - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781312554504.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(187,'OTL-237','GT-ISBN9781942341161','Spiral Workbook for Discrete Mathematics',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'This is a text that covers the standard topics in a sophomore-level course in discrete mathematics: logic, sets, proof techniques, basic number theory, functions, relations, and elementary combinatorics, with an emphasis on motivation. It explains and clarifies the unwritten conventions in mathematics, and guides the students through a detailed discussion on how a proof is revised from its draft to a final polished form. Hands-on exercises help students understand a concept soon after learning it. The text adopts a spiral approach: many topics are revisited multiple times, sometimes from a different perspective or at a higher level of complexity. The goal is to slowly develop students\' problem-solving and writing skills.Open SUNY Textbooks is an open access textbook publishing initiative established by State University of New York libraries and supported by SUNY Innovative Instruction Technology Grants. This initiative publishes high-quality, cost-effective course resources by engaging faculty as authors and peer-reviewers, and libraries as publishing service and infrastructure. The pilot launched in 2012, providing an editorial framework and service to authors, students and faculty, and establishing a community of practice among libraries. Participating libraries in the 2012- 2013 pilot include SUNY Geneseo, College at Brockport, College of Environmental Science and Forestry, SUNY Fredonia, Upstate Medical University, and University at Buffalo, with support from other SUNY libraries and SUNY Press. More information can be found at http://textbooks.opensuny.org.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 237.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/spiral-workbook-for-discrete-mathematics\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781942341161.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Pure.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Harris Kwong - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781942341161.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(188,'OTL-238','GT-OTL000238','Information Strategies for Communicators',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Written by two nationally recognized experts in information strategy, Information Strategies for Communicators leads students step-by-step through the information search and evaluation process for news and strategic communication message production. The book includes a conceptual model of the information strategy process, case studies to illustrate the process in action, and links to current examples throughout. The definitive text for the information search and evaluation process as practiced by news and strategic communication message producers. Currently used at the University of Minnesota School of Journalism and Mass Communication; JOUR 3004W/V, Information for Mass Communication.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 238.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/information-strategies-for-communicators\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Journalism, Media Studies & Communications.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Kathleen A. Hansen - Author / Nora Paul - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:01:00',NULL),(189,'OTL-239','GT-ISBN9781951693404','Algebra and Trigonometry 2e',NULL,'Tiếng Anh',NULL,2021,NULL,NULL,NULL,NULL,1,0,'Algebra and Trigonometry 2e provides a comprehensive exploration of mathematical principles and meets scope and sequence requirements for a typical introductory algebra and trigonometry course. The modular approach and the richness of content ensure that the book addresses the needs of a variety of courses. Algebra and Trigonometry 2e offers a wealth of examples with detailed, conceptual explanations, building a strong foundation in the material before asking students to apply what they’ve learned. The Algebra and Trigonometry 2e revision focused on improving relevance and representation as well as mathematical clarity and accuracy. Introductory narratives, examples, and problems were reviewed and revised using a diversity, equity, and inclusion framework. Many contexts, scenarios, and images have been changed to become even more relevant to students’ lives and interests. To maintain our commitment to accuracy and precision, examples, exercises, and solutions were reviewed by multiple faculty experts. All improvement suggestions and errata updates from the first edition were considered and unified across the different formats of the text. The first edition of Algebra and Trigonometry by OpenStax is available in web view here.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 239.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/algebra-and-trigonometry\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2021.\nISBN-13 ô CSV: 9781951693404.\nISBN-10 ô CSV: 1938168372.\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Algebra.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Geometry and Trigonometry.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Jay Abramson - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781951693404.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(190,'OTL-240','GT-ISBN9781951693411','College Algebra - 2e',NULL,'Tiếng Anh',NULL,2021,NULL,NULL,NULL,NULL,1,0,'College Algebra 2e provides a comprehensive exploration of algebraic principles and meets scope and sequence requirements for a typical introductory algebra course. The modular approach and richness of content ensure that the book addresses the needs of a variety of courses. College Algebra 2e offers a wealth of examples with detailed, conceptual explanations, building a strong foundation in the material before asking students to apply what they’ve learned. The College Algebra 2e revision focused on improving relevance and representation as well as mathematical clarity and accuracy. Introductory narratives, examples, and problems were reviewed and revised using a diversity, equity, and inclusion framework. Many contexts, scenarios, and images have been changed to become even more relevant to students’ lives and interests. To maintain our commitment to accuracy and precision, examples, exercises, and solutions were reviewed by multiple faculty experts. All improvement suggestions and errata updates from the first edition were considered and unified across the different formats of the text. The first edition of College Algebra by OpenStax is available in web view here.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 240.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/college-algebra-2015\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2021.\nISBN-13 ô CSV: 9781951693411.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Algebra.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Jay Abramson - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781951693411.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(191,'OTL-241','GT-ISBN9781938168994','Prealgebra - 2e',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Prealgebra 2e is designed to meet scope and sequence requirements for a one-semester prealgebra or basic math course. The book’s organization makes it easy to adapt to a variety of course syllabi. The text introduces the fundamental concepts of algebra while addressing the needs of students with diverse backgrounds and learning styles. Each topic builds upon previously developed material to demonstrate the cohesiveness and structure of mathematics. The second edition contains detailed updates and accuracy revisions to address comments and suggestions from users. Dozens of faculty experts worked through the text, exercises and problems, graphics, and and solutions to identify areas needing improvement. Though the authors made significant changes and enhancements, exercise and problem numbers remain nearly the same in order to ensure a smooth transition for faculty. The first edition of Prealgebra by OpenStax is available in web view in the ancillaries.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 241.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/prealgebra\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781938168994.\nISBN-10 ô CSV: 1938168992.\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Algebra.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Lynn Marecek - Author / MaryAnne Anthony-Smith - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781938168994.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(192,'OTL-242','GT-ISBN9781616101664','Theatrical Worlds',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'From the University of Florida College of Fine Arts, Charlie Mitchell and distinguished colleagues from across America present an introductory text for theatre and theoretical production. This book seeks to give insight into the people and processes that create theater. It does not strip away the feeling of magic but to add wonder for the artistry that make a production work well.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 242.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/theatrical-worlds\nPublisher ô CSV: University Press of Florida.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781616101664.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Arts.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Charles Mitchell - Editor',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781616101664.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(193,'OTL-243','GT-ISBN9781365605529','Introduction to Mathematical Analysis I - Second Edition',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Our goal with this textbook is to provide students with a strong foundation in mathematical analysis. Such a foundation is crucial for future study of deeper topics of analysis. Students should be familiar with most of the concepts presented here after completing the calculus sequence. However, these concepts will be reinforced through rigorous proofs. The lecture notes contain topics of real analysis usually covered in a 10-week course: the completeness axiom, sequences and convergence, continuity, and differentiation. The lecture notes also contain many well-selected exercises of various levels. Although these topics are written in a more abstract way compared with those available in some textbooks, teachers can choose to simplify them depending on the background of the students. For instance, rather than introducing the topology of the real line to students, related topological concepts can be replaced by more familiar concepts such as open and closed intervals. Some other topics such as lower and upper semicontinuity, differentiation of convex functions, and generalized differentiation of non-differentiable convex functions can be used as optional mathematical projects. In this way, the lecture notes are suitable for teaching students of different backgrounds. The second edition includes a number of improvements based on recommendations from students and colleagues and on our own experience teaching the course over the last several years. In this edition we streamlined the narrative in several sections, added more proofs, many examples worked out in detail, and numerous new exercises. In all we added over 50 examples in the main text and 100 exercises (counting parts).\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 243.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-mathematical-analysis-i-second-edition\nPublisher ô CSV: Portland State University Library.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781365605529.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Analysis.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Applied.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Beatriz Lafferriere - Author / Gerardo Lafferriere - Author / Mau Nam Nguyen - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781365605529.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(194,'OTL-244','GT-ISBN9780996150279','Cell and Molecular Biology: What We Know & How We Found Out - 5e',NULL,'Tiếng Anh',NULL,2020,NULL,NULL,NULL,NULL,1,0,'CMB5e is the latest edition of an interactive Open Educational Resource (OER) electronic textbook (iText), available under a Creative Commons CC-BY license. Like earlier editions, CMB5e opens with a short history of the discipline and a discussion of scientific method. The book remains focused on the understanding of evolution that informs all of the life sciences and continues to provide experimental support for what we know about cell and molecular biology. Having a sense of how science is practiced and how investigators think about experimental results is essential to understanding the relationship of cell structure and function, not to mention the natural world around us. CMB5e is available in three versions (plus a sample chapter): In each chapter of the Basic CMB5e iText, an introduction includes learning objectives and context-embedded links to short explanatory voice-over PowerPoint recordings (VOPs) and other web-links of interest. QR codes allow the reader just-in-time access to the VOPs on smart phones or any camera-enabled portable device. The Annotated CMB5e adds pre-written, interactive context-embedded Challenge boxes to the Basic version of the book. These contain open-ended questions that expand on text readings. Any or all of them can be the basis of informal class and online discussion or as graded assignments. The Instructor’s CMB5e iText adds a series of 25 Words or Less essay questions that the author used as short (i.e., easy to grade!) writing assignments to strengthen student’s critical thinking and writing skills. A CMB5e Sample Chapter. The Art and Illustration Resource for Cell and Molecular Biology contains high resolution JPGs of figures in all CMB5 digital and print versions. JPGs are all public domain or CC-BY licensed (a source list is included).\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 244.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/cell-and-molecular-biology-2e-what-we-know-how-we-found-out\nPublisher ô CSV: University of Wisconsin, Milwaukee.\nCopyright Year ô CSV: 2020.\nISBN-13 ô CSV: 9780996150279.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Biology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Gerald Bergtrom - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9780996150279.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(195,'OTL-245','GT-OTL000245','Precalculus',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'These are notes for a course in precalculus, as it is taught at New York City College of Technology - CUNY (where it is offered under the course number MAT 1375). Our approach is calculator based. For this, we will use the currently standard TI-84 calculator, and in particular, many of the examples will be explained and solved with it. However, we want to point out that there are also many other calculators that are suitable for the purpose of this course and many of these alternatives have similar functionalities as the calculator that we have chosen to use. An introduction to the TI-84 calculator together with the most common applications needed for this course is provided in appendix A. In the future we may expand on this by providing introductions to other calculators or computer algebra systems. This course in precalculus has the overarching theme of “functions.” This means that many of the often more algebraic topics studied in the previous courses are revisited under this new function theoretic point of view. However, in order to keep this text as self contained as possible we always recall all results that are necessary to follow the core of the course even if we assume that the student has familiarity with the formula or topic at hand. After a first introduction to the abstract notion of a function, we study polynomials, rational functions, exponential functions, logarithmic functions, and trigonometric functions with the function viewpoint. Throughout, we will always place particular importance to the corresponding graph of the discussed function which will be analyzed with the help of the TI-84 calculator as mentioned above. These are in fact the topics of the first four (of the five) parts of this precalculus course. In the fifth and last part of the book, we deviate from the above theme and collect more algebraically oriented topics that will be needed in calculus or other advanced mathematics courses or even other science courses. This part includes a discussion of the algebra of complex numbers (in particular complex numbers in polar form), the 2-dimensional real vector space R 2 sequences and series with focus on the arithmetic and geometric series (which are again examples of functions, though this is not emphasized), and finally the generalized binomial theorem.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 245.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/precalculus-2015\nPublisher ô CSV: CUNY Academic Works.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Thomas Tradler - Author / Holly Carley - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:01:00',NULL),(196,'OTL-246','GT-ISBN9781942341192','Nursing Care at the End of Life: What Every Clinician Should Know',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Nursing Care at the End of Life: What Every Clinician Should Know should be an essential component of basic educational preparation for the professional registered nurse student. Recent studies show that only one in four nurses feel confident in caring for dying patients and their families and less than 2% of overall content in nursing textbooks is related to end-of-life care, despite the tremendous growth in palliative and end-of-life care programs across the country. The purpose of this textbook is to provide an indepth look at death and dying in this country, including the vital role of the nurse in assisting patients and families along the journey towards the end of life. There is an emphasis throughout the book on the simple, yet understated value of effective interpersonal communication between the patient and clinician. The text provides a basic foundation of understanding death and dying, including a brief historical examination of some main conceptual models associated with how patients cope with impending loss. An overview of illness trajectories and models of care, such as hospice and palliative care are discussed. Lastly, the latest evidence-based approaches for pain and symptom management, ethical concerns, cultural considerations, care at the time of death, and grief/bereavement are examined. The goal of this text is to foster the necessary skills for nurses to provide compassionate care to individuals who are nearing the end of life and their families. Every chapter contains a “What You Should Know” section which highlights and reinforces foundational concepts.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 246.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/nursing-care-at-the-end-of-life-what-every-clinician-should-know\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781942341192.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Medicine - Nursing.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 600 — Công nghệ (Khoa học ứng dụng).\nContributors — nguyên bản ô CSV —: Susan E. Lowey - Author',NULL,NULL,'600','utc-elibrary/book-covers/isbn/9781942341192.jpg',4,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(197,'OTL-247','GT-ISBN9781942341215','Writing In College: From Competence to Excellence',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Writing in College is designed for students who have largely mastered high-school level conventions of formal academic writing and are now moving beyond the five-paragraph essay to more advanced engagement with text. It is well suited to composition courses or first-year seminars and valuable as a supplemental or recommended text in other writing-intensive classes. It provides a friendly, down-to-earth introduction to professors\' goals and expectations, demystifying the norms of the academy and how they shape college writing assignments. Each of the nine chapters can be read separately, and each includes suggested exercises to bring the main messages to life. Students will find in Writing in College a warm invitation to join the academic community as novice scholars and to approach writing as a meaningful medium of thought and communication. With concise discussions, clear multidisciplinary examples, and empathy for the challenges of student life, Guptill conveys a welcoming tone. In addition, each chapter includes Student Voices: peer-to-peer wisdom from real SUNY Brockport students about their strategies for and experiences with college writing. While there are many affordable writing guides available, most focus only on sentence-level issues or, conversely, a broad introduction to making the transition. Writing In College, in contrast, provides both a coherent frame for approaching writing assignments and indispensable advice for effective organization and expression.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 247.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/writing-in-college-from-competence-to-excellence\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781942341215.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Amy Guptill - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781942341215.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(198,'OTL-248','GT-ISBN9781937963040','Français interactif',NULL,'Tiếng Pháp',NULL,2019,NULL,NULL,NULL,NULL,1,0,'This textbook of classroom activities and homework accompanies Français interactif. Français interactif, the web-based French program developed and in use at the University of Texas since 2004, and its companion site, Tex\'s French Grammar (2000)are open access sites, free and open multimedia resources, which require neither password nor fees. Français interactif, used increasingly by students, teachers, and institutions throughout the world, includes 320 videos (American students in France, native French interviews, vocabulary and culture presentation videos) recorded vocabulary lists, phonetic lessons, online grammar lessons (600 pages) with self-correcting exercises and audio dialogues, online grammar tools (verb conjugation reference, verb practice), and diagnostic grammar tests.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 248.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/francais-interactif\nPublisher ô CSV: COERLL.\nCopyright Year ô CSV: 2019.\nISBN-13 ô CSV: 9781937963040.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Karen Kelton - Author / Nancy Guilloteau - Author / Carl Blyth - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781937963040.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(199,'OTL-249','GT-ISBN9781937963019','Deutsch im Blick - 2nd Edition',NULL,'Tiếng Đức',NULL,2017,NULL,NULL,NULL,NULL,1,0,'This textbook includes all 10 chapters of Deutsch im Blick. It accompanies http://coerll.utexas.edu/dib/, the web-based first-year German program developed and in use at the University of Texas since 2008, and its companion site, Grimm Grammar. Deutsch im Blick is an open access site with free and open multimedia resources, which requires neither password nor fees. Deutsch im Blick has been funded and created by Liberal Arts Instructional Technology Services at the University of Texas, and is currently supported by COERLL, the Center for Open Educational Resources and Language Learning UT-Austin, and the U.S. Department of Education Fund for the Improvement of Post-Secondary Education (FIPSE Grant P116B070251 & P116Y090057) as an example of the open access initiative.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 249.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/deutsch-im-blick\nPublisher ô CSV: COERLL.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: 9781937963019.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Zsuzsanna Abrams - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781937963019.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(200,'OTL-250','GT-ISBN9781937963026','Yorùbá Yé Mi',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'The Yorùbá Yé Mi textbook, combined with an open access, multi-media website at http://www.coerll.utexas.edu/yemi, is an interactive, communicative, introductory Yorùbá program. It provides college/university students with basic listening, speaking, reading, and writing skills of language learning in Yorùbá. It exposes the learner not only to Yorùbá language in meaningful situations but also to the culture of the Yorùbá-speaking people of South-western Nigeria. It contains effective techniques for teaching and learning Yorùbá including tones, and is user friendly in its approach.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 250.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/yorubaye-mi\nPublisher ô CSV: COERLL.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781937963026.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Fehintola Mosadomi - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781937963026.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(201,'OTL-251','GT-ISBN9781937963057','Conversa Brasileira',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'Conversa Brasileira is an online open access site that contains a series of 35 video scenarios in which Brazilians talk about their daily activities, everything from hobbies to shopping, and from traffic jams to soccer games. These materials are designed to help intermediate- and advanced-level learners of Portuguese to analyze the way that Brazilians really talk and improve in their own proficiency and fluency. This textbook provides a hardcopy of all of the online materials, including the dialog transcriptions, English translations, and lesson notes that link to the original website.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 251.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/conversa-brasileira\nPublisher ô CSV: COERLL.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: 9781937963057.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Orlando R. Kelm - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781937963057.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(202,'OTL-252','GT-ISBN9781938168024','Calculus Volume 1',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Calculus is designed for the typical two- or three-semester general calculus course, incorporating innovative features to enhance student learning. The book guides students through the core concepts of calculus and helps them understand how those concepts apply to their lives and the world around them. Due to the comprehensive nature of the material, we are offering the book in three volumes for flexibility and efficiency. Volume 1 covers functions, limits, derivatives, and integration. OpenStax College has compiled many resources for faculty and students, from faculty-only content to interactive homework and study guides.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 252.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/calculus-volume-1\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781938168024.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Gilbert Strang - Author / Edwin Herman - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781938168024.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(203,'OTL-254','GT-ISBN9781329996779','Beginning Japanese for Professionals: Book 1',NULL,'Ngôn ngữ gốc đa dạng — xem chủ đề OTL và nhan đề',NULL,2015,NULL,NULL,NULL,NULL,1,0,'This textbook is designed for beginning learners who want to learn basic Japanese for the purpose of living and working in Japan. Unlike textbooks written primarily for students, whose content largely centers on student life, this book focuses more on social and professional life beyond school. As a beginning level textbook, this book includes many elementary grammar patterns (Japanese Language Proficiency Test Levels 5 and 4), but the vocabulary and situations are selected specifically for working adults. Explanations are kept concise so as to only cover key points. The main focus is on oral communication and the accompanying audio is to be used extensively. This textbook can be used for self-study, as part of an online course, or as a traditional college course.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 254.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/beginning-japanese-for-professionals-book-1\nPublisher ô CSV: Portland State University Library.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781329996779.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Emiko Konomi - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781329996779.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(204,'OTL-255','GT-ISBN9781329996694','FROM MSA to CA: A Beginner\'s Guide to Transitioning to Colloquial Arabic',NULL,'Ngôn ngữ gốc đa dạng — xem chủ đề OTL và nhan đề',NULL,2015,NULL,NULL,NULL,NULL,1,0,'This book is for students who have studied Modern Standard Arabic (MSA) for one year or more and would like to learn colloquial Arabic basics using their knowledge of MSA. It aims at transitioning learners from Novice Mid level to Intermediate Low through presenting situations useful for living in an Arab country. The book has several features including hyperlinks, practice dialogues with open answers, cultural tips, and more.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 255.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/from-msa-to-ca-a-beginner-s-guide-to-transitioning-to-colloquial-arabic\nPublisher ô CSV: Portland State University Library.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781329996694.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Lina Gomaa - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781329996694.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(205,'OTL-256','GT-OTL000256','Applied Probability',NULL,'Tiếng Anh',NULL,2009,NULL,NULL,NULL,NULL,1,0,'This is a \"first course\" in the sense that it presumes no previous course in probability. The mathematical prerequisites are ordinary calculus and the elements of matrix algebra. A few standard series and integrals are used, and double integrals are evaluated as iterated integrals. The reader who can evaluate simple integrals can learn quickly from the examples how to deal with the iterated integrals used in the theory of expectation and conditional expectation. Appendix B provides a convenient compendium of mathematical facts used frequently in this work. And the symbolic toolbox, implementing MAPLE, may be used to evaluate integrals, if desired. In addition to an introduction to the essential features of basic probability in terms of a precise mathematical model, the work describes and employs user defined MATLAB procedures and functions (which we refer to as m-programs, or simply programs) to solve many important problems in basic probability. This should make the work useful as a stand-alone exposition as well as a supplement to any of several current textbooks. Most of the programs developed here were written in earlier versions of MATLAB, but have been revised slightly to make them quite compatible with MATLAB 7. In a few cases, alternate implementations are available in the Statistics Toolbox, but are implemented here directly from the basic MATLAB program, so that students need only that program (and the symbolic mathematics toolbox, if they desire its aid in evaluating integrals). Since machine methods require precise formulation of problems in appropriate mathematical form, it is necessary to provide some supplementary analytical material, principally the so-called minterm analysis. This material is not only important for computational purposes, but is also useful in displaying some of the structure of the relationships among events.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 256.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/applied-probability\nPublisher ô CSV: OpenStax CNX.\nCopyright Year ô CSV: 2009.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Applied.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Paul Pfeiffer - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:01:00',NULL),(206,'OTL-257','GT-OTL000257','Understanding Basic Music Theory',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'Although it is significantly expanded from \"Introduction to Music Theory\", this book still covers only the bare essentials of music theory. Music is a very large subject, and the advanced theory that students will want to pursue after mastering the basics will vary greatly. A trumpet player interested in jazz, a vocalist interested in early music, a pianist interested in classical composition, and a guitarist interested in world music, will all want to delve into very different facets of music theory; although, interestingly, if they all become very well-versed in their chosen fields, they will still end up very capable of understanding each other and cooperating in musical endeavors. The final section does include a few challenges that are generally not considered \"beginner level\" musicianship, but are very useful in just about every field and genre of music.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 257.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/understanding-basic-music-theory-2013\nPublisher ô CSV: OpenStax CNX.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Arts.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 700 — Nghệ thuật & Giải trí.\nContributors — nguyên bản ô CSV —: Catherine Schmidt-Jones - Author',NULL,NULL,'700','utc-elibrary/book-covers/defaults/default-book-cover.jpg',5,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:01:00',NULL),(207,'OTL-260','GT-OTL000260','Elementary Algebra',NULL,'Tiếng Anh',NULL,2010,NULL,NULL,NULL,NULL,1,0,'Elementary Algebra is a work text that covers the traditional topics studied in a modern elementary algebra course. Use of this book will help the student develop the insight and intuition necessary to master algebraic techniques and manipulative skills.Elementary Algebra is a work text that covers the traditional topics studied in a modern elementary algebra course. It is intended for students who (1) have no exposure to elementary algebra, (2) have previously had an unpleasant experience with elementary algebra, or (3) need to review algebraic concepts and techniques.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 260.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/elementary-algebra-2010\nPublisher ô CSV: OpenStax CNX.\nCopyright Year ô CSV: 2010.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Algebra.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Wade Ellis - Author / Denny Burzynski - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:01:00',NULL),(208,'OTL-261','GT-OTL000261','Fast Fourier Transforms',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'This book focuses on the discrete Fourier transform (DFT), discrete convolution, and, particularly, the fast algorithms to calculate them. These topics have been at the center of digital signal processing since its beginning, and new results in hardware, theory and applications continue to keep them important and exciting. This book uses an index map, a polynomial decomposition, an operator factorization, and a conversion to a filter to develop a very general and efficient description of fast algorithms to calculate the discrete Fourier transform (DFT). The work of Winograd is outlined, chapters by Selesnick, Pueschel, and Johnson are included, and computer programs are provided.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 261.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/fast-fourier-transforms\nPublisher ô CSV: OpenStax CNX.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: C. Sidney Burrus - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:01:00',NULL),(209,'OTL-262','GT-ISBN9781937963064','Le Littéraire dans le quotidien',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Le Littéraire dans le quotidien is an open textbook for use in French courses. The Literary in the Everyday represents a new pedagogical approach to reading and writing at the lower levels and is applicable to all languages. Teachers of foreign languages besides French can read about the approach in the Teacher\'s Guide. Go to Google Drive for individual chapters. Additionally, the Foreign Languages & The Literary in the Everyday (FLLITE) Project, a joint initiative of COERLL and CERCLL, two national foreign language resource centers, offers open resources for professional development in the publication of CC licensed FLLITE lessons in any language.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 262.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/le-litteraire-dans-le-quotidien\nPublisher ô CSV: COERLL.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781937963064.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Joanna Gay Luks - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781937963064.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(210,'OTL-263','GT-ISBN9781942341284','Teaching Autoethnography: Personal Writing in the Classroom',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Teaching Autoethnography: Personal Writing in the Classroom is dedicated to the practice of immersive ethnographic and autoethnographic writing that encourages authors to participate in the communities about which they write. This book draws not only on critical qualitative inquiry methods such as interview and observation, but also on theories and sensibilities from creative writing and performance studies, which encourage self-reflection and narrative composition. Concepts from qualitative inquiry studies, which examine everyday life, are combined with approaches to the creation of character and scene to help writers develop engaging narratives that examine chosen subcultures and the author\'s position in relation to her research subjects. The book brings together a brief history of first-person qualitative research and writing from the past forty years, examining the evolution of nonfiction and qualitative approaches in relation to the personal essay. A selection of recent student writing in the genre as well as reflective student essays on the experience of conducting research in the classroom is presented in the context of exercises for coursework and beyond. Also explored in detail are guidelines for interviewing and identifying subjects and techniques for creating informed sketches and images that engage the reader. This book provides approaches anyone can use to explore their communities and write about them first-hand. The methods presented can be used for a single assignment in a larger course or to guide an entire semester through many levels and varieties of informed personal writing.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 263.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/teaching-autoethnography-personal-writing-in-the-classroom\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781942341284.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Education.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Melissa Tombro - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781942341284.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:36','2026-05-06 09:00:00',NULL),(211,'OTL-264','GT-ISBN9781942341253','Good Corporation, Bad Corporation: Corporate Social Responsibility in the Global Economy',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This textbook provides an innovative, internationally oriented approach to the teaching of corporate social responsibility (CSR) and business ethics. Drawing on case studies involving companies and countries around the world, the textbook explores the social, ethical, and business dynamics underlying CSR in such areas as global warming, genetically modified organisms (GMO) in food production, free trade and fair trade, anti-sweatshop and living-wage movements, organic foods and textiles, ethical marketing practices and codes, corporate speech and lobbying, and social enterprise. The book is designed to encourage students and instructors to challenge their own assumptions and prejudices by stimulating a class debate based on each case study.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 264.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/good-corporation-bad-corporation-corporate-social-responsibility-in-the-global-economy\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781942341253.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences - Economics.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Guillermo C. Jimenez - Author / Elizabeth Pulos - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781942341253.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(212,'OTL-265','GT-ISBN9781942341222','Steps to Success: Crossing the Bridge Between Literacy Research and Practice',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Steps to Success: Crossing the Bridge Between Literacy Research and Practice introduces instructional strategies linked to the most current research-supported practices in the field of literacy. The book includes chapters related to scientifically-based literacy research, early literacy development, literacy assessment, digital age influences on children\'s literature, literacy development in underserved student groups, secondary literacy instructional strategies, literacy and modern language, and critical discourse analysis. Chapters are written by authors with expertise in both college teaching and the delivery of research-supported literacy practices in schools. The book features detailed explanations of a wide variety of literacy strategies that can be implemented by both beginning and expert practitioners. Readers will gain knowledge about topics frequently covered in college literacy courses, along with guided practice for applying this knowledge in their future or current classrooms. The book\'s success-oriented framework helps guide educators toward improving their own practices and is designed to foster the literacy development of students of all ages.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 265.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/steps-to-success-crossing-the-bridge-between-literacy-research-and-practice\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781942341222.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Education.\nSubject OTL 2 — nguyên bản ô CSV —: Education - Elementary Education.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Kristen A. Munger - Editor',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781942341222.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(213,'OTL-266','GT-OTL000266','The Intelligent Troglodyte’s Guide to Plato’s Republic',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'The Republic of Plato is one of the classic gateway texts into the study and practice of philosophy, and it is just the sort of book that has been able to arrest and redirect lives. How it has been able to do this, and whether or not it will be able to do this in your own case, is something you can only discover for yourself. The present guidebook aims to help a person get fairly deep, fairly quickly, into the project. It divides the dialogue into 96 sections and provides commentary on each section as well as questions for reflection and exploration. It is organized with a table of contents and is stitched together with a system of navigating bookmarks. Links to external sites such as the Perseus Classical Library are used throughout. This book is suitable for college courses or independent study.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 266.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-intelligent-troglodyte-s-guide-to-plato-s-republic\nPublisher ô CSV: A.T. Still University.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Philosophy.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Douglas Drabkin - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:01:00',NULL),(214,'OTL-267','GT-OTL000267','The Changing Story: digital stories that participate in transforming teaching & learning',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'The Changing Story gives you assignments, resources, and examples to use in your teaching and learning. It will also help you think of ways digital stories can be used in your teaching, and help students harness the power of visual storytelling.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 267.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-changing-story-digital-stories-that-participate-in-transforming-teaching-learning\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Education.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Linda Buturian - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:01:00',NULL),(215,'OTL-268','GT-ISBN9780870710247','Living with Earthquakes in the Pacific Northwest',NULL,'Tiếng Anh',NULL,2004,NULL,NULL,NULL,NULL,1,0,'In this expanded new edition of Living with Earthquakes, Robert Yeats, a leading authority on earthquakes in California and the Pacific Northwest, describes the threat posed by the Cascadia Subduction Zone, a great earthquake fault which runs for hundreds of miles offshore from British Columbia to northern California. New research reveals subtle movements on the deepest part of this fault every 14-15 months — building up strain toward the next major earthquake. Combining cutting-edge research with practical safety information, Living with Earthquakes: • introduces new information about the danger from faults beneath major Northwest cities: the Seattle Fault, Tacoma Fault, and Portland Hills Fault• explores such topics as earthquake forecasting, catastrophe insurance, tsunamis, soil liquefaction, and seismic waves in Northwest lakes caused by Alaskan earthquakes• reviews earthquake preparedness and disaster response in the aftermath of the 2001 Nisqually earthquake, the worst natural disaster in Washington\'s history• suggests actions that citizens can take to protect their families and homesAn essential guide for anyone interested in understanding earthquake science or in preparing for the next earthquake, this book is also a call to action. Vivid descriptions of recent disasters — including the great tsunami that swept down the Northwest coast in 1964, the 1993 Oregon earthquakes, and the 2001 Nisqually earthquake — underscore the urgent need for better earthquake planning and awareness.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 268.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/living-with-earthquakes-in-the-pacific-northwest\nPublisher ô CSV: Oregon State University.\nCopyright Year ô CSV: 2004.\nISBN-13 ô CSV: 9780870710247.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Earth Sciences.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Robert S. Yeats - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9780870710247.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(216,'OTL-269','GT-OTL000269','Physical Geology',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Physical Geology is a comprehensive introductory text on the physical aspects of geology, including rocks and minerals, plate tectonics, earthquakes, volcanoes, glaciation, groundwater, streams, coasts, mass wasting, climate change, planetary geology and much more. It has a strong emphasis on examples from western Canada, especially British Columbia, and also includes a chapter devoted to the geological history of western Canada. The book is a collaboration of faculty from Earth Science departments at Universities and Colleges across British Columbia and elsewhere.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 269.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/physical-geology\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Earth Sciences.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Steven Earle - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:01:00',NULL),(217,'OTL-270','GT-OTL000270','Sustaining the Commons',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This textbook discusses the main framework, concepts and applications of the work of Elinor Ostrom and her colleagues for an undergraduate audience. We began teaching a course on collective and the commons in 2007 at Arizona State University. Initially we made use of Ostrom\'s classic book “Governing the Commons”, but this book was not written for an undergraduate audience. Moreover, many new insights have been developed since the 1990 publication of “Governing the Commons”. Therefore we decided to write our own textbook, which we have been using since the Spring of 2012. In this book you will learn about institutions–the rules and norms that guide the interactions among us. Those rules and norms can be found from traffic rules, rules in sports, regulations on when and where alcohol can be consumed, to constitutional rules that define who can become president of the United States of America. Rules and norms guide us to cooperative outcomes of so-called collective action problems. If we rely on voluntary contributions only to get anything done, this may not lead to the best results. But research also shows that coercion of people to comply to strict rules do not necessary lead to good outcomes. What combination of sticks and carrots is needed to be successful to solve collective action problems such as sustaining the commons? The book is based on the work of Elinor Ostrom and her colleagues. Ostrom is best known as the 2009 co-recipient of the Nobel Prize in Economics “for her analysis of economic governance, especially the commons”. Elinor Ostrom was a professor at Indiana University since the mid 1960s, and a part-time research professor at Arizona State University since 2006. She was active in research and teaching until her death at the age of 78 on June 12, 2012.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 270.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/sustaining-the-commons\nPublisher ô CSV: Arizona State University.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Economics.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences - Political Science.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: John M. Anderies - Author / Marco A. Janssen - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:01:00',NULL),(218,'OTL-271','GT-OTL000271','A Primer on Sustainable Business',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Going green, green business, and sustainable business are topics on everyone’s mind. But what does all this mean exactly? A Primer on Sustainable Business answers that question and provides an introduction to the basics you need to know.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 271.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/a-primer-on-sustainable-business\nPublisher ô CSV: LibreTexts.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Business - Finance.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:01:00',NULL),(219,'OTL-272','GT-OTL000272','The Business Ethics Workshop',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Ethics is about determining value; it\'s deciding what\'s worth doing and what doesn\'t matter so much.Business ethics is the way we decide what kind of career to pursue, what choices we make on the job,which companies we want to work with, and what kind of economic world we want to live in and thenleave behind for those coming after. There are no perfect answers to these questions, but there\'s adifference between thinking them through and winging it. The Business Ethics Workshop provides aframework for identifying, analyzing, and resolving ethical dilemmas encountered through working life.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 272.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-business-ethics-workshop\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: James Brusseau - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:01:00',NULL),(220,'OTL-273','GT-OTL000273','Business Law and the Legal Environment',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Our goal is to provide students with a textbook that is up to date and comprehensive in its coverage of legal and regulatory issues—and organized to permit instructors to tailor the materials to their particular approach. This book engages students by relating law to everyday events with which they are already familiar (or with which they are familiarizing themselves in other business courses) and by its clear, concise, and readable style. (An earlier business law text by authors Lieberman and Siedel was hailed “the best written text in a very crowded field.”) This textbook provides context and essential concepts across the entire range of legal issues with which managers and business executives must grapple. The text provides the vocabulary and legal acumen necessary for businesspeople to talk in an educated way to their customers, employees, suppliers, government officials—and to their own lawyers.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 273.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/business-law-and-the-legal-environment\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Law - Civil Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Don Mayer - Author / Daniel M. Warner - Author / George J. Siedel - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:01:00',NULL),(221,'OTL-274','GT-ISBN9781946135070','Communication in the Real World - An Introduction to Communication Studies',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Communication in the Real World: An Introduction to Communication Studies overviews the time-tested conceptual foundations of the field, while incorporating the latest research and cutting-edge applications of these basics. Each chapter will include timely, concrete, and real-life examples of communication concepts in action. A key feature of this book is the integration of content regarding diversity and organizational communication in each chapter through examples and/or discrete sub-sections. Discussions of diversity are not relegated to feature boxes. Also integrated into the content are examples that are inclusive in terms of race, gender, sexuality, ability, age, marital status, religion, and other diverse identity characteristics.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 274.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/communication-in-the-real-world-an-introduction-to-communication-studies\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781946135070.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Journalism, Media Studies & Communications.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781946135070.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(222,'OTL-275','GT-ISBN9781453343623','Growth and Competitive Strategy in 3 Circles',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'The 3-Circle model was developed over the past several years, initially in strategic planning for a university graduate program and in an executive MBA course designed to integrate the concepts of marketing and competitive strategy. Over the course of time, the 3-Circle model has been successfully used by hundreds of organizations throughout the world in establishing and growing their market positions. Many of the case examples in this book demonstrating applications of the 3-Circle model applications are from executives who have attended executive education training at the University of Notre Dame. The development of competitive strategy is difficult because there are a lot of moving parts, as well as hundreds of frameworks, that might potentially guide the effort. Executives appreciate how the 3-Circle model simplifies the integration of customer, firm, and competitor analysis to generate growth strategies. It also provides a common language and process for understanding and explaining competitive advantage and for identifying profitable growth strategy.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 275.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/growth-and-competitive-strategy-in-3-circles\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453343623.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Business - Management.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Joe E. Urbany - Author / James H. Davis - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453343623.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(223,'OTL-276','GT-OTL000276','International Economics: Theory and Policy',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'This text strives to reach a median between these two approaches. First, I believe that students need to learn the theory and models to understand how economists understand the world. I also think these ideas are accessible to most students if they are explained thoroughly. This text presents numerous models in some detail, not by employing advanced mathematics, but rather by walking students through a detailed description of how a model\'s assumptions influence its conclusions. Second, and perhaps more important, students must learn how the models connect with the real world. I believe that theory is done primarily to guide policy. We do positive economics to help answer the normative questions; for example, what should a country do about its trade policy or its exchange rate policy? The results from models give us insights that help us answer these questions. Thus this text strives to explain why each model is interesting by connecting its results to some aspect of a current policy issue. A prime example is found in Chapter 11 \"Evaluating the Controversy between Free Trade and Protectionism\" of this book, which addresses the age-old question of whether countries should choose free trade or some type of selected protection. The chapter demonstrates how the results of the various models presented throughout the text contribute to our understanding of this long-standing debate.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 276.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/international-economics-theory-and-policy\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Economics.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences - Political Science.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Steve Suranovic - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:01:00',NULL),(224,'OTL-277','GT-ISBN9781453343265','Introduction to Contracts, Sales and Product Liability',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'This textbook provides context and essential concepts across the entire range of legal issues with whichmanagers and business executives must grapple. The text provides the vocabulary and legal acumennecessary for businesspeople to talk in an educated way to their customers, employees, suppliers,government officials—and to their own lawyers. Traditional publishers often create confusion among customers in the text selection process by offering ahuge array of publications. Once a text is selected, customers might still have to customize the text to meettheir needs. For example, publishers usually offer books that include either case summaries or excerptedcases, but some instructors prefer to combine case summaries with a few excerpted cases so that studentscan experience reading original material. Likewise, the manner in which most conventional textsincorporate video is cumbersome because the videos are contained in a separate library, which makesaccess more complicating for instructors and students.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 277.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-contracts-sales-and-product-liability\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453343265.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Law - Administrative Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Don Mayer - Author / Daniel Warner - Author / George J. Siedel - Author / Jethro K. Lieberman - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453343265.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(225,'OTL-278','GT-ISBN9781453344163','Introduction to the Law of Property, Estate Planning and Insurance',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Introduction to the Law of Property, Estate Planning and Insurance is an up-to-date textbook that covers legal issues that students must understand relating to real estate (an especially important business asset), as well as estate planning and insurance. The text is organized to permit instructors to tailor the materials to their particular approach. The authors take special care to engage students by relating law to everyday events with their clear, concise and readable style. After introductory chapters covering the legal environment of business, Introduction to the Law of Property, Estate Planning and Insurance provides students with context and essential legal concepts relating to property rights and duties, estate planning, insurance, secured transactions, mortgages, and related topics. The text provides the vocabulary and legal savvy they will need when working with these concepts, which are critical to business planning and success.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 278.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-the-law-of-property-estate-planning-and-insurance\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453344163.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Law - Administrative Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Don Mayer - Author / Daniel Warner - Author / George J. Siedel - Author / Jethro K. Lieberman - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453344163.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(226,'OTL-279','GT-ISBN9781453344170','Law for Entrepreneurs',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Law for Entrepreneurs is an up-to-date textbook that covers the broad spectrum of legal issues that entrepreneurs must understand when starting and running a business. The text is organized to permit instructors to tailor the materials to their particular approach. The authors take special care to engage students by relating law to everyday events with their clear, concise and readable style. After introductory chapters covering the legal environment of business, Law for Entrepreneurs provides students with context and essential legal concepts relating to contracts, product liability, intellectual property, insurance, agency law, partnerships, corporations, and employment law. The text provides the vocabulary and legal savvy that entrepreneurs need to talk in an educated way to customers, suppliers, employees, creditors, shareholders, government regulators and other stakeholders — and to their own lawyers.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 279.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/law-for-entrepreneurs\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453344170.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Law - Administrative Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Don Mayer - Author / Daniel Warner - Author / George J. Siedel - Author / Jethro K. Lieberman - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453344170.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(227,'OTL-280','GT-ISBN9781453343302','Law of Commercial Transactions',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Law of Commercial Transactions is an up-to-date textbook that covers legal issues that students who engage in commercial transactions must understand. The text is organized to permit instructors to tailor the materials to their particular approach. The authors take special care to engage students by relating law to everyday events with their clear, concise and readable style. After introductory chapters covering the legal environment of business, Law of Commercial Transactions provides students with context and essential legal concepts relating to key commercial transactions topics: contracts, sales, commercial paper, debtors and creditors. The text provides the vocabulary and legal savvy students will need to talk in an educated way to customers, suppliers, creditors, government regulators and other stakeholders — and to their own lawyers.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 280.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/law-of-commercial-transactions\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453343302.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Law - Administrative Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Don Mayer - Author / Daniel Warner - Author / George J. Siedel - Author / Jethro K. Lieberman - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453343302.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(228,'OTL-281','GT-ISBN9781453343258','Legal Aspects of Corporate Management and Finance',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Legal Aspects of Corporate Management and Finance is an up-to-date textbook that covers key legal issues relating to corporate management and finance. The text is organized to permit instructors to tailor the materials to their particular approach. The authors take special care to engage students by relating law to everyday events with their clear, concise and readable style. After introductory chapters covering the legal environment of business, Legal Aspects of Corporate Management and Finance provides students with context and essential legal concepts relating to contracts, agency law, partnerships, corporations, commercial paper, debtors and creditors. The text provides the vocabulary and legal savvy students will need to talk in an educated way to customers, suppliers, employees, creditors, shareholders, government regulators and other stakeholders — and to their own lawyers.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 281.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/legal-aspects-of-corporate-management-and-finance\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453343258.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Finance.\nSubject OTL 2 — nguyên bản ô CSV —: Law - Administrative Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Don Mayer - Author / Daniel Warner - Author / George J. Siedel - Author / Jethro K. Lieberman - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453343258.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(229,'OTL-282','GT-ISBN9781453343289','Legal Aspects of Marketing and Sales',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Legal Aspects of Marketing and Sales is an up-to-date textbook that covers legal issues that students who will work in marketing or with marketing managers must understand. The text is organized to permit instructors to tailor the materials to their particular approach. The authors take special care to engage students by relating law to everyday events with their clear, concise and readable style. After introductory chapters covering the legal environment of business, Legal Aspects of Marketing and Sales provides students with context and essential legal concepts relating to contracts, sales, intellectual property, antitrust law and unfair trade practices. The text provides the vocabulary and legal savvy they will need to talk in an educated way to customers, suppliers, shareholders, government regulators and other stakeholders — and to their own lawyers.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 282.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/legal-aspects-of-marketing-and-sales\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781453343289.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Marketing.\nSubject OTL 2 — nguyên bản ô CSV —: Law - Administrative Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Don Mayer - Author / Daniel Warner - Author / George J. Siedel - Author / Jethro K. Lieberman - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781453343289.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(230,'OTL-283','GT-ISBN9781942341208','Music and the Child',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Children are inherently musical. They respond to music and learn through music. Music expresses children\'s identity and heritage, teaches them to belong to a culture, and develops their cognitive well-being and inner self worth. As professional instructors, childcare workers, or students looking forward to a career working with children, we should continuously search for ways to tap into children\'s natural reservoir of enthusiasm for singing, moving and experimenting with instruments. But how, you might ask? What music is appropriate for the children I\'m working with? How can music help inspire a well-rounded child? How do I reach and teach children musically? Most importantly perhaps, how can I incorporate music into a curriculum that marginalizes the arts? This book explores a holistic, artistic, and integrated approach to understanding the developmental connections between music and children. This book guides professionals to work through music, harnessing the processes that underlie music learning, and outlining developmentally appropriate methods to understand the role of music in children\'s lives through play, games, creativity, and movement. Additionally, the book explores ways of applying music-making to benefit the whole child, i.e., socially, emotionally, physically, cognitively, and linguistically.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 283.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/music-and-the-child\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781942341208.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Arts.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 700 — Nghệ thuật & Giải trí.\nContributors — nguyên bản ô CSV —: Natalie Sarrazin - Author',NULL,NULL,'700','utc-elibrary/book-covers/isbn/9781942341208.jpg',5,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(231,'OTL-284','GT-OTL000284','The Process of Research Writing',NULL,'Tiếng Anh',NULL,2007,NULL,NULL,NULL,NULL,1,0,'The title of this book is The Process of Research Writing, and in the nutshell, that is what the book is about. A lot of times, instructors and students tend to separate “thinking,” “researching,” and “writing” into different categories that aren\'t necessarily very well connected. First you think, then you research, and then you write.The reality is though that the possibilities and process of research writing are more complicated and much richer than that. We think about what it is we want to research and write about, but at the same time, we learn what to think based on our research and our writing. The goal of this book is to guide you through this process of research writing by emphasizing a series of exercises that touch on different and related parts of the research process.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 284.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-process-of-research-writing\nPublisher ô CSV: Steven D. Krause.\nCopyright Year ô CSV: 2007.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Steven D. Krause - Author',NULL,NULL,'800','utc-elibrary/book-covers/defaults/default-book-cover.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:01:00',NULL),(232,'OTL-285','GT-ISBN9781491929568','Think Java: How To Think Like a Computer Scientist - 2e',NULL,'Tiếng Anh',NULL,2020,NULL,NULL,NULL,NULL,1,0,'Think Java is a hands-on introduction to computer science and programming used by many universities and high schools around the world. Its conciseness, emphasis on vocabulary, and informal tone make it particularly appealing for readers with little or no experience. The book starts with the most basic programming concepts and gradually works its way to advanced object-oriented techniques. In this fully updated and expanded edition, authors Allen Downey and Chris Mayfield introduce programming as a means for solving interesting problems. Each chapter presents material for one week of a college course and includes exercises to help you practice what you’ve learned. Along the way, you’ll see nearly every topic required for the AP Computer Science A exam and Java SE Programmer I certification.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 285.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/think-java-how-to-think-like-a-computer-scientist\nPublisher ô CSV: Green Tea Press.\nCopyright Year ô CSV: 2020.\nISBN-13 ô CSV: 9781491929568.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science - Programming Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Chris Mayfield - Author / Allen Downey - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781491929568.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(233,'OTL-287','GT-ISBN9781491907337','Think Stats: Probability and Statistics for Programmers - 2e',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'Think Stats is an introduction to Probability and Statistics for Python programmers. Think Stats emphasizes simple techniques you can use to explore real data sets and answer interesting questions. The book presents a case study using data from the National Institutes of Health. Readers are encouraged to work on a project with real datasets. If you have basic skills in Python, you can use them to learn concepts in probability and statistics. Think Stats is based on a Python library for probability distributions (PMFs and CDFs). Many of the exercises use short programs to run experiments and help readers develop understanding.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 287.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/think-stats-probability-and-statistics-for-programmers\nPublisher ô CSV: Green Tea Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781491907337.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Allen B. Downey - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781491907337.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(234,'OTL-288','GT-ISBN9781449370787','Think Bayes: Bayesian Statistics Made Simple',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Think Bayes is an introduction to Bayesian statistics using computational methods. The premise of this book, and the other books in the Think X series, is that if you know how to program, you can use that skill to learn other topics. Most books on Bayesian statistics use mathematical notation and present ideas in terms of mathematical concepts like calculus. This book uses Python code instead of math, and discrete approximations instead of continuous mathematics. As a result, what would be an integral in a math book becomes a summation, and most operations on probability distributions are simple loops. I think this presentation is easier to understand, at least for people with programming skills. It is also more general, because when we make modeling decisions, we can choose the most appropriate model without worrying too much about whether the model lends itself to conventional analysis. Also, it provides a smooth development path from simple examples to real-world problems.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 288.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/think-bayes-bayesian-statistics-made-simple\nPublisher ô CSV: Green Tea Press.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781449370787.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Allen B. Downey - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781449370787.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(235,'OTL-289','GT-ISBN9781492040200','Think Complexity: Exploring Complexity Science with Python - 2e',NULL,'Tiếng Anh',NULL,2018,NULL,NULL,NULL,NULL,1,0,'Complexity science uses computation to explore the physical and social sciences. In Think Complexity, you\'ll use graphs, cellular automata, and agent-based models to study topics in physics, biology, and economics. Whether you\'re an intermediate-level Python programmer or a student of computational modeling, you\'ll delve into examples of complex systems through a series of worked examples, exercises, case studies, and easy-to-understand explanations. In this updated second edition, you will: Work with NumPy arrays and SciPy methods, including basic signal processing and Fast Fourier Transform Study abstract models of complex physical systems, including power laws, fractals and pink noise, and Turing machines Get Jupyter notebooks filled with starter code and solutions to help you re-implement and extend original experiments in complexity; and models of computation like Turmites, Turing machines, and cellular automata Explore the philosophy of science, including the nature of scientific laws, theory choice, and realism and instrumentalism Ideal as a text for a course on computational modeling in Python, Think Complexity also helps self-learners gain valuable experience with topics and ideas they might not encounter otherwise.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 289.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/think-complexity-exploring-complexity-science-with-python\nPublisher ô CSV: Green Tea Press.\nCopyright Year ô CSV: 2018.\nISBN-13 ô CSV: 9781492040200.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Allen B. Downey - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781492040200.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(236,'OTL-290','GT-ISBN9781491938454','Think DSP: Digital Signal Processing in Python',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Think DSP is an introduction to Digital Signal Processing in Python. The premise of this book (and the other books in the Think X series) is that if you know how to program, you can use that skill to learn other things. The author is writing this book because he thinks the conventional approach to digital signal processing is backward: most books (and the classes that use them) present the material bottom-up, starting with mathematical abstractions like phasors.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 290.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/think-dsp-digital-signal-processing-in-python\nPublisher ô CSV: Green Tea Press.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781491938454.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Allen B. Downey - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781491938454.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(237,'OTL-291','GT-OTL000291','Open Logic Project',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'The Open Logic Text is an open-source, collaborative textbook of formal meta-logic and formal methods, starting at an intermediate level (i.e., after an introductory formal logic course). Though aimed at a non-mathematical audience (in particular, students of philosophy and computer science), it is rigorous. The Open Logic Text is a collaborative project and is under active development. Coverage of some topics currently included may not yet be complete, and many sections still require substantial revision. We plan to expand the text to cover more topics in the future. We also plan to add features to the text, such as a glossary, a list of further reading, historical notes, pictures, better explanations, sections explaining the relevance of results to philosophy, computer science, and mathematics, and more problems and examples. If you find an error, or have a suggestion, please let the project team know. The project operates in the spirit of open source. Not only is the text freely available, we provide the LaTeX source under the Creative Commons Attribution license, which gives anyone the right to download, use, modify, re-arrange, convert, and re-distribute our work, as long as they give appropriate credit.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 291.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/open-logic-project\nPublisher ô CSV: Open Logic Text.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Philosophy.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Richard Zach - Author / Andrew Arana - Author / Jeremy Avigad - Author / Walter Dean - Author / Gillian Russell - Author / Nicole Wyatt - Author / Audrey Yap - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:01:00',NULL),(238,'OTL-292','GT-ISBN9781602356603','Yoga Minds, Writing Bodies: Contemplative Writing Pedagogy',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'In Yoga Minds, Writing Bodies, Christy Wenger argues for the inclusion of Eastern-influenced contemplative education within writing studies. She observes that, although we have \"embodied\" writing education in general by discussing the rhetorics of racialized, gendered, and disabled bodies, we have done substantially less to address the particular bodies that occupy our classrooms. She proposes that we turn to contemplative education practices that engages student bodies through fusing a traditional curriculum with contemplative practices including yoga, meditation, and the martial arts. Drawing strength from the recent \"quiet revolution\" (Zajonc) of contemplative pedagogy within postsecondary education and a legacy of field interest attributable to James Moffett, this project draws on case studies of first-year college writers to present contemplative pedagogy as a means of teaching students mindfulness of their writing and learning in ways that promote the academic, rhetorical work accomplished in first-year composition classes while at the same time remaining committed to a larger scope of a writer\'s physical and emotional well-being.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 292.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/yoga-minds-writing-bodies-contemplative-writing-pedagogy\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781602356603.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Christy Wenger - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781602356603.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(239,'OTL-293','GT-ISBN9781602357747','Antiracist Writing Assessment Ecologies: Teaching and Assessing Writing for a Socially Just Future',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'In Antiracist Writing Assessment Ecologies, Asao B. Inoue theorizes classroom writing assessment as a complex system that is \"more than\" its interconnected elements. To explain how and why antiracist work in the writing classroom is vital to literacy learning, Inoue incorporates ideas about the white racial habitus that informs dominant discourses in the academy and other contexts. Inoue helps teachers understand the unintended racism that often occurs when teachers do not have explicit antiracist agendas in their assessments. Drawing on his own teaching and classroom inquiry, Inoue offers a heuristic for developing and critiquing writing assessment ecologies that explores seven elements of any writing assessment ecology: power, parts, purposes, people, processes, products, and places.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 293.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/antiracist-writing-assessment-ecologies-teaching-and-assessing-writing-for-a-socially-just-future\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781602357747.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Education - Higher Education.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Asao B. Inoue - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781602357747.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(240,'OTL-294','GT-ISBN9781602356474','Beyond Argument: Essaying as a Practice of (Ex)Change',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Beyond Argument offers an in-depth examination of how current ways of thinking about the writer-page relation in personal essays can be reconceived according to practices in the care of the self — an ethic by which writers such as Seneca, Montaigne, and Nietzsche lived. This approach promises to reinvigorate the form and address many of the concerns expressed by essay scholars and writers regarding the lack of rigorous exploration we see in our students\' personal essays — and sometimes, even, in our own. In pursuing this approach, Sarah Allen presents a version of subjectivity that enables productive debate in the essay, among essays, and beyond.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 294.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/beyond-argument-essaying-as-a-practice-of-ex-change\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781602356474.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Sarah Allen - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781602356474.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(241,'OTL-295','GT-ISBN9781602356320','Beyond Dichotomy: Synergizing Writing Center and Classroom Pedagogies',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'How closely can or should writing centers and writing classrooms collaborate? Beyond Dichotomy explores how research on peer tutoring one-to-one and in small groups can inform our work with students in writing centers and other tutoring programs, as well as in writing courses and classrooms. These multi-method (including rhetorical and discourse analyses and ethnographic and case-study) investigations center on several course-based tutoring (CBT) partnerships at two universities. Rather than practice separately in the center or in the classroom, rather than seeing teacher here and tutor there and student over there, CBT asks all participants in the dynamic drama of teaching and learning to consider the many possible means of connecting synergistically. This book offers the \"more-is-more\" value of designing more peer-to-peer learning situations for developmental and multicultural writers, and a more elaborate view of what happens in these peer-centered learning environments. It offers important implications—especially of directive and nondirective tutoring strategies and methods—for peer-to-peer learning and one-to-one tutoring and conferencing for all teachers and learners of writing.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 295.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/beyond-dichotomy-synergizing-writing-center-and-classroom-pedagogies\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781602356320.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Education - Higher Education.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Steven J. Corbett - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781602356320.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(242,'OTL-296','GT-ISBN9781602354227','The Centrality of Style',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'InThe Centrality of Style, editors Mike Duncan and Star Medzerian Vanguri argue that style is a central concern of composition studies even as they demonstrate that some of the most compelling work in the area has emerged from the margins of the field. Calling attention to this paradox in his foreword to the collection, Paul Butler observes, \"Many of the chapters work within the liminal space in which style serves as both a centralizing and decentralizing force in rhetoric and composition. Clearly, the authors and editors have made an invaluable contribution in their collection by exposing the paradoxical nature of a canon that continues to play a vital role in our disciplinary history.\"\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 296.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-centrality-of-style\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: 9781602354227.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Education - Higher Education.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Mike Duncan - Author / Star M. Vanguri - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781602354227.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(243,'OTL-297','GT-ISBN9781602353022','Chinese Rhetoric and Writing: An Introduction for Language Teachers',NULL,'Ngôn ngữ gốc đa dạng — xem chủ đề OTL và nhan đề',NULL,2012,NULL,NULL,NULL,NULL,1,0,'The authors of Chinese Rhetoric and Writing offer a response to the argument that Chinese students\' academic writing in English is influenced by \"culturally nuanced rhetorical baggage that is uniquely Chinese and hard to eradicate.\" Noting that this argument draws from \"an essentially monolingual and Anglo-centric view of writing,\" they point out that the rapid growth in the use of English worldwide calls for \"a radical reassessment of what English is in today\'s world.\" The result is a book that provides teachers of writing, and in particular those involved in the teaching of English academic writing to Chinese students, an introduction to key stages in the development of Chinese rhetoric, a wide-ranging field with a history of several thousand years. Understanding this important rhetorical tradition provides a strong foundation for assessing and responding to the writing of this growing group of students.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 297.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/chinese-rhetoric-and-writing-an-introduction-for-language-teachers\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781602353022.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Education.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Languages.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Andy Kirkpatrick - Author / Zhichang Xu - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781602353022.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(244,'OTL-298','GT-ISBN9781602356511','Critical Expressivism: Theory and Practice in the Composition Classroom',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'Critical Expressivism is an ambitious attempt to re-appropriate intellectual territory that has more often been charted by its detractors than by its proponents. Indeed, as Peter Elbow observes in his contribution to this volume, \"As far as I can tell, the term \'expressivist\' was coined and used only by people who wanted a word for people they disapproved of and wanted to discredit.\" The editors and contributors to this collection invite readers to join them in a new conversation, one informed by \"a belief that the term expressivism continues to have a vitally important function in our field.\"\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 298.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/critical-expressivism-theory-and-practice-in-the-composition-classroom\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781602356511.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Education - Higher Education.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Tara Roeder - Author / Roseanne Gatto - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781602356511.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(245,'OTL-299','GT-ISBN9781602352643','Copy(write): Intellectual Property in the Writing Classroom',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'The editors of Copy(write): Intellectual Property in the Writing Classroom bring together stories, theories, and research that can further inform the ways in which we situate and address intellectual property issues in our writing classrooms. The essays in the collection identify and describe a wide range of pedagogical strategies, consider theories, present research, explore approaches, and offer both cautionary tales and local and contextual successes that can further inform the ways in which we situate and address intellectual property issues in our teaching.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 299.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/copy-write-intellectual-property-in-the-writing-classroom\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: 9781602352643.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Education.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Martine Courant Rife - Editor / Shaun Slattery - Editor / Dànielle Nicole DeVoss - Editor',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781602352643.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(246,'OTL-300','GT-ISBN9781602351677','Design Discourse: Composing and Revising Programs in Professional and Technical Writing',NULL,'Tiếng Anh',NULL,2010,NULL,NULL,NULL,NULL,1,0,'Design Discourse: Composing and Revising Programs in Professional and Technical Writing, edited byDavid Franke, Alex Reid, andAnthony Di Renzo,addresses the complexities of developing professional and technical writing programs. The essays in the collection offer reflections on efforts to bridge two cultures — what the editors characterize as the \"art and science of writing\" — often by addressing explicitly the tensions between them. Design Discourse offers insights into the high-stakes decisions made by program designers as they seek to \"function at the intersection of the practical and the abstract, the human and the technical.\"\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 300.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/design-discourse-composing-and-revising-programs-in-professional-and-technical-writing\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2010.\nISBN-13 ô CSV: 9781602351677.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Education - Higher Education.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: David Franke - Author / Alex Reid - Author / Anthony Di Renzo - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781602351677.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(247,'OTL-301','GT-ISBN9781602353435','Writing Programs Worldwide: Profiles of Academic Writing in Many Places',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Emerging from the International WAC/WID Mapping Project, this collection of essays is meant to inform decision-making by teachers, program managers, and college/university administrators considering how writing can most appropriately be defined, managed, funded, and taught in the places where they work. Writing Programs Worldwide offers an important global perspective to the growing research literature in the shaping of writing programs. The authors of its program profiles show how innovators at a diverse range of universities on six continents have dealt creatively over many years with day-to-day and long-range issues affecting how students across disciplines and languages grow as communicators and learners. In these profiles, we see teachers and researchers relying on colleagues and on transnational scholarship to build initiatives that are both well suited to their specific environments and can serve as regional and often global models. Their struggles and achievements offer insights to colleagues in similar locales and across borders who seek to establish, enhance, and assess their own work as designers of writing programs. An introduction and three section essays by the editors illuminate themes that inform this collection. Growing networks of initiators and scholars and survey results from the International WAC/WID Mapping Project exemplify the argument of this collection for transnational exchange and collaboration.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 301.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/writing-programs-worldwide-profiles-of-academic-writing-in-many-places\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781602353435.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Education - Curriculum & Instruction.\nSubject OTL 2 — nguyên bản ô CSV —: Education.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Chris Thaiss - Author / Gerd Bräuer - Author / Paula Carlino - Author / Lisa Ganobcsik-Williams - Author / Aparna Sinha - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781602353435.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:37','2026-05-06 09:00:00',NULL),(248,'OTL-302','GT-ISBN9781602352681','Writing in Knowledge Societies',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'The editors of Writing in Knowledge Societies provide a thoughtful, carefully constructed collection that addresses the vital roles rhetoric and writing play as knowledge-making practices in diverse knowledge-intensive settings. The essays in this book examine the multiple, subtle, yet consequential ways in which writing is epistemic, articulating the central role of writing in creating, shaping, sharing, and contesting knowledge in a range of human activities in workplaces, civic settings, and higher education. Writing in Knowledge Societies helps us conceptualize the ways in which rhetoric and writing work to organize, (re-)produce, undermine, dominate, marginalize, or contest knowledge-making practices in diverse settings, showing the many ways in which rhetoric and writing operate in knowledge-intensive organizations and societies.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 302.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/writing-in-knowledge-societies\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: 9781602352681.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Doreen Starke-Meyerring - Author / Anthony Paré - Author / Natasha Artemeva - Author / Miriam Horne - Author / Larissa Yousoubova - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781602352681.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(249,'OTL-303','GT-ISBN9781602354432','ePortfolio Performance Support Systems: Constructing, Presenting, and Assessing Portfolios',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'ePortfolio Performance Support Systems: Constructing, Presenting, and Assessing Portfolios addresses theories and practices advanced by some of the most innovative and active proponents of ePortfolios. Editors Katherine V. Wills and Rich Rice interweave twelve essays that address the ways in which ePortfolios can facilitate sustainable and measureable writing-related student development, assessment and accountability, learning and knowledge transfer, and principles related to universal design for learning, just-in-time support, interaction design, and usability testing.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 303.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/eportfolio-performance-support-systems-constructing-presenting-and-assessing-portfolios\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: 9781602354432.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Education.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Katherine V. Wills - Editor / Rich Rice - Editor',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781602354432.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(250,'OTL-304','GT-ISBN9781602356672','Foundational Practices of Online Writing Instruction',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Foundational Practices of Online Writing Instruction, edited by Beth L. Hewett and Kevin Eric DePew, with associate editors Elif Guler and Robbin Zeff Warner, addresses the questions and decisions that administrators and instructors most need to consider when developing online writing programs and courses. Written by experts in the field (members of the Conference on College Composition and Communication Committee for Effective Practices in OWI and other experts and stakeholders), the contributors to this collection explain the foundations of the recently published (2013) A Position Statement of Principles and Examples Effective Practices for OWI and provide illustrative practical applications. To that end, in every chapter, the authors address issues of inclusive and accessible writing instruction (based upon physical and mental disability, linguistic ability, and socioeconomic challenges) in technology enhanced settings. The five parts of this book attempt to cover the most important issues relevant to principle-centered OWI: (1) An OWI Primer, (2) OWI Pedagogy and Administrative Decisions, (3) Practicing Inclusivity in OWI, (4) Faculty and Student Preparation for OWI, and (5) New Directions in OWI. Working from the belief that most writing courses eventually will be mediated online to various degrees, the editors offer principles and practices that will allow this collection to inform future composition theory and praxis. To this end, the editors hope that the guidance provided in this collection will encourage readers to join a conversation about designing OWI practices, contributing to the scholarship about OWI, and reshaping OWI theory.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 304.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/foundational-practices-of-online-writing-instruction\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781602356672.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Education - Curriculum & Instruction.\nSubject OTL 2 — nguyên bản ô CSV —: Education - Distance Education.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Beth L. Hewett - Editor / Kevin Eric DePew - Editor / Elif Guler - Editor / Robbin Zeff Warner - Editor',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781602356672.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(251,'OTL-305','GT-ISBN9781602351271','Genre in a Changing World',NULL,'Tiếng Anh',NULL,2009,NULL,NULL,NULL,NULL,1,0,'Genre studies and genre approaches to literacy instruction continue to develop in many regions and from a widening variety of approaches. Genre has provided a key to understanding the varying literacy cultures of regions, disciplines, professions and educational settings. Genre in a Changing World,edited by Charles Bazerman, Adair Bonini, and Débora Figueiredo,provides a wide-ranging sampler of the remarkable variety of current work. The twenty-four chapters in this volume, reflecting the work of scholars in Europe, Australasia, North and South America, were selected from more than 400 presentations at SIGET IV (the Fourth International Symposium on Genre Studies), held on the campus of UNISUL in Tubarão, Santa Catarina, Brazil in August 2007—the largest gathering on genre to that date. The chapters also represent a wide variety of approaches including rhetoric, Systemic Functional Linguistics, media and critical cultural studies, sociology, phenomenology, enunciation theory, the Geneva school of educational sequences, cognitive psychology, relevance theory, sociocultural psychology, activity theory, Gestalt psychology, and schema theory. Sections are devoted to theoretical issues, studies of genres in the professions, studies of genre and media, teaching and learning genre, and writing across the curriculum. The broad selection of material in this volume displays the full range of contemporary genre studies and sets the ground for a next generation of work.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 305.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/genre-in-a-changing-world\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2009.\nISBN-13 ô CSV: 9781602351271.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Charles Bazerman - Editor / Adair Bonini - Editor / Débora Figueiredo - Editor',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781602351271.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(252,'OTL-306','GT-ISBN9781602353541','International Advances in Writing Research: Cultures, Places, Measures',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'The thirty chapters in this edited collection were selected from the more than 500 presentations at the Writing Research Across Borders II Conference in 2011. With representatives from more than forty countries, this conference gave rise to the International Society for the Advancement of Writing Research. The chapters selected for this collection represent cutting edge research on writing from all regions, organized around three themes—cultures, places, and measures. The authors report research that considers writing in all levels of schooling, in science, in the public sphere, and in the workplace, as well as at the relationship among these various places of writing. The authors also consider the cultures of writing—among them national cultures, gender cultures, schooling cultures, scientific cultures, and cultures of the workplace. Finally, the chapters examine various ways of measuring writing and how these measures interact with practices of teaching and learning.Edited by Charles Bazerman, Chris Dean, Jessica Early, Karen Lunsford, Suzie Null, Paul Rogers, and Amanda Stansell.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 306.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/international-advances-in-writing-research-cultures-places-measures\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781602353541.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Charles Bazerman - Author / Chris Dean - Author / Jessica Singer Early - Author / Karen Lunsford - Author / Suzie Null - Author / Paul Rogers - Author / Amanda Stansell - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781602353541.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(253,'OTL-307','GT-ISBN9781602354753','A Rhetoric of Literate Action: Literate Action Volume 1',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'The first in a two-volume set, A Rhetoric of Literate Action is written for \"the experienced writer with a substantial repertoire of skills, [who] now would find it useful to think in more fundamental strategic terms about what they want their texts to accomplish, what form the texts might take, how to develop specific contents, and how to arrange the work of writing.\" The reader is offered a framework for identifying and understanding the situations writing comes out of and is directed toward; a consideration of how a text works to transform a situation and achieve the writer\'s motives; and advice on how to bring the text to completion and \"how to manage the work and one\'s own emotions and energies so as to accomplish the work most effectively.\"\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 307.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/a-rhetoric-of-literate-action-literate-action-volume-1\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: 9781602354753.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Charles Bazerman - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781602354753.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(254,'OTL-308','GT-ISBN9781602354791','A Theory of Literate Action: Literate Action Volume 2',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'The second in a two-volume set, A Theory of Literate Action draws on work from the social sciences—and in particular sociocultural psychology, phenomenological sociology, and the pragmatic tradition of social science—to \"reconceive rhetoric fundamentally around the problems of written communication rather than around rhetoric\'s founding concerns of high stakes, agonistic, oral public persuasion\" (p. 3). An expression of more than a quarter-century of reflection and scholarly inquiry, this volume represents a significant contribution to contemporary rhetorical theory.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 308.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/a-theory-of-literate-action-literate-action-volume-2\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: 9781602354791.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Charles Bazerman - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781602354791.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(255,'OTL-309','GT-ISBN9781602358010','Placing the History of College Writing: Stories from the Incomplete Archive',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'In Placing the History of College Writing, Nathan Shepley argues that pre-1950s composition history, if analyzed with the right conceptual tools, can pluralize and clarify our understanding of the relationship between the writing of college students and the writing\'s physical, social, and discursive surroundings. Even if the immediate outcome of student writing is to generate academic credit, Shepley shows, the writing does more complex rhetorical work. It gives students chances to uphold or adjust institutional codes for student behavior, allows students and their literacy sponsors to respond to sociopolitical issues in a city or state, enables faculty and administrators to create strategic representations of institutional or program identities, and connects people across disciplines, occupations, and geographic locations. Shepley argues that even if many of today\'s composition scholars and instructors work at institutions that lack extensive historical records of the kind usually preferred by composition historians, those scholars and teachers can mine their institutional collections for signs of the various contexts with which student writing dealt.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 309.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/placing-the-history-of-college-writing-stories-from-the-incomplete-archive\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781602358010.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - History.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 900 — Lịch sử & Địa lý.\nContributors — nguyên bản ô CSV —: Nathan Shepley - Author',NULL,NULL,'900','utc-elibrary/book-covers/isbn/9781602358010.jpg',7,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(256,'OTL-310','GT-ISBN9781602355057','WAC and Second-Language Writers: Research Towards Linguistically and Culturally Inclusive Programs and Practices',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'In WAC and Second-Language Writers, the editors and contributors pursue the ambitious goal of including within WAC theory, research, and practice the differing perspectives, educational experiences, and voices of second-language writers. The chapters within this collection not only report new research but also share a wealth of pedagogical, curricular, and programmatic practices relevant to second-language writers. Representing a range of institutional perspectives—including those of students and faculty at public universities, community colleges, liberal arts colleges, and English-language schools—and a diverse set of geographical and cultural contexts, the editors and contributors report on work taking place in the United States, Asia, Europe, and the Middle East.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 310.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/wac-and-second-language-writers-research-towards-linguistically-and-culturally-inclusive-programs-and-practices\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781602355057.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Education - Curriculum & Instruction.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Terry Myers Zawacki - Editor / Michelle Cox - Editor',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781602355057.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(257,'OTL-311','GT-ISBN9781602358096','WAC Partnerships Between Secondary and Postsecondary Institutions',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Working with educators at all academic levels involved in WAC partnerships, the authors and editors of this collection demonstrate successful models of collaboration between schools and institutions so others can emulate and promote this type of collaboration. The chapters in this collection describe and reflect on collaborative partnerships among middle schools, high schools, colleges, and universities that are designed to prepare students for the kinds of work and civic engagement required to succeed in and contribute to society. The WAC partnerships celebrated in this collection include frameworks to build connectivity between institutions while addressing Common Core State Standards, academic and non-academic collaborations around science education, WAC partnerships in Argentina and Germany, and both long- and short-term collaborations.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 311.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/wac-partnerships-between-secondary-and-postsecondary-institutions\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781602358096.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Education.\nSubject OTL 2 — nguyên bản ô CSV —: Education - Higher Education.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Jacob Blumner - Editor / Pamela Childers - Editor',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781602358096.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(258,'OTL-312','GT-ISBN9781602357617','Working With Academic Literacies: Case Studies Towards Transformative Practice',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'The editors and contributors to this collection explore what it means to adopt an \"academic literacies\" approach in policy and pedagogy. Transformative practice is illustrated through case studies and critical commentaries from teacher-researchers working in a range of higher education contexts—from undergraduate to postgraduate levels, across disciplines, and spanning geopolitical regions including Australia, Brazil, Canada, Cataluña, Finland, France, Ireland, Portugal, South Africa, the United Kingdom, and the United States. Key questions addressed include: How can a wider range of semiotic resources and technologies fruitfully serve academic meaning and knowledge making? What kinds of writing spaces do we need and how can these be facilitated? How can theory and practice from \"Academic Literacies\" be used to open up debate about writing pedagogy at institutional and policy levels?\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 312.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/working-with-academic-literacies-case-studies-towards-transformative-practice\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781602357617.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Education - Higher Education.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Theresa Lillis - Author / Kathy Harrington - Author / Mary Lea - Author / Sally Mitchell - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781602357617.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(259,'OTL-313','GT-ISBN9783952334102','Squeak by Example',NULL,'Tiếng Anh',NULL,2009,NULL,NULL,NULL,NULL,1,0,'Squeak is a modern open-source development environment for the classic Smalltalk-80 programming language. Despite being the first purely object-oriented language and environment, Smalltalk is in many ways still far ahead of its successors in promoting a vision of an environment where everything is an object, and anything can change at run-time. Squeak by Example, intended for both students and developers, will guide you gently through the Squeak language and environment by means of a series of examples and exercises. The book helps you get started with A Quick Tour of Squeak and guides you through A First Application. The Smalltalk language is introduced in three chapters on Syntax in a Nutshell, Understanding Message Syntax and The Smalltalk Object Model. Development with Squeak is covered in The Squeak Programming Environment and SUnit. Several of the key classes are presented in chapters on Basic Classes, Collections, Streams and Morphic. The first edition of the book concludes with chapters on Classes and Metaclasses and Frequently Asked Questions.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 313.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/squeak-by-example\nPublisher ô CSV: University of Bern.\nCopyright Year ô CSV: 2009.\nISBN-13 ô CSV: 9783952334102.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Andrew P. Black - Author / Stéphane Ducasse - Author / Oscar Nierstrasz - Author / Damien Pollet - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9783952334102.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(260,'OTL-314','GT-ISBN9781365654596','Pharo by Example 5.0',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Pharo is an open-source, elegant and pure object-oriented language that supports truly immersive and life programming experience. Pharo offers excellent tools such as hot-debuggers and on the fly code update that change the programming experience. More at http://www.pharo.org.Pharo is a powerful language and IDE that companies use to deliver complex business-effective applications. More at: http://www.pharo.org/success In Pharo everything is an object, and anything can change at run-time under your fingers. Pharo is written in itself you can explore a complete world. You can feel and talk to objects. But Pharo does not stop there, with Pharo you can improve your object-oriented skills by rediscovering the essence of object-oriented programming. Pharo by Example 50, intended for both students and developers, will guide you gently through the Pharo language and environment by means of a series of examples and exercises. This book is available under the Creative Commons Attribution-ShareAlike 3.0 license.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 314.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/pharo-by-example-5-0\nPublisher ô CSV: Stéphane Ducasse.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781365654596.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Stéphane Ducasse - Author / Dmitri Zagidulin - Author / Nicolai Hess - Author / Dimitris Chloupis - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781365654596.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(261,'OTL-315','GT-ISBN9783952334164','Deep into Pharo',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'Pharo is a clean, innovative, open-source, live-programming environment. Deep into Pharois the second volume of a series of books covering Pharo. Whereas the first volume is intended for newcomers, this second volume covers deeper topics.You will learn about Pharo frameworks and libraries such as Glamour, PetitParser, Roassal, FileSystem, Regex, and Socket. You will explore the language with chapters on exceptions, blocks, small integers, and floats. You will discover tools such as profilers, Metacello and Gofer.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 315.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/deep-into-pharo\nPublisher ô CSV: Square Bracket Associates.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: 9783952334164.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Alexandre Bergel - Author / Damien Cassou - Author / Stéphane Ducasse - Author / Jannik Laval - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9783952334164.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(262,'OTL-316','GT-ISBN9780692700877','Introduction to Autonomous Robots',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This book introduces concepts in mobile, autonomous robotics to 3rd-4th year students in Computer Science or a related discipline. The book covers principles of robot motion, forward and inverse kinematics of robotic arms and simple wheeled platforms, perception, error propagation, localization and simultaneous localization and mapping. The cover picture shows a wind-up toy that is smart enough to not fall off a table just using intelligent mechanism design and illustrate the importance of the mechanism in designing intelligent, autonomous systems. This book is open source, open to contributions, and released under a creative common license.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 316.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-autonomous-robots\nPublisher ô CSV: Nikolaus Correll.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9780692700877.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Nikolaus Correll - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9780692700877.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(263,'OTL-317','GT-OTL000317','Creative Clinical Teaching In The Health Professions',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'This peer reviewed e-book is a must-read for nurses and other health professionals who strive to teach with creativity and excellence in clinical settings. Each chapter presents current evidence informed educational practice knowledge. Each topic is also presented with text boxes describing ‘Creative Strategies\' that clinical teachers from across Canada have successfully implemented. For those who are interested in background knowledge, the authors provided a comprehensive literature base. And, for those interested mainly in \'what to do,\' the text box summaries offer step-by-step directions for creative, challenging activities that both new and experienced instructors can begin using immediately.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 317.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/creative-clinical-teaching-in-the-health-professions\nPublisher ô CSV: Athabasca University Press.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Medicine.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 600 — Công nghệ (Khoa học ứng dụng).\nContributors — nguyên bản ô CSV —: Sherri Melrose - Author / Caroline Park - Author / Beth Perry - Author',NULL,NULL,'600','utc-elibrary/book-covers/defaults/default-book-cover.jpg',4,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:01:00',NULL),(264,'OTL-318','GT-ISBN9781961584792','American Government - 4e',NULL,'Tiếng Anh',NULL,2025,NULL,NULL,NULL,NULL,1,0,'American Government 4e aligns with the topics and objectives of many government courses. The authors have worked to develop meaningful and memorable explanations, narratives, and examples regarding the actions, workings, and outputs of government. The offering focuses on the real-world impact of government, and presents the importance and benefits of civic engagement by students. This book follows a logical progression from the fundamental principles of institutional design at the founding, to avenues of political participation, to thorough coverage of political structures. American Government 4e is designed to continually build upon what students have already learned and emphasizes connections between topics as well as between theory and applications. The goal of each section is to enable students not just to recognize concepts, but to work with them in ways that will be useful in later courses, future careers, and as engaged citizens. In order to help students understand the ways that government, society, and individuals interconnect, the revision includes updated information on the 2024 election results, recent court decisions and legal actions, and new opportunities for civic engagement.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 318.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/american-government\nPublisher ô CSV: OpenStax CNX.\nCopyright Year ô CSV: 2025.\nISBN-13 ô CSV: 9781961584792.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Political Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Glen Krutz - Author / Sylvie Waskiewicz - Editor',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781961584792.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(265,'OTL-319','GT-ISBN9780997920178','Fundamentals of Business - 4th Edition',NULL,'Tiếng Anh',NULL,2023,NULL,NULL,NULL,NULL,1,0,'Fundamentals of Business, 4th Edition is an open education resource intended to serve as a no-cost, faculty-customizable primary text for one-semester undergraduate introductory business courses. It covers the following topics in business: Teamwork; economics; ethics; entrepreneurship; business ownership, management, and leadership; organizational structures and operations management; human resources and motivating employees; managing in labor union contexts; marketing and pricing strategy; hospitality and tourism, accounting and finance, personal finances, and technology in business. The textbook was designed for use in Virginia Tech’s Pamplin College of Business introductory level business course, MGT1104 Foundations of Business and is shared under a Creative Commons Attribution Non-Commercial ShareAlike 4.0 license. If you are an instructor reviewing, adopting, or adapting this textbook, please help us understand your use by filling out this form http://bit.ly/business-interest. A testbank is now available by request for this book: http://hdl.handle.net/10919/93404. The testbank covers chapters 1-18 and (currently) aligns to previous editions of the textbook. It is available to any instructor who has adopted Fundamentals of Business in their course.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 319.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/fundamentals-of-business\nPublisher ô CSV: Virginia Tech Libraries.\nCopyright Year ô CSV: 2023.\nISBN-13 ô CSV: 9780997920178.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Management.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Stephen J. Skripak - Author / Ron Poff - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9780997920178.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(266,'OTL-320','GT-OTL000320','Bankruptcy Law and Practice - Fifth Edition',NULL,'Tiếng Anh',NULL,2024,NULL,NULL,NULL,NULL,1,0,'This is the Fifth Edition of Bankruptcy Law and Practice, a Casebook Designed to Train Lawyers for the Practice of Bankruptcy Law. It is designed for a one-semester course in debtor/creditor law and bankruptcy. The book deals with both creditor remedies and debtor protections, starting with state law collection remedies, exemptions, and the important special protections for secured creditors under both Article 9 of the Uniform Commercial Code and state real property recording acts. After a thorough review of state law debt collection practice, the book covers the basics of straight bankruptcy law with a focus on Chapter 7 of the Bankruptcy Code, both for individuals and businesses. Although the book has a practice focus, it covers the major Supreme Court cases (including those decided in June 2024), and important appellate cases with an emphasis on areas of uncertainty. The book also emphasizes the Bankruptcy Code itself, using problem sets to get students to work through the language of the Bankruptcy Code.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 320.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/bankruptcy-law-and-practice\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2024.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Gregory Germain - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:01:00',NULL),(267,'OTL-321','GT-OTL000321','Sources of American Law: An Introduction to Legal Research - 8th Edition',NULL,'Tiếng Anh',NULL,2024,NULL,NULL,NULL,NULL,1,0,'At its most basic definition the practice of law comprises conducting research to find relevant rules of law and then applying those rules to the specific set of circumstances faced by a client. However, in American law, the legal rules to be applied derive from myriad sources, complicating the process and making legal research different from other sorts of research. This text introduces first-year law students to the new kind of research required to study and to practice law. It seeks to demystify the art of legal research by following a “Source and Process” approach. First, the text introduces students to the major sources of American law and describes the forms the various authorities traditionally took in print. After establishing this base, the text proceeds to instruct students on the methods they will most likely use in practice, namely electronic research techniques and the consultation of secondary sources. Sources of Law incorporates screencasts currently hosted on YouTube that actively demonstrate the processes described in the static text. Finally, the text illustrates how the different pieces come together in the legal research process. Sources of Law focuses on realistic goals for 1Ls to learn in a relatively small amount of instruction time, and so focuses mainly on the basics. It does introduce some advanced material so that 1Ls can recognize pieces of information they may encounter in research, but it does not fully cover researching materials outside the scope of the traditional 1L course. As such, it is best-suited for introductory legal research courses for 1Ls. What\'s New in the Eighth Edition: The Eighth Edition primarily expands Chapter 9’s discussion of the research process to compare currently available legal generative AI tools to previously existing research tools such as secondary sources and electronic citators. That expansion also addresses some of the AI tools’ limitations and further discusses how thoughtful evaluation of available research tools can affect the research process.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 321.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/sources-of-american-law-an-introduction-to-legal-research\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2024.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Beau Steenken - Author / Tina M. Brooks - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:01:00',NULL),(268,'OTL-322','GT-OTL000322','Law of Wills',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'The purpose of this casebook is to train law students to think and act like probate attorneys. This book is meant to be used in conjunction with the author\'s book on the law of trusts. This book\'s focus is problem-solving and legal application; the book includes numerous problems, so law students can learn to apply the law they learn from reading the cases. It also contains collaborative learning exercises to encourage students to engage in group problem-solving. The book is divided into three parts to reflect the main types of issues that students will encounter if they practice probate law. The book\'s organization mirrors the manner in which probate law is practiced in the real world. The book starts with an examination of the intestacy system because the majority of people die without executing a will. Therefore, most of the legal issues a probate lawyer faces center around the intestacy system. Unlike the typical wills casebook, this book provides a detailed discussion of the intestacy system. A chapter on ethics is included because probate attorneys encounter ethical issues that are different from attorneys practicing in other areas of law. The second part of the book includes an exploration of the testacy system. It is arranged so professors can lead students from the client interview to the will execution. The first three chapters of this section deal with issues that directly impact the existence of the inheritance system. It analyzes a person\'s ability to control the disposition of his or her property after death. This serves as the students\' first introduction to the power of the “dead hand”. These chapters are included to start a public policy discussion about the rights of the dead, the right of heirs, and the necessity of an inheritance system. I tell my students that, when executing a will, they must think of the ways that it can be contested. In addition, I tell them that a will can be contested on two fronts-an attack on the testator and an attack on the will. Two chapters in this part highlight the ways that the testator\'s ability to execute a valid will may questioned. The final chapters in this unit show the issues that can be raised to dispute the validity of the will. They also explain the different types of wills that are available. The final part of the book deals with non-probate transfers. These chapters are included to show students the other devises that people can use to distribute their property. That knowledge is important because the majority of people use these procedures to transfer their property. At the end of the semester, my students have to draft a will based upon a fact pattern that I give them. I intentionally include non-probate property in order to see if they will attempt to distribute that using the will.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 322.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/law-of-wills\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Property Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Browne C. Lewis - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:01:00',NULL),(269,'OTL-323','GT-ISBN9781365302886','Basic Income Tax - 2023-2024 Edition',NULL,'Tiếng Anh',NULL,2023,NULL,NULL,NULL,NULL,1,0,'This book is the 8th edition of a basic income tax text. This edition incorporates the Tax Cuts and Jobs Act of 2017. It is intended to be a readable text, suitable for a three-hour course for a class comprised of law students with widely different backgrounds. The text integrates several of the CALI drills that Professor James Edward Maule (Villanova University) prepared.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 323.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/basic-income-tax\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2023.\nISBN-13 ô CSV: 9781365302886.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: William P. Kratzke - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781365302886.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(270,'OTL-324','GT-OTL000324','What Color is Your C.F.R.?',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'What Color is Your C.F.R.? is a problem-based law workbook with a colorful twist. Conceived and written by law librarians, it uses easy to understand plain language and is a light-hearted but helpful supplement to instruction on basic legal research. The book takes a non-traditional approach to legal research and uses short legal research exercises and coloring.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 324.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/what-color-is-your-c-f-r\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Elizabeth Gotauco - Illustrator / Nicole Dyszlewski - Author / Raquel M. Ortiz - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:01:00',NULL),(271,'OTL-325','GT-OTL000325','Torts: Cases, Principles, and Institutions - 6th Edition',NULL,'Tiếng Anh',NULL,2022,NULL,NULL,NULL,NULL,1,0,'This is the Fifth Edition of Torts: Cases, Principles, and Institutions, a casebook for a one-semester torts course that carves out a distinctive niche in the field by focusing on the institutions and sociology of American tort law. The book retains many of the familiar features of the traditional casebook, including many of the classic cases. Like the best casebooks, it seeks to survey the theoretical principles underlying those cases. But it aims to supplement the cases and principles with editorial notes that focus students’ attention on the institutional features of our tort system, including features such as the pervasiveness of settlements, the significance of the market, the role of the plaintiff\'s bar, the importance of private insurance, the contingency fee, and the jury. These institutional arrangements are what make American tort law distinctive. They are how the substantive doctrines of tort law are translated into the practice of torts lawyers. And they are sociologically fascinating in their own right. TCPI integrates the institutional materials into the cases and notes rather than segregate them into separate sections of their own. It does so because its aim is not to teach the details of any one institution, such as the mechanics of the law of subrogation or workers’ compensation. Few one-semester torts classes can take up so much material. Instead, the book integrates the institutional material into the main text to draw general lessons about the massive, sprawling systems of private administration that American law has created under the umbrella of our torts system.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 325.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/torts-cases-principles-and-institutions\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2022.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Civil Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: John Fabian Witt - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:01:00',NULL),(272,'OTL-326','GT-ISBN9781621711513','Elementary New Testament Greek',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'The need for this particular grammar arises from the peculiar shape of the MDiv curriculum at Asbury Theological Seminary. Several years ago the faculty adopted a curriculum that required one semester of Greek and one semester of Hebrew, each as preparatory for a basic exegesis course in each discipline. It became clear after several years of trial and error that a “lexical” or “tools” approach to learning Greek and Hebrew was inadequate, no matter how skilled the instructors or how motivated the students. In today\'s general vacuum of grammatical training in public education across the United States, students typically enter seminary training with no knowledge of how languages work. Any training we might give them in accessing grammatical information through the use of Bible software programs will, we learned, come to naught in the absence of an understanding of just what such information actually means. We agreed that we actually needed to “teach the language itself,” at least in some rudimentary fashion, if we hoped students would make sense of grammatical and linguistic issues involved biblical interpretation. The first 12 chapters of this grammar are designed to correspond to the first semester\'s instructional agenda. In these chapters we introduce all the parts of speech, explain and drill the basic elements of grammar, set forth the larger verb system (excluding the perfect system), teach the tenses of the Indicative Mood only (again, excluding the perfect system), and help students build a vocabulary of all NT words occurring 100 times or more. We also lead students into the NT itself with carefully chosen examples, while at the same time guiding them in each lesson to learn the use of the standard NT lexicon [BDAG] and an exegetical grammar [Wallace\'s Greek Grammar Beyond the Basics]. We are well aware of the limitations of this approach, but genuinely believe that some instruction along these lines is better than none, and that such an approach provide a foundation for students interested in moving beyond the first semester (into chapters 13-24) into a firmer grasp of the language of the NT.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 326.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/elementary-new-testament-greek\nPublisher ô CSV: First Fruits Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781621711513.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Languages.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Joseph R. Dongell - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781621711513.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:00:00',NULL),(273,'OTL-327','GT-OTL000327','Sales and Leases: A Problem-based Approach - Second Edition',NULL,'Tiếng Anh',NULL,2023,NULL,NULL,NULL,NULL,1,0,'Sales and Leases is a coursebook for a 3-credit course in personal property sales and leases – the subject matter of UCC Articles 2 and 2A. Adjustments could be made for other credit allocations and chapters can be used on a stand-alone basis. The course is designed so that students both review the rules and principles they studied in their first-year course in Contracts and learn the rules that apply to the subset of contracts for the sale and lease of goods. Students taking this course should be well-prepared to solve legal problems in contracts and sales, and should be well-prepared for those parts of the bar exam as well. While the course in Contracts focuses on the rules of common-law contracts, the focus of this course is the rules found in legislation. Therefore, instead of emphasizing case analysis, the book contains a good deal of narrative that assists students in working through the complexity of the statutes. Students will need to supplement the book with a complete copy of the UCC that includes the Official Comments. Discussion of other statutes, such as UETA and Magnuson-Moss, is incorporated where appropriate. The approach is problem-based, which we believe is more appropriate for an upper-division course based primarily on statutes. The narrative is interspersed with problems for class discussion that require students to apply the principles and rules to particular fact situations. Many times there is an issue of interpretation or policy in the Code, however, and therefore each chapter also contains at least one case that explores an issue arising under the statute.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 327.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/sales-and-leases-a-problem-based-approach\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2023.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Contract Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Scott J. Burnham - Author / Kristen Juras - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:01:00',NULL),(274,'OTL-328','GT-OTL000328','Signal Computing: Digital Signals in the Software Domain',NULL,'Tiếng Anh',NULL,2020,NULL,NULL,NULL,NULL,1,0,'In this book, you will learn how digital signals are captured, represented, processed, communicated, and stored in computers. The specific topics we will cover include: physical properties of the source information (such as sound or images), devices for information capture (microphones, cameras), digitization, compression, digital signal representation (JPEG, MPEG), digital signal processing (DSP), signal analysis and feature extraction via re-representation as functions of frequency, and network communication. By the end of this book, you should understand the problems and solutions facing signal computing systems development in the areas of data structures and algorithms, data analytics, feature extraction, information retrieval, user interfaces, and communications.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 328.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/signal-computing-digital-signals-in-the-software-domain\nPublisher ô CSV: Michael Stiber, Eric Larson.\nCopyright Year ô CSV: 2020.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Michael D. Stiber - Author / Bilin Zhang Stiber - Author / Eric C. Larson - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:01:00',NULL),(275,'OTL-330','GT-OTL000330','The Story of Contract Law: Formation - Fourth Edition',NULL,'Tiếng Anh',NULL,2021,NULL,NULL,NULL,NULL,1,0,'This book, revised as the Third Edition July 2019, is designed to teach contract doctrine beginning with the most fundamental concepts and building on these until the structure of contract doctrine as coherent and cohesive regulation appears. The order of presentation is, in fact, the order in which contract doctrine developed historically, but it is also, in general, the order in which arguments are introduced in litigation. The book begins with the most basic, core concept of contract law—exchange. The book teaches exchange using simple cases drawn from the actual development of the exchange concept’s most obvious manifestation—the doctrine of consideration. These cases have basic but engaging facts. They do not take long to read, but they must be read carefully. They make an excellent introduction to law study. Logically, every doctrine of contract formation is centered on whether and when a fair exchange occurred. In litigation, the plaintiff alleges a promise and consideration—an exchange (a plausible one, and therefore fair enough at that point). Defenses to formation are a response to the allegation that a fair exchange occurred. Allegations of both promise and consideration show that the defendant assented. As between assent and exchange, exchange is the more fundamental concept, but because the law talks so often about assent, assent is covered at length afterward so that the function of the assent doctrines is apparent. Other doctrines, such as remedies (just an introduction in this first volume), waiver, seals, the Statute of Frauds, definiteness, and general public policy limitations are placed where students can best grasp their import in the context of the other doctrines. Along the way, most of the doctrines in the book are repeated in the cases, questions, or in class discussion. This repetition cements understanding, builds trust, and also allows students to see how the doctrines mesh together to regulate coherently.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 330.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-story-of-contract-law-formation\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2021.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Contract Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Val Ricks - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:01:00',NULL),(276,'OTL-331','GT-OTL000331','Torts: Cases and Contexts Volume 1',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Plain-spoken and convivial, this casebook makes a deliberate effort to explain the law, rather than to provide a mere compilation of readings and questions. Simple concepts are presented simply. Complex concepts are broken down and accompanied by examples and problems. By being clear and straightforward, the casebook aims to quickly get students to the point where they can navigate regions of gray and build nuanced arguments. The book is written from the conviction that when students stop to puzzle over something, it should be because the law itself puzzles, not because the book obfuscates. Students describe the book as easy to read. A key aim is context, with explanations of how pieces of doctrine fit into the bigger picture. There is also a continual effort to plug doctrine into the real world of practice, getting students to think about litigation strategy and tactics. Another key feature is a high-degree of organization. Doctrine is explained upfront, independent of and before the cases. After the cases, there is no notes-and-questions mishmash. Historical notes, check-your-understanding questions, questions to ponder, and problems are all separately labeled as such. The readings are rich with variety. The classic cases are here, of course. But there are also atypical readings that allow students to see tort law from different perspectives, including an opening statement, a closing argument, administrative-enforcement letters, an excerpt from a novel, and an opinion on tribal law from a Navajo court. Many selections are also startlingly modern, with facts involving texting-and-driving, alcoholic energy drinks, Facebook libel, suddenly accelerating Toyotas, and the misery of a six-hour tarmac delay.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 331.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/torts-cases-and-contexts-volume-1\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Civil Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Eric E. Johnson - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:01:00',NULL),(277,'OTL-332','GT-OTL000332','U.S. Federal Income Taxation of Individuals 2023',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'This is the tenth edition of this textbook, updated through December 15, 2022 for use beginning January 2023. In addition to incorporating new law and all inflation adjustments, this edition builds on updates made for the ninth edition and incorporates new charts pertaining to economic and tax data, including December 2019 CBO charts showing that income inequality between 2015 and 2020 (with the Tax Cuts and Jobs Act enacted in 2017) worsened after taxes and transfers than before taxes and transfers are taken into account. This textbook is not intended to be an exhaustive treatise; rather, it is intended to be far more useful than that for beginning tax law students by equipping the novice not merely with unmoored detail but rather with a rich blueprint that illuminates the deeper structural framework on which that detail hangs (sometimes crookedly). Chapter 1 outlines the conceptual meaning of the term income for uniquely tax purposes and examines the Internal Revenue Code provisions that translate this construct into positive law. Chapter 2 explores various forms of consumption taxation because the modern Internal Revenue Code is best perceived as a hybrid income-consumption tax that also contains many provisions that are inconsistent with both forms of taxation. Chapter 3 then provides students with the story of how we got to where we are today, important context about the distribution of the tax burden, the budget, and economic trends, as well as material on ethical debates, economic theories, and politics as they affect taxation. Armed with this larger blueprint, students are in a much better position to evaluate the myriad pieces that follow throughout the remaining 18 chapters. For example, they are in a better position to appreciate how applying the income tax rules for debt to a debt-financed investment afforded more favorable consumption tax treatment creates tax shelter problems. Stated another way, they can better appreciate how the tax system can sometimes be used to generate (or combat) unfair and economically inefficient rent-seeking behavior. eBook versions (mobi and epub) will be available for free in early January 2023.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 332.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/u-s-federal-income-taxation-of-individuals-2017\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Deborah A Geier - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:38','2026-05-06 09:01:00',NULL),(278,'OTL-333','GT-OTL000333','Choosing & Using Sources: A Guide to Academic Research',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Choosing & Using Sources presents a process for academic research and writing, from formulating your research question to selecting good information and using it effectively in your research assignments. Additional chapters cover understanding types of sources, searching for information, and avoiding plagiarism. Each chapter includes self-quizzes and activities to reinforce core concepts and help you apply them. There are also appendices for quick reference on search tools, copyright basics, and fair use. What experts are saying about Choosing & Using Sources: A Guide to Academic Research: “…a really fantastic contribution that offers a much needed broadened perspective on the process of research, and is packed to the brim with all kinds of resources and advice on how to effectively use them. The chapter on plagiarism is really excellent, and the chapter on searching for sources is utterly brilliant.” – Chris Manion, PhDCoordinator of Writing Across the Curriculum at Ohio State University “… an excellent resource for students, with engaging content, graphics, and examples—very compelling. The coverage of copyright is outstanding.” – J. Craig GibsonCo-chair of ACRL\'s Task Force on Information Literacy Competency Standards for Higher Education\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 333.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/choosing-using-sources-a-guide-to-academic-research\nPublisher ô CSV: Ohio State University Libraries.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Education.\nSubject OTL 2 — nguyên bản ô CSV —: Student Success.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Cheryl Lowry - Editor',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(279,'OTL-334','GT-ISBN9781947172630','Chemistry: Atoms First - 2e',NULL,'Tiếng Anh',NULL,2019,NULL,NULL,NULL,NULL,1,0,'Chemistry: Atoms First 2e is a peer-reviewed, openly licensed introductory textbook produced through a collaborative publishing partnership between OpenStax and the University of Connecticut and UConn Undergraduate Student Government Association. This text is an atoms-first adaptation of OpenStax Chemistry 2e. The intention of “atoms-first” involves a few basic principles: first, it introduces atomic and molecular structure much earlier than the traditional approach, and it threads these themes through subsequent chapters. This approach may be chosen as a way to delay the introduction of material such as stoichiometry that students traditionally find abstract and difficult, thereby allowing students time to acclimate their study skills to chemistry. Additionally, it gives students a basis for understanding the application of quantitative principles to the chemistry that underlies the entire course. It also aims to center the study of chemistry on the atomic foundation that many will expand upon in a later course covering organic chemistry, easing that transition when the time arrives. The second edition has been revised to incorporate clearer, more current, and more dynamic explanations, while maintaining the same organization as the first edition. Substantial improvements have been made in the figures, illustrations, and example exercises that support the text narrative.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 334.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/chemistry-atoms-first\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2019.\nISBN-13 ô CSV: 9781947172630.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Chemistry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Paul Flowers - Author / Edward J. Neth - Author / William R. Robinson - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781947172630.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:00:00',NULL),(280,'OTL-335','GT-OTL000335','World Regional Geography',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Rather than present students with a broad, novice-level introduction to geography, emphasizing places and vocabulary terms, this text approaches geography as experts understand the discipline, focusing on connections and an in-depth understanding of core themes. This thematic approach, informed by pedagogical research, provides students with an introduction to thinking geographically. Instead of repeating the same several themes each chapter, this text emphasizes depth over breadth by arranging each chapter around a central theme and then exploring that theme in detail as it applies to the particular region. In addition, while chapters are designed to stand alone and be rearranged or eliminated at the instructor\'s discretion, the theme of globalization and inequality unites all of the regions discussed. This core focus enables students to draw connections between regions and to better understand the interconnectedness of our world. Furthermore, the focus on both globalization and inequality helps demonstrate the real-world application of the concepts discussed. Colonialism, for instance, rather than a historical relict, becomes a force that has shaped geography and informs social justice. This thematic approach is also intended to facilitate active learning and would be suitable for a flipped or team-based learning-style course since it more easily integrates case studies and higher-order thinking than the traditional model. Each chapter begins with a list of learning objectives. This text was written with the backward course design model in mind and the content of each chapter was structured around these learning objectives. Because of this backward design focus, the length of each chapter is considerably shorter than most traditional textbooks. The intention is for the instructor to supplement the text with problems, case studies, and news articles and to use the text as a springboard for discussing deeper issues. The chapters are written in an accessible style, often addressing the student directly, and the author\'s voice has intentionally tried to remain present in the text. Following the Washington Post\'s gender-inclusive style guide, the singular they is intentionally used throughout the text. Rhetorical questions are also used to help students reflect on concepts and to encourage them to dig deeper and consider concepts from different perspectives.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 335.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/world-regional-geography\nPublisher ô CSV: Caitlin Finlayson.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 1077115032.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Earth Sciences.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences - Cultural & Ethnic Studies.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Caitlin Finlayson - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(281,'OTL-336','GT-ISBN9781530051120','Python for Everybody: Exploring Data Using Python 3',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'I never seemed to find the perfect data-oriented Python book for my course, so I set out to write just such a book. Luckily at a faculty meeting three weeks before I was about to start my new book from scratch over the holiday break, Dr. Atul Prakash showed me the Think Python book which he had used to teach his Python course that semester. It is a well-written Computer Science text with a focus on short, direct explanations and ease of learning.The overall book structure has been changed to get to doing data analysis problems as quickly as possible and have a series of running examples and exercises about data analysis from the very beginning. Chapters 2–10 are similar to the Think Python book, but there have been major changes. Number-oriented examples and exercises have been replaced with data- oriented exercises. Topics are presented in the order needed to build increasingly sophisticated data analysis solutions. Some topics like try and except are pulled forward and presented as part of the chapter on conditionals. Functions are given very light treatment until they are needed to handle program complexity rather than introduced as an early lesson in abstraction. Nearly all user-defined functions have been removed from the example code and exercises outside of Chapter 4. The word “recursion”1 does not appear in the book at all. In chapters 1 and 11–16, all of the material is brand new, focusing on real-world uses and simple examples of Python for data analysis including regular expressions for searching and parsing, automating tasks on your computer, retrieving data across the network, scraping web pages for data, object-oriented programming, using web services, parsing XML and JSON data, creating and using databases using Structured Query Language, and visualizing data. The ultimate goal of all of these changes is a shift from a Computer Science to an Informatics focus is to only include topics into a first technology class that can be useful even if one chooses not to become a professional programmer.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 336.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/python-for-everybody-exploring-data-using-python-3\nPublisher ô CSV: Charles Severance.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781530051120.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science - Programming Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Charles Severance - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781530051120.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:00:00',NULL),(282,'OTL-337','GT-ISBN9781300160137','Fundamentals of Electrical Engineering I',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'The course focuses on the creation, manipulation, transmission, and reception of information by electronic means. Elementary signal theory; time- and frequency-domain analysis; Sampling Theorem. Digital information theory; digital transmission of analog signals; error-correcting codes.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 337.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/fundamentals-of-electrical-engineering-1\nPublisher ô CSV: OpenStax CNX.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781300160137.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Engineering & Technology - Electrical Engineering.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 600 — Công nghệ (Khoa học ứng dụng).\nContributors — nguyên bản ô CSV —: Don Johnson - Author',NULL,NULL,'600','utc-elibrary/book-covers/isbn/9781300160137.jpg',4,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:00:00',NULL),(283,'OTL-338','GT-OTL000338','A First Course in Electrical and Computer Engineering',NULL,'Tiếng Anh',NULL,2009,NULL,NULL,NULL,NULL,1,0,'This book was written for an experimental freshman course at the University of Colorado. The course is now an elective that the majority of our electrical and computer engineering students take in the second semester of their freshman year, just before their first circuits course. Our department decided to offer this course for several reasons: we wanted to pique student\' interest in engineering by acquainting them with engineering teachers early in their university careers and by providing with exposure to the types of problems that electrical and computer engineers are asked to solve; we wanted students entering the electrical and computer engineering programs to be prepared in complex analysis, phasors, and linear algebra, topics that are of fundamental importance in our discipline; we wanted students to have an introduction to a software application tool, such as MATLAB, to complete their preparation for practical and efficient computing in their subsequent courses and in their professional careers; we wanted students to make early contact with advanced topics like vector graphics, filtering, and binary coding so that they would gain a more rounded picture of modern electrical and computer engineering. In order to introduce this course, we had to sacrifice a second semester of Pascal programming. We concluded that the sacrifice was worth making because we found that most of our students were prepared for high-level language computing after just one semester of programming. We believe engineering educators elsewhere are reaching similar conclusions about their own students and curriculums. We hope this book helps create a much needed dialogue about curriculum revision and that it leads to the development of similar introductory courses that encourage students to enter and practice our craft.Students electing to take this course have completed one semester of calculus, computer programming, chemistry, and humanities. Concurrently with this course, students take physics and a second semester of calculus, as well as a second semester in the humanities. By omitting the advanced topics marked by asterisks, we are able to cover Complex Numbers through Linear Algebra, plus two of the three remaining chapters. The book is organized so that the instructor can select any two of the three. If every chapter of this book is covered, including the advanced topics, then enough material exists for a two-semester course. The first three chapters of this book provide a fairly complete coverage of complex numbers, the functions e^x and e^jand phasors. Our department philosophy is that these topics must be understood if a student is to succeed in electrical and computer engineering. These three chapters may also be used as a supplement to a circuits course. A measured pace of presentation, taking between sixteen and eighteen lectures, is sufficient to cover all but the advanced sections in Complex Numbers through Phasors. The chapter on \"linear algebra\" is prerequisite for all subsequent chapters. We use eight to ten lectures to cover it. We devote twelve to sixteen lectures to cover topics from Vector Graphics through Binary Codes. (We assume a semester consisting of 42 lectures and three exams.) The chapter on vector graphics applies the linear algebra learned in the previous chapter to the problem of translating, scaling, and rotating images. \"Filtering\" introduces the student to basic ideas in averaging and filtering. The chapter on \"Binary Codes\" covers the rudiments of binary coding, including Huffman codes and Hamming codes. If the users of this book find \"Vector Graphics\" through \"Binary Codes\" too confining, we encourage them to supplement the essential material in \"Complex Numbers\" through \"Linear Algebra\" with their own course notes on additional topics. Within electrical and computer engineering there are endless possibilities. Practically any set of topics that can be taught with conviction and enthusiasm will whet the student\'s appetite. We encourage you to write to us or to our editor, Tom Robbins, about your ideas for additional topics. We would like to think that our book and its subsequent editions will have an open architecture that enables us to accommodate a wide range of student and faculty interests. Throughout this book we have used MATLAB programs to illustrate key ideas. MATLAB is an interactive, matrix-oriented language that is ideally suited to circuit analysis, linear systems, control theory, communications, linear algebra, and numerical analysis. MATLAB is rapidly becoming a standard software tool in universities and engineering companies. (For more information about MATLAB, return the attached card in the back of this book to The MathWorks, Inc.) MATLAB programs are designed to develop the student\'s ability to solve meaningful problems, compute, and plot in a high-level applications language. Our students get started in MATLAB by working through “An Introduction to MATLAB,” while seated at an IBM PC (or look-alike) or an Apple Macintosh. We also have them run through the demonstration programs in \"Complex Numbers\". Each week we give three classroom lectures and conduct a one-hour computer lab session. Students use this lab session to hone MATLAB skills, to write programs, or to conduct the numerical experiments that are given at the end of each chapter. We require that these experiments be carried out and then reported in a short lab report that contains (i) introduction, (ii) analytical computations, (iii) computer code, (iv) experimental results, and (v) conclusions. The quality of the numerical results and the computer graphics astonishes students. Solutions to the chapter problems are available from the publisher for instructors who adopt this text for classroom use. We wish to acknowledge our late colleague Richard Roberts, who encouraged us to publish this book, and Michael Lightner and Ruth Ravenel, who taught \"Linear Algebra\" and \"Vector Graphics\" and offered helpful suggestions on the manuscript. We thank C. T. Mullis for allowing us to use his notes on binary codes to guide our writing of \"Binary Codes\". We thank Cédric Demeure and Peter Massey for their contributions to the writing of \"An Introduction to MATLAB\" and \"The Edix Editor\". We thank Tom Robbins, our editor at Addison-Wesley, for his encouragement, patience, and many suggestions. We are especially grateful to Julie Fredlund, who composed this text through many drafts and improved it in many ways. We thank her for preparing an excellent manuscript for production.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 338.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/a-first-course-in-electrical-and-computer-engineering\nPublisher ô CSV: OpenStax CNX.\nCopyright Year ô CSV: 2009.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: Engineering & Technology - Electrical Engineering.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Louis Scharf - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(284,'OTL-339','GT-ISBN9781973702719','Applied Combinatorics',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'Applied Combinatorics is an open-source textbook for a course covering the fundamental enumeration techniques (permutations, combinations, subsets, pigeon hole principle), recursion and mathematical induction, more advanced enumeration techniques (inclusion-exclusion, generating functions, recurrence relations, Polyá theory), discrete structures (graphs, digraphs, posets, interval orders), and discrete optimization (minimum weight spanning trees, shortest paths, network flows). There are also chapters introducing discrete probability, Ramsey theory, combinatorial applications of network flows, and a few other nuggets of discrete mathematics. Applied Combinatorics began its life as a set of course notes we developed when Mitch was a TA for a larger than usual section of Tom\'s MATH 3012: Applied Combinatorics course at Georgia Tech in Spring Semester 2006. Since then, the material has been greatly expanded and exercises have been added. The text has been in use for most MATH 3012 sections at Georgia Tech for several years now. Since the text has been available online for free, it has also been adopted at a number of other institutions for a wide variety of courses. In August 2016, we made the first release of Applied Combinatorics in HTML format, thanks to a conversion of the book\'s source from LaTeX to MathBook XML. An inexpensive print-on-demand version is also available for purchase. Find out all about ways to get the book. Since Fall 2016, Applied Combinatorics has been on the list of approved open textbooks from the American Institute of Mathematics. Applied Combinatorics is open source and licensed under the Creative Commons Attribution-ShareAlike 4.0 International License (CC-BY-SA).\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 339.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/applied-combinatorics\nPublisher ô CSV: Mitchel T. Keller, William T. Trotter.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: 9781973702719.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Applied.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Mitchel T. Keller - Author / William T. Trotter - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781973702719.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:00:00',NULL),(285,'OTL-340','GT-OTL000340','First Amendment: Cases, Controversies, and Contexts - Second Edition',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This Casebook (Second Edition, December 2019) is intended to be used in an upper-division course covering the First Amendment to the United States Constitution. Its 14 chapters are substantially the same length, with the exception of Chapter One, the introduction, and Chapters Eleven and Twelve which in combination are the usual length. It is intended for 13 or 14 week semester that meets once or twice per week. Each Chapter contains a “Chapter Outline” at the beginning for ease of reference. The Casebook is organized with the Speech Clauses as Part One and the Religion Clauses as Part Two. Unlike many other courses, there is no accepted organizational scheme within these broad areas. As the Introduction notes, First Amendment doctrine, especially within freedom of speech, presents a varied and haphazard landscape. The Casebook follows a scheme that has proven effective in Professor Robson’s years of teaching the course to hundreds of students. The selection of cases tends toward the most recent and these tend to be less heavily edited. These recent cases often contain extended discussions of earlier cases that are not included in the Casebook.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 340.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/first-amendment-cases-controversies-and-contexts\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Administrative Law.\nSubject OTL 2 — nguyên bản ô CSV —: Law - Constitutional Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Ruthann Robson - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(286,'OTL-341','GT-OTL000341','Property Volume 1',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'This is Volume 1 of a two volume set written for Property Law. From the Preface: Property, as a vaguely defined collection of contract, tort, and criminal cases, does not take on the natural structure of a substantive area of the law through the systematic study of duty, breach, causation, defenses, and damages. Instead this textbook and most Property courses survey various topics in law with two goals in mind. First, we will study a number of traditional property topics, those where the issue of \"ownership\" and what that entails have long been thought to be a central issue. Second, but most importantly, our interdisciplinary study will introduce some of the major analytical techniques in law, from reasoning using precedent to law and economics to distributive justice. As we roam among topics, our goal is always, relentlessly to ask, \"Why?\" \"Why should the law protect this party\'s interest?\" These major techniques that we will pick up along the way will help us provide better and better answers to this question.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 341.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/property-volume-1\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Property Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Christian Turner - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(287,'OTL-342','GT-OTL000342','Property Volume 2',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'This is Volume 2 of a two volume set written for Property Law. From the Preface to Volume 1: Property, as a vaguely defined collection of contract, tort, and criminal cases, does not take on the natural structure of a substantive area of the law through the systematic study of duty, breach, causation, defenses, and damages. Instead this textbook and most Property courses survey various topics in law with two goals in mind. First, we will study a number of traditional property topics, those where the issue of \"ownership\" and what that entails have long been thought to be a central issue. Second, but most importantly, our interdisciplinary study will introduce some of the major analytical techniques in law, from reasoning using precedent to law and economics to distributive justice. As we roam among topics, our goal is always, relentlessly to ask, \"Why?\" \"Why should the law protect this party\'s interest?\" These major techniques that we will pick up along the way will help us provide better and better answers to this question.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 342.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/property-volume-2\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Property Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Christian Turner - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(288,'OTL-343','GT-OTL000343','The Law of Trusts',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'The use of testamentary trusts is becoming an important part of estate planning. As a result, students who want to make a living as probate attorneys will need to know how trusts fit into estate planning. In addition, bar examiners realize that it is important for students to have a basic knowledge of trust law. That realization will result in bar examination questions that test that knowledge. This book is designed for use as a supplementary text for a course on wills and trusts and the primary text in a seminar or course exploring the law of trusts.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 343.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-law-of-trusts\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Contract Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Browne C. Lewis - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(289,'OTL-344','GT-OTL000344','Graphic Design and Print Production Fundamentals',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'This textbook -- written by a group of select experts with a focus on different aspects of the design process, from creation to production -- addresses the many steps of creating and then producing physical, printed, or other imaged products that people interact with on a daily basis. It covers the concept that, while most modern graphic design is created on computers using design software, the ideas and concepts don\'t stay on the computer. The ideas need to be completed in the computer software, then progress to an imaging (traditionally referred to as printing) process. Keywords are highlighted throughout and summarized in a Glossary at the end of the book, and each chapter includes exercises and suggested readings.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 344.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/graphic-design-and-print-production-fundamentals\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Arts.\nSubject OTL 2 — nguyên bản ô CSV —: Computer Science.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Wayne Collins - Author / Alex Haas - Author / Ken Jeffery - Author / Alan Martin - Author / Roberto Medeiros - Author / Steven Tomljanovic - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(290,'OTL-346','GT-ISBN9781909188242','Writing as Material Practice: Substance, surface and medium',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'Writing as Material Practice grapples with the issue of writing as a form of material culture in its ancient and more recent manifestations, and in the contexts of production and consumption. Fifteen case studies explore the artefactual nature of writing — the ways in which materials, techniques, colour, scale, orientation and visibility inform the creation of inscribed objects and spaces, as well as structure subsequent engagement, perception and meaning making. Covering a temporal span of some 5000 years, from c.3200 BCE to the present day, and ranging in spatial context from the Americas to the Near East, the chapters in this volume bring a variety of perspectives which contribute to both specific and broader questions of writing materialities. The authors also aim to place past graphical systems in their social contexts so they can be understood in relation to the people who created and attributed meaning to writing and associated symbolic modes through a diverse array of individual and wider social practices.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 346.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/writing-as-material-practice-substance-surface-and-medium\nPublisher ô CSV: Ubiquity Press.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: 9781909188242.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Kathryn Piquette - Editor',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781909188242.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:00:00',NULL),(291,'OTL-348','GT-OTL000348','Anatomy and Physiology of Animals',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Veterinary nurses need to have a firm grasp of the normal structure of an animal\'s body and how it functions before they can understand the effect diseases and injuries have and the best ways to treat them. This book describes the structure of the animal body and the way in which it works. Animals encountered in normal veterinary practice are used as examples where possible.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 348.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/anatomy-and-physiology-of-animals\nPublisher ô CSV: WikiBooks.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Biology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 600 — Công nghệ (Khoa học ứng dụng).\nContributors — nguyên bản ô CSV —: Ruth Lawson - Author',NULL,NULL,'600','utc-elibrary/book-covers/defaults/default-book-cover.jpg',4,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(292,'OTL-349','GT-OTL000349','General Biology',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'The word biology means, \"the science of life\", from the Greek bios, life, and logos, wordor knowledge. Therefore, Biology is the science of Living Things. That is why Biology issometimes known as Life Science.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 349.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/general-biology\nPublisher ô CSV: WikiBooks.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Biology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Paul Doerder - Author / Ralph Gibson - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(293,'OTL-350','GT-OTL000350','Biofundamentals 2.0',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Our goal is to present the key observations andunifying concepts upon which modern biology isbased; it is not a survey of all biology! Onceunderstood, these foundational observations andconcepts should enable you to approach any biologicalprocess, from disease to kindness, from a scientificperspective. To understand biological systems we need toconsider them from two complementary perspectives;how they came to be (the historic, that is, evolutionary) and how their structures, traits, and behaviors areproduced (the mechanistic, that is, the physicochemical).\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 350.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/biofundamentals-2-0\nPublisher ô CSV: Michael Klymkowsky, Melanie Cooper.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Biology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Michael W. Klymkowsky - Author / Melanie M. Cooper - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(294,'OTL-351','GT-OTL000351','Concept Development Studies in Chemistry',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'This collection of Concept Development Studies in Chemistry is presented to redirect the focus of learning. In each concept development study, a major chemical concept is developed and refined by analysis of experimental observations and careful reasoning. Each study begins with the definition of an initial Foundation of assumed knowledge, followed by a statement of questions which arise from the Foundation. Analysis of these questions is presented as a series of observations and logical deductions, followed by further questions. This detailed process is followed until the conceptual development of a model provides a reasonable answer to the stated questions.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 351.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/concept-development-studies-in-chemistry\nPublisher ô CSV: OpenStax CNX.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Chemistry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: John S. Hutchinson - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(295,'OTL-352','GT-OTL000352','Computer Networking : Principles, Protocols and Practice',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'This open textbook aims to fill the gap between the open-source implementations and the open-source network specifications by providing a detailed but pedagogical description of the key principles that guide the operation of the Internet.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 352.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/computer-networking-principles-protocols-and-practice\nPublisher ô CSV: Saylor Foundation.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Olivier Bonaventure - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(296,'OTL-353','GT-OTL000353','An Introduction to Computer Networks - Second Edition',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'An Introduction to Computer Networksis a free and open general-purpose computer-networking textbook, complete with diagrams and exercises.It covers the LAN, internetworking and transport layers, focusing primarily on TCP/IP. Particular attention is paid to congestion; other special topics include queuing, real-time traffic, network management, security and the ns simulator. The book is suitable as the primary text for an undergraduate or introductory graduate course in computer networking, as a supplemental text for a wide variety of network-related courses, and as a reference work.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 353.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/an-introduction-to-computer-networks\nPublisher ô CSV: Peter L Dordal.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Peter Lars Dordal - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(297,'OTL-354','GT-OTL000354','Database Design - 2nd Edition',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'This second edition of Database Design book covers the concepts used in database systems and the database design process. Topics include: The history of databases Characteristics and benefits of databases Data models Data modelling Classification of database management systems Integrity rules and constraints Functional dependencies Normalization Database development process New to this edition are more examples, highlighted and defined key terms, both throughout and at the end of each chapter, and end-of-chapter review exercises. Two new chapters have been added on SQL, along with appendices that include a data model example, sample ERD exercises and SQL lab with solutions.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 354.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/database-design-2nd-edition\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science - Databases.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Adrienne Watt - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(298,'OTL-355','GT-ISBN9781927356814','Teaching Crowds: Learning and Social Media',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'Within the rapidly expanding field of educational technology, learners and educators must confront a seemingly overwhelming selection of tools designed to deliver and facilitate both online and blended learning. Many of these tools assume that learning is configured and delivered in closed contexts, through learning management systems (LMS). However, while traditional \"classroom\" learning is by no means obsolete, networked learning is in the ascendant. A foundational method in online and blended education, as well as the most common means of informal and self-directed learning, networked learning is rapidly becoming the dominant mode of teaching as well as learning. In Teaching Crowds, Dron and Anderson introduce a new model for understanding and exploiting the pedagogical potential of Web-based technologies, one that rests on connections — on networks and collectives — rather than on separations. Recognizing that online learning both demands and affords new models of teaching and learning, the authors show how learners can engage with social media platforms to create an unbounded field of emergent connections. These connections empower learners, allowing them to draw from one another\'s expertise to formulate and fulfill their own educational goals. In an increasingly networked world, developing such skills will, they argue, better prepare students to become self-directed, lifelong learners.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 355.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/teaching-crowds-learning-and-social-media\nPublisher ô CSV: Athabasca University Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781927356814.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Education - Curriculum & Instruction.\nSubject OTL 2 — nguyên bản ô CSV —: Education - Distance Education.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Jon Dron - Author / Terry Anderson - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781927356814.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:00:00',NULL),(299,'OTL-356','GT-ISBN9781894975292','Education for a Digital World: Advice, Guidelines and Effective Practice from Around Globe',NULL,'Tiếng Anh',NULL,2008,NULL,NULL,NULL,NULL,1,0,'Education for a Digital World contains a comprehensive collection of proven strategies and tools for effective online teaching, based on the principles of learning as a social process. It offers practical, contemporary guidance to support e-learning decision-making, instructional choices, as well as program and course planning, and development.Practical advice, real-life examples, case studies, and useful resources supply in-depth perspectives about structuring and fostering socially engaging learning in an online environment. A plethora of e-learning topics provide insights, ideas, and usable tools. Tips and evidence-based theory guide administrators, program and course developers, project teams, and teachers through the development of online learning opportunities.Education for a Digital World is an indispensable guide, resource, textbook and manual for policymakers and practitioners in developing and developed countries.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 356.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/education-for-a-digital-world-advice-guidelines-and-effective-practice-from-around-globe\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2008.\nISBN-13 ô CSV: 9781894975292.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Education - Curriculum & Instruction.\nSubject OTL 2 — nguyên bản ô CSV —: Education - Distance Education.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Sandy Hirtz - Author / David G. Harper - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781894975292.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:00:00',NULL),(300,'OTL-357','GT-ISBN9781909188211','Reading With My Eyes Open: Embracing the critical and the personal in language pedagogy',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'Untangling the various approaches to language teaching and their history, Gerdi Quist maps recent thinking in language studies at university. Using an interdisciplinary theoretical framework, drawn from educational philosophy, cultural studies, intercultural studies and language pedagogy, the author discusses the many tensions and currents in contemporary language teaching. The author puts forward an alternative pedagogy, that of a cultuurtekst-perspective, which engages learners at complex linguistic and cultural levels. In discussing the case study in which this approach is tested, the author develops her argument for embracing various critical perspectives through the personal engagement of students. From the start the author acknowledges her own engaged position as a language teacher in a liberal humanistic educational environment. She adopts a self-critical perspective through which her engagement with adverse student reaction leads to deepening insights both for the author and her students as part of the non-linear process of learning. Gerdi Quist teaches Dutch language and lectures on multiculturalism and intercultural communication. Recent publications included a book chapter and journal articles on language pedagogy and intercultural communication.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 357.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/reading-with-my-eyes-open-embracing-the-critical-and-the-personal-in-language-pedagogy\nPublisher ô CSV: Ubiquity Press.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: 9781909188211.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Education.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Linguistics.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Gerdi Quist - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781909188211.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:00:00',NULL),(301,'OTL-358','GT-OTL000358','Conventions 101: A Functional Approach to Teaching (And Assessing!) Grammar and Punctuation',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This is a collection of cumulative units of study for conventional errors common in student writing. It\'s flexible, functional, and zeroes in problems typically seen in writing of all types, from the eternal “there/they\'re/their” struggle to correct colon use. Units are organized from most simple to most challenging.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 358.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/conventions-101-a-functional-approach-to-teaching-and-assessing-grammar-and-punctuation\nPublisher ô CSV: Open Oregon Educational Resources.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Education.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Linguistics.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Chauna Ramsey - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(302,'OTL-359','GT-OTL000359','About Writing: A Guide',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This writer\'s reference condenses and covers everything a beginning writing student should need to successfully compose college-level work. The book covers the basics of composition and revising, including how to build a strong thesis, how to peer review a fellow student\'s work, and a handy checklist for revision, before moving on to a broad overview of academic writing. Included for those students who need writing help at the most basic level are comprehensive sections on sentence style and grammar, verbs, nouns and other tenets of basic grammar. Finally, the sections on research and citation should help any student find solid evidence for their school work and cite it correctly, as well as encouraging an understanding of why citation is so important in the first place. This is a guide that is useful to writing students of all levels, either as a direct teaching tool or a simple reference.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 359.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/about-writing-a-guide\nPublisher ô CSV: Open Oregon Educational Resources.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Robin Jeffrey - Author',NULL,NULL,'800','utc-elibrary/book-covers/defaults/default-book-cover.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(303,'OTL-360','GT-OTL000360','Writing for Strategic Communication Industries',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Good writing skills are important in today\'s competitive work environment. This is especially the case for communication-related professions such as public relations, brand communication, journalism, and marketing. Writing for Strategic Communication Industries emphasizes practical application of academic inquiry to help readers improve their writing skills. This book gives readers: Straightforward chapters that use real-world examples to illustrate key points. Discussion of different writing styles and techniques. Examples of communication materials such as press releases, creative briefs, feature articles, and more. Embedded videos of insights from communication professionals. Tips on pitching to the media. A collection of popular sources for further explanation.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 360.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/writing-for-strategic-communication-industries\nPublisher ô CSV: Ohio State University Libraries.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Journalism, Media Studies & Communications - Organizational Communication.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Jasmine Roberts - Author',NULL,NULL,'800','utc-elibrary/book-covers/defaults/default-book-cover.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(304,'OTL-362','GT-ISBN9789038221021','The Ideologies of Lived Space in Literary Texts, Ancient and Modern',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'In a brief essay called Des espaces autres (1984) Michel Foucault announced that after the nineteenth century, which was dominated by a historical outlook, the current century might rather be the century of space. His prophecy has been fulfilled: the end of the twentieth century witnessed a ‘spatial turn\' in humanities which was perhaps partly due to the globalisation of our modern world. Inspired by the spatial turn in the humanities, this volume presents a number of essays on the ideological role of space in literary texts. The individual articles analyse ancient and modern literary texts from the angle of the most recent theoretical conceptualisations of space. The focus throughout is on how the experience of space is determined by dominant political, philosophical or religious ideologies and how, in turn, the description of spaces in literature is employed to express, broadcast or deconstruct this experience. By bringing together ancient and modern, mostly postcolonial texts, this volume hopes to stimulate discussion among disciplines and across continents. Among the authors discussed are: Homer, Nonnus, Alcaeus of Lesbos, Apollonius of Rhodes, Vergil, Herodotus, Panagiotis Soutsos, Assia Djebar, Tahar Djaout, Olive Senior, Jamaica Kincaid, Stefan Heym, Benoit Dutuertre, Henrik Stangerup and David Malouf.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 362.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-ideologies-of-lived-space-in-literary-texts-ancient-and-modern\nPublisher ô CSV: Academia Press.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: 9789038221021.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Jo Heirman - Author / Jacqueline Klooster - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9789038221021.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:00:00',NULL),(305,'OTL-363','GT-ISBN9780748690800','The Emergence of Irish Gothic Fiction - Histories, Origins, Theories?',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'Provides a new account of the emergence of Irish gothic fiction in mid-eighteenth century. This book provides a robustly theorised and thoroughly historicised account of the ‘beginnings\' of Irish gothic fiction, maps the theoretical terrain covered by other critics, and puts forward a new history of the emergence of the genre in Ireland. The main argument the book makes is that the Irish gothic should be read in the context of the split in Irish Anglican public opinion that opened in the 1750s, and seen as a fictional instrument of liberal Anglican opinion in a changing political landscape. By providing a fully historicized account of the beginnings of the genre in Ireland, the book also addresses the theoretical controversies that have bedevilled discussion of the Irish gothic in the 1980s, 1990s and 2000s. The book gives ample space to the critical debate, and rigorously defends a reading of the Irish gothic as an Anglican, Patriot tradition. This reading demonstrates the connections between little-known Irish gothic fictions of the mid-eighteenth century (The Adventures of Miss Sophia Berkley and Longsword), and the Irish gothic tradition more generally, and also the gothic as a genre of global significance. Key Features * Examines gothic texts including Mary Shelley\'s Frankenstein, Horace Walpole\'s The Castle of Otranto, Bram Stoker\'s Dracula, Charles Robert Maturin\'s Melmoth the Wanderer, (Anon), The Adventures of Miss Sophia Berkley and Thomas Leland\'s Longsword * Provides a rigorous and robust theory of the Irish Gothic * Reads early Irish gothic fully into the political context of mid-eighteenth century Ireland This title was made Open Access by libraries from around the world through Knowledge Unlatched.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 363.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-emergence-of-irish-gothic-fiction-histories-origins-theories\nPublisher ô CSV: Edinburgh University Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9780748690800.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Jarlath Killeen - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9780748690800.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:00:00',NULL),(306,'OTL-367','GT-OTL000367','Clinical Procedures for Safer Patient Care',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'The checklist approach, used in this textbook, aims to provide standardized processes for clinical skills and to help nursing schools and clinical practice partners keep procedural practice current. Each skill/procedure is covered in a chapter that has learning objectives, a brief overview of the relevant theory, checklists of steps for procedures with the rationale behind each step of the process, and a summary of key takeaways. Key terms are set in bold throughout the book and laid out again in a Glossary in the appendix. All 88 checklists are also summarized, and hyperlinked to the original checklist, in the appendix.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 367.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/clinical-procedures-for-safer-patient-care\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Medicine - Nursing.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 600 — Công nghệ (Khoa học ứng dụng).\nContributors — nguyên bản ô CSV —: Glynda Rees Doyle - Author / Jodie McCutcheon - Author',NULL,NULL,'600','utc-elibrary/book-covers/defaults/default-book-cover.jpg',4,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(307,'OTL-368','GT-ISBN9780988223738','History in the Making: A History of the People of the United States of America to 1877 - 1',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'This textbook examines U.S. History from before European Contact through Reconstruction, while focusing on the people and their history.Prior to its publication, History in the Making underwent a rigorous double blind peer review, a process that involved over thirty scholars who reviewed the materially carefully, objectively, and candidly in order to ensure not only its scholarly integrity but also its high standard of quality.This book provides a strong emphasis on critical thinking about US History by providing several key features in each chapter. Learning Objectives at the beginning of each chapter help students to understand what they will learn in each chapter. Before You Move On sections at the end of each main section are designed to encourage students to reflect on important concepts and test their knowledge as they read. In addition, each chapter includes Critical Thinking Exercises that ask the student to deeply explore chapter content, Key Terms, and a Chronology of events.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 368.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/history-in-the-making-a-history-of-the-people-of-the-united-states-of-america-to-1877\nPublisher ô CSV: The University Press of North Georgia.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: 9780988223738.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - History.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 900 — Lịch sử & Địa lý.\nContributors — nguyên bản ô CSV —: Catherine Locks - Author / Sarah K. Mergel - Author / Pamela Thomas Roseman - Author / Tamara Spike - Author',NULL,NULL,'900','utc-elibrary/book-covers/isbn/9780988223738.jpg',7,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:00:00',NULL),(308,'OTL-369','GT-OTL000369','Organic Chemistry Laboratory Techniques',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This resource was created by Lisa Nichols (chemistry faculty at Butte Community College in Northern California) as a result of an academic sabbatical leave in the Fall-2015 to Spring 2016 term. The target audience are undergraduate students in organic chemistry. In this resource you will find theory and procedures on the main organic lab techniques (chromatography, crystallization, extraction, distillation) as well as general concepts on how to set up and heat apparatuses (see the Table of Contents tab for a more complete listing of topics). All procedures are accompanied by step-by-step pictures, and graphics are heavily utilized throughout the resource.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 369.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/organic-chemistry-laboratory-techniques\nPublisher ô CSV: Lisa Nichols.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Chemistry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Lisa Nichols - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(309,'OTL-370','GT-ISBN9781938168062','Calculus Volume 2',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Calculus is designed for the typical two- or three-semester general calculus course, incorporating innovative features to enhance student learning. The book guides students through the core concepts of calculus and helps them understand how those concepts apply to their lives and the world around them. Due to the comprehensive nature of the material, we are offering the book in three volumes for flexibility and efficiency. Volume 2 covers integration, differential equations, sequences and series, and parametric equations and polar coordinates.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 370.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/calculus-volume-2\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781938168062.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Gilbert Strang - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781938168062.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:00:00',NULL),(310,'OTL-371','GT-ISBN9781938168079','Calculus Volume 3',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Calculus is designed for the typical two- or three-semester general calculus course, incorporating innovative features to enhance student learning. The book guides students through the core concepts of calculus and helps them understand how those concepts apply to their lives and the world around them. Due to the comprehensive nature of the material, we are offering the book in three volumes for flexibility and efficiency. Volume 3 covers parametric equations and polar coordinates, vectors, functions of several variables, multiple integration, and second-order differential equations.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 371.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/calculus-volume-3\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781938168079.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Gilbert Strang - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781938168079.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:00:00',NULL),(311,'OTL-374','GT-OTL000374','Introduction to Art: Design, Context, and Meaning',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Introduction to Art: Design, Context, and Meaning offers a comprehensive introduction to the world of Art. Authored by four USG faculty members with advance degrees in the arts, this textbooks offers up-to-date original scholarship. It includes over 400 high-quality images illustrating the history of art, its technical applications, and its many uses.Combining the best elements of both a traditional textbook and a reader, it introduces such issues in art as its meaning and purpose; its meaning and purpose; its structure, material, and form; and its diverse effects on our lives. Its digital nature allows students to follow links to applicable sources and videos, expanding the students\' educational experiences beyond the textbook. Introduction to Art: Design, Context, and Meaning provides a new and free alternative to traditional textbooks, making it an invaluable resource in our modern age of technology and advancement.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 374.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-art-design-context-and-meaning\nPublisher ô CSV: University of North Georgia Press.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Arts.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Pamela Sachant - Author / Peggy Blood - Author / Jeffery A LeMieux - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:01:00',NULL),(312,'OTL-375','GT-ISBN9781940771106','World History: Cultures, States, and Societies to 1500',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'World History: Cultures, States, and Societies to 1500 offers a comprehensive introduction to the history of humankind from prehistory to 1500. Authored by six USG faculty members with advance degrees in History, this textbook offers up-to-date original scholarship. It covers such cultures, states, and societies as Ancient Mesopotamia, Ancient Israel, Dynastic Egypt, India\'s Classical Age, the Dynasties of China, Archaic Greece, the Roman Empire, Islam, Medieval Africa, the Americas, and the Khanates of Central Asia.It includes 350 high-quality images and maps, chronologies, and learning questions to help guide student learning. Its digital nature allows students to follow links to applicable sources and videos, expanding their educational experience beyond the textbook. It provides a new and free alternative to traditional textbooks, making World History an invaluable resource in our modern age of technology and advancement.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 375.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/world-history-cultures-states-and-societies-to-1500\nPublisher ô CSV: University of North Georgia Press.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781940771106.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - History.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 900 — Lịch sử & Địa lý.\nContributors — nguyên bản ô CSV —: Eugene Berger - Author / George L. Israel - Author / Charolette Miller - Author',NULL,NULL,'900','utc-elibrary/book-covers/isbn/9781940771106.jpg',7,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:00:00',NULL),(313,'OTL-376','GT-ISBN9781607826590','Introductory Algebra',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'Introductory Algebra provides a comprehensive introduction of variables, functionsand linear equations and gives students a solid foundation in algebra.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 376.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introductory-algebra\nPublisher ô CSV: Independent.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781607826590.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Pure.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Anne Marie Gloag - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781607826590.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:00:00',NULL),(314,'OTL-378','GT-ISBN9781938168277','University Physics Volume 1',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'University Physics is a three-volume collection that meets the scope and sequence requirements for two- and three-semester calculus-based physics courses. Volume 1 covers mechanics, sound, oscillations, and waves. This textbook emphasizes connections between between theory and application, making physics concepts interesting and accessible to students while maintaining the mathematical rigor inherent in the subject. Frequent, strong examples focus on how to approach a problem, how to work with the equations, and how to check and generalize the result.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 378.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/university-physics-volume-1\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781938168277.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Physics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Jeff Sanny - Author / Samuel Ling - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781938168277.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:39','2026-05-06 09:00:00',NULL),(315,'OTL-379','GT-ISBN9781938168161','University Physics Volume 2',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'University Physics is a three-volume collection that meets the scope and sequence requirements for two- and three-semester calculus-based physics courses. Volume 1 covers mechanics, sound, oscillations, and waves. Volume 2 covers thermodynamics, electricity and magnetism, and Volume 3 covers optics and modern physics. This textbook emphasizes connections between between theory and application, making physics concepts interesting and accessible to students while maintaining the mathematical rigor inherent in the subject. Frequent, strong examples focus on how to approach a problem, how to work with the equations, and how to check and generalize the result.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 379.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/university-physics-volume-2\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781938168161.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Physics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Jeff Sanny - Author / Samuel Ling - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781938168161.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:00:00',NULL),(316,'OTL-380','GT-ISBN9781938168185','University Physics Volume 3',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'University Physics is a three-volume collection that meets the scope and sequence requirements for two- and three-semester calculus-based physics courses. Volume 1 covers mechanics, sound, oscillations, and waves. Volume 2 covers thermodynamics, electricity and magnetism, and Volume 3 covers optics and modern physics. This textbook emphasizes connections between between theory and application, making physics concepts interesting and accessible to students while maintaining the mathematical rigor inherent in the subject. Frequent, strong examples focus on how to approach a problem, how to work with the equations, and how to check and generalize the result.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 380.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/university-physics-volume-3\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781938168185.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Physics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Jeff Sanny - Author / Samuel Ling - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781938168185.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:00:00',NULL),(317,'OTL-381','GT-ISBN9780198732860','Field Trials of Health Interventions: A Toolbox',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Before new interventions can be used in disease control programmes, it is essential that they are carefully evaluated in “field trials”, which may be complex and expensive undertakings. Descriptions of the detailed procedures and methods used in trials that have been conducted in the past have generally not been published. As a consequence, those planning such trials have few guidelines available and little access to previously accumulated knowledge. In this book the practical issues of trial design and conduct are discussed fully and in sufficient detail for the text to be used as a “toolbox” by field investigators. The toolbox has now been extensively tested through use of the first two editions and this third edition is a comprehensive revision, incorporating the many developments that have taken place with respect to trials since 1996 and involving more than 30 contributors. Most of the chapters have been extensively revised and 7 new chapters have been added.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 381.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/field-trials-of-health-interventions-a-toolbox\nPublisher ô CSV: Oxford University Press.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9780198732860.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Medicine.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Peter G. Smith - Editor / Richard H. Morrow - Editor / David A. Ross - Editor',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9780198732860.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:00:00',NULL),(318,'OTL-382','GT-ISBN9780813818566','Veterinary Epidemiology: Principles and Methods',NULL,'Tiếng Anh',NULL,1987,NULL,NULL,NULL,NULL,1,0,'The purpose of this textbook is to provide an introductory, yet comprehensive, source of information on epidemiology for veterinary students, researchers, and practitioners. There has not been a textbook that presents analytic epidemiology as a science, basic to veterinary medicine\'s efforts in health management (herd health) as well as in clinical medicine.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 382.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/veterinary-epidemiology-principles-and-methods\nPublisher ô CSV: Virginia Tech Libraries.\nCopyright Year ô CSV: 1987.\nISBN-13 ô CSV: 9780813818566.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Medicine - Veterinary Medicine.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 600 — Công nghệ (Khoa học ứng dụng).\nContributors — nguyên bản ô CSV —: Wayne S. Martin - Author / Alan H. Meek - Author / Preben Willebtrg - Author',NULL,NULL,'600','utc-elibrary/book-covers/isbn/9780813818566.jpg',4,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:00:00',NULL),(319,'OTL-383','GT-OTL000383','Accounting Principles: A Business Perspective',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'Accounting Principles: A Business Perspective uses annual reports of real companies to illustrate many of the accounting concepts in use in business today. Gaining an understanding of accounting terminology and concepts, however, is not enough to ensure your success. You also need to be able to find information on the Internet, analyze various business situations, work effectively as a member of a team, and communicate your ideas clearly. This text was developed to help you develop these skills.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 383.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/accounting-principles-a-business-perspective\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Accounting.\nSubject OTL 2 — nguyên bản ô CSV —: Business.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Roger H. Hermanson - Author / James D. Edwards - Author / Michael W. Maher - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(320,'OTL-384','GT-OTL000384','Principles of Business Statistics',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'You are probably asking yourself the question, \"When and where will I use statistics?\". If you read any newspaper or watch television, or use the Internet, you will see statistical information. There are statistics about crime, sports, education, politics, and real estate. Typically, when you read a newspaper article or watch a news program on television, you are given sample information. With this information, you may make a decision about the correctness of a statement, claim, or \"fact.\" Statistical methods can help you make the \"best educated guess.\"\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 384.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/principles-of-business-statistics\nPublisher ô CSV: OpenStax CNX.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Mihai Nica - Editor',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(321,'OTL-385','GT-OTL000385','Introductory Business Statistics',NULL,'Tiếng Anh',NULL,2010,NULL,NULL,NULL,NULL,1,0,'The book \"Introductory Business Statistics\" by Thomas K. Tiemann explores the basic ideas behind statistics, such as populations, samples, the difference between data and information, and most importantly sampling distributions. The author covers topics including descriptive statistics and frequency distributions, normal and t-distributions, hypothesis testing, t-tests, f-tests, analysis of variance, non-parametric tests, and regression basics. Using real-world examples throughout the text, the author hopes to help students understand how statistics works, not just how to \"get the right number.\"\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 385.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introductory-business-statistics\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2010.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Applied.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Thomas K. Tiemann - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(322,'OTL-388','GT-OTL000388','Introducing Marketing',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'Through good economic times and bad, marketing remains the pivotal function in any business. Determining and satisfying the needs of customers through products that have value and accessibility and whose features are clearly communicated is the general purpose of any business. It is also a fundamental definition of marketing. This text introduces students to the marketing strategies and tools that practitioners use to market their products.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 388.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introducing-marketing\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Marketing.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: John Burnett - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(323,'OTL-389','GT-OTL000389','Media Studies 101',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'Media Studies 101 is the open educational resource for media studies studies in New Zealand, Australia, and Pacifica. We have constructed this text so it can be read in a number of ways. You may wish to follow the structured order of \'chapters\' like you would in a traditional printed textbook. Each section builds on and refers back to previous sections to build up your knowledge and skills. Alternatively, you may want to go straight to the section you are interested in -- links will help guide you back to definitions and key ideas if you need to refresh your knowledge or understand a new concept.This text is open under a Creative Commons NZ BY license.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 389.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/media-studies-101\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Journalism, Media Studies & Communications - New Media Journalism.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 700 — Nghệ thuật & Giải trí.\nContributors — nguyên bản ô CSV —: Erika Pearson - Author',NULL,NULL,'700','utc-elibrary/book-covers/defaults/default-book-cover.jpg',5,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(324,'OTL-390','GT-ISBN9781951693503','Astronomy - 2e',NULL,'Tiếng Anh',NULL,2022,NULL,NULL,NULL,NULL,1,0,'Designed to meet the scope and sequence of your course, Astronomy 2e is written in clear non-technical language, with the occasional touch of humor and a wide range of clarifying illustrations. It has many analogies drawn from everyday life to help non-science majors appreciate, on their own terms, what our modern exploration of the universe is revealing. The book can be used for either a one-semester or two-semester introductory course. The second edition has been updated according to new exploration and discoveries. The second edition also includes a significant amount of new art and images. The first edition of Astronomy by OpenStax is available in web view here.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 390.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/astronomy\nPublisher ô CSV: OpenStax CNX.\nCopyright Year ô CSV: 2022.\nISBN-13 ô CSV: 9781951693503.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Andrew Fraknoi - Author / David Morrison - Author / Sidney C. Wolff - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781951693503.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:00:00',NULL),(325,'OTL-391','GT-ISBN9781642150834','Information Literacy: Research and Collaboration across Disciplines',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This collection brings together scholarship and pedagogy from multiple perspectives and disciplines, offering nuanced and complex perspectives on Information Literacy in the second decade of the 21st century. Taking as a starting point the concerns that prompted the Association of Research Libraries (ACRL) to review the Information Literacy Standards for Higher Education and develop the Framework for Information Literacy for Higher Education (2015), the chapters in this collection consider six frameworks that place students in the role of both consumer and producer of information within today\'s collaborative information environments. Contributors respond directly or indirectly to the work of the ACRL, providing a bridge between past/current knowledge and the future and advancing the notion that faculty, librarians, administrators, and external stakeholders share responsibility and accountability for the teaching, learning, and research of Information Literacy.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 391.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/information-literacy-research-and-collaboration-across-disciplines\nPublisher ô CSV: WAC Clearinghouse.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781642150834.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-NoDerivs.\nSubject OTL 1 — nguyên bản ô CSV —: Education - Higher Education.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Barbara J. D\'Angelo - Editor / Sandra Jamieson - Editor / Barry Maid - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781642150834.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:00:00',NULL),(326,'OTL-392','GT-ISBN9781946135018','Immigrant and Refugee Families - 2nd Ed.',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Immigrant and Refugee Families: Global Perspectives on Displacement and Resettlement Experiences offers an interdisciplinary perspective on immigrant and refugee families\' challenges and resilience across multiple domains, including economic, political, health, and human rights. This new edition has been revised and updated from the original 2016 edition. Co-edited with equal contribution by Jaime Ballard, Elizabeth Wieling, Catherine Solheim, and Lekie Dwanyen\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 392.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/immigrant-and-refugee-families-global-perspectives-on-displacement-and-resettlement-experiences\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781946135018.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Cultural & Ethnic Studies.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences - Political Science.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Jaime Ballard - Editor / Elizabeth Wieling - Editor / Catherine Solheim - Editor / Lekie Dwanyen - Editor',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781946135018.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:00:00',NULL),(327,'OTL-393','GT-OTL000393','Together: The Science of Social Psychology',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This textbook presents core concepts common to introductory social psychology courses. The 8 units include 27 modules covering key social psych topics such as research methods, group processes, social influence, and relationships. This book can be modified: feel free to add or remove modules to better suit your specific needs. Each module in this book is accompanied by instructor\'s manual, PowerPoint presentation, test items, adaptive student quiz, and reading anticipation guide.Please note that the publisher requires you to login to access and download the textbooks.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 393.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/together-the-science-of-social-psychology\nPublisher ô CSV: Noba.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Psychology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Robert Biswas-Diener - Editor / Ed Diener - Editor',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(328,'OTL-394','GT-ISBN9781534970748','Discrete Mathematics: An Open Introduction - 4th Edition',NULL,'Tiếng Anh',NULL,2024,NULL,NULL,NULL,NULL,1,0,'Discrete Mathematics: An Open Introduction is a free, open source textbook appropriate for a first or second year undergraduate course for math and computer science majors. The book is especially well-suited for courses that incorporate inquiry-based learning. Since Spring 2013, the book has been used as the primary textbook or a supplemental resource at more than 200 colleges and universities around the world (see the partial adoptions list). After many years of development, I am pleased to announce that the 4th edition of Discrete Mathematics: an Open Introduction is now available, here and on Runestone Academy. The new edition brings many improvements and a new organization of content. In particular, the book now starts with logic and proofs, then practices those proofs with graph theory. The second half of the book contains material on counting (with a new \"application to probability\" section) and sequences. Over the last few years, I have found that students have more success with this arrangement. There is also a stronger emphasis on discrete structures, which should make the book more useful for students in computer science, while still focusing on understanding mathematical concepts essential for math majors and future math teachers.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 394.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/discrete-mathematics-an-open-introduction\nPublisher ô CSV: Oscar Levin.\nCopyright Year ô CSV: 2024.\nISBN-13 ô CSV: 9781534970748.\nISBN-10 ô CSV: 1534970746.\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Pure.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Oscar Levin - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781534970748.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:00:00',NULL),(329,'OTL-395','GT-OTL000395','Proofs and Concepts: The Fundamentals of Abstract Mathematics',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'This free undergraduate textbook provides an introduction to proofs, logic, sets, functions, and other fundamental topics of abstract mathematics. It is designed to be the textbook for a bridge course that introduces undergraduates to abstract mathematics, but it is also suitable for independent study by undergraduates (or mathematically mature high-school students), or for use as a very inexpensive supplement to undergraduate courses in any field of abstract mathematics.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 395.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/proofs-and-concepts-the-fundamentals-of-abstract-mathematics\nPublisher ô CSV: Dave Witte Morris, Joy Morris.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Pure.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Dave Witte Morris - Author / Joy Morris - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(330,'OTL-396','GT-OTL000396','Applied Finite Mathematics',NULL,'Tiếng Anh',NULL,2011,NULL,NULL,NULL,NULL,1,0,'Applied Finite Mathematics covers topics including linear equations, matrices, linear programming, the mathematics of finance, sets and counting, probability, Markov chains, and game theory.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 396.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/applied-finite-mathematics\nPublisher ô CSV: OpenStax CNX.\nCopyright Year ô CSV: 2011.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Applied.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Rupinder Sekhon - Editor',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(331,'OTL-397','GT-OTL000397','Modern Philosophy',NULL,'Tiếng Anh',NULL,2013,NULL,NULL,NULL,NULL,1,0,'This is a textbook in modern philosophy. It combines readings from primary sources with two pedagogical tools. Paragraphs in italics introduce figures and texts. Numbered study questions (also in italics) ask students to reconstruct an argument or position from the text, or draw connections among the readings. And I have added an introductory chapter (Chapter 0 – Minilogic and Glossary), designed to present the basic tools of philosophy and sketch some principles and positions. The immediate goal is to encourage students to grapple with the ideas rather than passing their eyes over the texts. This makes for a better classroom experience and permits higher-level discussions. Another goal is to encourage collaboration among instructors, as they revise and post their own versions of the book.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 397.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/modern-philosophy\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2013.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Philosophy.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Walter Ott - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(332,'OTL-399','GT-ISBN9781946135001','Linear Regression Using R: An Introduction to Data Modeling',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Linear Regression Using R: An Introduction to Data Modeling presents one of the fundamental data modeling techniques in an informal tutorial style. Learn how to predict system outputs from measured data using a detailed step-by-step process to develop, train, and test reliable regression models. Key modeling and programming concepts are intuitively described using the R programming language. All of the necessary resources are freely available online.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 399.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/linear-regression-using-r-an-introduction-to-data-modeling\nPublisher ô CSV: University of Minnesota Libraries Publishing.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781946135001.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Pure.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: David J. Lilja - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781946135001.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:00:00',NULL),(333,'OTL-402','GT-OTL000402','Calculus-Based Physics I',NULL,'Tiếng Anh',NULL,2008,NULL,NULL,NULL,NULL,1,0,'Calculus-Based Physics is an introductory physics textbook designed for use in the two-semester introductory physics course typically taken by science and engineering students.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 402.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/calculus-based-physics-i\nPublisher ô CSV: Jeffrey W. Schnick.\nCopyright Year ô CSV: 2008.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Physics.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Calculus.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Jeffrey Schnick - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(334,'OTL-403','GT-OTL000403','Calculus-Based Physics II',NULL,'Tiếng Anh',NULL,2008,NULL,NULL,NULL,NULL,1,0,'Calculus-Based Physics is an introductory physics textbook designed for use in the two-semester introductory physics course typically taken by science and engineering students.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 403.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/calculus-based-physics-ii\nPublisher ô CSV: Jeffrey W. Schnick.\nCopyright Year ô CSV: 2008.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Physics.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Calculus.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Jeffrey Schnick - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(335,'OTL-404','GT-ISBN9781938168147','Microbiology',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Microbiology covers the scope and sequence requirements for a single-semester microbiology course for non-majors. The book presents the core concepts of microbiology with a focus on applications for careers in allied health. The pedagogical features of the text make the material interesting and accessible while maintaining the career-application focus and scientific rigor inherent in the subject matter. Microbiology\'s art program enhances students\' understanding of concepts through clear and effective illustrations, diagrams, and photographs.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 404.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/microbiology\nPublisher ô CSV: OpenStax CNX.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781938168147.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Biology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Nina Parker - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781938168147.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:00:00',NULL),(336,'OTL-405','GT-ISBN9780692471289','Animals & Ethics 101: Thinking Critically About Animal Rights',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This book provides an overview of the current debates about the nature and extent of our moral obligations to animals. Which, if any, uses of animals are morally wrong, which are morally permissible (i.e., not wrong) and why? What, if any, moral obligations do we, individually and as a society (and a global community), have towards animals and why? How should animals be treated? Why? We will explore the most influential and most developed answers to these questions – given by philosophers, scientists, and animal advocates and their critics – to try to determine which positions are supported by the best moral reasons.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 405.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/animals-ethics-101-thinking-critically-about-animal-rights\nPublisher ô CSV: Open Philosophy Press.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9780692471289.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Philosophy.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Nathan Nobis - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9780692471289.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:00:00',NULL),(337,'OTL-407','GT-ISBN9781940771335','Understanding Music: Past and Present',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Understanding Music: Past and Present is an open Music Appreciation textbook co-authored by music faculty across Georgia. The text covers the fundamentals of music and the physics of sound, an exploration of music from the Middle Ages to the present day, and a final chapter on popular music in the United States.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 407.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/understanding-music-past-and-present\nPublisher ô CSV: University of North Georgia Press.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781940771335.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Arts.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Alan Clark - Author / Thomas Heflin - Author / Jeffery Kluball - Author / Elizabeth Kramer - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781940771335.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:00:00',NULL),(338,'OTL-408','GT-ISBN9781940771342','Writing the Nation: A Concise Introduction to American Literature 1865 to Present',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Writing the Nation: A Concise Guide to American Literature 1865 to Present is a text that surveys key literary movements and the American authors associated with the movement. Topics include late romanticism, realism, naturalism, modernism, and modern literature.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 408.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/writing-the-nation-a-concise-introduction-to-american-literature-1865-to-present\nPublisher ô CSV: University of North Georgia Press.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781940771342.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Amy Berke - Author / Robert Bleil - Author / Jordan Cofer - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781940771342.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:00:00',NULL),(339,'OTL-409','GT-ISBN9781940771328','World Literature I: Beginnings to 1650',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'This peer-reviewedWorld Literature Ianthology includes introductory text and images before each series of readings. Sections of the text are divided bytimeperiod in three parts: the Ancient World, Middle Ages, and Renaissance, and then divided into chapters by location.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 409.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/world-literature-i-beginnings-to-1650\nPublisher ô CSV: University of North Georgia Press.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781940771328.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Laura Getty - Author / Kyounghye Kwon - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781940771328.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:00:00',NULL),(340,'OTL-410','GT-ISBN9781940771229','Compact Anthology of World Literature',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'A world literature class may be the first place that some students have encountered European works, let alone non-Western texts. The emphasis in this anthology, therefore, is on non-Western and European works, with only the British authors who were the most influential to European and non-Western authors (such as Shakespeare, whose works have influenced authors around the world to the present day). In a world literature class, there is no way that a student can be equally familiar with all of the societies, contexts, time periods, cultures, religions, and languages that they will encounter; even though the works presented here are translated, students will face issues such as unfamiliar names and parts of the story (such as puns) that may not translate well or at all. Since these stories are rooted in their cultures and time periods, it is necessary to know the basic context of each work to understand the expectations of the original audience. The introductions in this anthology are meant to be just that: a basic overview of what students need to know before they begin reading, with topics that students can research further. An open access literature textbook cannot be a history book at the same time, but history is the great companion of literature: The more history students know, the easier it is for them to interpret literature. These works can help students understand the present, as well. In an electronic age, with this text available to anyone with computer access around the world, it has never been more necessary to recognize and understand differences among nationalities and cultures. The literature in this anthology is foundational, in the sense that these works influenced the authors who followed them. A word to the instructor: The texts have been chosen with the idea that they can be compared and contrasted, using common themes. Rather than numerous (and therefore often random) choices of texts from various periods, these selected works are meant to make both teaching and learning easier. While cultural expectations are not universal, many of the themes found in these works are.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 410.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/compact-anthology-of-world-literature\nPublisher ô CSV: University of North Georgia Press.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781940771229.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Laura Getty - Author / Kyounghye Kwon - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781940771229.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:00:00',NULL),(341,'OTL-411','GT-OTL000411','Exploring Public Speaking - 4th Edition',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'In Exploring Public Speaking, especially in its second through fourth editions, we have attempted to create a usable, zero-cost textbook for basic public speaking courses or courses that include basic public speaking skills as one of their primary learning outcomes. The free, open nature of the text means that instructors are able to use all or part of it, and add their own materials. We believe this text addresses all the subjects that traditional publishers’ books would address in an appropriate writing style and with appropriate college-level learning theory in mind. The appendices address some additional topics that might be excluded from most texts, but that we believe add to the experience: learning theory, plagiarism, speaking online, speaking to diverse audiences, and humor in public speaking. In the third and fourth editions we have added “case study” examples and some different outline samples. We think this book is especially useful in coverage of PowerPoint, audience analysis and responsiveness, ethics in public speaking, persuasion, special occasion speeches, and structure of speeches. Because it was written by communication professors with decades of experience in the classroom, we are aware of the needs of basic public speaking students. Three ancillaries are currently available: electronic “flash cards” for study, PowerPoint slide decks on the 15 main chapters, and test banks for the 15 main chapters. As the website is developed, it will include videos of student speeches.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 411.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/exploring-public-speaking-2nd-revision\nPublisher ô CSV: University System of Georgia.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Kris Barton - Author / Barbara G. Tucker - Author',NULL,NULL,'800','utc-elibrary/book-covers/defaults/default-book-cover.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(342,'OTL-412','GT-ISBN9781636350653','Technical Writing',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This open textbook offers students of technical writing an introduction to the processes and products involved in professional, workplace, and technical writing. The text is broken up into sections reflecting key components of researching, developing, and producing a technical report. Readers will also learn about other professional communication, designing documents, and creating and integrating graphics. Written especially for an academic setting, this book provides readers with guidance on information literacy and documenting sources. This book was collected, adapted, and edited from multiple openly licensed sources.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 412.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/technical-writing-2016\nPublisher ô CSV: Open Oregon Educational Resources.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781636350653.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Annemarie Hamlin - Author / Chris Rubio - Author',NULL,NULL,'800','utc-elibrary/book-covers/isbn/9781636350653.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:00:00',NULL),(343,'OTL-413','GT-OTL000413','How to Learn Like A Pro',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'How to Learn Like a Pro! features the “big six” effective learning/study skills topics: learning styles and preferences, time and materials management, critical thinking and reading, note-taking, memory principles, and test-taking techniques. Each of the six units featuring a total of twenty-three lessons and accompanying exercises (with a dash of humor here and there) were developed with the diverse student body of the community college in mind as well as learners in other educational venues.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 413.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/how-to-learn-like-a-pro\nPublisher ô CSV: Open Oregon Educational Resources.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Education.\nSubject OTL 2 — nguyên bản ô CSV —: Student Success.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Phyllis Nissila - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(344,'OTL-414','GT-OTL000414','Supporting Individuals with Intellectual Disabilities & Mental Illness',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'This multidisciplinary resource develops topics of interest to all those who care about and for individuals with co-occurring intellectual disabilities and mental illness. Each chapter presents current evidence informed practice knowledge. Each topic is also presented with audio enabled text boxes emphasizing ‘Key Points for Caregivers.\' For those who are interested in background knowledge, we provided the comprehensive literature base. And, for those interested mainly in ‘what to do,\' we provided text box summaries for reading and listening.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 414.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/supporting-individuals-with-intellectual-disabilities-mental-illness\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Medicine.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Sherri Melrose - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(345,'OTL-415','GT-OTL000415','Calculus: Early Transcendentals - 2021-A',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'Calculus: Early Transcendentals, originally by D. Guichard, has been redesigned by the Lyryx editorial team. Substantial portions of the content, examples, and diagrams have been redeveloped, with additional contributions provided by experienced and practicing instructors. This approachable text provides a comprehensive understanding of the necessary techniques and concepts of the typical Calculus course sequence, and is suitable for the standard Calculus I, II and III courses. To practice and develop an understanding of topics, this text offers a range of problems, from routine to challenging, with selected solutions. As this is an open text, instructors and students are encouraged to interact with the textbook through annotating, revising, and reusing to your advantage. Suggestions for contributions to this growing textbook are welcome. Lyryx develops and supports open texts, with editorial services to adapt the text for each particular course. In addition, Lyryx provides content-specific formative online assessment, a wide variety of supplements, and in-house support available 7 days/week for both students and instructors.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 415.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/calculus-early-transcendentals\nPublisher ô CSV: Lyryx.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: David Guichard - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(346,'OTL-417','GT-OTL000417','Intermediate Financial Accounting - 2021-A Volume 1',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This text is intended for a first course in Intermediate Financial Accounting. It presumes that students have already completed one or two Introductory Financial Accounting courses. The book reflects current International Financial Reporting Standards (IFRS), such as IFRS 15 - Revenue from Contracts With Customers. It focuses on more difficult intermediate accounting topics that match prerequisite requirements for students advancing to a second level Intermediate Financial Accounting course. Advanced topics that are covered in Advanced Financial Accounting courses, such as consolidations and foreign exchange, are not included here. The text is written with an approachable style that focuses on key concepts that will be relevant to students\' future careers as accountants. The book provides a review of Introductory Accounting concepts and covers all topics essential to a first level Intermediate Accounting course: the conceptual framework and current landscape of financial reporting; statements of financial position, comprehensive income, cash flows and shareholders\' equity; cash and receivables; revenue; inventory; property plant and equipment; intangible assets; and intercorporate investments.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 417.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/intermediate-financial-accounting-volume-1\nPublisher ô CSV: Lyryx.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Accounting.\nSubject OTL 2 — nguyên bản ô CSV —: Business.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Glenn Arnold - Author / Suzanne Kyle - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(347,'OTL-418','GT-OTL000418','Applied Developmental Systems Science: Everything You Always Wanted to Know About Theories, Meta-Theories, Methods, and Interventions but Didn\'t Realize You Needed to Ask. An Advanced Textbook',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'This textbook provides a toolbox, a guidebook, and an instruction manual for researchers and interventionists who want to conceptualize and study applied problems from a developmental systems perspective, and for those who want to teach their graduate (or advanced undergraduate) students how to do this. It is designed to be useful to practitioners who focus on applied developmental problems, such as improving the important developmental contexts where people live, learn, and work, including the applied professions in education, social work, counseling, health care, community development, and business, all of which at their core are concerned with optimizing the development of their students, clients, patients, workers, citizens, and others whose lives they touch.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 418.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/applied-developmental-systems-science-everything-you-always-wanted-to-know-about-theories-meta-theories-methods-and-interventions-but-didn-t-realize-you-needed-to-ask-an-advanced-textbook\nPublisher ô CSV: Portland State University Library.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Religion.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences - Sociology.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Ellen Skinner - Author / Thomas Kindermann - Author / Robert W. Roeser - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(348,'OTL-419','GT-OTL000419','Introduction to Programming Using Java - Eighth Edition',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Welcome to the Eighth Edition of Introduction to Programming Using Java, a free, on-line textbook on introductory programming, which uses Java as the language of instruction. This book is directed mainly towards beginning programmers, although it might also be useful for experienced programmers who want to learn something about Java. It is not meant to provide complete coverage of the Java language. The eighth edition requires Java 8 or later, and it uses JavaFX for GUI programming. Version 8.1 is a small update of Version 8.0. This version briefly covers some of the new features in Java 11 and makes it clearer how to use this book with Java 11 and later.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 419.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-programming-using-java-seventh-edition\nPublisher ô CSV: David J. Eck.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science - Programming Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: David J. Eck - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:40','2026-05-06 09:01:00',NULL),(349,'OTL-420','GT-OTL000420','Introduction to Computer Graphics',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Introduction to Computer Graphics is a free, on-line textbook covering the fundamentals of computer graphics and computer graphics programming. This book is meant for use as a textbook in a one-semester course that would typically be taken by undergraduate computer science majors in their third or fourth year of college.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 420.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-computer-graphics\nPublisher ô CSV: David J. Eck.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: David J. Eck - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(350,'OTL-421','GT-OTL000421','Project Management for Instructional Designers',NULL,'Tiếng Anh',NULL,2018,NULL,NULL,NULL,NULL,1,0,'Project Management for Instructional Designers (PM4ID) is a textbook about project management tailored specifically for instructional designers, intended for use in graduate programs in educational technology. This book is based on a pre-existing openly licensed textbook which was donated to the commons by a benefactor that desires to remain anonymous, and has been collaboratively revised and remixed by faculty and students at Brigham Young University.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 421.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/project-management-for-instructional-designers\nPublisher ô CSV: David Wiley.\nCopyright Year ô CSV: 2018.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Education - Curriculum & Instruction.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Bobbie Sandberg - Author / Royce Kimmons - Author / Rebecca Zundel - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(351,'OTL-422','GT-ISBN9781329999091','Korean Through Folktales',NULL,'Ngôn ngữ gốc đa dạng — xem chủ đề OTL và nhan đề',NULL,2017,NULL,NULL,NULL,NULL,1,0,'Korean Through Folktales consists of four chapters and each centers on a famous Korean folktale. The lessons and values that famous folktales teach are embedded and permeated in various aspects of the Koran culture. Using folktales in the curriculum will provide an engaging way to expose students to a slice of the target culture that native Koreans are naturally exposed to at an early age. Through the selected folktales and various activities offered in the book, students can gain cultural knowledge and insights into traditional and cultural values while they are given linguistic lessons to reinforce their acquired skills and to apply the learned materials in an integrated approach. Korean Through Folktales is designed to accompany 1st-year, 2nd-year, and 3rd-year Korean courses offered at Portland State University. However, any Korean teacher can adopt this book to supplement his/her course materials at elementary, intermediate, and advanced levels. There are four chapters in the book. Each chapter will note main themes of a widely known folktale introduced in the chapter, followed by the links to several videos to watch and get a gist or a background of the story. The ensuing section will introduce important elements and symbolism embedded in the story so as to provide insights and to enhance the depth of appreciation. After that, three versions of the folktale are presented for different levels, followed by grammar lessons, exercises, and tasks. Traces of folktales and allusions to them are evident in cultural products that many students enjoy, such as dramas, movies, and music. Therefore, knowledge in folktales will help students make cultural connections as well as enrich their experience of learning the Korean language.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 422.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/korean-through-folktales\nPublisher ô CSV: Portland State University Library.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: 9781329999091.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: KyungAh Yoon - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781329999091.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:00:00',NULL),(352,'OTL-423','GT-ISBN9781936153107','Tajik Persian: Readings in History, Culture and Society',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Tajik Persian: Readings in History, Culture and Society seeks to help students develop reading proficiency in Tajik at advanced level through authentic texts written for native speakers and provides them glimpses into the history, culture and society of Tajikistan without losing its focus on cultural aspects of the country—an aspect that constitutes a core component in the second language acquisition. The book can be adopted by instructors as a supplementary or the main textbook for advanced-level courses.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 423.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/tajik-persian-readings-in-history-culture-and-society\nPublisher ô CSV: University of Kansas Libraries.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781936153107.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Razi Ahmad - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781936153107.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:00:00',NULL),(353,'OTL-424','GT-OTL000424','Torts: Cases and Contexts Volume 2',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Plain-spoken and convivial, this casebook makes a deliberate effort to explain the law, rather than to provide a mere compilation of readings and questions. Simple concepts are presented simply. Complex concepts are broken down and accompanied by examples and problems. By being clear and straightforward, the casebook aims to quickly get students to the point where they can navigate regions of gray and build nuanced arguments. The book is written from the conviction that when students stop to puzzle over something, it should be because the law itself puzzles, not because the book obfuscates. Students describe the book as easy to read. A key aim is context, with explanations of how pieces of doctrine fit into the bigger picture. There is also a continual effort to plug doctrine into the real world of practice, getting students to think about litigation strategy and tactics. Another key feature is a high-degree of organization. Doctrine is explained upfront, independent of and before the cases. After the cases, there is no notes-and-questions mishmash. Historical notes, check-your-understanding questions, questions to ponder, and problems are all separately labeled as such. The readings are rich with variety. The classic cases are here, of course. But there are also atypical readings that allow students to see tort law from different perspectives, including an opening statement, a closing argument, administrative-enforcement letters, an excerpt from a novel, and an opinion on tribal law from a Navajo court. Many selections are also startlingly modern, with facts involving texting-and-driving, alcoholic energy drinks, Facebook libel, suddenly accelerating Toyotas, and the misery of a six-hour tarmac delay. Please note that the publisher requires you to login to access and download the textbooks.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 424.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/torts-cases-and-contexts-volume-2\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Civil Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Eric E. Johnson - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(354,'OTL-425','GT-OTL000425','Wetlands Law: A Course Source - 5th Edition',NULL,'Tiếng Anh',NULL,2024,NULL,NULL,NULL,NULL,1,0,'This is the revised, fifth edition of The Wetlands Law Course Source. It can be used as the primary text for a two credit seminar or as a supplemental text to cover wetlands material in an environmental law, natural resources law, or water law course. In addition, the administrative law chapter can be used as a supplement in a range of administrative law-related courses, such as environmental law, health law, labor law, immigration law, and others, to introduce basic administrative law concepts. Unlike traditional casebooks or coursebooks, a “course source” includes resources to train students in all three apprenticeships identified by the Carnegie Foundation in its influential report on legal education, Educating Lawyers: Preparation for the Profession of Law. To address the knowledge apprenticeship, the Wetlands Law Course Source includes all of the traditional elements of a casebook or coursebook (cases, commentary, notes and questions) and includes several hypotheticals and problem exercises that focus on reinforcing wetlands law. In addition, as one of the many forms of summative and formative assessment included in the book, every chapter includes one or more CALI exercise as a “quiz” to reinforce the material covered in the chapter. To address the skills apprenticeship, the Wetlands Law Course Source includes sixteen separate legal research exercises, several drafting exercises, a negotiation exercise, and an interviewing and counseling exercise. To address the values apprenticeship, the Course Source includes several professionalism scenarios, with questions related to the scenarios. The Course Source also incorporates a wealth of audio/video materials and external links to bring the cases, disputes and materials in the book to life, including the audio for the oral arguments in most of the principal cases excerpted in the book, a Google map identifying the location of the properties involved in all of the principal cases excerpted in the book, decision documents, administrative orders, property maps, pictures, local media coverage and other background materials for the principal cases. While the principal cases have been edited, the book includes links to the full unedited versions of almost all of the cases in the book. Throughout each chapter, there are several “Resource” sections that identify reports, databases, audio or video materials, government documents, and other materials that are relevant to the topics covered in the chapter. In addition, the book contains links to interviews that the author conducted regarding wetlands issues with attorneys who work with local communities and with the Department of Justice, the National Wildlife Federation, and the Environmental Council of the States. The links in the book have also been re-purposed as a web-based library of wetlands teaching resources, which is accessible at: https://www.envirolawteachers.com/wetlands-law-a-course-source.html\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 425.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/wetlands-law-a-course-source\nPublisher ô CSV: CALI\'s eLangdell® Press.\nCopyright Year ô CSV: 2024.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Administrative Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Stephen M. Johnson - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(355,'OTL-426','GT-OTL000426','Português para principiantes',NULL,'Tiếng Bồ Đào Nha',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Português para principiantes is a time-tested text which can be used in conjunction with a variety of approaches to the teaching of beginning Portuguese. This media-rich text is designed to provide learners with a solid grammatical basis for using Brazilian Portuguese as well as regular opportunities to practice and improve their ability to read, speak, and understand the Portuguese language as it is used in contemporary Brazil.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 426.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/portugues-para-principiantes\nPublisher ô CSV: A.T. Still University.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Severino J. Albuquerque - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(356,'OTL-427','GT-OTL000427','Introduction to Psychology - 1st Canadian Edition',NULL,'Tiếng Anh',NULL,2010,NULL,NULL,NULL,NULL,1,0,'This book is designed to help students organize their thinking about psychology at a conceptual level. The focus on behaviour and empiricism has produced a text that is better organized, has fewer chapters, and is somewhat shorter than many of the leading books. The beginning of each section includes learning objectives; throughout the body of each section are key terms in bold followed by their definitions in italics; key takeaways, and exercises and critical thinking activities end each section.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 427.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-psychology-1st-canadian-edition\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2010.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Psychology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Jennifer Walinga - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(357,'OTL-428','GT-OTL000428','Nature of Geographic Information Systems',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'The purpose of this text is to promote understanding of the Geographic Information Science and Technology enterprise (GIS&T, also known as “geospatial”).\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 428.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/nature-of-geographic-information-systems\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science - Information Systems.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: David DiBiase - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(358,'OTL-429','GT-ISBN9781775352419','Canadian History: Pre-Confederation',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Canadian History: Pre-Confederation is a survey text that introduces undergraduate students to important themes in North American history to 1867. It provides room for Aboriginal and European agendas and narratives, explores the connections between the territory that coalesces into the shape of modern Canada and the larger continent and world in which it operates, and engages with emergent issues in the field. The material is pursued in a largely chronological manner to the early 19th century, at which point social, economic, and political change are dissected. Canadian History: Pre-Confederation provides, as well, a reconnaissance of historical methodology and debates in the field, exercises for students, Key Terms and a Glossary, and section-by-section Key Points. Although this text can be modified, expanded, reduced, and reorganized to suit the needs of the instructor, it is organized so as to support learning, to broaden (and sometimes provoke) debate, and to engage students in thinking like historians. Written and reviewed by subject experts drawn from colleges and universities, this is the first open textbook on the topic of Canadian history.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 429.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/canadian-history-pre-confederation\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9781775352419.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - History.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 900 — Lịch sử & Địa lý.\nContributors — nguyên bản ô CSV —: John Douglas Belshaw - Author',NULL,NULL,'900','utc-elibrary/book-covers/isbn/9781775352419.jpg',7,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:00:00',NULL),(359,'OTL-430','GT-ISBN9781774200094','Mastering Strategic Management - 1st Canadian Edition',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'Mastering Strategic Management is designed to enhance student engagement in three innovative ways. The first is through visual adaptations of the key content in the book. It is well documented that many of today\'s students are visual learners. To meet students\' wants and needs (and thereby create a much better teaching experience for professors), Mastering Strategic Management contains multiple graphic concept pages in ever section of every chapter of the book. Think of graphic concept pages as almost like info-graphics for key concepts in each section. This feature sets Mastering Strategic Management apart from any strategic management book on the market today. The second way the authors capture student interest through their textbook is by using a real-world company as the running example in each chapter. For example, Chapter 1 in Mastering Strategic Management utilizes Blackberry to harness the conceptual coverage of the chapter in a running, corporate, application to which students will relate. The third inventive way Mastering Strategic Management holds the attention of strategic management students is through the “strategy at the movies” feature in each chapter that links course concepts with a popular motion picture.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 430.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/mastering-strategic-management-1st-canadian-edition\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781774200094.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Management.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Janice Edwards - Author / Dave Ketchen - Author / Jeremy Short - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781774200094.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:00:00',NULL),(360,'OTL-431','GT-OTL000431','Research Methods in Psychology - 2nd Canadian Edition',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'The present adaptation constitutes the second Canadian edition and was co-authored by Rajiv S. Jhangiani (Kwantlen Polytechnic University) and I-Chant A. Chiang (Quest University Canada) and is licensed under a Creative Commons Attribution-NonCommercial-ShareAlike 4.0 International License. Revisions include the following: Chapter 1: Added a description of the “Many Labs Replication Project,” added a reference to the Neurobonkers website, and embedded videos about open access publishing, driver distraction, two types of empirical studies, and the use of evidence to evaluate the world around us.Chapter 2: Updated the exemplar study in the chapter overview, added relevant examples and descriptions of contemporary studies, provided a link to an interactive visualization for correlations, added a description of double-blind peer review, added a figure to illustrate a spurious correlation, and embedded videos about how to develop a good research topic, searching the PsycINFO database, using Google Scholar, and how to read an academic paper.Chapter 3: Added in LaCour ethical violation. Revised chapter headings and order to reflect TCPS-2 moral principles.Chapter 4: Added in difference between laws and effects and theoretical framework.Chapter 5: Added fuller descriptions of the levels of measurement, added a table to summarize the levels of measurement, added a fuller description of the MMPI, removed the discussion of the IAT, and added descriptions of concurrent, predictive, and convergent validity.Chapter 6: Added in construct validity, statistical validity, mundane realism, psychological realism, Latin Square Design. Updated references.Chapter 7: Added in mixed-design studies and fuller discussion of qualitative-quantitative debate.Chapter 8: Added an exercise to sketch the 8 possible results of a 2 x 2 factorial experiment.Chapter 9: Added information about Canadian Election Studies, more references, specific guidelines about order and open-ended questions, and rating scale. Updated online survey creation sites.Chapter 11: Updated examples and links to online resources.Chapter 13: Added discussion of p-curve and BASP announcement about banning p-values. Added a section that introduces the “replicability crisis” in psychology, along with discussions of questionable research practices, best practices in research design and data management, and the emergence of open science practices and Transparency and Openness Promotion guidelines. Glossary of key terms: Added. In addition, throughout the textbook, we revised the language to be more precise and to improve flow, added links to other chapters, added images, updated hyperlinks, corrected spelling and formatting errors, and changed references to reflect the contemporary Canadian context.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 431.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/research-methods-in-psychology-2nd-canadian-edition\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Psychology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Rajiv S. Jhangiani - Author / I-Chant A. Chiang - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(361,'OTL-432','GT-OTL000432','Introductory Business Statistics with Interactive Spreadsheets - 1st Canadian Edition',NULL,'Tiếng Anh',NULL,2010,NULL,NULL,NULL,NULL,1,0,'Introductory Business Statistics with Interactive Spreadsheets – 1st Canadian Edition is an adaptation of Thomas K. Tiemann\'s book, Introductory Business Statistics. This new edition still contains the basic ideas behind statistics, such as populations, samples, the difference between data and information, and sampling distributions as well as information on descriptive statistics and frequency distributions, normal and t-distributions, hypothesis testing, t-tests, f-tests, analysis of variance, non-parametric tests, and regression basics. New topics include the chi-square test and categorical variables, null and alternative hypotheses for the test of independence, simple linear regression model, least squares method, coefficient of determination, confidence interval for the average of the dependent variable, and prediction interval for a specific value of the dependent variable. This new edition also allows readers to learn the basic and most commonly applied statistical techniques in business in an interactive way — when using the web version — through interactive Excel spreadsheets. For each topic, a customized interactive template has been created within which selected values can be repeatedly changed to observe how the entire process, as well as the outcomes, are automatically adjusted. Also, in this adapted edition, the real-world examples throughout the text, and the information in general, have been revised to reflect Canadian content.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 432.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introductory-business-statistics-with-interactive-spreadsheets-1st-canadian-edition\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2010.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Business.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Applied.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Mohammad Mahbobi - Author / Thomas K. Tiemann - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(362,'OTL-433','GT-OTL000433','Ethics in Law Enforcement',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'In this book, you will examine the moral and ethical issues that exist within law enforcement. This book will also familiarize you with the basic history, principles, and theories of ethics. These concepts will then be applied to the major components of the criminal justice system: policing, the courts, and corrections. Discussion will focus on personal values, individual responsibility, decision making, discretion, and the structure of accountability. Specific topics covered will include core values, codes of conduct, ethical dilemmas, organizational consequences, liability, and the importance of critical thinking. By the end of this book, you will be able to distinguish and critically debate contemporary ethical issues in law enforcement.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 433.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/ethics-in-law-enforcement\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Law.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Steve McCartney - Author / Rick Parent - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(363,'OTL-434','GT-ISBN9781974214167','Euclidean plane and its relatives',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'This book is meant to be rigorous, conservative, elementary and minimalist. At the same time it includes about the maximum what students can absorb in one semester. Approximately one-third of the material used to be covered in high school, but not any more.The present book is based on the courses given by the author at the Pennsylvania State University as an introduction to the foundations of geometry. The lectures were oriented to sophomore and senior university students. These students already had a calculus course. In particular,they are familiar with the real numbers and continuity. It makes it possible to cover the material faster and in a more rigorous way than it could be done in high school.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 434.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/euclidean-plane-and-its-relatives\nPublisher ô CSV: Anton Petrunin.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: 9781974214167.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Geometry and Trigonometry.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Anton Petrunin - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9781974214167.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:00:00',NULL),(364,'OTL-435','GT-OTL000435','PDX Journeys: Studying and Living in the US, Low-Intermediate Novel and Textbook for University ESL Students',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Each unit begins with a chapter of fiction about a teacher and students in one ESL class. Reading comprehension and reading skills exercises follow. Prefix and suffix vocabulary-focus exercises are included. Academic Word List vocabulary exercises help students build a strong foundation in both receptive and productive knowledge. The following chapters in each unit expand on unit themes through non-fiction articles focusing on academic preparation, international experiences, and cultural adjustment. Vocabulary is repeated and comprehension and reading skills are further practiced.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 435.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/pdx-journeys-studying-and-living-in-the-us-low-intermediate-novel-and-textbook-for-university-esl-students\nPublisher ô CSV: Portland State University Library.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Amber Bliss Calderón - Author',NULL,NULL,'800','utc-elibrary/book-covers/defaults/default-book-cover.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(365,'OTL-436','GT-ISBN9781774200216','Introduction to Sociology - 2nd Canadian Edition',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Introduction to Sociology adheres to the scope and sequence of a typical introductory sociology course. In addition to comprehensive coverage of core concepts, foundational scholars, and emerging theories, we have incorporated section reviews with engaging questions, discussions that help students apply the sociological imagination, and features that draw learners into the discipline in meaningful ways. Although this text can be modified and reorganized to suit your needs, the standard version is organized so that topics are introduced conceptually, with relevant, everyday experiences.For the student, this book is based on the teaching and research experience of numerous sociologists. In today\'s global socially networked world, the topic of Sociology is more relevant than ever before. We hope that through this book, students will learn how simple, everyday human actions and interactions can change the world. In this book, you will find applications of Sociology concepts that are relevant, current, and balanced. For instructors, this text is intended for a one-semester introductory course and includes these features: Sociological Research: Highlights specific current and relevant research studies. Sociology in the Real World: Ties chapter content to student life and discusses sociology in terms of the everyday. Big Picture: Features present sociological concepts at a national or international level. Case Study: Describes real-life people whose experiences relate to chapter content. Social Policy and Debate: Discusses political issues that relate to chapter content. Section Summaries distill the information in each section for both students and instructors down to key, concise points addressed in the section. Key Terms are bold and are followed by a definition in context. Definitions of key terms are also listed in the Key Terms, which appears at the end of each chapter. Section Quizzes provide opportunities to apply and test the information students learn throughout each section. Both multiple-choice and short-response questions feature a variety of question types and range of difficulty. Further Research: This feature helps students further explore the section topic and offers related research topics that could be explored.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 436.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-sociology-2nd-canadian-edition\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781774200216.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Religion.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences - Sociology.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: William Little - Author / Ron McGivern - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781774200216.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:00:00',NULL),(366,'OTL-437','GT-OTL000437','British Columbia in a Global Context',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'This first year Geography textbook takes a holistic approach to Geography by incorporating elements of physical, human and regional geography, as well as bringing in methods and perspectives from spatial information science.. This textbook applies a fundamental geographical approach to understanding our globally changing world by looking at local processes which are linked to larger global processes and events. The textbook includes numerous case studies specific to British Columbia as well as a number of suggested service learning activities. Over the course of four days in June, 2014, 5 faculty members from across British Columbia supported by a facilitator, librarian, researcher, illustrator, programmer and instructional designer, created this book. This involved drawing on our own research, teaching and experience and working with the team to put it all together into an online format; one which would be accessible to students and educators alike. Beyond the unique way in which this book was created in a Book Sprint process, there are other elements of this book that make it unique. First, it takes a holistic approach to first year Geography, incorporating elements of Physical, Human, and Regional Geography, as well as bringing in methods and perspectives from Spatial Information Science. Pedagogically, this book incorporates elements of service learning and suggested service learning activities recognizing that the study of Geography is deeply connected to the communities we live in. Many of the suggestions for service learning are illustrated through the use of case studies from across BC. The book is aimed at a a first year or introductory Geography student, and would be suitable for a first year Geography course on BC.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 437.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/british-columbia-in-a-global-context\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Geography.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 900 — Lịch sử & Địa lý.',NULL,NULL,'900','utc-elibrary/book-covers/defaults/default-book-cover.jpg',7,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(367,'OTL-438','GT-OTL000438','Introduction to Tourism and Hospitality in BC',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'This textbook is an introduction to the tourism and hospitality industry in British Columbia, and is written with a first year college and university audience in mind. It is a collaborative work with input from educators, industry leaders, employers, and past graduates of BC\'s tourism and hospitality management programs. All chapters have been reviewed by experts in the field. Each chapter is organized thematically moving from a global, then national and finally provincial context. Some chapters are quite global in focus while others concentrate primarily on British Columbia. Chapter content is based on available data and research, and input from collaborators. Each chapter features “Spotlight On” text boxes that highlight an organization, business, or other key component of the chapter\'s theme. “Take a Closer Look” features encourage students to do further reading on particular subjects. At the end of each chapter, key terms are presented in alphabetical order to help students gain confidence with terminology. These are followed by chapter exercises and a case study for in-depth exploration of the subject matter. Key terms are summarized in a Glossary at the end of the textbook.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 438.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-tourism-and-hospitality-in-bc\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Morgan Westcott - Author / Geoffrey Bird - Author / Peter Briscoe - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(368,'OTL-439','GT-ISBN9781771991841','Health and Safety in Canadian Workplaces',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Workplace injuries happen every day and can profoundly affect workers, their families, and the communities they live in. This textbook provides workers with an introduction to effective injury prevention. The book pays particular attention to how issues of precarious employment, gender, and ill health can be better handled in Canadian occupational health and safety (OHS).This introduction to OHS differs from others because it contends that the practice of occupational health and safety can only be properly understood if we acknowledge that workers and employers have conflicting interests. Specifically, we investigate which workplace hazards are recognized and controlled,the manner in which these hazards are controlled, and who makes these decisions. These are all factors that reflect the broader political economy of employment and suggest that OHS is contested terrain.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 439.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/health-and-safety-in-canadian-workplaces\nPublisher ô CSV: Athabasca University Press.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781771991841.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Human Resources.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Jason Foster - Author / Bob Barnetson - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781771991841.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:00:00',NULL),(369,'OTL-440','GT-OTL000440','Java with BlueJ',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This book is Part I of a two-part set that introduces the Java programming language. The text assumes the student will be using the BlueJ development environment and provides some introductory BlueJ material. Our experience has been that BlueJ is easy to learn and provides a good programming environment for the beginner programmer.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 440.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/java-with-bluej\nPublisher ô CSV: Ron McFadyen.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science - Programming Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Ron McFadyen - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(370,'OTL-441','GT-OTL000441','Java with BlueJ Part 2',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This book is Part II of a two-part set that introduces the Java programming language. The text assumes the student will be using the BlueJ development environment and provides some introductory BlueJ material. Our experience has been that BlueJ is easy to learn and provides a good programming environment for the beginner programmer.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 441.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/java-with-bluej-part-2\nPublisher ô CSV: Ron McFadyen.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science - Programming Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Ron McFadyen - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(371,'OTL-442','GT-OTL000442','Relational Databases and Microsoft Access 365 - Version 4.0',NULL,'Tiếng Anh',NULL,2021,NULL,NULL,NULL,NULL,1,0,'This text is a free introductory text that introduces MS Access and relational database design. The motivation is to support an introductory database system course which, to the student, is either a service course providing an introduction to database concepts, or, as a prerequisite for more advanced study in the field.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 442.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/relational-databases-and-microsoft-access\nPublisher ô CSV: Ron McFadyen.\nCopyright Year ô CSV: 2021.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science - Databases.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Ron McFadyen - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(372,'OTL-443','GT-ISBN9780998625713','Elementary Algebra',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'Elementary Algebra is designed to meet the scope and sequence requirements of a one-semester elementary algebra course. The book\'s organization makes it easy to adapt to a variety of course syllabi. The text expands on the fundamental concepts of algebra while addressing the needs of students with diverse backgrounds and learning styles. Each topic builds upon previously developed material to demonstrate the cohesiveness and structure of mathematics.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 443.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/elementary-algebra-2017\nPublisher ô CSV: OpenStax.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: 9780998625713.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Algebra.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Lynn Marecek - Author / MaryAnne Anthony-Smith - Author',NULL,NULL,'500','utc-elibrary/book-covers/isbn/9780998625713.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:00:00',NULL),(373,'OTL-444','GT-OTL000444','My Math GPS: Elementary Algebra Guided Problem Solving - 2016 Edition',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'My Math GPS: Elementary Algebra Guided Problem Solving is a textbook that aligns to the CUNY Elementary Algebra Learning Objectives that are tested on the CUNY Elementary Algebra Final Exam (CEAFE). This book contextualizes arithmetic skills into Elementary Algebra content using a problem-solving pedagogy. Classroom assessments and online homework are available from the authors.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 444.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/my-math-gps-elementary-algebra-guided-problem-solving-2016-edition\nPublisher ô CSV: CUNY Academic Works.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Algebra.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Jonathan Cornick - Author / Michael Guy - Author / Karan Puri - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(374,'OTL-445','GT-OTL000445','Human Anatomy and Physiology Preparatory Course',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'The goal of this preparatory textbook is to give students a chance to become familiar with some terms and some basic concepts they will find later on in the Anatomy and Physiology course, especially during the first few weeks of the course. Organization and functioning of the human organism are generally presented starting from the simplest building blocks, and then moving into levels of increasing complexity. This textbook follows the same presentation. It begins introducing the concept of homeostasis, then covers the chemical level, and later on a basic introduction to cellular level, organ level, and organ system level. This second edition incorporates a module on protein synthesis, and a complementary base pairing learning objective as requested by many students. This edition incorporates links to audios for all learning objectives, and many learning objectives have online videos associated to them. The textbook is organized in five Units, divided into sixteen Modules covering a total of fifty-three Learning Objectives. Each learning objective includes a short self-assessment at the end of it.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 445.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/human-anatomy-and-physiology-preparatory-course\nPublisher ô CSV: CUNY Academic Works.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Biology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 600 — Công nghệ (Khoa học ứng dụng).\nContributors — nguyên bản ô CSV —: Carlos Liachovitzky - Author',NULL,NULL,'600','utc-elibrary/book-covers/defaults/default-book-cover.jpg',4,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(375,'OTL-446','GT-ISBN9780991388707','Music: Its Language, History, and Culture',NULL,'Tiếng Anh',NULL,2015,NULL,NULL,NULL,NULL,1,0,'Welcome to Music 1300, Music: Its Language History, and Culture. The course has a numberof interrelated objectives:1. To introduce you to works representative of a variety of music traditions.These include the repertoires of Western Europe from the Middle Agesthrough the present; of the United States, including art music, jazz, folk, rock, musical theater; and from at least two non-Western world areas (Africa, Asia, Latin America, the Caribbean, the Middle East, Indian subcontinent).2. To enable you to speak and write about the features of the music you study,employing vocabulary and concepts of melody, rhythm, harmony, texture, timbre,and form used by musicians.3. To explore with you the historic, social, and cultural contexts and the role of class, ethnicity, and gender in the creation and performance of music,including practices of improvisation and the implications of oral andnotated transmission.4. To acquaint you with the sources of musical sounds—instruments and voices fromdifferent cultures, found sounds, electronically generated sounds; basic principlesthat determine pitch and timbre.5. To examine the influence of technology, mass media, globalization, and transnationalcurrents on the music of today.The chapters in this reader contain definitions and explanations of musical terms and concepts,short essays on subjects related to music as a creative performing art, biographical sketchesof major figures in music, and historical and cultural background information on music fromdifferent periods and places.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 446.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/music-its-language-history-and-culture\nPublisher ô CSV: CUNY Academic Works.\nCopyright Year ô CSV: 2015.\nISBN-13 ô CSV: 9780991388707.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Arts.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Douglas Cohen - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9780991388707.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:00:00',NULL),(376,'OTL-447','GT-OTL000447','Statistical Inference For Everyone',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'This is a new approach to an introductory statistical inference textbook, motivated by probability theory as logic. It is targeted to the typical Statistics 101 college student, and covers the topics typically covered in the first semester of such a course. It is freely available under the Creative Commons License, and includes a software library in Python for making some of the calculations and visualizations easier.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 447.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/statistical-inference-for-everyone\nPublisher ô CSV: Brian Blais.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Applied.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Brian Blais - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(377,'OTL-448','GT-ISBN9781910814185','International Relations',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This book is designed to be a ‘Day 0\' introduction to International Relations. As a beginner\'s guide, it has been structured to condense the most important information into the smallest space and present that information in the most accessible way. The chapters offer a broad sweep of the basic components of International Relations and the key contemporary issues that concern the discipline. The narrative arc forms a complete circle, taking readers from no knowledge to competency. The journey starts by examining how the international system was formed and ends by reflecting that International Relations is always adapting to events and is therefore a never-ending journey of discovery. Unlike typical textbooks, there are no boxes, charts, pictures or exercises. The philosophy underpinning this book is that these things can be a distraction. This book, like others in the E-IR Foundations series, is designed to capture attention with an engaging narrative. The chapters are short, with simple paragraphs and clear sentences placing the reader inside crucial issues and debates so they can understand how things work, and where they fit in the world around them.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 448.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/international-relations\nPublisher ô CSV: E-International Relations.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781910814185.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Geography.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - Religion.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 900 — Lịch sử & Địa lý.\nContributors — nguyên bản ô CSV —: Stephen McGlinchey - Author',NULL,NULL,'900','utc-elibrary/book-covers/isbn/9781910814185.jpg',7,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:00:00',NULL),(378,'OTL-449','GT-OTL000449','Intellectual Property: Law & the Information Society—Cases and Materials',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This book is an introduction to intellectual property law, the set of private legal rights that allows individuals and corporations to control intangible creations and marks—from logos to novels to drug formulae—and the exceptions and limitations that define those rights. It focuses on the three graphmain forms of US federal intellectual property—trademark, copyright and patent—but many of the ideas discussed here apply far beyond those legal areas and far beyond the law of the United States. The book is intended to be a textbook for the basic Intellectual Property class, but because it is an open coursebook, which can be freely edited and customized, it is also suitable for an undergraduate class, or for a business, library studies, communications or other graduate school class. Each chapter contains cases and secondary readings and a set of problems or role-playing exercises involving the material. The problems range from a video of the Napster oral argument to counseling clients about search engines and trademarks, applying the First Amendment to digital rights management and copyright or commenting on the Supreme Court\'s rulings on gene patents.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 449.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/intellectual-property-law-the-information-society-cases-and-materials\nPublisher ô CSV: James Boyle, Jennifer Jenkins.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Law - Civil Law.\nSubject OTL 2 — nguyên bản ô CSV —: Law.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: James Boyle - Author / Jennifer Jenkins - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(379,'OTL-450','GT-OTL000450','A Different Road To College: A Guide For Transitioning Non-Traditional Students',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'A Different Road To College: A Guide For Transitioning Non-Traditional Students is designed to introduce students to the contextual issues of college. Non-traditional students have an ever-growing presence on college campuses, especially community colleges. This open educational resource is designed to engage students in seeing themselves as college students and understanding the complexity of what that means to their lives. Non-traditional students face critical issues surrounding participation and success in college. These critical issues include, but are not limited to, the following Strategies for managing competing needs on their time Difficulty navigating institutional environments Understanding the culture of college Transitional services not in place to the same degree as for “traditional” students Knowledgeable support systems Personal barriers Unpredictable influences on their schedules Work first, study second priorities Paying for college Underprepared foundation skills (Reading, Writing, Math, Computer Literacy, Human Relations, Oral Communication).Most textbooks available on the topic of college transition/success today focus on the traditional 18-year old student and the needs of someone living away from home for the first time.The goal of the book is to help students understand how to select the right college for them and then become acquainted with the inner workings and language of college. The book is designed to be a practical guide for first-generation college students as they navigate potentially unfamiliar topics such as understanding the costs of college beyond tuition, navigating college websites, and defining critical language needed to understand communication regarding the context and culture of the college.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 450.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/a-different-road-to-college-a-guide-for-transitioning-non-traditional-students\nPublisher ô CSV: Open Oregon Educational Resources.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Student Success.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Alise Lamoreaux - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(380,'OTL-451','GT-OTL000451','Open Research',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'If you have an interest in openness, open education, research skills or want to find out more about the impact of Open EducationalResources (OER), then this resource is for you. You could be: Using an OER with students and interested in assessing its impact Facilitating sessions on open practice with students or colleagues and looking for inspiration Working on a research project and wanting to find out more about incorporating open research techniques into your own practice Curious about the benefits and challenges of open research Looking to use open tools in your research Wanting increased impact for your research Interested in open research on OER This resource will help you explore what open research is, how you can ethically and openly share your findings so others can reuse or develop your work, and the role of reflection and open dissemination. Whilst many challenges and issues apply to all aspects of research (for example: choosing an appropriate methodology), open research brings a range of different opportunities and challenges; it\'s these that we are specifically interested in exploring. What can openness add to the research process?\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 451.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/open-research\nPublisher ô CSV: OER Hub.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Education - Higher Education.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Rebecca Pitt - Author / Beatriz de los Arcos - Author / Rob Farrow - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(381,'OTL-452','GT-ISBN9781942341420','A Concise Introduction to Logic',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'A Concise Introduction to Logic is an introduction to formal logic suitable for undergraduates taking a general education course in logic or critical thinking, and is accessible and useful to any interested in gaining a basic understanding of logic. This text takes the unique approach of teaching logic through intellectual history; the author uses examples from important and celebrated arguments in philosophy to illustrate logical principles. The text also includes a basic introduction to findings of advanced logic. As indicators of where the student could go next with logic, the book closes with an overview of advanced topics, such as the axiomatic method, set theory, Peano arithmetic, and modal logic. Throughout, the text uses brief, concise chapters that readers will find easy to read and to review.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 452.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/a-concise-introduction-to-logic\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: 9781942341420.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Philosophy.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Craig DeLancey - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781942341420.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:00:00',NULL),(382,'OTL-453','GT-ISBN9781593275846','Eloquent JavaScript: A Modern Introduction to Programming',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'JavaScript lies at the heart of almost every modern web application, from social apps like Twitter to browser-based game frameworks like Phaser and Babylon. Though simple for beginners to pick up and play with, JavaScript is a flexible, complex language that you can use to build full-scale applications. This much anticipated and thoroughly revised third edition of Eloquent JavaScript dives deep into the JavaScript language to show you how to write beautiful, effective code. It has been updated to reflect the current state of Java¬Script and web browsers and includes brand-new material on features like class notation, arrow functions, iterators, async functions, template strings, and block scope. A host of new exercises have also been added to test your skills and keep you on track.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 453.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/eloquent-javascript-a-modern-introduction-to-programming\nPublisher ô CSV: No Starch Press.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781593275846.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Computer Science - Programming Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Marijn Haverbeke - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781593275846.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:00:00',NULL),(383,'OTL-454','GT-OTL000454','Web Literacy for Student Fact-Checkers',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'The web gives us many such strategies and tactics and tools, which, properly used, can get students closer to the truth of a statement or image within seconds. For some reason we have decided not to teach students these specific techniques. As many people have noted, the web is both the largest propaganda machine ever created and the most amazing fact-checking tool ever invented. But if we haven\'t taught our students those capabilities is it any surprise that propaganda is winning? This is an unabashedly practical guide for the student fact-checker. It supplements generic information literacy with the specific web-based techniques that can get you closer to the truth on the web more quickly.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 454.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/web-literacy-for-student-fact-checkers\nPublisher ô CSV: Mike Caulfield.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Student Success.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Mike Caulfield - Author',NULL,NULL,'800','utc-elibrary/book-covers/defaults/default-book-cover.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(384,'OTL-455','GT-OTL000455','A Guide to Technical Communications: Strategies & Applications',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Welcome to the textbook for Engineering Technical Communications courses at The Ohio State University. Our aim in writing this textbook was to create a resource specifically focused on and applicable to the kinds of communication skills most beneficial to the students who take our courses. Therefore, this textbook focuses on developing both technical and professional communication skills and will help readers practice strategies for critically analyzing audiences and contexts, real-world applications of rhetorical principles, and skills for producing documents (reports, proposals, instructions), presentations, videos, and wide variety of other professional communications.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 455.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/a-guide-to-technical-communications-strategies-applications\nPublisher ô CSV: Ohio State University Libraries.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Journalism, Media Studies & Communications - Technical Writing.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Lynn Hall - Author / Leah Wahlin - Author',NULL,NULL,'800','utc-elibrary/book-covers/defaults/default-book-cover.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(385,'OTL-456','GT-ISBN9781774200131','Project Management',NULL,'Tiếng Anh',NULL,2014,NULL,NULL,NULL,NULL,1,0,'This book covers the basics of project management. This includes the process of initiation, planning, execution, control and close out that all projects share.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 456.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/project-management\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2014.\nISBN-13 ô CSV: 9781774200131.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Business - Management.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Adrienne Watt - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781774200131.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:00:00',NULL),(386,'OTL-457','GT-OTL000457','Introduction to Logic and Critical Thinking',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This is an introductory textbook in logic and critical thinking. The goal of the textbook is to provide the reader with a set of tools and skills that will enable them to identify and evaluate arguments. The book is intended for an introductory course that covers both formal and informal logic. As such, it is not a formal logic textbook, but is closer to what one would find marketed as a “critical thinking textbook.”\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 457.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-logic-and-critical-thinking\nPublisher ô CSV: Matthew J. Van Cleave.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Philosophy.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Matthew Van Cleave - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:01:00',NULL),(387,'OTL-458','GT-ISBN9781944548223','The Economics of Food and Agricultural Markets - 2nd Edition',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'The Second Edition of Economics of Food and Agricultural Markets (2019) is written for applied intermediate microeconomics courses. The book showcases the power of economic principles to explain and predict issues and current events in the food, agricultural, agribusiness, international trade, labor markets, and natural resource sectors. The field of agricultural economics is relevant, important and interesting. The study of market structures, also called industrial organization, provides powerful, timely, and useful tools for any individual or group making personal choices, business decisions, or public policies in food and agricultural industries. Readers will benefit from a large number of real-world examples and applications of the economic concepts under discussion. The book introduces economic principles in a succinct and reader-friendly format, providing students and instructors with a clear, up-to-date, and straightforward approach to learning how a market-based economy functions, and how to use simple economic principles for improved decision making. The principles are applied to timely, interesting, and important real-world issues through words, graphs, and simple algebra and calculus. This book is intended for students who study agricultural economics, microeconomics, rural development and/or environmental policy. The goal of the book is to encourage students to learn to “think like an economist” through application of benefits and costs to every decision, idea, and strategic decision. This objective is accomplished by including extended examples that cover a broad range of topics including the analysis of consumer decisions, supply and demand, and market efficiency; the design of pricing strategies; advertising and marketing decisions; and public policy analysis. Contents The book begins with a review and introduction of economic principles, including markets, scarcity, and the scientific method. Supply and demand are examined carefully and completely, with numerous real-world examples. The power of the market model is employed to explain and predict economic phenomena and current events. Elasticities are defined, explained, and put to use in decision making for all individuals, businesses, and policy makers. Next, the motivation for and consequences of globalization, immigration, and international trade are explored. Government policies are surveyed, including taxes, subsidies, trade policies, and immigration policies. Monopoly and monopsony are presented, using numerous real-world examples and anecdotes. Pricing strategies are comprehensively discussed, including price discrimination, peak-load pricing, two-part pricing, bundling, and advertising. Monopolistic competition and oligopoly are defined, explained, and used to understand real-world markets. Game theory, or strategic decision making, is introduced and used to demonstrate how to make better decisions in numerous situations when other individuals and groups are affected by a choice or strategy. Repeated games, sequential games, and first-mover advantage are carefully presented and considered.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 458.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-economics-of-food-and-agricultural-markets\nPublisher ô CSV: New Prairie Press.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: 9781944548223.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Economics.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 600 — Công nghệ (Khoa học ứng dụng).\nContributors — nguyên bản ô CSV —: Andrew Barkley - Author',NULL,NULL,'600','utc-elibrary/book-covers/isbn/9781944548223.jpg',4,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:41','2026-05-06 09:00:00',NULL),(388,'OTL-459','GT-OTL000459','Introduction to Statistics',NULL,'Tiếng Anh',NULL,2003,NULL,NULL,NULL,NULL,1,0,'Introduction to Statistics is a resource for learning and teaching introductory statistics. This work is in the public domain. Therefore, it can be copied and reproduced without limitation. However, we would appreciate a citation where possible. Please cite as: Online Statistics Education: A Multimedia Course of Study (http://onlinestatbook.com/). Project Leader: David M. Lane, Rice University. Instructor\'s manual, PowerPoint Slides, and additional questions are available.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 459.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-statistics\nPublisher ô CSV: David Lane.\nCopyright Year ô CSV: 2003.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: No Rights Reserved.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Applied.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: David Lane - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:42','2026-05-06 09:01:00',NULL),(389,'OTL-460','GT-OTL000460','Forest Measurements: An Applied Approach',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'This is a forest measurements textbook written for field technicians. Silvicultural applications and illustrations are provided to demonstrate the relevance of the measurements. Special “technique tips” for each skill are intended to help increase data collection accuracy and confidence. These include how to avoid common pitfalls, effective short cuts and essentials for recording field data correctly. The emphasis is on elementary skills; it is not intended to be a timber cruising guide.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 460.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/forest-measurements-an-applied-approach\nPublisher ô CSV: Open Oregon Educational Resources.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Joan DeYoung - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:42','2026-05-06 09:01:00',NULL),(390,'OTL-461','GT-ISBN9781945764028','Introduction to Women, Gender, Sexuality Studies',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'This textbook introduces key feminist concepts and analytical frameworks used in the interdisciplinary Women, Gender, Sexualities field. It unpacks the social construction of knowledge and categories of difference, processes and structures of power and inequality, with a focus on gendered labor in the global economy, and the historical development of feminist social movements. The book emphasizes feminist sociological approaches to analyzing structures of power, drawing heavily from empirical feminist research.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 461.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-women-gender-sexuality-studies\nPublisher ô CSV: UMass Amherst.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: 9781945764028.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Economics.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences - Gender & Sexuality Studies.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Miliann Kang - Author / Donovan Lessard - Author / Laura Heston - Author / Sonny Nordmarken - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781945764028.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:42','2026-05-06 09:00:00',NULL),(391,'OTL-462','GT-OTL000462','Yet Another Calculus Text',NULL,'Tiếng Anh',NULL,2007,NULL,NULL,NULL,NULL,1,0,'I intend this book to be, firstly, a introduction to calculus based on the hyperrealnumber system. In other words, I will use infinitesimal and infinite numbers freely. Just as most beginning calculus books provide no logical justification for the real number system, I will provide none for the hyperreals. The reader interested in questions of foundations should consult books such asAbraham Robinson\'s Non-standard Analysis or Robert Goldblatt\'s Lectures onthe Hyperreals. Secondly, I have aimed the text primarily at readers who already have somefamiliarity with calculus. Although the book does not explicitly assume any prerequisites beyond basic algebra and trigonometry, in practice the pace istoo fast for most of those without some acquaintance with the basic notions of calculus.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 462.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/yet-another-calculus-text\nPublisher ô CSV: Dan Sloughter.\nCopyright Year ô CSV: 2007.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Calculus.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Pure.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Dan Sloughter - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:42','2026-05-06 09:01:00',NULL),(392,'OTL-463','GT-OTL000463','A Primer of Real Analysis',NULL,'Tiếng Anh',NULL,2009,NULL,NULL,NULL,NULL,1,0,'This is a short introduction to the fundamentals of real analysis. Although the prerequisites are few, I have written the text assuming the reader has the level of mathematical maturity of one who has completed the standard sequence of calculus courses, has had some exposure to the ideas of mathematical proof (including induction), and has an acquaintance with such basic ideas as equivalence relations and the elementary algebraic properties of the integers.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 463.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/a-primer-of-real-analysis\nPublisher ô CSV: Dan Sloughter.\nCopyright Year ô CSV: 2009.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Mathematics - Analysis.\nSubject OTL 2 — nguyên bản ô CSV —: Mathematics - Applied.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Dan Sloughter - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:42','2026-05-06 09:01:00',NULL),(393,'OTL-464','GT-OTL000464','Perspectives: An Open Invitation to Cultural Anthropology - Second Edition',NULL,'Tiếng Anh',NULL,2020,NULL,NULL,NULL,NULL,1,0,'We are delighted to bring to you this novel textbook, a collection of chapters on the essential topics in cultural anthropology. Different from other introductory textbooks, this book is an edited volume with each chapter written by a different author. Each author has written from their experiences working as an anthropologist and that personal touch makes for an accessible introduction to cultural anthropology. Our approach to cultural anthropology is holistic. We see the interconnectedness of cultural practices and, in all of the chapters, we emphasize the comparison of cultures and the ways of life of different peoples. We start with Laura Nader’s observation that cultural differences need not be seen as a problem. In our complicated world of increasing migration, nationalism, and climate challenges, cultural diversity might actually be the source of conflict resolution and new approaches to ensuring a healthier world. Indeed, as Katie Nelson reminds us, anthropology exposes the familiarity in the ideas and practices of others that seem bizarre. Robert Borofsky advocates for anthropology’s ability to empower people and facilitate good. Borofsky calls on anthropologists to engage with a wider public to bring our incredible stories and important insights to helping resolve the most critical issues we face in the world today. This book brings Nader, Nelson, Borofsky, and many others together to demonstrate that our anthropological understandings can help all of us to improve the lives of people the world over. We need you, as students, to see the possibilities. As instructors, we want to help you easily share anthropological knowledge and understanding. We want all readers to be inspired by the intensely personal writings of the anthropologists who contribute to this volume.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 464.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/perspectives-an-open-invitation-to-cultural-anthropology\nPublisher ô CSV: American Anthropological Association.\nCopyright Year ô CSV: 2020.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Anthropology.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences - Cultural & Ethnic Studies.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Nina Brown - Author / Thomas Mcllwraith - Author / Laura Tubelle de González - Author',NULL,NULL,'300','utc-elibrary/book-covers/defaults/default-book-cover.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:42','2026-05-06 09:01:00',NULL),(394,'OTL-465','GT-ISBN9781622399253','Global Women\'s Issues: Women in the World Today, extended version',NULL,'Tiếng Anh',NULL,2012,NULL,NULL,NULL,NULL,1,0,'We cannot solve global challenges unless women participate fully in efforts to find solutions. Female participation in the private sector is a crucial economic driver for societies worldwide. Economic security benefits every facet of a woman\'s life, with positive effects on the health, education and vitality of families. Learn about women who are changing their societies for the better. This book is based on the twelve critical areas of concern identified in the Beijing Declaration and Platform for Action at the Fourth World Conference on Women in Beijing in 1995: The burden of poverty on women, unequal access to education and training, inequalities and inadequacies in and unequal access to health care and related services, violence against women, the effects of armed or other kinds of conflict on women, including those living under foreign occupation, inequality in economic structures and policies, inequality between men and women in the sharing of power and decision-making at all levels, insufficient mechanisms at all levels to promote the advancement of women, lack of respect for and inadequate promotion and protection of the human rights of women, stereotyping of women and inequality in women\'s access to and participation in all communication systems, especially in the media, gender inequalities in the management of natural resources and in the safeguarding of the environment, and persistent discrimination against and violation of the rights of the girl child. This extended version of Global Women\'s Issues: Women in the World Today includes, for each chapter, a summary, key words, multiple choice questions, discussion questions, essay questions, and a list of additional resources. Copies of the original book are also available in Arabic, Portuguese, and Spanish.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 465.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/global-women-s-issues-women-in-the-world-today-extended-version\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2012.\nISBN-13 ô CSV: 9781622399253.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Gender & Sexuality Studies.\nSubject OTL 2 — nguyên bản ô CSV —: Social Sciences - Political Science.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Janni Aragon - Author / Mariel Miller - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781622399253.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:42','2026-05-06 09:00:00',NULL),(395,'OTL-466','GT-OTL000466','Greek and Latin Roots: Part I - Latin',NULL,'Tiếng Anh',NULL,2016,NULL,NULL,NULL,NULL,1,0,'Greek and Latin Roots: Part I - Latin is part one of a two part series. This series examines the systematic principles by which a large portion of English vocabulary has evolved from Latin and (to a lesser degree) from Greek. This book focuses on Latin roots. A link to the second part focusing on the Greek roots can be found below. Part I will try to impart some skill in the recognition and proper use of words derived from Latin. There is a stress on principles: although students will be continually looking at interesting individual words, their constant aim will be to discover predictable general patterns of historical development, so that they may be able to cope with new and unfamiliar words of any type that they have studied. They will be shown how to approach the problem by a procedure known as “word analysis,” which is roughly comparable to the dissection of an interesting specimen in the biology laboratory. The text assumes no previous knowledge of Latin, and does not involve the grammatical study of this language—except for a few basic features of noun and verb formation that will help students to understand the Latin legacy in English. Although there will be some attention paid to the historical interaction of Latin with English, this text is definitely not a systematic history of the English language. It focuses on only those elements within English that have been directly or indirectly affected by this classical language. In order to provide the broadest possible service to students, the text emphasizes standard English vocabulary in current use. The more exotic technical vocabulary of science and medicine can be extremely interesting, but is explored in only summary fashion. Nevertheless, this text should be of considerable value, say, to a would-be botanist or medical doctor, if only by providing the foundation for further specialized enquiry.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 466.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/greek-and-latin-roots-part-i-latin\nPublisher ô CSV: BCcampus.\nCopyright Year ô CSV: 2016.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Languages.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Peter Smith - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:42','2026-05-06 09:01:00',NULL),(396,'OTL-467','GT-ISBN9781942341406','The History of Our Tribe: Hominini',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'Where did we come from? What were our ancestors like? Why do we differ from other animals? How do scientists trace and construct our evolutionary history? The History of Our Tribe: Hominini provides answers to these questions and more. The book explores the field of paleoanthropology past and present. Beginning over 65 million years ago, Welker traces the evolution of our species, the environments and selective forces that shaped our ancestors, their physical and cultural adaptations, and the people and places involved with their discovery and study. It is designed as a textbook for a course on Human Evolution but can also serve as an introductory text for relevant sections of courses in Biological or General Anthropology or general interest. It is both a comprehensive technical reference for relevant terms, theories, methods, and species and an overview of the people, places, and discoveries that have imbued paleoanthropology with such fascination, romance, and mystery.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 467.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-history-of-our-tribe-hominini\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: 9781942341406.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Social Sciences - Anthropology.\nSubject OTL 2 — nguyên bản ô CSV —: Humanities - History.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 300 — Khoa học xã hội.\nContributors — nguyên bản ô CSV —: Barbara Welker - Author',NULL,NULL,'300','utc-elibrary/book-covers/isbn/9781942341406.jpg',2,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:42','2026-05-06 09:00:00',NULL),(397,'OTL-468','GT-ISBN9781942341468','Exploring Movie Construction & Production: What’s so exciting about movies?',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'Exploring Movie Construction & Production contains eight chapters of the major areas of film construction and production. The discussion covers theme, genre, narrative structure, character portrayal, story, plot, directing style, cinematography, and editing. Important terminology is defined and types of analysis are discussed and demonstrated. An extended example of how a movie description reflects the setting, narrative structure, or directing style is used throughout the book to illustrate building blocks of each theme. This approach to film instruction and analysis has proved beneficial to increasing students\' learning, while enhancing the creativity and critical thinking of the student.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 468.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/exploring-movie-construction-production-what-s-so-exciting-about-movies\nPublisher ô CSV: Open SUNY.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: 9781942341468.\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Arts.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: John Reich - Author',NULL,NULL,'000','utc-elibrary/book-covers/isbn/9781942341468.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:42','2026-05-06 09:00:00',NULL),(398,'OTL-469','GT-OTL000469','Introduction to Permaculture',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'Permaculture Design is a method of land planning that can be applied at scales from the home garden to city block to village to farm. It is an ethically based whole-systems design approach that uses concepts, principles, and methods derived from ecosystems, indigenous technologies, and other time-tested practices to create sustainable human settlements and institutions. Although rooted in horticulture and agriculture, Permaculture design is interdisciplinary, touching on a wide range of subjects including regional planning, ecology, animal husbandry, appropriate technology, architecture, social justice, and international development. This open text book is derived from the content of the Massive Open Online Course “Intro to Permaculture”. The original course also included interactive mapping and design tools that accompanied this content. The course and book provide a general overview of the Permaculture design system. The book can be downloaded as a print version. However, there are many accompanying videos and content pages that are linked to throughout the text, so it is best viewed online where the links can be accessed.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 469.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/introduction-to-permaculture\nPublisher ô CSV: Oregon State University.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 000 — Khoa học máy tính, Thông tin & Tổng quát.\nContributors — nguyên bản ô CSV —: Andrew Millison - Author',NULL,NULL,'000','utc-elibrary/book-covers/defaults/default-book-cover.jpg',1,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:42','2026-05-06 09:01:00',NULL),(399,'OTL-470','GT-OTL000470','Microbiology',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'In this textbook the focus will be on the bacteria and archaea (traditionally known as the “prokaryotes,”) and the viruses and other acellular agents.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 470.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/microbiology-2017\nPublisher ô CSV: Oregon State University.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial-ShareAlike.\nSubject OTL 1 — nguyên bản ô CSV —: Natural Sciences - Biology.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 500 — Khoa học tự nhiên & Toán học.\nContributors — nguyên bản ô CSV —: Linda Bruslind - Author',NULL,NULL,'500','utc-elibrary/book-covers/defaults/default-book-cover.jpg',3,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:42','2026-05-06 09:01:00',NULL),(400,'OTL-471','GT-OTL000471','The Word on College Reading and Writing',NULL,'Tiếng Anh',NULL,2017,NULL,NULL,NULL,NULL,1,0,'Written by five college reading and writing instructors, this interactive, multimedia text draws from decades of experience teaching students who are entering the college reading and writing environment for the very first time. It includes examples, exercises, and definitions for just about every reading- and writing-related topic students will encounter in their college courses.\n——\nNguồn CSV Open Textbook Library (University of Minnesota, CC0).\nOTL ID 471.\nTrang thư viện OTL: https://open.umn.edu/opentextbooks/textbooks/the-word-on-college-reading-and-writing\nPublisher ô CSV: Open Oregon Educational Resources.\nCopyright Year ô CSV: 2017.\nISBN-13 ô CSV: .\nISBN-10 ô CSV: .\nLicense ô CSV của OTL cho bản ghi này: Attribution-NonCommercial.\nSubject OTL 1 — nguyên bản ô CSV —: Humanities - Literature, Rhetoric, and Poetry.\nSubject OTL 2 — nguyên bản ô CSV —: —.\nPhân loại UTC sau khi lập luật từ tựa + Subject: 800 — Văn học.\nContributors — nguyên bản ô CSV —: Monique Babin - Author / Carol Burnell - Author / Susan Pesznecker - Author / Nicole Rosevear - Author / Jaime Wood - Author',NULL,NULL,'800','utc-elibrary/book-covers/defaults/default-book-cover.jpg',6,1,'textbook','circulation_only','[]',NULL,NULL,NULL,'2026-05-02 09:45:42','2026-05-06 09:01:00',NULL),(401,'REG-UTC-2026-0401','GT-ISBN9780132350884','Clean Code','A Handbook of Agile Software Craftsmanship','Tiếng Anh','1',2008,464,25,'24 cm',285000,12,0,'Sách tập trung vào nguyên tắc viết mã sạch, dễ bảo trì, phù hợp cho học phần kỹ thuật phần mềm và thực hành lập trình.','Bản in bìa mềm, phục vụ mượn về nhà theo chính sách hiện hành.','Boston','TU-600-C1','utc-elibrary/book-covers/isbn/9780132350884.jpg',4,1,'textbook','circulation_only','{\"isbn\": \"9780132350884\", \"source\": \"manual-curation-v1\"}',3,3,NULL,'2026-05-06 08:10:00','2026-05-06 08:10:00',NULL),(402,'REG-UTC-2026-0402','GT-ISBN9781449373320','Designing Data-Intensive Applications','The Big Ideas Behind Reliable, Scalable, and Maintainable Systems','Tiếng Anh','1',2017,616,70,'24 cm',420000,8,0,'Tài liệu nền tảng về hệ thống dữ liệu hiện đại: lưu trữ, xử lý luồng, độ tin cậy và khả năng mở rộng.','Ưu tiên phục vụ nhóm môn CSDL phân tán và kiến trúc hệ thống.','Sebastopol','TU-600-D2','utc-elibrary/book-covers/isbn/9781449373320.jpg',4,2,'reference','circulation_only','{\"isbn\": \"9781449373320\", \"source\": \"manual-curation-v1\"}',3,3,NULL,'2026-05-06 08:10:00','2026-05-06 08:10:00',NULL),(403,'REG-UTC-2026-0403','GT-ISBN9780596009205','Head First Java','Second Edition','Tiếng Anh','2',2005,720,500,'24 cm',315000,10,0,'Giáo trình Java theo phong cách trực quan, phù hợp cho người mới học lập trình hướng đối tượng.','Sách tham khảo bổ trợ cho học phần Java cơ bản và nâng cao.','Beijing','TU-500-B1','utc-elibrary/book-covers/isbn/9780596009205.jpg',3,1,'textbook','circulation_only','{\"isbn\": \"9780596009205\", \"source\": \"manual-curation-v1\"}',3,3,NULL,'2026-05-06 08:10:00','2026-05-06 08:10:00',NULL),(404,'REG-UTC-2026-0404','GT-ISBN9780133591620','Modern Operating Systems','Pearson New International Edition','Tiếng Anh','4',2014,1136,150,'24 cm',455000,6,0,'Giáo trình chuyên sâu về nguyên lý hệ điều hành, bao gồm quản lý tiến trình, bộ nhớ, hệ tệp và bảo mật.','Dùng chính cho học phần Hệ điều hành và kiến trúc máy tính.','Boston','TU-600-C1','utc-elibrary/book-covers/isbn/9780133591620.jpg',4,2,'reference','circulation_only','{\"isbn\": \"9780133591620\", \"source\": \"manual-curation-v1\"}',3,3,NULL,'2026-05-06 08:10:00','2026-05-06 08:10:00',NULL);
