INSERT INTO `news_posts` VALUES (1,'asfag-asgagah-aaa','asfag asgagah ; aaa','<p>fafag</p><p><br></p><p><img src=\"data:image/png;base64,\" alt=\"Biểu đồ UML-Thêm bài viết.drawio.png\" style=\"max-width: 100%; height: auto;\"></p><p>fafag</p>\n\n<!-- news-attachments:start --><hr /><p><strong>Tệp đính kèm:</strong></p><ul><li><a href=\"http://localhost:8000/upload/news/attachments/fcbc8aaf-a639-48f1-bd50-18f641c33d1e.pdf\" target=\"_blank\" rel=\"noopener noreferrer\">发音练习 Luyện tập phát âm.pdf</a></li></ul><!-- news-attachments:end -->','upload/news/thumbnails/fae87621-a305-4c84-9c4d-aa22885fc409.png','active','news','2026-05-05 13:04:35',2,2,NULL,'2026-05-05 13:04:35','2026-05-05 13:04:35'),(2,'thong-bao-lich-nghi-30-4-1-5','Thông báo lịch nghỉ lễ 30/4 - 1/5','<p>Kính gửi toàn thể cán bộ, giảng viên và các bạn sinh viên Đại học Giao thông Vận tải (UTC),</p><p>Hòa chung không khí hân hoan chào mừng Ngày Giải phóng miền Nam 30/04 và Ngày Quốc tế Lao động 01/05, Thư viện số UTC xin trân trọng thông báo lịch nghỉ lễ như sau:</p><ul><li><strong>Thời gian bắt đầu nghỉ:</strong> Từ thứ Ba, ngày 30/04/2026.</li><li><strong>Thời gian kết thúc nghỉ:</strong> Đến hết thứ Tư, ngày 01/05/2026.</li><li><strong>Thời gian mở cửa trở lại:</strong> Thứ Năm, ngày 02/05/2026 lúc 07:30 sáng.</li></ul><p>Trong thời gian nghỉ lễ, hệ thống Thư viện số (Tra cứu trực tuyến, đọc tài liệu số, gia hạn sách) vẫn hoạt động bình thường. Tuy nhiên, các dịch vụ mượn trả sách giấy tại quầy và hỗ trợ trực tiếp sẽ tạm ngưng.</p><p>Kính chúc quý thầy cô cùng toàn thể các bạn sinh viên có một kỳ nghỉ lễ thật vui vẻ, an toàn và ý nghĩa bên gia đình!</p><p><em>Trân trọng,</em><br><strong>Ban Giám đốc Thư viện UTC</strong></p>',NULL,'active','notice','2026-04-25 08:30:00',3,3,NULL,'2026-04-25 08:30:00','2026-04-25 08:30:00'),(3,'huong-dan-gia-han-sach-online','Hướng dẫn gia hạn sách online','<p>Chào các bạn độc giả,</p><p>Để tạo điều kiện thuận lợi hơn trong việc mượn và đọc sách, Thư viện số UTC đã chính thức cập nhật tính năng gia hạn sách trực tuyến ngay trên nền tảng web.</p><h3>Các bước thực hiện gia hạn:</h3><ol><li>Đăng nhập vào tài khoản Thư viện số UTC của bạn.</li><li>Truy cập vào mục <strong>Hồ sơ cá nhân</strong> (Profile) -> Chọn thẻ <strong>Phiếu mượn</strong> (Loans).</li><li>Tìm đến cuốn sách bạn đang mượn và muốn gia hạn, sau đó nhấn nút <strong>Gia hạn</strong> màu xanh.</li><li>Hệ thống sẽ xác nhận và tự động cộng thêm số ngày mượn cho bạn (thường là 7 đến 14 ngày tùy loại sách).</li></ol><h3>Lưu ý quan trọng:</h3><ul><li>Mỗi cuốn sách / phiếu mượn chỉ được phép gia hạn trực tuyến tối đa <strong>01 lần</strong>.</li><li>Tính năng gia hạn <strong>KHÔNG</strong> áp dụng đối với những cuốn sách đã quá hạn trả. Nếu sách đã quá hạn, bạn bắt buộc phải mang sách đến quầy thủ thư để trả và thanh toán phí phạt (nếu có).</li><li>Sách thuộc kho tham khảo hoặc mượn đọc tại chỗ không được phép gia hạn mang về.</li></ul><p>Nếu gặp bất kỳ khó khăn nào trong quá trình thao tác, vui lòng liên hệ bộ phận hỗ trợ trực tuyến qua Fanpage hoặc Email của Thư viện.</p>',NULL,'active','notice','2026-04-27 10:15:00',3,3,NULL,'2026-04-27 10:15:00','2026-04-27 10:15:00'),(4,'cap-nhat-kho-tai-lieu-tham-khao-thang-5','Cập nhật kho tài liệu tham khảo tháng 5','<p>Tin vui dành cho cộng đồng sinh viên khối ngành Kinh tế và Kỹ thuật!</p><p>Trong tháng 5 này, Thư viện UTC đã tiến hành bổ sung và cập nhật hàng loạt tài liệu tham khảo mới nhất từ các nhà xuất bản uy tín trong và ngoài nước. Đặc biệt tập trung vào các giáo trình, sách chuyên khảo phục vụ trực tiếp cho các đồ án, môn học chuyên ngành.</p><h3>Chi tiết cập nhật:</h3><ul><li>Bổ sung <strong>hơn 500 đầu sách mới</strong> thuộc lĩnh vực Kinh tế vận tải, Cơ khí, Công nghệ thông tin và Điện tử viễn thông.</li><li>Cập nhật hơn 200 luận văn, luận án thạc sĩ và tiến sĩ xuất sắc của sinh viên các khóa trước.</li><li>Nhiều đầu sách ngoại văn chuẩn quốc tế đã được số hóa và đưa lên hệ thống đọc trực tuyến.</li></ul><p>Các tài liệu bản giấy hiện đã được xếp lên kệ tại khu vực <strong>Tham khảo tầng 5 và tầng 6</strong>. Mời các bạn độc giả nhanh chóng tra cứu mã sách trên hệ thống Thư viện số (phân loại 300 - Khoa học xã hội, 500 - Khoa học tự nhiên, 600 - Công nghệ) và đến mượn ngay hôm nay!</p>',NULL,'active','news','2026-05-02 14:00:00',3,3,NULL,'2026-05-02 14:00:00','2026-05-02 14:00:00'),(5,'thong-bao-ke-hoach-so-hoa-luan-an','Thông báo kế hoạch số hóa luận án','<p>Kính gửi quý thầy cô và các bạn sinh viên, học viên cao học,</p><p>Thực hiện kế hoạch chuyển đổi số mạnh mẽ trong năm 2026, Thư viện UTC chính thức khởi động dự án <strong>\"Số hóa 100% Luận văn, Luận án và Đồ án tốt nghiệp xuất sắc\"</strong>.</p><p>Dự án này nhằm mục đích bảo tồn các công trình nghiên cứu khoa học có giá trị của sinh viên và giảng viên nhà trường, đồng thời tạo ra một kho dữ liệu mở, giúp thế hệ sinh viên tiếp theo dễ dàng tham khảo và kế thừa.</p><h3>Kế hoạch triển khai:</h3><ul><li><strong>Giai đoạn 1 (05/2026 - 08/2026):</strong> Tiến hành thu thập và scan kỹ thuật số toàn bộ luận án Tiến sĩ từ năm 2015 đến nay.</li><li><strong>Giai đoạn 2 (09/2026 - 12/2026):</strong> Áp dụng công nghệ nhận dạng ký tự quang học (OCR) để trích xuất văn bản, hỗ trợ tính năng tìm kiếm nội dung sâu (Deep Search) trên hệ thống.</li></ul><p>Trong thời gian triển khai, khu vực kho lưu trữ luận án bản cứng tại Tầng 4 có thể sẽ bị hạn chế truy cập trong một số khung giờ nhất định. Chúng tôi rất mong nhận được sự thông cảm và phối hợp từ quý độc giả.</p>',NULL,'active','notice','2026-05-03 09:00:00',3,3,NULL,'2026-05-03 09:00:00','2026-05-03 09:00:00'),(6,'huong-dan-tra-cuu-theo-tu-phan-loai','Hướng dẫn tra cứu theo tủ phân loại','<p>Bạn là tân sinh viên và cảm thấy bối rối trước hàng ngàn đầu sách trong Thư viện? Đừng lo, bài viết này sẽ hướng dẫn bạn cách tra cứu sách theo chuẩn phân loại thập phân Dewey (DDC) một cách dễ hiểu nhất.</p><p>Thư viện UTC áp dụng hệ thống phân loại DDC để sắp xếp sách trên kệ. Mỗi môn loại kiến thức sẽ tương ứng với một dải số từ 000 đến 900.</p><h3>Các dải số phổ biến tại UTC:</h3><ul><li><strong>000:</strong> Tin học, Khoa học máy tính và Thông tin chung.</li><li><strong>300:</strong> Khoa học xã hội (Kinh tế, Luật, Thống kê, Xã hội học...). Rất cần thiết cho các bạn khối ngành Kinh tế vận tải.</li><li><strong>500:</strong> Khoa học tự nhiên (Toán học, Vật lý, Hóa học...).</li><li><strong>600:</strong> Công nghệ và Khoa học ứng dụng (Cơ khí, Xây dựng cầu đường, Điện - Điện tử...). Đây là khu vực trọng điểm của sinh viên khối kỹ thuật!</li></ul><h3>Mẹo tìm sách nhanh:</h3><p>Khi tra cứu trên Thư viện số, hãy để ý đến mục <strong>\"Ký hiệu xếp giá\"</strong> (Ví dụ: 624.2/NGU-T). Số 624.2 cho bạn biết sách nằm ở khu vực Xây dựng Cầu đường (Kệ số 6, Tầng 5), và \"NGU-T\" là viết tắt tên tác giả Nguyễn Văn T. để bạn dễ tìm trên kệ chữ cái.</p><p>Hãy thử áp dụng ngay hôm nay nhé!</p>',NULL,'active','notice','2026-05-04 08:45:00',3,3,NULL,'2026-05-04 08:45:00','2026-05-04 08:45:00'),(7,'quy-dinh-muon-tra-cap-nhat-thang-5','Quy định mượn/trả cập nhật tháng 5','<p>Kính gửi toàn thể bạn đọc,</p><p>Nhằm nâng cao chất lượng phục vụ và đảm bảo sự công bằng trong việc luân chuyển tài liệu, Thư viện UTC xin thông báo một số điều chỉnh về <strong>Quy định mượn/trả tài liệu</strong>, chính thức áp dụng từ ngày 15/05/2026.</p><h3>Những thay đổi chính:</h3><ul><li><strong>Số lượng sách mượn về:</strong> Sinh viên hệ chính quy được mượn tối đa <strong>05 cuốn</strong> cùng lúc (thay vì 03 cuốn như trước đây). Giảng viên được mượn tối đa <strong>10 cuốn</strong>.</li><li><strong>Thời gian mượn:</strong> Mặc định là <strong>14 ngày</strong> cho sách giáo trình và <strong>07 ngày</strong> cho sách tham khảo.</li><li><strong>Phí phạt quá hạn:</strong> Để răn đe tình trạng găm sách, phí phạt trễ hạn được điều chỉnh thành <strong>5.000 VNĐ / 1 cuốn / 1 ngày trễ</strong>. Phí thu được sẽ sung vào quỹ mua sắm sách mới cho sinh viên.</li><li><strong>Chính sách làm mất sách:</strong> Trong trường hợp làm mất hoặc hư hỏng nặng tài liệu, độc giả phải đền bù một cuốn sách mới hoàn toàn giống hệt, hoặc đền bù bằng tiền mặt gấp <strong>03 lần</strong> giá trị hiện hành của cuốn sách đó.</li></ul><p>Quy định chi tiết bằng văn bản đã được niêm yết tại bảng tin các tầng và đăng tải trong chuyên mục Quy định trên Website. Mong các bạn đọc kỹ và tuân thủ để xây dựng môi trường học thuật văn minh.</p>',NULL,'active','notice','2026-05-05 07:40:00',3,3,NULL,'2026-05-05 07:40:00','2026-05-05 07:40:00'),(8,'thong-bao-bo-sung-kho-giao-trinh-khoi-cong-nghe','Thông báo bổ sung kho giáo trình khối công nghệ','<p>Chào các kỹ sư tương lai của khối Công nghệ & Kỹ thuật!</p><p>Đáp ứng nhu cầu học tập và nghiên cứu tăng cao trong học kỳ này, Thư viện UTC vừa nhập kho thành công đợt sách mới với số lượng lớn, tập trung hoàn toàn vào mảng Công nghệ thông tin, Cơ khí động lực và Tự động hóa.</p><h3>Các tựa sách nổi bật:</h3><ul><li>Lập trình Web hiện đại với React, Vue và Laravel (Phiên bản mới nhất).</li><li>Trí tuệ nhân tạo và Machine Learning ứng dụng trong giao thông.</li><li>Giáo trình Thiết kế Vi mạch, IoT và Hệ thống nhúng.</li><li>Tài liệu hướng dẫn AutoCAD, SolidWorks cơ bản và nâng cao.</li></ul><p>Tất cả giáo trình đã được bộ phận kỹ thuật dán mã vạch và phân loại lên các giá sách từ <strong>A1 đến A5 tại Tầng 6</strong>. Kính mời các bạn sinh viên đến mượn ngay hôm nay để có sự chuẩn bị tốt nhất cho các đồ án sắp tới!</p>',NULL,'active','notice','2026-05-05 09:10:00',3,3,NULL,'2026-05-05 09:10:00','2026-05-05 09:10:00'),(9,'huong-dan-xu-ly-phieu-muon-qua-han','Hướng dẫn xử lý phiếu mượn quá hạn','<p>Quá hạn trả sách là tình huống không ai mong muốn, nhưng nếu lỡ rơi vào trường hợp này, bạn cần bình tĩnh xử lý theo các bước sau đây để không bị khóa thẻ thư viện.</p><h3>Quy trình xử lý:</h3><ol><li><strong>Mang sách đến trực tiếp thư viện:</strong> Khi sách đã quá hạn, hệ thống gia hạn online sẽ bị vô hiệu hóa. Bạn bắt buộc phải đem sách đến Quầy mượn trả tại Tầng 1.</li><li><strong>Báo cáo với thủ thư:</strong> Thông báo mã số thẻ sinh viên và giao lại sách cho cán bộ thư viện kiểm tra tình trạng.</li><li><strong>Đóng phí phạt:</strong> Mức phạt mặc định là 5.000 VNĐ/cuốn/ngày. Bạn có thể thanh toán bằng tiền mặt hoặc quét mã QR VNPay ngay tại quầy.</li><li><strong>Xóa nợ và mở khóa thẻ:</strong> Sau khi hoàn tất đóng phạt, thủ thư sẽ cập nhật trạng thái trên hệ thống. Thẻ của bạn sẽ lập tức hoạt động bình thường trở lại.</li></ol><p><em>Mẹo nhỏ:</em> Để tránh bị phạt, hãy thường xuyên đăng nhập vào Thư viện số để theo dõi ngày đến hạn của các phiếu mượn và tranh thủ gia hạn online kịp thời nhé!</p>',NULL,'active','notice','2026-05-05 11:00:00',3,3,NULL,'2026-05-05 11:00:00','2026-05-05 11:00:00'),(10,'thong-bao-mo-rong-khung-gio-phuc-vu-cuoi-tuan','Thông báo mở rộng khung giờ phục vụ cuối tuần','<p>Kính gửi quý độc giả,</p><p>Thấu hiểu nhu cầu ôn thi cuối kỳ đang đến gần và mong muốn có một không gian yên tĩnh, tập trung để học tập vào dịp cuối tuần, Ban Giám đốc Thư viện UTC quyết định <strong>mở rộng khung giờ phục vụ</strong> vào Thứ Bảy và Chủ Nhật.</p><h3>Chi tiết lịch hoạt động mới (áp dụng từ tháng 5/2026):</h3><ul><li><strong>Thứ Hai - Thứ Sáu:</strong> 07:30 - 21:00 (Mở cửa thông tầm).</li><li><strong>Thứ Bảy & Chủ Nhật:</strong> 08:00 - 17:00 (Mở cửa nguyên ngày, không nghỉ trưa).</li></ul><p>Lưu ý: Vào cuối tuần, Thư viện chỉ mở cửa các phòng đọc mở, phòng học nhóm và khu vực tự học. Các dịch vụ cấp thẻ mới, thu tiền phạt và xử lý nợ sách sẽ không hoạt động. Xin quý độc giả lưu ý để sắp xếp công việc hợp lý.</p><p>Chúc các bạn có những giờ phút học tập hiệu quả tại Thư viện UTC!</p>',NULL,'active','notice','2026-05-05 14:20:00',3,3,NULL,'2026-05-05 14:20:00','2026-05-05 14:20:00');
/*!40000 ALTER TABLE `news_posts` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `notifications`
--

DROP TABLE IF EXISTS `notifications`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `notifications` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `recipient_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Nhóm nhận: admin|user',
  `recipient_id` int unsigned NOT NULL COMMENT 'ID người nhận thông báo',
  `type` varchar(120) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Loại thông báo nghiệp vụ',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tiêu đề hiển thị',
  `message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Nội dung thông báo',
  `severity` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'info' COMMENT 'Mức độ: info|warning|critical',
  `entity_type` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Loại thực thể liên quan',
  `entity_id` int unsigned DEFAULT NULL COMMENT 'ID thực thể liên quan',
  `action_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'URL điều hướng khi click thông báo',
  `meta` json DEFAULT NULL COMMENT 'Dữ liệu mở rộng cho frontend',
  `dedupe_key` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Khóa chống trùng thông báo',
  `read_at` timestamp NULL DEFAULT NULL COMMENT 'Thời điểm đã đọc',
  `created_by` int unsigned DEFAULT NULL COMMENT 'Người tạo bản ghi',
  `updated_by` int unsigned DEFAULT NULL COMMENT 'Người cập nhật bản ghi',
  `deleted_by` int unsigned DEFAULT NULL COMMENT 'Người xóa (soft/hard)',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `notifications_dedupe_key_unique` (`dedupe_key`),
  KEY `notifications_created_by_foreign` (`created_by`),
  KEY `notifications_updated_by_foreign` (`updated_by`),
  KEY `notifications_deleted_by_foreign` (`deleted_by`),
  KEY `notifications_recipient_stream_idx` (`recipient_type`,`recipient_id`,`id`),
  KEY `notifications_recipient_unread_idx` (`recipient_type`,`recipient_id`,`read_at`),
  KEY `notifications_recipient_type_index` (`recipient_type`),
  KEY `notifications_recipient_id_index` (`recipient_id`),
  KEY `notifications_type_index` (`type`),
  KEY `notifications_read_at_index` (`read_at`),
  CONSTRAINT `notifications_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
