INSERT INTO `site_contents` VALUES (1,'page','gioi-thieu-thu-vien-utc','Giới thiệu Thư viện Trường Đại học Giao thông Vận tải','Thông tin tổng quan về Trung tâm Thông tin – Thư viện Trường Đại học Giao thông Vận tải.','<p>Trung tâm Thông tin – Thư viện Trường Đại học Giao thông Vận tải là đơn vị phục vụ đào tạo, nghiên cứu khoa học và học tập của cán bộ, giảng viên, sinh viên toàn trường.</p>\n<p>Thư viện cung cấp các dịch vụ: đọc tại chỗ, mượn về nhà, tra cứu tài liệu, hỗ trợ tư vấn thông tin, phục vụ học liệu điện tử và các cơ sở dữ liệu trực tuyến.</p>','intro',NULL,1,'2026-05-02 09:44:32','[]',NULL,NULL,NULL,'2026-05-02 09:44:32','2026-05-02 09:44:32'),(2,'page','chuc-nang-nhiem-vu-thu-vien','Chức năng, nhiệm vụ','Chức năng, nhiệm vụ chính của Trung tâm Thông tin – Thư viện.','<ul>\n  <li>Thu thập, xử lý, tổ chức và lưu trữ tài liệu phục vụ đào tạo và nghiên cứu khoa học.</li>\n  <li>Cung cấp dịch vụ thông tin – thư viện cho cán bộ, giảng viên, sinh viên và học viên.</li>\n  <li>Phát triển các bộ sưu tập số, học liệu điện tử và các dịch vụ tra cứu trực tuyến.</li>\n  <li>Phối hợp với các đơn vị trong và ngoài trường để chia sẻ nguồn lực thông tin.</li>\n  <li>Tổ chức hướng dẫn kỹ năng khai thác và sử dụng thông tin cho bạn đọc.</li>\n</ul>','intro',NULL,1,'2026-05-02 09:44:32','[]',NULL,NULL,NULL,'2026-05-02 09:44:32','2026-05-02 09:44:32'),(3,'page','lich-su-thanh-tich-thu-vien','Lịch sử, thành tích','Lược sử hình thành và phát triển của Thư viện Trường ĐH GTVT.','<p>Thư viện Trường Đại học Giao thông Vận tải được hình thành và phát triển cùng với quá trình xây dựng và trưởng thành của Nhà trường.</p>\n<p>Qua nhiều giai đoạn, Thư viện từng bước hiện đại hóa cơ sở vật chất, bổ sung nguồn tài liệu phong phú về lĩnh vực giao thông vận tải, xây dựng, kinh tế, công nghệ thông tin và nhiều ngành liên quan.</p>','intro',NULL,1,'2026-05-02 09:44:32','[]',NULL,NULL,NULL,'2026-05-02 09:44:32','2026-05-02 09:44:32'),(4,'page','quy-dinh-su-dung-thu-vien','Quy định sử dụng Thư viện','Quy định sử dụng tài liệu, không gian và dịch vụ tại Thư viện UTC.','<ul>\n  <li>Giữ trật tự, không gây ồn ào, không sử dụng điện thoại trong phòng đọc.</li>\n  <li>Giữ gìn tài liệu, không viết vẽ, gạch xóa, làm rách hoặc làm bẩn sách.</li>\n  <li>Không tự ý mang tài liệu ra khỏi Thư viện khi chưa làm thủ tục mượn.</li>\n  <li>Tuân thủ thời hạn mượn trả theo quy định, nộp phạt khi trả quá hạn hoặc làm mất, hỏng tài liệu.</li>\n  <li>Xuất trình thẻ thư viện hoặc giấy tờ hợp lệ khi sử dụng dịch vụ.</li>\n</ul>','rule',NULL,1,'2026-05-02 09:44:32','[]',NULL,NULL,NULL,'2026-05-02 09:44:32','2026-05-02 09:44:32'),(5,'page','thu-tuc-lam-the-thu-vien','Thủ tục làm thẻ Thư viện','Hướng dẫn đăng ký và sử dụng thẻ thư viện.','<ol>\n  <li>Sinh viên, học viên, cán bộ, giảng viên của Trường được đăng ký sử dụng Thư viện.</li>\n  <li>Chuẩn bị: thẻ sinh viên hoặc giấy tờ tùy thân, ảnh thẻ theo yêu cầu (nếu cần).</li>\n  <li>Đăng ký thông tin tại bộ phận thủ thư hoặc qua hệ thống trực tuyến (nếu được hỗ trợ).</li>\n  <li>Nhận thẻ và kiểm tra thông tin cá nhân trên thẻ.</li>\n  <li>Thẻ thư viện được dùng để mượn sách, sử dụng phòng đọc và các dịch vụ khác.</li>\n</ol>','rule',NULL,1,'2026-05-02 09:44:32','[]',NULL,NULL,NULL,'2026-05-02 09:44:32','2026-05-02 09:44:32'),(6,'page','lich-phuc-vu-thu-vien','Lịch phục vụ Thư viện','Giờ mở cửa và lịch phục vụ tại các phòng đọc, phòng mượn.','<p>Giờ mở cửa chung: <strong>08:15 - 16:45</strong> (từ thứ Hai đến thứ Sáu, trừ ngày lễ, Tết theo quy định của Nhà trường).</p>\n<p>Các phòng đọc, phòng mượn có thể có lịch phục vụ cụ thể, được Thư viện thông báo trên website và tại bảng tin.</p>','rule',NULL,1,'2026-05-02 09:44:32','{\"opening_hours\": \"08:15 - 16:45\"}',NULL,NULL,NULL,'2026-05-02 09:44:32','2026-05-02 09:44:32'),(7,'page','thu-tuc-nop-luan-van-luan-an','Thủ tục nộp luận văn, luận án','Quy định về việc nộp và lưu chiểu luận văn, luận án tại Thư viện.','<ol>\n  <li>Người học hoàn thành luận văn, luận án theo quy định của Nhà trường.</li>\n  <li>Nộp bản in và/hoặc bản số (file PDF) cho Thư viện theo hướng dẫn của đơn vị quản lý đào tạo.</li>\n  <li>Thư viện tiếp nhận, kiểm tra hình thức và lập biên bản bàn giao.</li>\n  <li>Sau khi hoàn tất, tài liệu được đưa vào kho lưu trữ và/hoặc bộ sưu tập số phục vụ tra cứu.</li>\n</ol>','rule',NULL,1,'2026-05-02 09:44:32','[]',NULL,NULL,NULL,'2026-05-02 09:44:32','2026-05-02 09:44:32'),(8,'service','muon-ve-nha','Dịch vụ mượn về nhà',NULL,'Cho phép bạn đọc mượn tài liệu về nhà theo quy định của Thư viện.','MUON_VE_NHA',NULL,1,'2026-05-02 09:44:32','[]',NULL,NULL,NULL,'2026-05-02 09:44:32','2026-05-02 09:44:32'),(9,'service','doc-tai-cho','Dịch vụ đọc tại chỗ',NULL,'Phục vụ đọc tài liệu tại các phòng đọc trong khuôn viên Thư viện.','DOC_TAI_CHO',NULL,1,'2026-05-02 09:44:32','[]',NULL,NULL,NULL,'2026-05-02 09:44:32','2026-05-02 09:44:32'),(10,'service','tra-cuu-theo-yeu-cau','Tra cứu theo yêu cầu',NULL,'Hỗ trợ tra cứu thông tin, tài liệu theo yêu cầu của bạn đọc.','TRA_CUU_THEO_YEU_CAU',NULL,1,'2026-05-02 09:44:32','[]',NULL,NULL,NULL,'2026-05-02 09:44:32','2026-05-02 09:44:32'),(11,'service','tu-van-ho-tro','Hỗ trợ tư vấn và giải đáp thông tin',NULL,'Tư vấn sử dụng Thư viện, hướng dẫn tìm kiếm tài liệu, sử dụng cơ sở dữ liệu.','TU_VAN_HO_TRO',NULL,1,'2026-05-02 09:44:32','[]',NULL,NULL,NULL,'2026-05-02 09:44:32','2026-05-02 09:44:32'),(12,'service','ban-giao-trinh','Bán giáo trình',NULL,'Cung cấp giáo trình và tài liệu tham khảo phục vụ học tập tại Trường.','BAN_GIAO_TRINH',NULL,1,'2026-05-02 09:44:32','[]',NULL,NULL,NULL,'2026-05-02 09:44:32','2026-05-02 09:44:32'),(13,'post','gioi-thieu-sach-moi-ly-thuyet-thiet-ke-va-tinh-toan-cau-hien-dai','Giới thiệu sách mới: Lý thuyết thiết kế và tính toán cầu hiện đại','Giới thiệu tới bạn đọc cuốn sách về lý thuyết thiết kế và tính toán cầu hiện đại cho ngành GTVT.',NULL,'news',2,1,'2026-05-02 09:44:32','[]',NULL,NULL,NULL,'2026-05-02 09:44:32','2026-05-02 09:44:32'),(14,'post','khao-sat-chat-luong-dich-vu-thu-vien-ky-ii','Khảo sát chất lượng dịch vụ Thư viện kỳ II','Thư viện tổ chức khảo sát ý kiến bạn đọc về chất lượng dịch vụ kỳ II nhằm nâng cao hiệu quả phục vụ.',NULL,'announcement',2,1,'2026-05-02 09:44:32','[]',NULL,NULL,NULL,'2026-05-02 09:44:32','2026-05-02 09:44:32'),(15,'post','huong-dan-tan-sinh-vien-su-dung-thu-vien','Hướng dẫn tân sinh viên sử dụng Thư viện','Thông tin dành cho tân sinh viên về cách đăng ký thẻ và sử dụng các dịch vụ tại Thư viện.',NULL,'announcement',2,1,'2026-05-02 09:44:32','[]',NULL,NULL,NULL,'2026-05-02 09:44:32','2026-05-02 09:44:32');
/*!40000 ALTER TABLE `site_contents` ENABLE KEYS */;
